    progress = dict(fsm.get("progress") or {})
    has_progress = bool(progress.get("has_progress"))
    return {
        "schema_version": SCHEMA_VERSION,
        "progress": progress,
        "current_step": progress.get("current_step"),
        "total_steps": progress.get("total_steps"),
        "progress_percent": progress.get("progress_percent"),
        "section_label": progress.get("section_label") or "",
        "has_progress": has_progress,
        "reason": "progress_detected" if has_progress else "no_progress_detected",
        "fsm_state": str(fsm.get("state") or ""),
        "fsm_state_reason": str(fsm.get("state_reason") or ""),
    }


