def build_leaf_task_type_registry(
    *,
    leaf_tasks: Sequence[Mapping[str, Any] | str] | None = None,
    task_type_hint: str = "",
    allowed_types: Sequence[str] | None = None,
) -> Dict[str, Any]:
    allowed = [str(item).strip().lower() for item in (allowed_types or ["implement", "test", "verify", "inspect", "migrate", "calibrate", "report"]) if str(item or "").strip()]
    hint = str(task_type_hint or "").strip().lower()

    def _collect(rows: Sequence[Mapping[str, Any] | str] | None) -> List[Dict[str, Any]]:
        collected: List[Dict[str, Any]] = []
        for row in rows or []:
            if isinstance(row, Mapping):
                collected.append(dict(row))
            else:
                text = str(row or "").strip()
                if text:
                    collected.append({"task_name": text})
        return collected

    tasks = _collect(leaf_tasks)
    buckets: Dict[str, List[str]] = {task_type: [] for task_type in allowed}
    unknown_tasks: List[str] = []

    def _infer_type(row: Mapping[str, Any]) -> str:
        raw = str(_first_nonempty(row.get("task_type"), row.get("kind"), row.get("type"), "")).strip().lower()
        if raw in allowed:
            return raw
        name = str(_first_nonempty(row.get("task_name"), row.get("name"), row.get("reason"), hint, "")).strip().lower()
        for task_type in allowed:
            if task_type in name:
                return task_type
        if "verify" in name or "validation" in name:
            return "verify" if "verify" in allowed else ""
        if "test" in name or "check" in name:
            return "test" if "test" in allowed else ""
        if "inspect" in name or "review" in name:
            return "inspect" if "inspect" in allowed else ""
        if "implement" in name or "build" in name or "create" in name:
            return "implement" if "implement" in allowed else ""
        if "migrate" in name or "move" in name:
            return "migrate" if "migrate" in allowed else ""
        if "calibrate" in name or "tune" in name:
            return "calibrate" if "calibrate" in allowed else ""
        if "report" in name or "summary" in name:
            return "report" if "report" in allowed else ""
        return ""

    for index, task in enumerate(tasks, start=1):
        task_name = str(_first_nonempty(task.get("task_name"), task.get("name"), f"task_{index}")).strip().lower()
        task_type = _infer_type(task)
        if task_type:
            buckets.setdefault(task_type, []).append(task_name)
        else:
            unknown_tasks.append(task_name)

    for task_type in buckets:
        buckets[task_type] = sorted({value for value in buckets[task_type] if value})

    total = len(tasks)
    if total == 0:
        reason = "leaf_task_type_registry_missing"
    elif unknown_tasks:
        reason = "leaf_task_type_registry_partial"
    else:
        reason = "leaf_task_type_registry_ready"

    registry_id = _sha1_payload(
        {
            "hint": hint,
            "buckets": {key: buckets.get(key, []) for key in sorted(buckets)},
            "unknown": sorted(unknown_tasks),
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "registry_id": registry_id,
        "task_type_hint": hint,
        "buckets": {key: buckets.get(key, []) for key in sorted(buckets)},
        "bucket_counts": {key: len(values) for key, values in sorted(buckets.items())},
        "unknown_tasks": sorted({value for value in unknown_tasks}),
        "task_count": total,
        "reason": reason,
        "is_complete": reason == "leaf_task_type_registry_ready",
        "should_warn": reason != "leaf_task_type_registry_ready",
        "should_block": reason == "leaf_task_type_registry_missing",
    }


