def build_leaf_done_definition(
    *,
    required_completion_signals: Sequence[Any] | None = None,
    observed_signals: Sequence[Any] | None = None,
    investigation_only: bool = False,
    leaf_hint: str = "",
) -> Dict[str, Any]:
    required = sorted({str(item).strip().lower() for item in (required_completion_signals or []) if str(item or "").strip()})
    observed = sorted({str(item).strip().lower() for item in (observed_signals or []) if str(item or "").strip()})
    hint = str(leaf_hint or "").strip().lower()
    inspect_only = bool(investigation_only)
    missing = [item for item in required if item not in observed]

    if inspect_only and observed:
        reason = "leaf_done_definition_investigated"
    elif required and not missing:
        reason = "leaf_done_definition_done"
    elif required or observed:
        reason = "leaf_done_definition_partial"
    else:
        reason = "leaf_done_definition_missing"

    done_id = _sha1_payload(
        {
            "required": required,
            "observed": observed,
            "investigation_only": inspect_only,
            "hint": hint,
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "done_id": done_id,
        "leaf_hint": hint,
        "required_completion_signals": required,
        "observed_signals": observed,
        "missing_signals": missing,
        "investigation_only": inspect_only,
        "reason": reason,
        "is_complete": reason in {"leaf_done_definition_done", "leaf_done_definition_investigated"},
        "is_investigated_only": reason == "leaf_done_definition_investigated",
        "should_warn": reason == "leaf_done_definition_partial",
        "should_block": reason == "leaf_done_definition_missing",
    }


