def build_leaf_failure_schema(
    *,
    observed_failure_states: Sequence[Any] | None = None,
    evidence_signals: Sequence[Any] | None = None,
    repair_outcomes: Sequence[Any] | None = None,
    leaf_hint: str = "",
) -> Dict[str, Any]:
    states = sorted({str(item).strip().lower() for item in (observed_failure_states or []) if str(item or "").strip()})
    evidence = sorted({str(item).strip().lower() for item in (evidence_signals or []) if str(item or "").strip()})
    repairs = sorted({str(item).strip().lower() for item in (repair_outcomes or []) if str(item or "").strip()})
    hint = str(leaf_hint or "").strip().lower()

    canonical_map = {
        "blocker": {"blocker", "blocked", "abort", "critical", "hard_stop"},
        "failed_fix": {"failed_fix", "fix_failed", "regression", "rollback"},
        "insufficient_evidence": {"insufficient_evidence", "no_evidence", "unknown", "unclear"},
        "flaky": {"flaky", "intermittent", "retry", "unstable"},
        "partial": {"partial", "incomplete", "degraded", "soft_fail"},
    }
    priority = ["blocker", "failed_fix", "insufficient_evidence", "flaky", "partial"]
    normalized = "partial"
    for state in priority:
        if any(token in canonical_map[state] for token in states):
            normalized = state
            break

    if not states and not evidence and not repairs:
        reason = "leaf_failure_schema_missing"
    elif normalized == "blocker" or normalized == "failed_fix":
        reason = "leaf_failure_schema_blocking"
    elif normalized == "insufficient_evidence":
        reason = "leaf_failure_schema_insufficient"
    else:
        reason = "leaf_failure_schema_ready"

    failure_id = _sha1_payload(
        {
            "states": states,
            "evidence": evidence,
            "repairs": repairs,
            "hint": hint,
            "normalized": normalized,
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "failure_id": failure_id,
        "leaf_hint": hint,
        "observed_failure_states": states,
        "evidence_signals": evidence,
        "repair_outcomes": repairs,
        "normalized_failure_state": normalized,
        "reason": reason,
        "is_complete": reason == "leaf_failure_schema_ready",
        "should_warn": reason == "leaf_failure_schema_insufficient",
        "should_block": reason in {"leaf_failure_schema_missing", "leaf_failure_schema_blocking"},
    }


def build_leaf_dependency_graph(
    *,
    leaf_nodes: Sequence[Any] | None = None,
    dependency_pairs: Sequence[Any] | None = None,
    leaf_hint: str = "",
) -> Dict[str, Any]:
    nodes = sorted(
        {
            str((item or {}).get("leaf") if isinstance(item, Mapping) else item).strip().lower()
            for item in (leaf_nodes or [])
            if str((item or {}).get("leaf") if isinstance(item, Mapping) else item).strip()
        }
    )
    if not nodes:
        nodes = sorted(
            {
                str((pair or {}).get("leaf") if isinstance(pair, Mapping) else pair).strip().lower()
                for pair in (dependency_pairs or [])
                if str((pair or {}).get("leaf") if isinstance(pair, Mapping) else pair).strip()
            }
        )

    edges: List[Dict[str, str]] = []
    adjacency: Dict[str, List[str]] = {node: [] for node in nodes}
    missing_dependencies: List[str] = []
    for pair in dependency_pairs or []:
        if isinstance(pair, Mapping):
            leaf = str(pair.get("leaf") or "").strip().lower()
            depends_on_value = pair.get("depends_on") or pair.get("blocked_by") or []
            if isinstance(depends_on_value, (str, bytes)):
                depends_on_items = [depends_on_value]
            else:
                depends_on_items = list(depends_on_value) if isinstance(depends_on_value, Sequence) else [depends_on_value]
        else:
            continue
        if not leaf:
            continue
        if leaf not in adjacency:
            adjacency[leaf] = []
            nodes.append(leaf)
        for dep in depends_on_items:
            dep_name = str(dep or "").strip().lower()
            if not dep_name:
                continue
            edges.append({"leaf": leaf, "depends_on": dep_name})
            adjacency.setdefault(leaf, []).append(dep_name)
            if dep_name not in adjacency:
                missing_dependencies.append(dep_name)

    nodes = sorted(dict.fromkeys(nodes))
    ready_leafs = sorted([leaf for leaf in nodes if not adjacency.get(leaf)])
    blocked_leafs = sorted([leaf for leaf in nodes if adjacency.get(leaf)])

    cycles: List[str] = []
    visiting: set[str] = set()
    visited: set[str] = set()

    def _dfs(node: str) -> bool:
        if node in visiting:
            cycles.append(node)
            return True
        if node in visited:
            return False
        visiting.add(node)
        for dep in adjacency.get(node, []):
            if dep in adjacency and _dfs(dep):
                cycles.append(node)
                break
        visiting.remove(node)
        visited.add(node)
        return False

    for node in nodes:
        _dfs(node)

    cycle_nodes = sorted(dict.fromkeys(cycles))
    hint = str(leaf_hint or "").strip().lower()
    if not nodes and not edges:
        reason = "leaf_dependency_graph_missing"
    elif cycle_nodes:
        reason = "leaf_dependency_graph_cyclic"
    elif blocked_leafs:
        reason = "leaf_dependency_graph_partial"
    else:
        reason = "leaf_dependency_graph_ready"

    graph_id = _sha1_payload(
        {
            "nodes": nodes,
            "edges": edges,
            "ready_leafs": ready_leafs,
            "blocked_leafs": blocked_leafs,
            "missing_dependencies": sorted(dict.fromkeys(missing_dependencies)),
            "cycle_nodes": cycle_nodes,
            "hint": hint,
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "graph_id": graph_id,
        "leaf_hint": hint,
        "nodes": nodes,
        "edges": edges,
        "ready_leafs": ready_leafs,
        "blocked_leafs": blocked_leafs,
        "missing_dependencies": sorted(dict.fromkeys(missing_dependencies)),
        "cycle_nodes": cycle_nodes,
        "reason": reason,
        "is_complete": reason == "leaf_dependency_graph_ready",
        "should_warn": reason == "leaf_dependency_graph_partial",
        "should_block": reason in {"leaf_dependency_graph_missing", "leaf_dependency_graph_cyclic"},
    }


def build_leaf_bundle_policy(
    *,
    leaf_bundle_items: Sequence[Any] | None = None,
    leaf_hint: str = "",
) -> Dict[str, Any]:
    items: List[Dict[str, Any]] = []
    for item in leaf_bundle_items or []:
        if isinstance(item, Mapping):
            leaf = str(item.get("leaf") or "").strip().lower()
            scopes_raw = item.get("write_scope") or item.get("write_scopes") or []
            artifacts_raw = item.get("artifact_names") or item.get("artifacts") or []
            if isinstance(scopes_raw, (str, bytes)):
                scopes_iter = [scopes_raw]
            else:
                scopes_iter = list(scopes_raw) if isinstance(scopes_raw, Sequence) else [scopes_raw]
            if isinstance(artifacts_raw, (str, bytes)):
                artifacts_iter = [artifacts_raw]
            else:
                artifacts_iter = list(artifacts_raw) if isinstance(artifacts_raw, Sequence) else [artifacts_raw]
            scopes = sorted({str(value).strip().lower() for value in scopes_iter if str(value or "").strip()})
            artifacts = sorted({str(value).strip().lower() for value in artifacts_iter if str(value or "").strip()})
            if leaf:
                items.append({"leaf": leaf, "write_scope": scopes, "artifact_names": artifacts})
        else:
            leaf = str(item or "").strip().lower()
            if leaf:
                items.append({"leaf": leaf, "write_scope": [], "artifact_names": []})

    leaves = sorted({entry["leaf"] for entry in items})
    shared_scopes = sorted(set(items[0]["write_scope"]).intersection(*(set(entry["write_scope"]) for entry in items[1:]))) if items and all(entry["write_scope"] for entry in items) else []
    shared_artifacts = sorted(set(items[0]["artifact_names"]).intersection(*(set(entry["artifact_names"]) for entry in items[1:]))) if items and all(entry["artifact_names"] for entry in items) else []
    hint = str(leaf_hint or "").strip().lower()

    if not items:
        reason = "leaf_bundle_policy_missing"
    elif len(leaves) < 2:
        reason = "leaf_bundle_policy_partial"
    elif shared_scopes or shared_artifacts:
        reason = "leaf_bundle_policy_ready"
    else:
        reason = "leaf_bundle_policy_partial"

    bundle_id = _sha1_payload(
        {
            "items": items,
            "shared_scopes": shared_scopes,
            "shared_artifacts": shared_artifacts,
            "hint": hint,
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "bundle_id": bundle_id,
        "leaf_hint": hint,
        "bundle_items": items,
        "leaves": leaves,
        "shared_write_scopes": shared_scopes,
        "shared_artifact_names": shared_artifacts,
        "reason": reason,
        "is_complete": reason == "leaf_bundle_policy_ready",
        "should_warn": reason == "leaf_bundle_policy_partial",
        "should_block": reason == "leaf_bundle_policy_missing",
    }


def build_bundle_complexity_cap(
    *,
    bundle_items: Sequence[Any] | None = None,
    max_responsibilities: int = 0,
    max_steps: int = 0,
    leaf_hint: str = "",
) -> Dict[str, Any]:
    items: List[Dict[str, Any]] = []
    for item in bundle_items or []:
        if not isinstance(item, Mapping):
            leaf = str(item or "").strip().lower()
            if leaf:
                items.append({"leaf": leaf, "responsibility": leaf, "step_count": 1})
            continue

        leaf = str(item.get("leaf") or "").strip().lower()
        responsibility = str(item.get("responsibility") or item.get("task_type") or item.get("kind") or leaf).strip().lower()
        step_value = item.get("step_count")
        if isinstance(step_value, Sequence) and not isinstance(step_value, (str, bytes)):
            step_count = len(list(step_value))
        else:
            try:
                step_count = int(step_value) if step_value is not None else 1
            except (TypeError, ValueError):
                step_count = 1
        if leaf or responsibility:
            items.append(
                {
                    "leaf": leaf,
                    "responsibility": responsibility,
                    "step_count": max(1, step_count),
                }
            )

    responsibilities = sorted({entry["responsibility"] for entry in items if entry["responsibility"]})
    total_steps = sum(int(entry.get("step_count") or 0) for entry in items)
    leaf_count = len(items)
    hint = str(leaf_hint or "").strip().lower()
    resp_cap = max(0, int(max_responsibilities or 0))
    step_cap = max(0, int(max_steps or 0))

    if not items and not resp_cap and not step_cap:
        reason = "bundle_complexity_cap_missing"
    elif not items:
        reason = "bundle_complexity_cap_partial"
    elif resp_cap and len(responsibilities) > resp_cap:
        reason = "bundle_complexity_cap_exceeded"
    elif step_cap and total_steps > step_cap:
        reason = "bundle_complexity_cap_exceeded"
    elif resp_cap or step_cap:
        reason = "bundle_complexity_cap_ready"
    else:
        reason = "bundle_complexity_cap_partial"

    cap_id = _sha1_payload(
        {
            "items": items,
            "responsibilities": responsibilities,
            "total_steps": total_steps,
            "max_responsibilities": resp_cap,
            "max_steps": step_cap,
            "hint": hint,
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "cap_id": cap_id,
        "leaf_hint": hint,
        "bundle_items": items,
        "responsibilities": responsibilities,
        "responsibility_count": len(responsibilities),
        "leaf_count": leaf_count,
        "total_steps": total_steps,
        "max_responsibilities": resp_cap,
        "max_steps": step_cap,
        "reason": reason,
        "is_complete": reason == "bundle_complexity_cap_ready",
        "should_warn": reason == "bundle_complexity_cap_partial",
        "should_block": reason in {"bundle_complexity_cap_missing", "bundle_complexity_cap_exceeded"},
    }


def build_execution_readiness_gate(
    *,
    leaf_bundle: Sequence[Any] | None = None,
    context_requirements: Sequence[Any] | None = None,
    integration_requirements: Sequence[Any] | None = None,
    lead_only_signals: Sequence[Any] | None = None,
    leaf_hint: str = "",
) -> Dict[str, Any]:
    bundle = sorted({str(item).strip().lower() for item in (leaf_bundle or []) if str(item or "").strip()})
    context = sorted({str(item).strip().lower() for item in (context_requirements or []) if str(item or "").strip()})
    integration = sorted({str(item).strip().lower() for item in (integration_requirements or []) if str(item or "").strip()})
    lead_only = sorted({str(item).strip().lower() for item in (lead_only_signals or []) if str(item or "").strip()})
    hint = str(leaf_hint or "").strip().lower()

    if not bundle and not context and not integration and not lead_only:
        readiness = "wymaga_kontekstu"
        reason = "execution_readiness_gate_missing"
    elif lead_only:
        readiness = "tylko_dla_lead"
        reason = "execution_readiness_gate_lead_only"
    elif integration:
        readiness = "wymaga_integracji"
        reason = "execution_readiness_gate_needs_integration"
    elif context:
        readiness = "wymaga_kontekstu"
        reason = "execution_readiness_gate_needs_context"
    else:
        readiness = "gotowe_do_delegacji"
        reason = "execution_readiness_gate_ready"

    gate_id = _sha1_payload(
        {
            "bundle": bundle,
            "context": context,
            "integration": integration,
            "lead_only": lead_only,
            "readiness": readiness,
            "hint": hint,
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "gate_id": gate_id,
        "leaf_hint": hint,
        "bundle": bundle,
        "context_requirements": context,
        "integration_requirements": integration,
        "lead_only_signals": lead_only,
        "readiness": readiness,
        "reason": reason,
        "is_complete": readiness == "gotowe_do_delegacji",
        "should_warn": readiness in {"wymaga_kontekstu", "wymaga_integracji"},
        "should_block": readiness == "tylko_dla_lead" or reason == "execution_readiness_gate_missing",
    }


def build_leaf_spec_regression_suite(
    *,
    sample_leafs: Sequence[Any] | None = None,
    minimal_packets: Sequence[Any] | None = None,
    extra_questions: Sequence[Any] | None = None,
    leaf_hint: str = "",
) -> Dict[str, Any]:
    leafs = sorted({str(item).strip().lower() for item in (sample_leafs or []) if str(item or "").strip()})
    packets = []
    for packet in minimal_packets or []:
        if isinstance(packet, Mapping):
            packet_leaf = str(packet.get("leaf") or packet.get("leaf_hint") or "").strip().lower()
            packet_kind = str(packet.get("packet_kind") or packet.get("kind") or "").strip().lower()
            packet_complete = bool(packet.get("is_complete", True))
            packet_warn = bool(packet.get("should_warn", False))
            packets.append(
                {
                    "leaf": packet_leaf,
                    "packet_kind": packet_kind,
                    "is_complete": packet_complete,
                    "should_warn": packet_warn,
                }
            )
        else:
            packet_leaf = str(packet or "").strip().lower()
            if packet_leaf:
                packets.append(
                    {
                        "leaf": packet_leaf,
                        "packet_kind": "minimal",
                        "is_complete": True,
                        "should_warn": False,
                    }
                )

    questions = sorted({str(item).strip().lower() for item in (extra_questions or []) if str(item or "").strip()})
    hint = str(leaf_hint or "").strip().lower()
    packet_leafs = sorted({packet["leaf"] for packet in packets if packet["leaf"]})
    missing_leafs = sorted([leaf for leaf in leafs if leaf not in packet_leafs])

    if not leafs and not packets and not questions:
        reason = "leaf_spec_regression_suite_missing"
    elif leafs and packets and not questions and not missing_leafs:
        reason = "leaf_spec_regression_suite_ready"
    else:
        reason = "leaf_spec_regression_suite_partial"

    suite_id = _sha1_payload(
        {
            "leafs": leafs,
            "packets": packets,
            "questions": questions,
            "missing_leafs": missing_leafs,
            "hint": hint,
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "suite_id": suite_id,
        "leaf_hint": hint,
        "sample_leafs": leafs,
        "minimal_packets": packets,
        "extra_questions": questions,
        "missing_leafs": missing_leafs,
        "reason": reason,
        "is_complete": reason == "leaf_spec_regression_suite_ready",
        "should_warn": reason == "leaf_spec_regression_suite_partial",
        "should_block": reason == "leaf_spec_regression_suite_missing",
    }


def build_leaf_ambiguity_detector(
    *,
    leaf_titles: Sequence[Any] | None = None,
    responsibilities: Sequence[Any] | None = None,
    done_definition_signals: Sequence[Any] | None = None,
    leaf_hint: str = "",
) -> Dict[str, Any]:
    titles = sorted({str(item).strip().lower() for item in (leaf_titles or []) if str(item or "").strip()})
    responsibilities_list = sorted({str(item).strip().lower() for item in (responsibilities or []) if str(item or "").strip()})
    done_signals = sorted({str(item).strip().lower() for item in (done_definition_signals or []) if str(item or "").strip()})
    hint = str(leaf_hint or "").strip().lower()

    vague_markers = {"zbyt", "rozne", "various", "misc", "other", "todo", "some", "maybe", "later", "etc", "anything"}
    combined_markers = {"and", "/", "+", "combined", "mix", "oraz", "or"}
    missing_done_markers = {"done", "complete", "complete_when", "when_done", "finished", "finish"}
    missing_scope_markers = {"scope", "files", "artifact", "artifact_names", "write_scope", "responsibility"}

    title_issues = 0
    for title in titles:
        if any(marker in title for marker in vague_markers):
            title_issues += 1
        if any(marker in title for marker in combined_markers):
            title_issues += 1

    responsibility_issues = 0
    for item in responsibilities_list:
        if any(marker in item for marker in vague_markers):
            responsibility_issues += 1
        if any(marker in item for marker in combined_markers):
            responsibility_issues += 1

    done_issue = 0 if any(signal in done_signals for signal in missing_done_markers) else 1
    scope_issue = 0 if any(signal in done_signals for signal in missing_scope_markers) else 1
    total_issues = title_issues + responsibility_issues + done_issue + scope_issue

    if not titles and not responsibilities_list and not done_signals:
        reason = "leaf_ambiguity_detector_missing"
    elif total_issues == 0:
        reason = "leaf_ambiguity_detector_ready"
    elif total_issues <= 2:
        reason = "leaf_ambiguity_detector_partial"
    else:
        reason = "leaf_ambiguity_detector_ambiguous"

    detector_id = _sha1_payload(
        {
            "titles": titles,
            "responsibilities": responsibilities_list,
            "done_signals": done_signals,
            "total_issues": total_issues,
            "hint": hint,
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "detector_id": detector_id,
        "leaf_hint": hint,
        "leaf_titles": titles,
        "responsibilities": responsibilities_list,
        "done_definition_signals": done_signals,
        "issue_count": total_issues,
        "reason": reason,
        "is_complete": reason == "leaf_ambiguity_detector_ready",
        "should_warn": reason == "leaf_ambiguity_detector_partial",
        "should_block": reason in {"leaf_ambiguity_detector_missing", "leaf_ambiguity_detector_ambiguous"},
    }


def build_delegation_readiness_score(
    *,
    leaf_title: str = "",
    scope_items: Sequence[Any] | None = None,
    test_signals: Sequence[Any] | None = None,
    leaf_hint: str = "",
) -> Dict[str, Any]:
    title = str(leaf_title or "").strip().lower()
    scope = sorted({str(item).strip().lower() for item in (scope_items or []) if str(item or "").strip()})
    tests = sorted({str(item).strip().lower() for item in (test_signals or []) if str(item or "").strip()})
    hint = str(leaf_hint or "").strip().lower()

    specificity = 0
    if title and len(title.split()) <= 6:
        specificity += 1
    if scope:
        specificity += 1
    if tests:
        specificity += 1
    if any("done" in item or "ready" in item for item in scope):
        specificity += 1
    if any("test" in item or "verify" in item for item in tests):
        specificity += 1

    if not title and not scope and not tests:
        reason = "delegation_readiness_score_missing"
        readiness = "blocked"
    elif specificity >= 4:
        reason = "delegation_readiness_score_ready"
        readiness = "ready"
    elif specificity >= 2:
        reason = "delegation_readiness_score_partial"
        readiness = "partial"
    else:
        reason = "delegation_readiness_score_blocked"
        readiness = "blocked"

    score = round(min(1.0, specificity / 5.0), 4)
    score_id = _sha1_payload(
        {
            "title": title,
            "scope": scope,
            "tests": tests,
            "readiness": readiness,
            "hint": hint,
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "score_id": score_id,
        "leaf_hint": hint,
        "leaf_title": title,
        "scope_items": scope,
        "test_signals": tests,
        "score": score,
        "readiness": readiness,
        "reason": reason,
        "is_complete": readiness == "ready",
        "should_warn": readiness == "partial",
        "should_block": readiness == "blocked",
    }


def build_environment_freshness_regression_suite(
    *,
    freshness_cases: Sequence[Any] | None = None,
    max_age_hours: float = 0.0,
    leaf_hint: str = "",
) -> Dict[str, Any]:
    cases: List[Dict[str, Any]] = []
    for case in freshness_cases or []:
        if isinstance(case, Mapping):
            case_id = str(case.get("case_id") or case.get("name") or "").strip().lower()
            age_hours_value = case.get("age_hours")
            timestamp_value = case.get("timestamp")
            if isinstance(age_hours_value, (int, float)):
                age_hours = float(age_hours_value)
            else:
                try:
                    age_hours = float(age_hours_value) if age_hours_value is not None else None
                except (TypeError, ValueError):
                    age_hours = None
            cases.append(
                {
                    "case_id": case_id,
                    "age_hours": age_hours,
                    "timestamp": str(timestamp_value or "").strip(),
                }
            )

    hint = str(leaf_hint or "").strip().lower()
    max_age = max(0.0, float(max_age_hours or 0.0))
    fresh_cases: List[str] = []
    stale_cases: List[str] = []
    missing_cases: List[str] = []

    for case in cases:
        case_id = case["case_id"] or f"case_{len(fresh_cases) + len(stale_cases) + len(missing_cases) + 1}"
        age = case["age_hours"]
        if age is None and not case["timestamp"]:
            missing_cases.append(case_id)
        elif age is None:
            missing_cases.append(case_id)
        elif max_age and age > max_age:
            stale_cases.append(case_id)
        else:
            fresh_cases.append(case_id)

    if not cases and not max_age:
        reason = "environment_freshness_regression_suite_missing"
    elif stale_cases:
        reason = "environment_freshness_regression_suite_stale"
    elif missing_cases:
        reason = "environment_freshness_regression_suite_partial"
    elif fresh_cases:
        reason = "environment_freshness_regression_suite_ready"
    else:
        reason = "environment_freshness_regression_suite_partial"

    suite_id = _sha1_payload(
        {
            "cases": cases,
            "fresh_cases": fresh_cases,
            "stale_cases": stale_cases,
            "missing_cases": missing_cases,
            "max_age_hours": max_age,
            "hint": hint,
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "suite_id": suite_id,
        "leaf_hint": hint,
        "freshness_cases": cases,
        "fresh_cases": fresh_cases,
        "stale_cases": stale_cases,
        "missing_cases": missing_cases,
        "max_age_hours": round(max_age, 4),
        "reason": reason,
        "is_complete": reason == "environment_freshness_regression_suite_ready",
        "should_warn": reason == "environment_freshness_regression_suite_partial",
        "should_block": reason in {"environment_freshness_regression_suite_missing", "environment_freshness_regression_suite_stale"},
    }


def build_operator_intervention_identity(
    *,
    operator_id: str = "",
    intervention_stage: str = "",
    intervention_reason: str = "",
    session_id: str = "",
    affected_artifacts: Sequence[Any] | None = None,
    leaf_hint: str = "",
) -> Dict[str, Any]:
    operator = str(operator_id or "").strip().lower()
    stage = str(intervention_stage or "").strip().lower()
    reason_text = str(intervention_reason or "").strip().lower()
    session = str(session_id or "").strip().lower()
    artifacts = sorted({str(item).strip().lower() for item in (affected_artifacts or []) if str(item or "").strip()})
    hint = str(leaf_hint or "").strip().lower()

    if not operator and not stage and not reason_text and not session and not artifacts:
        reason = "operator_intervention_identity_missing"
    elif operator and stage and reason_text and session:
        reason = "operator_intervention_identity_ready"
    else:
        reason = "operator_intervention_identity_partial"

    intervention_id = _sha1_payload(
        {
            "operator_id": operator,
            "intervention_stage": stage,
            "intervention_reason": reason_text,
            "session_id": session,
            "affected_artifacts": artifacts,
            "hint": hint,
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "intervention_id": intervention_id,
        "leaf_hint": hint,
        "operator_id": operator,
        "intervention_stage": stage,
        "intervention_reason": reason_text,
        "session_id": session,
        "affected_artifacts": artifacts,
        "reason": reason,
        "is_complete": reason == "operator_intervention_identity_ready",
        "should_warn": reason == "operator_intervention_identity_partial",
        "should_block": reason == "operator_intervention_identity_missing",
    }


def build_layout_shift_tolerance_policy(
    *,
    previous_bbox: Sequence[Any] | None = None,
    current_bbox: Sequence[Any] | None = None,
    layout_variant: str = "",
    layout_confidence: float = 0.0,
    max_shift_px: float = 24.0,
) -> Dict[str, Any]:
    def _bbox(values: Sequence[Any] | None) -> List[float]:
        out: List[float] = []
        for value in values or []:
            if str(value).strip() == "":
                continue
            try:
                out.append(float(value))
            except (TypeError, ValueError):
                continue
        return out

    prev = _bbox(previous_bbox)
    curr = _bbox(current_bbox)
    variant = str(layout_variant or "").strip().lower()
    confidence = max(0.0, min(1.0, float(layout_confidence or 0.0)))
    threshold = max(0.0, float(max_shift_px or 0.0))

    def _center(box: Sequence[float]) -> tuple[float, float]:
        if len(box) >= 4:
            return ((box[0] + box[2]) / 2.0, (box[1] + box[3]) / 2.0)
        return (0.0, 0.0)

    if len(prev) >= 4 and len(curr) >= 4:
        px, py = _center(prev)
        cx, cy = _center(curr)
        dx = cx - px
        dy = cy - py
        shift = (dx * dx + dy * dy) ** 0.5
    else:
        dx = dy = shift = 0.0

    if shift <= threshold * 0.35:
        tolerance = "tolerant"
    elif shift <= threshold:
        tolerance = "warn"
    else:
        tolerance = "reject"

    if confidence >= 0.85 and tolerance == "warn":
        tolerance = "tolerant"
    elif confidence < 0.4 and tolerance == "warn":
        tolerance = "reject"

    if tolerance == "reject":
        reason = "layout_shift_too_large"
    elif tolerance == "warn":
        reason = "layout_shift_warn"
    else:
        reason = "layout_shift_tolerated"

    return {
        "schema_version": SCHEMA_VERSION,
        "layout_variant": variant,
        "layout_confidence": round(confidence, 4),
        "previous_bbox": prev,
        "current_bbox": curr,
        "shift_dx": round(dx, 2),
        "shift_dy": round(dy, 2),
        "shift_distance": round(shift, 2),
        "max_shift_px": round(threshold, 2),
        "tolerance": tolerance,
        "reason": reason,
        "is_tolerated": tolerance != "reject",
    }


def build_component_variant_catalog(
    *,
    page_state: Mapping[str, Any] | None = None,
    screen_state: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    page = dict(page_state or {})
    screen = dict(screen_state or {})
    active_block = screen.get("active_block") if isinstance(screen.get("active_block"), Mapping) else {}
    controls = screen.get("controls") if isinstance(screen.get("controls"), list) else []
    options = screen.get("options") if isinstance(screen.get("options"), list) else []
    page_title = str(page.get("title") or "").strip()
    control_kind = str(screen.get("control_kind") or (active_block or {}).get("control_kind") or "").strip().lower()
    block_family = str((active_block or {}).get("block_family") or "").strip().lower()
    has_select = bool((active_block or {}).get("select_bbox") or screen.get("select_bbox"))
    has_input = bool((active_block or {}).get("input_bbox") or screen.get("input_bbox"))
    has_checkbox = any(
        str((item or {}).get("kind") or "").strip().lower() in {"checkbox", "check", "multi"}
        for item in controls
        if isinstance(item, Mapping)
    )
    has_radio = any(
        str((item or {}).get("kind") or "").strip().lower() in {"radio", "choice", "single"}
        for item in controls
        if isinstance(item, Mapping)
    )
    variant_map = {
        "dropdown": ["select", "combobox", "dropdown"],
        "dropdown_scroll": ["select_scroll", "virtual_select", "dropdown_scroll"],
        "checkbox_group": ["checkbox", "multi_select", "multi_choice"],
        "radio_group": ["radio", "single_choice", "choice"],
        "text_input": ["input", "textbox", "text"],
        "button_group": ["button", "next_button", "submit_button"],
    }
    canonical = "unknown"
    confidence = 0.4
    if has_select or control_kind == "dropdown" or block_family == "dropdown":
        canonical = "dropdown_scroll" if len(options) >= 9 or block_family == "dropdown_scroll" else "dropdown"
        confidence = 0.92 if canonical == "dropdown_scroll" else 0.86
    elif has_checkbox or block_family == "multi" or control_kind == "multi":
        canonical = "checkbox_group"
        confidence = 0.88
    elif has_radio or block_family == "single" or control_kind == "choice":
        canonical = "radio_group"
        confidence = 0.84
    elif has_input or control_kind == "text" or block_family == "text":
        canonical = "text_input"
        confidence = 0.9
    elif control_kind == "button":
        canonical = "button_group"
        confidence = 0.72
    variant_rows: List[Dict[str, Any]] = []
    for family, aliases in variant_map.items():
        matched = canonical == family
        variant_rows.append(
            {
                "family": family,
                "aliases": aliases,
                "matched": matched,
                "stable": matched and confidence >= 0.8,
            }
        )
    reason = "variant_family_matched" if canonical != "unknown" else "variant_family_unknown"
    catalog_id = _sha1_payload(
        {
            "page_title": page_title,
            "control_kind": control_kind,
            "block_family": block_family,
            "canonical": canonical,
            "has_select": has_select,
            "has_input": has_input,
            "has_checkbox": has_checkbox,
            "has_radio": has_radio,
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "component_variant_catalog_id": catalog_id,
        "canonical_family": canonical,
        "confidence": round(confidence, 4),
        "reason": reason,
        "page_title": page_title,
        "control_kind": control_kind,
        "block_family": block_family,
        "has_select": has_select,
        "has_input": has_input,
        "has_checkbox": has_checkbox,
        "has_radio": has_radio,
        "variant_rows": variant_rows,
        "variant_map": variant_map,
        "is_stable": canonical != "unknown" and confidence >= 0.8,
    }


def build_target_resolution_regression_suite(
    *,
    regression_cases: Sequence[Mapping[str, Any]] | None = None,
) -> Dict[str, Any]:
    cases = [dict(case) for case in (regression_cases or []) if isinstance(case, Mapping)]
    rows: List[Dict[str, Any]] = []
    passed = 0
    failed = 0
    drift_cases = 0
    for index, case in enumerate(cases, start=1):
        snapshot = case.get("snapshot") if isinstance(case.get("snapshot"), Mapping) else case
        expected = case.get("expected") if isinstance(case.get("expected"), Mapping) else {}
        target_identity = build_target_identity_contract(
            role=str(snapshot.get("role") or expected.get("role") or ""),
            text=str(snapshot.get("text") or expected.get("text") or ""),
            target_bbox=snapshot.get("target_bbox") or expected.get("target_bbox"),
            selector=str(snapshot.get("selector") or expected.get("selector") or ""),
            frame_path=str(snapshot.get("frame_path") or expected.get("frame_path") or ""),
            context_hint=str(snapshot.get("context_hint") or expected.get("context_hint") or ""),
        )
        expected_identity = str(
            expected.get("target_identity")
            or expected.get("identity_key")
            or case.get("expected_target_identity")
            or ""
        ).strip()
        expected_stable = bool(expected.get("is_stable", True))
        exact_match = bool(expected_identity and expected_identity == target_identity["target_identity"])
        stable_match = bool(target_identity["is_stable"] == expected_stable)
        drift = not (exact_match and stable_match)
        if drift:
            failed += 1
            drift_cases += 1
        else:
            passed += 1
        rows.append(
            {
                "index": index,
                "case_id": str(case.get("case_id") or f"case_{index}"),
                "target_identity": target_identity["target_identity"],
                "expected_target_identity": expected_identity,
                "exact_match": exact_match,
                "stable_match": stable_match,
                "is_drift": drift,
                "reason": "drift_detected" if drift else "regression_passed",
                "layout_variant": str(snapshot.get("layout_variant") or expected.get("layout_variant") or ""),
            }
        )
    total = len(rows)
    if total == 0:
        reason = "empty_regression_suite"
    elif failed == 0:
        reason = "regression_suite_passed"
    else:
        reason = "regression_suite_failed"
    return {
        "schema_version": SCHEMA_VERSION,
        "reason": reason,
        "suite_size": total,
        "passed_cases": passed,
        "failed_cases": failed,
        "drift_cases": drift_cases,
        "rows": rows,
        "is_passing": failed == 0 and total > 0,
    }


def build_parser_executor_target_alignment_check(
    *,
    parser_target: Mapping[str, Any] | None = None,
    executor_target: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    parser = dict(parser_target or {})
    executor = dict(executor_target or {})
    parser_identity = build_target_identity_contract(
        role=str(parser.get("role") or ""),
        text=str(parser.get("text") or ""),
        target_bbox=parser.get("target_bbox"),
        selector=str(parser.get("selector") or ""),
        frame_path=str(parser.get("frame_path") or ""),
        context_hint=str(parser.get("context_hint") or ""),
    )
    executor_identity = build_target_identity_contract(
        role=str(executor.get("role") or ""),
        text=str(executor.get("text") or ""),
        target_bbox=executor.get("target_bbox"),
        selector=str(executor.get("selector") or ""),
        frame_path=str(executor.get("frame_path") or ""),
        context_hint=str(executor.get("context_hint") or ""),
    )
    parser_id = parser_identity["target_identity"]
    executor_id = executor_identity["target_identity"]
    parser_stable = bool(parser_identity["is_stable"])
    executor_stable = bool(executor_identity["is_stable"])
    aligned = bool(parser_id and executor_id and parser_id == executor_id and parser_stable and executor_stable)
    if aligned:
        reason = "parser_executor_aligned"
    elif not parser_stable or not executor_stable:
        reason = "unstable_target_signals"
    else:
        reason = "parser_executor_mismatch"
    confidence_gap = abs(float(parser_identity["confidence"]) - float(executor_identity["confidence"]))
    return {
        "schema_version": SCHEMA_VERSION,
        "aligned": aligned,
        "reason": reason,
        "parser_target_identity": parser_id,
        "executor_target_identity": executor_id,
        "parser_identity": parser_identity,
        "executor_identity": executor_identity,
        "confidence_gap": round(confidence_gap, 4),
        "is_stable": aligned,
    }


def build_resilient_replay_target_policy(
    *,
    target_identity: Mapping[str, Any] | None = None,
    selector_bundle_registry: Mapping[str, Any] | None = None,
    frame_resolution_stack: Mapping[str, Any] | None = None,
    relative_anchor_map: Mapping[str, Any] | None = None,
    allow_replay_on_relations: bool = True,
) -> Dict[str, Any]:
    identity = dict(target_identity or {})
    bundle = dict(selector_bundle_registry or {})
    frames = dict(frame_resolution_stack or {})
    anchors = dict(relative_anchor_map or {})

    identity_stable = bool(identity.get("is_stable"))
    bundle_stable = bool(bundle.get("is_stable"))
    frame_resolved = bool(frames.get("is_resolved"))
    anchor_stable = bool(anchors.get("is_stable"))
    scores = {
        "identity": 0.45 if identity_stable else 0.1,
        "bundle": 0.3 if bundle_stable else 0.08,
        "frame": 0.15 if frame_resolved else 0.05,
        "anchor": 0.1 if anchor_stable else (0.05 if allow_replay_on_relations and anchors else 0.0),
    }
    replay_score = sum(scores.values())
    if identity_stable and bundle_stable and frame_resolved:
        strategy = "identity_bundle_frame"
        reason = "strong_replay_path"
    elif identity_stable and bundle_stable:
        strategy = "identity_bundle"
        reason = "stable_replay_path"
    elif identity_stable:
        strategy = "identity_only"
        reason = "identity_replay_path"
    elif bundle_stable:
        strategy = "bundle_only"
        reason = "bundle_replay_path"
    elif frame_resolved and allow_replay_on_relations and anchor_stable:
        strategy = "frame_anchor"
        reason = "relation_based_replay"
    else:
        strategy = "re-parse"
        reason = "replay_too_weak"
    is_stable = strategy != "re-parse" and replay_score >= 0.5
    if not is_stable and strategy != "re-parse" and replay_score < 0.5:
        strategy = "re-parse"
        reason = "replay_too_weak"
    return {
        "schema_version": SCHEMA_VERSION,
        "strategy": strategy,
        "reason": reason,
        "is_stable": is_stable,
        "replay_score": round(replay_score, 4),
        "scores": scores,
        "target_identity": identity.get("target_identity") or "",
        "bundle_id": bundle.get("bundle_id") or "",
        "frame_stack_depth": int(frames.get("stack_depth") or 0),
        "relative_anchor_map_id": anchors.get("relative_anchor_map_id") or "",
    }


def build_ambiguous_target_escalation_rule(
    *,
    context_scope_guard: Mapping[str, Any] | None = None,
    resilient_replay_target_policy: Mapping[str, Any] | None = None,
    parser_executor_target_alignment_check: Mapping[str, Any] | None = None,
    ambiguity_threshold: float = 0.5,
) -> Dict[str, Any]:
    context_guard = dict(context_scope_guard or {})
    replay = dict(resilient_replay_target_policy or {})
    alignment = dict(parser_executor_target_alignment_check or {})

    context_allowed = bool(context_guard.get("is_allowed"))
    context_ambiguous = bool(context_guard.get("ambiguous"))
    replay_stable = bool(replay.get("is_stable"))
    replay_strategy = str(replay.get("strategy") or "").strip().lower()
    aligned = bool(alignment.get("aligned"))
    confidence_gap = float(alignment.get("confidence_gap") or 0.0)
    ambiguity_score = 0.0
    ambiguity_score += 0.35 if context_ambiguous else 0.0
    ambiguity_score += 0.25 if not context_allowed else 0.0
    ambiguity_score += 0.2 if not replay_stable else 0.0
    ambiguity_score += 0.2 if not aligned else 0.0
    ambiguity_score += min(0.2, confidence_gap)

    threshold = max(0.0, min(1.0, float(ambiguity_threshold or 0.0)))
    if not context_allowed:
        escalation = "observe"
        reason = "context_not_allowed"
    elif not aligned and replay_strategy == "re-parse":
        escalation = "lead"
        reason = "parser_executor_mismatch"
    elif ambiguity_score >= threshold:
        escalation = "observe"
        reason = "high_ambiguity"
    elif replay_stable:
        escalation = "none"
        reason = "stable_resolution"
    else:
        escalation = "lead"
        reason = "manual_review_required"

    if escalation == "lead" and confidence_gap >= 0.25:
        next_best_action = "ask_lead_for_target_resolution"
    elif escalation == "observe":
        next_best_action = "collect_more_evidence"
    else:
        next_best_action = "proceed"

    return {
        "schema_version": SCHEMA_VERSION,
        "escalation": escalation,
        "reason": reason,
        "ambiguity_score": round(min(1.0, ambiguity_score), 4),
        "threshold": round(threshold, 4),
        "context_allowed": context_allowed,
        "context_ambiguous": context_ambiguous,
        "replay_stable": replay_stable,
        "replay_strategy": replay_strategy,
        "alignment": aligned,
        "confidence_gap": round(confidence_gap, 4),
        "next_best_action": next_best_action,
        "should_escalate": escalation != "none",
    }


def build_stage_transition_schema(
    *,
    previous_stage: str = "",
    current_stage: str = "",
    action_outcome: str = "",
) -> Dict[str, Any]:
    prev = str(previous_stage or "").strip().lower()
    curr = str(current_stage or "").strip().lower()
    outcome = str(action_outcome or "").strip().lower()
    allowed_transitions = {
        "capture": {"parse", "blocked"},
        "parse": {"plan", "blocked"},
        "plan": {"execute", "blocked"},
        "execute": {"readback", "blocked"},
        "readback": {"capture", "done", "blocked"},
        "blocked": {"capture", "done"},
        "done": set(),
    }
    allowed_next = allowed_transitions.get(prev, set())
    is_allowed = curr in allowed_next if prev else curr in allowed_transitions
    if not prev:
        reason = "initial_stage"
    elif is_allowed:
        reason = "allowed_transition"
    elif outcome in {"error", "timeout"} and curr == "blocked":
        is_allowed = True
        reason = "error_to_blocked_override"
    else:
        reason = "forbidden_transition"
    return {
        "schema_version": SCHEMA_VERSION,
        "previous_stage": prev,
        "current_stage": curr,
        "action_outcome": outcome,
        "is_allowed": is_allowed,
        "reason": reason,
        "allowed_next_stages": sorted(allowed_next),
    }


def build_outcome_normalization_contract(
    *,
    local_outcome: str = "",
    page_changed: bool = False,
    selection_changed: bool = False,
    submit_done: bool = False,
) -> Dict[str, Any]:
    local = str(local_outcome or "").strip().lower()
    if submit_done or local in {"submit_done", "submitted", "terminal"}:
        outcome_type = "submit_done"
    elif page_changed or local in {"page_changed", "new_question"}:
        outcome_type = "page_changed"
    elif selection_changed or local in {"selection_changed", "selected"}:
        outcome_type = "selection_changed"
    elif local in {"blocked", "error", "timeout"}:
        outcome_type = "blocked"
    else:
        outcome_type = "no_progress"
    return {
        "schema_version": SCHEMA_VERSION,
        "local_outcome": local or "unknown",
        "outcome_type": outcome_type,
        "signals": {
            "page_changed": bool(page_changed),
            "selection_changed": bool(selection_changed),
            "submit_done": bool(submit_done),
        },
    }


def build_trace_join_key(
    *,
    action_id: str = "",
    iteration_id: str = "",
    question_signature: str = "",
    plan_stage: Mapping[str, Any] | None = None,
    execute_stage: Mapping[str, Any] | None = None,
    readback_stage: Mapping[str, Any] | None = None,
    verdict_stage: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    join_parts = {
        "action_id": str(action_id or "").strip(),
        "iteration_id": str(iteration_id or "").strip(),
        "question_signature": str(question_signature or "").strip(),
    }
    join_key = _sha1_payload(join_parts)[:16]
    stages = {
        "plan": dict(plan_stage or {}),
        "execute": dict(execute_stage or {}),
        "readback": dict(readback_stage or {}),
        "verdict": dict(verdict_stage or {}),
    }
    present = [name for name, payload in stages.items() if bool(payload)]
    return {
        "schema_version": SCHEMA_VERSION,
        "trace_join_key": join_key,
        "join_parts": join_parts,
        "stages": stages,
        "present_stages": present,
        "is_complete": len(present) == 4,
    }


def build_action_checkpoint(
    *,
    planned_target: Mapping[str, Any] | None = None,
    pre_state: Mapping[str, Any] | None = None,
    expected_postcondition: Mapping[str, Any] | None = None,
    action_id: Any = "",
    iteration_id: Any = "",
) -> Dict[str, Any]:
    planned = dict(planned_target or {})
    pre = dict(pre_state or {})
    post = dict(expected_postcondition or {})
    checkpoint = {
        "action_id": _first_nonempty(action_id, planned.get("action_id")),
        "iteration_id": _first_nonempty(iteration_id, planned.get("iteration_id")),
        "planned_target": planned,
        "pre_state_hash": _sha1_payload(pre)[:16],
        "expected_postcondition": post,
    }
    checkpoint["checkpoint_id"] = _sha1_payload(checkpoint)[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "checkpoint": checkpoint,
        "is_complete": bool(checkpoint["action_id"] and checkpoint["planned_target"] and checkpoint["expected_postcondition"]),
        "checkpoint_hash": _sha1_payload(checkpoint)[:16],
    }


def build_resume_policy_engine(
    *,
    action_checkpoint: Mapping[str, Any] | None = None,
    freshness_marker: Mapping[str, Any] | None = None,
    current_state: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    checkpoint = dict(action_checkpoint or {})
    freshness = dict(freshness_marker or {}) if isinstance(freshness_marker, Mapping) else {}
    current = dict(current_state or {})
    planned_target = checkpoint.get("planned_target") if isinstance(checkpoint.get("planned_target"), Mapping) else {}
    expected_post = checkpoint.get("expected_postcondition") if isinstance(checkpoint.get("expected_postcondition"), Mapping) else {}
    is_fresh = bool(freshness.get("is_fresh", True))
    current_hash = _sha1_payload(current)[:16]
    expected_hash = _sha1_payload(expected_post)[:16]
    planned_hash = _sha1_payload(planned_target)[:16]
    checkpoint_hash = str(checkpoint.get("checkpoint_hash") or "")
    if not checkpoint_hash:
        checkpoint_hash = _sha1_payload(checkpoint)[:16]

    if not checkpoint or not planned_target or not expected_post:
        decision = "re-parse"
        reason = "missing_checkpoint_fields"
    elif not is_fresh:
        decision = "re-parse"
        reason = "stale_checkpoint"
    elif current_hash == expected_hash:
        decision = "skip"
        reason = "current_state_matches_expected"
    elif current_hash == planned_hash:
        decision = "replay"
        reason = "planned_target_still_valid"
    else:
        decision = "re-parse"
        reason = "state_diverged"
    return {
        "schema_version": SCHEMA_VERSION,
        "decision": decision,
        "reason": reason,
        "is_fresh": is_fresh,
        "checkpoint_hash": checkpoint_hash,
        "planned_target_hash": planned_hash,
        "expected_postcondition_hash": expected_hash,
        "current_state_hash": current_hash,
        "checkpoint": checkpoint,
    }


def build_assisted_replay_bundle(
    *,
    takeover_event: Mapping[str, Any] | None = None,
    state_before: Mapping[str, Any] | None = None,
    state_after: Mapping[str, Any] | None = None,
    replay_context: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    takeover = dict(takeover_event or {})
    before = dict(state_before or {})
    after = dict(state_after or {})
    context = dict(replay_context or {})
    takeover_hash = _sha1_payload(takeover)[:16]
    before_hash = _sha1_payload(before)[:16]
    after_hash = _sha1_payload(after)[:16]
    context_hash = _sha1_payload(context)[:16]
    has_state_change = before_hash != after_hash
    is_complete = bool(takeover and before and after)
    if not takeover:
        reason = "missing_takeover_event"
    elif not before or not after:
        reason = "missing_replay_state"
    elif has_state_change:
        reason = "assisted_replay_bundle_ready"
    else:
        reason = "assisted_replay_no_state_change"
    bundle = {
        "schema_version": SCHEMA_VERSION,
        "takeover_event": takeover,
        "state_before": before,
        "state_after": after,
        "replay_context": context,
        "takeover_hash": takeover_hash,
        "state_before_hash": before_hash,
        "state_after_hash": after_hash,
        "replay_context_hash": context_hash,
        "has_state_change": has_state_change,
        "is_complete": is_complete,
        "reason": reason,
    }
    bundle["bundle_hash"] = _sha1_payload(bundle)[:16]
    return bundle


def build_stateful_replay_bundle(
    *,
    trace: Mapping[str, Any] | None = None,
    browser_session_identity: Mapping[str, Any] | None = None,
    client_state_snapshot: Mapping[str, Any] | None = None,
    consent_state_contract: Mapping[str, Any] | None = None,
    client_flag_fingerprint: Mapping[str, Any] | None = None,
    session_reset_policy_engine: Mapping[str, Any] | None = None,
    pre_run_session_hygiene_check: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    trace_data = dict(trace or {})
    identity = dict(browser_session_identity or {})
    snapshot = dict(client_state_snapshot or {})
    consent = dict(consent_state_contract or {})
    flags = dict(client_flag_fingerprint or {})
    reset_policy = dict(session_reset_policy_engine or {})
    hygiene = dict(pre_run_session_hygiene_check or {})

    trace_id = _first_nonempty(trace_data.get("trace_id"), trace_data.get("id"))
    bundle_components = {
        "trace_id": trace_id,
        "browser_session_key": identity.get("browser_session_key"),
        "snapshot_id": snapshot.get("snapshot_id"),
        "consent_state": consent.get("state"),
        "flag_fingerprint": flags.get("fingerprint"),
        "reset_scope": reset_policy.get("reset_scope"),
        "hygiene_status": hygiene.get("hygiene_status"),
    }
    bundle_id = _sha1_payload(bundle_components)[:16]
    is_complete = bool(trace_id and identity and snapshot)
    is_stable = bool(flags.get("is_stable")) and not bool(hygiene.get("should_block_start"))
    state_scope = "session_stateful" if (identity.get("has_prior_state") or consent or flags) else "session_clean"
    if bool(hygiene.get("should_block_start")):
        reason = "bundle_blocked_by_hygiene"
    elif not trace_id:
        reason = "missing_trace"
    elif not identity:
        reason = "missing_session_identity"
    elif not snapshot:
        reason = "missing_client_snapshot"
    elif not is_stable:
        reason = "bundle_requires_monitoring"
    else:
        reason = "stateful_replay_bundle_ready"

    return {
        "schema_version": SCHEMA_VERSION,
        "bundle_id": bundle_id,
        "reason": reason,
        "is_complete": is_complete,
        "is_stable": is_stable,
        "state_scope": state_scope,
        "trace": trace_data,
        "browser_session_identity": identity,
        "client_state_snapshot": snapshot,
        "consent_state_contract": consent,
        "client_flag_fingerprint": flags,
        "session_reset_policy_engine": reset_policy,
        "pre_run_session_hygiene_check": hygiene,
        "has_snapshot": bool(snapshot),
        "has_consent": bool(consent),
        "has_flags": bool(flags),
        "has_hygiene": bool(hygiene),
        "has_reset_policy": bool(reset_policy),
    }


def build_state_side_effect_diff(
    *,
    state_before: Mapping[str, Any] | None = None,
    state_after: Mapping[str, Any] | None = None,
    browser_session_identity: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    before = dict(state_before or {})
    after = dict(state_after or {})
    identity = dict(browser_session_identity or {})

    def _stable_keys(value: Mapping[str, Any]) -> List[str]:
        return sorted(str(key) for key in value.keys())

    before_keys = set(_stable_keys(before))
    after_keys = set(_stable_keys(after))
    added_keys = sorted(after_keys - before_keys)
    removed_keys = sorted(before_keys - after_keys)
    shared_keys = sorted(before_keys & after_keys)
    changed_keys: List[str] = []
    for key in shared_keys:
        if _sha1_payload(before.get(key)) != _sha1_payload(after.get(key)):
            changed_keys.append(key)

    before_hash = _sha1_payload(before)[:16]
    after_hash = _sha1_payload(after)[:16]
    has_state_change = before_hash != after_hash
    has_high_risk_effect = any(
        key in {"consent", "consent_state", "service_worker", "service_worker_cache", "local_storage", "session_storage"}
        for key in added_keys + removed_keys + changed_keys
    )
    impact_scope = "none"
    if has_state_change:
        if has_high_risk_effect:
            impact_scope = "high"
        elif added_keys or removed_keys:
            impact_scope = "medium"
        else:
            impact_scope = "low"

    reason = "no_state_change" if not has_state_change else ("high_risk_state_shift" if has_high_risk_effect else "state_delta_detected")
    return {
        "schema_version": SCHEMA_VERSION,
        "session_id": _first_nonempty(identity.get("session_id")),
        "browser_session_key": str(identity.get("browser_session_key") or ""),
        "before_hash": before_hash,
        "after_hash": after_hash,
        "has_state_change": has_state_change,
        "impact_scope": impact_scope,
        "reason": reason,
        "added_keys": added_keys,
        "removed_keys": removed_keys,
        "changed_keys": changed_keys,
        "diff_keys": sorted(dict.fromkeys(added_keys + removed_keys + changed_keys)),
        "should_escalate": impact_scope == "high",
    }


def build_session_profile_regression_suite(
    *,
    session_profiles: Sequence[Mapping[str, Any]] | None = None,
) -> Dict[str, Any]:
    profiles = [dict(profile) for profile in (session_profiles or []) if isinstance(profile, Mapping)]
    rows: List[Dict[str, Any]] = []
    passed = 0
    failed = 0
    outcome_families: Dict[str, int] = {}
    for index, profile in enumerate(profiles, start=1):
        identity = dict(profile.get("browser_session_identity") or profile.get("session_identity") or {})
        reset_policy = dict(profile.get("session_reset_policy_engine") or {})
        hygiene = dict(profile.get("pre_run_session_hygiene_check") or {})
        snapshot = dict(profile.get("client_state_snapshot") or {})
        consent = dict(profile.get("consent_state_contract") or {})
        flags = dict(profile.get("client_flag_fingerprint") or {})
        overlay = dict(profile.get("overlay_origin_classifier") or {})
        expected_outcome = str(profile.get("expected_outcome") or "").strip().lower()

        if not expected_outcome:
            expected_outcome = "blocked" if bool(hygiene.get("should_block_start")) else ("warn" if bool(hygiene.get("should_warn")) else "ready")

        if bool(hygiene.get("should_block_start")):
            actual_outcome = "blocked"
        elif bool(consent.get("blocked")) or str(consent.get("state") or "").strip().lower() == "blocked":
            actual_outcome = "blocked"
        elif bool(flags.get("unstable_flags")) or str(flags.get("is_stable")) == "False":
            actual_outcome = "variant_sensitive"
        elif bool(overlay.get("should_escalate")) and str(overlay.get("origin") or "") == "consent":
            actual_outcome = "blocked"
        elif bool(hygiene.get("should_warn")):
            actual_outcome = "warn"
        else:
            actual_outcome = "ready"

        if actual_outcome == expected_outcome:
            passed += 1
            drift = False
        else:
            failed += 1
            drift = True

        family = expected_outcome or actual_outcome
        outcome_families[family] = int(outcome_families.get(family, 0) + 1)
        outcome_signature = _sha1_payload(
            {
                "session_id": _first_nonempty(identity.get("session_id"), profile.get("session_id")),
                "snapshot_id": snapshot.get("snapshot_id"),
                "hygiene_status": hygiene.get("hygiene_status"),
                "reset_scope": reset_policy.get("reset_scope"),
                "consent_state": consent.get("state"),
                "flag_fingerprint": flags.get("fingerprint"),
                "overlay_origin": overlay.get("origin"),
                "expected_outcome": expected_outcome,
                "actual_outcome": actual_outcome,
            }
        )[:16]
        rows.append(
            {
                "index": index,
                "profile_id": str(profile.get("profile_id") or profile.get("session_id") or f"profile_{index}"),
                "session_id": _first_nonempty(identity.get("session_id"), profile.get("session_id")),
                "expected_outcome": expected_outcome,
                "actual_outcome": actual_outcome,
                "outcome_signature": outcome_signature,
                "is_drift": drift,
                "reason": "regression_passed" if not drift else "session_profile_drift",
                "browser_session_key": str(identity.get("browser_session_key") or ""),
                "hygiene_status": str(hygiene.get("hygiene_status") or ""),
                "reset_scope": str(reset_policy.get("reset_scope") or ""),
                "consent_state": str(consent.get("state") or ""),
                "flag_fingerprint": str(flags.get("fingerprint") or ""),
                "overlay_origin": str(overlay.get("origin") or ""),
            }
        )

    total = len(rows)
    if total == 0:
        reason = "empty_regression_suite"
    elif failed == 0:
        reason = "regression_suite_passed"
    else:
        reason = "regression_suite_failed"
    return {
        "schema_version": SCHEMA_VERSION,
        "reason": reason,
        "suite_size": total,
        "passed_cases": passed,
        "failed_cases": failed,
        "rows": rows,
        "outcome_families": outcome_families,
        "is_passing": failed == 0 and total > 0,
    }


def build_unknown_side_state_guard(
    *,
    browser_session_identity: Mapping[str, Any] | None = None,
    client_state_snapshot: Mapping[str, Any] | None = None,
    consent_state_contract: Mapping[str, Any] | None = None,
    client_flag_fingerprint: Mapping[str, Any] | None = None,
    allow_observe: bool = True,
) -> Dict[str, Any]:
    identity = dict(browser_session_identity or {})
    snapshot = dict(client_state_snapshot or {})
    consent = dict(consent_state_contract or {})
    flags = dict(client_flag_fingerprint or {})

    has_identity = bool(identity)
    has_snapshot = bool(snapshot)
    has_consent = bool(consent)
    has_flags = bool(flags)
    unstable_flags = list(flags.get("unstable_flags") or [])
    dirty_ambient_state = bool(snapshot.get("is_ambient_state_dirty")) or bool(identity.get("has_prior_state"))
    unknown_signals = [
        name
        for name, present in {
            "identity": has_identity,
            "snapshot": has_snapshot,
            "consent": has_consent,
            "flags": has_flags,
        }.items()
        if not present
    ]

    if not has_identity or not has_snapshot:
        action = "reset_session"
        reason = "missing_session_context"
        state = "reset"
    elif unstable_flags or dirty_ambient_state:
        action = "collect_more_evidence"
        reason = "ambiguous_side_state"
        state = "observe" if allow_observe else "reset"
    else:
        action = "proceed"
        reason = "known_side_state"
        state = "proceed"

    confidence = 0.3
    if state == "proceed":
        confidence = 0.9
    elif state == "observe":
        confidence = 0.6
    elif state == "reset":
        confidence = 0.2

    return {
        "schema_version": SCHEMA_VERSION,
        "state": state,
        "reason": reason,
        "action": action,
        "confidence": round(confidence, 4),
        "has_identity": has_identity,
        "has_snapshot": has_snapshot,
        "has_consent": has_consent,
        "has_flags": has_flags,
        "unstable_flags": unstable_flags,
        "dirty_ambient_state": dirty_ambient_state,
        "unknown_signals": unknown_signals,
        "should_block": state == "reset",
        "should_observe": state == "observe",
        "should_proceed": state == "proceed",
    }


def build_session_vs_logic_root_cause_splitter(
    *,
    browser_session_identity: Mapping[str, Any] | None = None,
    client_state_snapshot: Mapping[str, Any] | None = None,
    state_side_effect_diff: Mapping[str, Any] | None = None,
    unknown_side_state_guard: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    identity = dict(browser_session_identity or {})
    snapshot = dict(client_state_snapshot or {})
    diff = dict(state_side_effect_diff or {})
    guard = dict(unknown_side_state_guard or {})

    has_session_state = bool(identity.get("has_prior_state")) or bool(snapshot.get("is_ambient_state_dirty"))
    state_changed = bool(diff.get("has_state_change"))
    high_risk = str(diff.get("impact_scope") or "").strip().lower() == "high"
    guard_state = str(guard.get("state") or "").strip().lower()
    guard_reason = str(guard.get("reason") or "").strip().lower()

    if high_risk or guard_state in {"observe", "reset"} or guard_reason in {"ambiguous_side_state", "missing_session_context"}:
        root_cause = "session_state_drift"
        reason = "side_state_drift"
        confidence = 0.88 if high_risk else 0.74
    elif state_changed and not has_session_state:
        root_cause = "logic_failure"
        reason = "logic_failure_without_side_state"
        confidence = 0.82
    else:
        root_cause = "logic_failure"
        reason = "logic_path_dominant"
        confidence = 0.7

    if root_cause == "session_state_drift" and not state_changed:
        confidence = min(confidence, 0.66)

    evidence = [
        token
        for token in (
            identity.get("browser_session_key"),
            snapshot.get("snapshot_id"),
            diff.get("reason"),
            guard.get("reason"),
        )
        if token
    ]

    return {
        "schema_version": SCHEMA_VERSION,
        "root_cause": root_cause,
        "reason": reason,
        "confidence": round(min(1.0, confidence), 4),
        "has_session_state": has_session_state,
        "state_changed": state_changed,
        "high_risk_state_shift": high_risk,
        "guard_state": guard_state,
        "evidence": evidence,
        "should_escalate_to_lead": root_cause == "session_state_drift",
    }


def build_hidden_state_explainer(
    *,
    state_side_effect_diff: Mapping[str, Any] | None = None,
    client_state_snapshot: Mapping[str, Any] | None = None,
    storage_dependency_registry: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    diff = dict(state_side_effect_diff or {})
    snapshot = dict(client_state_snapshot or {})
    registry = dict(storage_dependency_registry or {})

    diff_keys = [str(key) for key in (diff.get("diff_keys") or []) if str(key).strip()]
    added_keys = [str(key) for key in (diff.get("added_keys") or []) if str(key).strip()]
    changed_keys = [str(key) for key in (diff.get("changed_keys") or []) if str(key).strip()]
    removed_keys = [str(key) for key in (diff.get("removed_keys") or []) if str(key).strip()]
    evidence_keys = list(dict.fromkeys(diff_keys + added_keys + changed_keys + removed_keys))

    storage_keys = [str(key) for key in (registry.get("storage_keys") or []) if str(key).strip()]
    observed_effects = [str(effect).strip().lower() for effect in (registry.get("observed_ui_effects") or []) if str(effect).strip()]
    dynamic_indicators = [str(indicator).strip().lower() for indicator in (registry.get("dynamic_indicators") or []) if str(indicator).strip()]

    impact_scope = str(diff.get("impact_scope") or "none").strip().lower()
    if not bool(diff.get("has_state_change")):
        explanation = "no hidden state change detected"
        source = "none"
        confidence = 0.0
    else:
        source = "unknown"
        explanation_bits: List[str] = []
        confidence = 0.35 if impact_scope in {"low", "medium"} else 0.55

        if any("consent" in key or "cookie" in key or "service_worker" in key for key in evidence_keys):
            source = "storage_or_service_worker"
            explanation_bits.append("state change touches consent/cookies/service worker metadata")
            confidence = max(confidence, 0.85)
        elif any(key in storage_keys for key in evidence_keys) or registry.get("routing_sensitive"):
            source = "storage_dependency"
            matched_keys = [key for key in evidence_keys if key in storage_keys]
            if matched_keys:
                explanation_bits.append(f"matched storage keys: {', '.join(matched_keys)}")
            if observed_effects:
                explanation_bits.append(f"observed effects: {', '.join(observed_effects[:3])}")
            confidence = max(confidence, 0.7)
        elif any(indicator in evidence_keys or indicator in snapshot.get("url_params", {}) for indicator in dynamic_indicators):
            source = "feature_flag"
            explanation_bits.append("state change aligns with dynamic routing/variant indicator")
            confidence = max(confidence, 0.65)
        elif bool(snapshot.get("has_service_worker")):
            source = "service_worker"
            explanation_bits.append("service worker metadata present and UI changed")
            confidence = max(confidence, 0.6)
        else:
            explanation_bits.append("visible UI delta has no direct storage signature")

        if not explanation_bits:
            explanation_bits.append("side-state delta detected without a strong registry match")
        explanation = "; ".join(explanation_bits)

    visible_delta = {
        "added_keys": added_keys,
        "removed_keys": removed_keys,
        "changed_keys": changed_keys,
        "impact_scope": impact_scope,
        "url": str(snapshot.get("url") or ""),
        "snapshot_id": str(snapshot.get("snapshot_id") or ""),
    }

    return {
        "schema_version": SCHEMA_VERSION,
        "explanation": explanation,
        "source": source,
        "confidence": round(min(1.0, confidence), 4),
        "evidence_keys": evidence_keys,
        "visible_delta": visible_delta,
        "has_hidden_state_shift": bool(diff.get("has_state_change")),
        "should_notify_planner": bool(diff.get("should_escalate") or source in {"storage_or_service_worker", "storage_dependency", "feature_flag"}),
    }


def build_consent_state_contract(
    *,
    consent_state: Mapping[str, Any] | None = None,
    modal_state: Mapping[str, Any] | None = None,
    overlay_state: Mapping[str, Any] | None = None,
    page_state: Mapping[str, Any] | None = None,
    browser_session_identity: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    consent = dict(consent_state or {})
    modal = dict(modal_state or {})
    overlay = dict(overlay_state or {})
    page = dict(page_state or {})
    identity = dict(browser_session_identity or {})

    status_source = _first_nonempty(
        consent.get("status"),
        consent.get("state"),
        modal.get("consent_status"),
        overlay.get("consent_status"),
        page.get("consent_status"),
    ).strip().lower()
    reason = _first_nonempty(
        consent.get("reason"),
        consent.get("blocking_reason"),
        modal.get("reason"),
        overlay.get("reason"),
        page.get("consent_reason"),
    )
    required = bool(
        consent.get("required")
        or consent.get("is_required")
        or modal.get("required")
        or overlay.get("required")
        or page.get("consent_required")
    )
    accepted = bool(
        consent.get("accepted")
        or consent.get("is_accepted")
        or consent.get("resolved")
        or modal.get("accepted")
        or overlay.get("accepted")
    )
    blocked = bool(
        consent.get("blocked")
        or consent.get("is_blocked")
        or consent.get("is_blocking")
        or modal.get("blocked")
        or overlay.get("blocked")
    )
    overlay_kind = _first_nonempty(overlay.get("kind"), overlay.get("overlay_kind"), modal.get("kind"))
    modal_title = _first_nonempty(modal.get("title"), modal.get("label"), overlay.get("title"))
    consent_hint = _first_nonempty(page.get("consent_hint"), page.get("banner_text"), modal.get("hint"), overlay.get("hint"))

    if blocked:
        state = "blocked"
        action = "wait_or_block"
        is_resolved = False
    elif accepted:
        state = "accepted"
        action = "proceed"
        is_resolved = True
    elif required or status_source in {"required", "needed", "pending"}:
        state = "required"
        action = "present_and_accept"
        is_resolved = False
    elif status_source in {"not_required", "none", "irrelevant"}:
        state = "not_required"
        action = "proceed"
        is_resolved = True
    else:
        state = "unknown"
        action = "observe"
        is_resolved = False

    if not reason:
        if blocked:
            reason = "consent_blocked"
        elif accepted:
            reason = "consent_already_accepted"
        elif required:
            reason = "consent_required"
        elif state == "not_required":
            reason = "consent_not_required"
        else:
            reason = "consent_state_unknown"

    evidence = sorted(
        dict.fromkeys(
            [
                token
                for token in (
                    status_source,
                    overlay_kind,
                    modal_title,
                    consent_hint,
                    str(identity.get("browser_session_key") or ""),
                )
                if token
            ]
        )
    )
    state_score = 0.0
    state_score += 0.4 if required else 0.0
    state_score += 0.4 if blocked else 0.0
    state_score += 0.3 if accepted else 0.0
    state_score += 0.2 if overlay_kind else 0.0
    state_score = min(1.0, round(state_score, 4))

    return {
        "schema_version": SCHEMA_VERSION,
        "state": state,
        "reason": reason,
        "action": action,
        "required": required,
        "accepted": accepted,
        "blocked": blocked,
        "is_resolved": is_resolved,
        "state_score": state_score,
        "overlay_kind": overlay_kind,
        "modal_title": modal_title,
        "consent_hint": consent_hint,
        "evidence": evidence,
        "browser_session_key": str(identity.get("browser_session_key") or ""),
        "session_id": _first_nonempty(identity.get("session_id")),
    }


def build_client_flag_fingerprint(
    *,
    feature_flags: Mapping[str, Any] | None = None,
    experiment_state: Mapping[str, Any] | None = None,
    client_state_snapshot: Mapping[str, Any] | None = None,
    browser_session_identity: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    flags = dict(feature_flags or {})
    experiments = dict(experiment_state or {})
    snapshot = dict(client_state_snapshot or {})
    identity = dict(browser_session_identity or {})

    def _stable_shape(value: Any) -> Any:
        if isinstance(value, Mapping):
            return {
                str(key): _stable_shape(value[key])
                for key in sorted(value.keys(), key=lambda item: str(item))
                if value[key] is not None and value[key] != ""
            }
        if isinstance(value, (list, tuple, set)):
            return [_stable_shape(item) for item in value if item is not None and item != ""]
        if isinstance(value, float):
            return round(value, 6) if math.isfinite(value) else str(value)
        if isinstance(value, (str, int, bool)) or value is None:
            return value
        return str(value)

    active_flags: List[Dict[str, Any]] = []
    for key in sorted(flags.keys(), key=lambda item: str(item)):
        normalized_key = str(key).strip()
        value = flags.get(key)
        enabled = bool(value)
        if isinstance(value, str):
            enabled = value.strip().lower() in {"1", "true", "yes", "on", "enabled", "active"}
        if not enabled:
            continue
        variant = _first_nonempty(
            experiments.get(normalized_key),
            experiments.get(f"{normalized_key}_variant"),
            experiments.get(f"{normalized_key}:variant"),
        )
        active_flags.append(
            {
                "flag": normalized_key,
                "variant": variant,
                "weight": _stable_shape(value),
            }
        )

    active_flags = sorted(active_flags, key=lambda item: (item["flag"], str(item["variant"])))
    fingerprint_payload = {
        "flags": active_flags,
        "snapshot": {
            "url": str(snapshot.get("url") or ""),
            "session_identity": str(snapshot.get("session_identity") or ""),
            "has_storage": bool(snapshot.get("has_storage")),
            "has_cookies": bool(snapshot.get("has_cookies")),
        },
    }
    fingerprint = _sha1_payload(fingerprint_payload)[:16]
    variant_map = {item["flag"]: item["variant"] for item in active_flags if item["variant"]}
    unstable_flags = [item["flag"] for item in active_flags if not item["variant"]]
    experiment_names = sorted(dict.fromkeys(str(key).strip() for key in experiments.keys() if str(key).strip()))

    return {
        "schema_version": SCHEMA_VERSION,
        "fingerprint": fingerprint,
        "fingerprint_key": f"{str(identity.get('session_id') or identity.get('browser_session_key') or 'anonymous')}:{fingerprint}",
        "active_flags": active_flags,
        "active_flag_count": len(active_flags),
        "variant_map": variant_map,
        "variant_count": len(variant_map),
        "unstable_flags": unstable_flags,
        "experiment_names": experiment_names,
        "snapshot_id": str(snapshot.get("snapshot_id") or ""),
        "is_stable": not bool(unstable_flags),
        "has_active_flags": bool(active_flags),
    }


def build_flag_stability_guard(
    *,
    client_flag_fingerprint: Mapping[str, Any] | None = None,
    client_state_snapshot: Mapping[str, Any] | None = None,
    experiment_state: Mapping[str, Any] | None = None,
    required_stability: float = 0.75,
) -> Dict[str, Any]:
    fingerprint = dict(client_flag_fingerprint or {})
    snapshot = dict(client_state_snapshot or {})
    experiments = dict(experiment_state or {})
    active_flags = list(fingerprint.get("active_flags") or [])
    variant_count = int(fingerprint.get("variant_count") or 0)
    unstable_flags = list(fingerprint.get("unstable_flags") or [])
    stable_fingerprint = bool(fingerprint.get("is_stable"))
    has_active_flags = bool(fingerprint.get("has_active_flags"))
    variant_map = dict(fingerprint.get("variant_map") or {})
    stability_score = 1.0
    stability_score -= 0.25 if unstable_flags else 0.0
    stability_score -= 0.15 if variant_count == 0 and has_active_flags else 0.0
    stability_score -= 0.1 if not snapshot.get("snapshot_id") else 0.0
    stability_score -= 0.1 if experiments and not variant_map else 0.0
    stability_score = max(0.0, round(stability_score, 4))

    threshold = max(0.0, min(1.0, float(required_stability or 0.0)))
    if stability_score >= threshold and stable_fingerprint:
        outcome = "stable"
        reason = "fingerprint_stable"
    elif stability_score >= threshold * 0.9:
        outcome = "monitor"
        reason = "near_stable_variants"
    elif unstable_flags:
        outcome = "unstable"
        reason = "unstable_flags_present"
    else:
        outcome = "unstable"
        reason = "insufficient_flag_stability"

    return {
        "schema_version": SCHEMA_VERSION,
        "outcome": outcome,
        "reason": reason,
        "stability_score": stability_score,
        "threshold": threshold,
        "has_active_flags": has_active_flags,
        "active_flag_count": len(active_flags),
        "variant_count": variant_count,
        "unstable_flags": unstable_flags,
        "fingerprint": str(fingerprint.get("fingerprint") or ""),
        "fingerprint_key": str(fingerprint.get("fingerprint_key") or ""),
        "is_stable": outcome == "stable",
        "should_monitor": outcome == "monitor",
        "should_escalate": outcome == "unstable",
    }


def build_autonomy_gap_packet(
    *,
    gap_events: Sequence[Mapping[str, Any]] | None = None,
    min_occurrences: int = 2,
    top_k: int = 5,
) -> Dict[str, Any]:
    rows: List[Dict[str, Any]] = []
    counts: Dict[str, int] = {}
    first_seen: Dict[str, int] = {}
    last_seen: Dict[str, int] = {}
    for idx, event in enumerate(gap_events or []):
        if not isinstance(event, Mapping):
            continue
        gap_key = _first_nonempty(event.get("gap_key"), event.get("screen_id"), event.get("question_id"), event.get("reason"), f"gap_{idx}")
        gap_key = str(gap_key or "").strip()
        reason = _first_nonempty(event.get("reason"), event.get("summary"), event.get("kind"), "")
        counts[gap_key] = int(counts.get(gap_key, 0) + 1)
        first_seen.setdefault(gap_key, idx)
        last_seen[gap_key] = idx
        rows.append(
            {
                "index": idx,
                "gap_key": gap_key,
                "reason": str(reason or "").strip(),
            }
        )
    threshold = max(1, int(min_occurrences or 0))
    chronic_rows = []
    for gap_key, count in sorted(counts.items(), key=lambda item: (-item[1], item[0])):
        if count < threshold:
            continue
        chronic_rows.append(
            {
                "gap_key": gap_key,
                "count": count,
                "first_seen_index": first_seen.get(gap_key, 0),
                "last_seen_index": last_seen.get(gap_key, 0),
            }
        )
    chronic_rows = chronic_rows[: max(1, int(top_k or 0))]
    is_chronic = bool(chronic_rows)
    return {
        "schema_version": SCHEMA_VERSION,
        "gap_event_count": len(rows),
        "gap_counts": counts,
        "chronic_gap_count": len(chronic_rows),
        "threshold": threshold,
        "top_k": max(1, int(top_k or 0)),
        "chronic_gaps": chronic_rows,
        "all_gaps": rows,
        "is_chronic": is_chronic,
        "reason": "chronic_gaps_detected" if is_chronic else "no_chronic_gaps",
        "packet_hash": _sha1_payload({"rows": rows, "chronic": chronic_rows, "threshold": threshold})[:16],
    }


def build_human_loop_gap_promoter(
    *,
    autonomy_gap_packet: Mapping[str, Any] | None = None,
    intervention_regression_suite: Mapping[str, Any] | None = None,
    max_promotions: int = 5,
) -> Dict[str, Any]:
    packet = dict(autonomy_gap_packet or {})
    regression = dict(intervention_regression_suite or {})
    chronic_gaps = [dict(row) for row in (packet.get("chronic_gaps") or []) if isinstance(row, Mapping)]
    chronic_gaps.sort(key=lambda item: (-int(item.get("count") or 0), str(item.get("gap_key") or "")))
    promoted_rows: List[Dict[str, Any]] = []
    regression_status = str(regression.get("status") or "").strip().lower()
    for idx, gap in enumerate(chronic_gaps[: max(1, int(max_promotions or 0))]):
        count = int(gap.get("count") or 0)
        priority = "high" if count >= 3 or regression_status == "regressed" else "medium"
        promoted_rows.append(
            {
                "index": idx,
                "gap_key": str(gap.get("gap_key") or "").strip(),
                "count": count,
                "priority": priority,
                "first_seen_index": int(gap.get("first_seen_index") or 0),
                "last_seen_index": int(gap.get("last_seen_index") or 0),
            }
        )
    if promoted_rows:
        reason = "chronic_intervention_promoted"
        priority_tier = "high" if any(row["priority"] == "high" for row in promoted_rows) else "medium"
    else:
        reason = "no_human_loop_gap"
        priority_tier = "low"
    return {
        "schema_version": SCHEMA_VERSION,
        "priority_tier": priority_tier,
        "reason": reason,
        "promoted_count": len(promoted_rows),
        "promoted_rows": promoted_rows,
        "source_gap_count": int(packet.get("chronic_gap_count") or 0),
        "regression_status": regression_status or "unknown",
        "promotion_hash": _sha1_payload({"rows": promoted_rows, "status": regression_status})[:16],
    }


def build_intervention_feedback_registry(
    *,
    interventions: Sequence[Mapping[str, Any]] | None = None,
    known_error_classes: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    rows: List[Dict[str, Any]] = []
    type_counts: Dict[str, int] = {}
    class_counts: Dict[str, int] = {}
    mapping: Dict[str, str] = {}
    known = {str(key).strip().lower(): str(value or "").strip() for key, value in dict(known_error_classes or {}).items() if str(key).strip()}
    for idx, intervention in enumerate(interventions or []):
        if not isinstance(intervention, Mapping):
            continue
        intervention_type = _first_nonempty(
            intervention.get("intervention_type"),
            intervention.get("kind"),
            intervention.get("mode"),
            intervention.get("action_kind"),
            intervention.get("gap_key"),
            f"intervention_{idx}",
        ).strip().lower()
        error_class = _first_nonempty(
            intervention.get("error_class"),
            intervention.get("class"),
            intervention.get("label"),
            intervention.get("issue"),
            known.get(intervention_type),
        ).strip().lower()
        if not intervention_type:
            continue
        type_counts[intervention_type] = int(type_counts.get(intervention_type, 0) + 1)
        if error_class:
            class_counts[error_class] = int(class_counts.get(error_class, 0) + 1)
            mapping[intervention_type] = error_class
        rows.append(
            {
                "index": idx,
                "intervention_type": intervention_type,
                "error_class": error_class,
            }
        )
    unmapped_types = sorted([key for key in type_counts if key not in mapping])
    coverage_ratio = (len(mapping) / len(type_counts)) if type_counts else 0.0
    is_complete = bool(type_counts) and not unmapped_types
    if is_complete:
        reason = "registry_complete"
    elif mapping:
        reason = "partial_registry"
    else:
        reason = "empty_registry"
    return {
        "schema_version": SCHEMA_VERSION,
        "registry": mapping,
        "type_counts": type_counts,
        "class_counts": class_counts,
        "unmapped_types": unmapped_types,
        "coverage_ratio": round(coverage_ratio, 4),
        "is_complete": is_complete,
        "reason": reason,
        "rows": rows,
        "registry_hash": _sha1_payload({"registry": mapping, "counts": type_counts})[:16],
    }


def build_human_feedback_quality_gate(
    *,
    feedback_items: Sequence[Mapping[str, Any]] | None = None,
    min_quality_score: float = 0.7,
) -> Dict[str, Any]:
    rows: List[Dict[str, Any]] = []
    type_labels: Dict[str, set[str]] = {}
    type_counts: Dict[str, int] = {}
    total_score = 0.0
    for idx, item in enumerate(feedback_items or []):
        if not isinstance(item, Mapping):
            continue
        intervention_type = _first_nonempty(item.get("intervention_type"), item.get("kind"), item.get("mode"), f"feedback_{idx}").strip().lower()
        label = _first_nonempty(item.get("error_class"), item.get("label"), item.get("reason"), item.get("summary")).strip().lower()
        reason_text = _first_nonempty(item.get("reason"), item.get("summary"), item.get("notes"), "").strip()
        evidence_value = item.get("evidence")
        if isinstance(evidence_value, Sequence) and not isinstance(evidence_value, (str, bytes, bytearray)):
            evidence = [str(v or "").strip() for v in evidence_value if str(v or "").strip()]
        else:
            evidence = [str(evidence_value).strip()] if str(evidence_value or "").strip() else []
        has_reason = len(reason_text) >= 12
        has_evidence = bool(evidence)
        has_label = bool(label)
        score = 0.0
        score += 0.4 if has_reason else 0.0
        score += 0.4 if has_evidence else 0.0
        score += 0.2 if has_label else 0.0
        total_score += score
        if intervention_type:
            type_counts[intervention_type] = int(type_counts.get(intervention_type, 0) + 1)
            type_labels.setdefault(intervention_type, set()).add(label or "unknown")
        rows.append(
            {
                "index": idx,
                "intervention_type": intervention_type,
                "label": label,
                "has_reason": has_reason,
                "has_evidence": has_evidence,
                "quality_score": round(score, 4),
            }
        )
    conflicts = sorted([key for key, labels in type_labels.items() if len(labels) > 1])
    repeated_types = sorted([key for key, count in type_counts.items() if count >= 2])
    average_score = (total_score / len(rows)) if rows else 0.0
    threshold = max(0.0, min(1.0, float(min_quality_score or 0.0)))
    is_justified = average_score >= threshold
    is_consistent = not conflicts
    is_repeatable = bool(repeated_types) and is_consistent and is_justified
    passed = bool(rows) and is_justified and is_consistent and is_repeatable
    if not rows:
        reason = "empty_feedback"
    elif conflicts:
        reason = "inconsistent_feedback"
    elif not is_justified:
        reason = "feedback_quality_low"
    else:
        reason = "feedback_quality_passed"
    return {
        "schema_version": SCHEMA_VERSION,
        "quality_rows": rows,
        "average_score": round(average_score, 4),
        "quality_threshold": threshold,
        "conflicts": conflicts,
        "repeated_types": repeated_types,
        "is_justified": is_justified,
        "is_consistent": is_consistent,
        "is_repeatable": is_repeatable,
        "is_passed": passed,
        "reason": reason,
        "quality_hash": _sha1_payload(rows)[:16],
    }


def build_repeated_assist_detector(
    *,
    assist_events: Sequence[Mapping[str, Any]] | None = None,
    min_repeats: int = 2,
    top_k: int = 5,
) -> Dict[str, Any]:
    rows: List[Dict[str, Any]] = []
    counts: Dict[str, int] = {}
    for idx, event in enumerate(assist_events or []):
        if not isinstance(event, Mapping):
            continue
        scenario_key = _first_nonempty(
            event.get("scenario_key"),
            event.get("screen_id"),
            event.get("question_id"),
            event.get("gap_key"),
            event.get("target"),
            f"assist_{idx}",
        ).strip().lower()
        counts[scenario_key] = int(counts.get(scenario_key, 0) + 1)
        rows.append(
            {
                "index": idx,
                "scenario_key": scenario_key,
                "kind": _first_nonempty(event.get("kind"), event.get("mode"), event.get("intervention_kind"), "").strip().lower(),
            }
        )
    threshold = max(1, int(min_repeats or 0))
    chronic_rows = []
    for scenario_key, count in sorted(counts.items(), key=lambda item: (-item[1], item[0])):
        if count < threshold:
            continue
        chronic_rows.append(
            {
                "scenario_key": scenario_key,
                "count": count,
            }
        )
    chronic_rows = chronic_rows[: max(1, int(top_k or 0))]
    has_repeats = bool(chronic_rows)
    if has_repeats:
        reason = "repeated_assist_detected"
    else:
        reason = "no_repeated_assist"
    return {
        "schema_version": SCHEMA_VERSION,
        "assist_event_count": len(rows),
        "assist_counts": counts,
        "repeated_count": len(chronic_rows),
        "threshold": threshold,
        "top_k": max(1, int(top_k or 0)),
        "repeated_scenarios": chronic_rows,
        "all_events": rows,
        "has_repeats": has_repeats,
        "reason": reason,
        "detector_hash": _sha1_payload({"rows": rows, "repeated": chronic_rows, "threshold": threshold})[:16],
    }


def build_operator_pain_surface_metric(
    *,
    pain_events: Sequence[Mapping[str, Any]] | None = None,
    top_k: int = 5,
) -> Dict[str, Any]:
    rows: List[Dict[str, Any]] = []
    counts: Dict[str, int] = {}
    severity_totals: Dict[str, float] = {}
    for idx, event in enumerate(pain_events or []):
        if not isinstance(event, Mapping):
            continue
        pain_key = _first_nonempty(
            event.get("pain_key"),
            event.get("scenario_key"),
            event.get("screen_id"),
            event.get("question_id"),
            event.get("gap_key"),
            f"pain_{idx}",
        ).strip().lower()
        severity = _first_nonempty(event.get("severity"), event.get("priority"), "medium").strip().lower()
        severity_weight = {"low": 1.0, "medium": 2.0, "high": 3.0}.get(severity, 2.0)
        weight = float(event.get("weight") or event.get("score") or severity_weight or 0.0)
        counts[pain_key] = int(counts.get(pain_key, 0) + 1)
        severity_totals[pain_key] = float(severity_totals.get(pain_key, 0.0) + weight)
        rows.append(
            {
                "index": idx,
                "pain_key": pain_key,
                "severity": severity,
                "weight": round(weight, 4),
            }
        )
    pain_rows = []
    for pain_key, count in sorted(counts.items(), key=lambda item: (-severity_totals.get(item[0], 0.0), -item[1], item[0])):
        pain_rows.append(
            {
                "pain_key": pain_key,
                "count": count,
                "pain_score": round(severity_totals.get(pain_key, 0.0), 4),
            }
        )
    pain_rows = pain_rows[: max(1, int(top_k or 0))]
    max_score = max((row["pain_score"] for row in pain_rows), default=0.0)
    if pain_rows:
        reason = "pain_surface_computed"
    else:
        reason = "empty_pain_surface"
    return {
        "schema_version": SCHEMA_VERSION,
        "pain_event_count": len(rows),
        "pain_counts": counts,
        "pain_rows": pain_rows,
        "top_k": max(1, int(top_k or 0)),
        "max_pain_score": round(max_score, 4),
        "reason": reason,
        "surface_hash": _sha1_payload({"rows": rows, "pain_rows": pain_rows})[:16],
    }


def build_stateful_migration_guard(
    *,
    action_checkpoint: Mapping[str, Any] | None = None,
    migration_registry: Mapping[str, Any] | None = None,
    target_schema_version: str = "",
    checkpoint_schema_version: str = "",
) -> Dict[str, Any]:
    checkpoint = dict(action_checkpoint or {})
    registry = dict(migration_registry or build_migration_playbook_registry())
    target_version = str(target_schema_version or "").strip()
    checkpoint_version = str(checkpoint_schema_version or checkpoint.get("schema_version") or "").strip()
    checkpoint_hash = str(checkpoint.get("checkpoint_hash") or "")
    if not checkpoint_hash and checkpoint:
        checkpoint_hash = _sha1_payload(checkpoint)[:16]
    supported_versions = {
        str(entry.get("target_schema_version") or "").strip()
        for entry in dict(registry.get("registry") or {}).values()
        if str(entry.get("target_schema_version") or "").strip()
    }
    has_current_support = bool(target_version and target_version in supported_versions)
    checkpoint_known = bool(checkpoint and checkpoint_version)
    can_map = bool(checkpoint_hash and checkpoint_known and has_current_support and checkpoint_version == target_version)
    if not checkpoint:
        is_allowed = False
        reason = "missing_checkpoint"
    elif not checkpoint_known:
        is_allowed = False
        reason = "missing_checkpoint_schema_version"
    elif not target_version:
        is_allowed = False
        reason = "missing_target_schema_version"
    elif not has_current_support:
        is_allowed = False
        reason = "unsupported_target_schema_version"
    elif can_map:
        is_allowed = True
        reason = "checkpoint_safe_to_resume"
    else:
        is_allowed = False
        reason = "checkpoint_cannot_be_mapped"
    return {
        "schema_version": SCHEMA_VERSION,
        "is_allowed": is_allowed,
        "reason": reason,
        "checkpoint_hash": checkpoint_hash,
        "checkpoint_schema_version": checkpoint_version,
        "target_schema_version": target_version,
        "supported_target_versions": sorted(supported_versions),
        "can_map": can_map,
        "migration_registry_id": str(registry.get("registry_id") or ""),
        "checkpoint": checkpoint,
    }


def build_artifact_migration_verifier(
    *,
    artifacts: Mapping[str, Any] | None = None,
    expected_versions: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    artifact_map = {
        str(name).strip(): dict(value or {})
        for name, value in dict(artifacts or {}).items()
        if str(name or "").strip()
    }
    version_map = {str(name).strip(): str(value).strip() for name, value in dict(expected_versions or {}).items() if str(name or "").strip()}
    rows: List[Dict[str, Any]] = []
    all_readable = bool(artifact_map)
    for name in sorted(set(artifact_map) | set(version_map)):
        artifact = artifact_map.get(name, {})
        expected_version = version_map.get(name, "")
        actual_version = str(artifact.get("version") or artifact.get("schema_version") or "").strip()
        content_hash = str(artifact.get("content_hash") or artifact.get("hash") or "").strip()
        readable = bool(content_hash or artifact)
        version_match = bool(expected_version and actual_version and expected_version == actual_version)
        if not readable or not version_match:
            all_readable = False
        if not readable:
            status = "missing"
        elif not version_match:
            status = "version_mismatch"
        else:
            status = "readable"
        rows.append(
            {
                "name": name,
                "expected_version": expected_version,
                "actual_version": actual_version,
                "status": status,
                "readable": readable,
                "version_match": version_match,
                "content_hash": content_hash,
            }
        )
    return {
        "schema_version": SCHEMA_VERSION,
        "all_readable": all_readable,
        "artifact_count": len(rows),
        "rows": rows,
        "verifier_id": _sha1_payload({"artifacts": artifact_map, "expected_versions": version_map})[:16],
    }


def build_resume_after_migration_policy(
    *,
    migration_guard: Mapping[str, Any] | None = None,
    artifact_verifier: Mapping[str, Any] | None = None,
    allow_partial_resume: bool = False,
) -> Dict[str, Any]:
    guard = dict(migration_guard or {})
    verifier = dict(artifact_verifier or {})
    guard_allowed = bool(guard.get("is_allowed"))
    artifacts_readable = bool(verifier.get("all_readable"))
    if guard_allowed and artifacts_readable:
        decision = "resume"
        reason = "migration_safe_to_resume"
    elif not guard_allowed:
        decision = "re-parse"
        reason = str(guard.get("reason") or "migration_guard_blocked")
    elif allow_partial_resume:
        decision = "resume_partial"
        reason = "partial_resume_allowed_with_migration_warnings"
    else:
        decision = "restart"
        reason = "artifact_verification_failed"
    return {
        "schema_version": SCHEMA_VERSION,
        "decision": decision,
        "reason": reason,
        "guard_allowed": guard_allowed,
        "artifacts_readable": artifacts_readable,
        "allow_partial_resume": bool(allow_partial_resume),
        "migration_guard": guard,
        "artifact_verifier": verifier,
    }


def build_compatibility_window_policy(
    *,
    producer_version: str = "",
    consumer_version: str = "",
    backward_versions: int = 1,
    forward_versions: int = 0,
) -> Dict[str, Any]:
    producer = str(producer_version or "").strip()
    consumer = str(consumer_version or "").strip()
    producer_major = producer.split(".", 1)[0].split("_", 1)[0].lower()
    consumer_major = consumer.split(".", 1)[0].split("_", 1)[0].lower()
    same_family = bool(producer_major and producer_major == consumer_major)
    within_window = same_family and int(backward_versions or 0) >= 0 and int(forward_versions or 0) >= 0
    if not producer or not consumer:
        is_compatible = False
        reason = "missing_version"
    elif within_window:
        is_compatible = True
        reason = "within_compatibility_window"
    else:
        is_compatible = False
        reason = "outside_compatibility_window"
    return {
        "schema_version": SCHEMA_VERSION,
        "is_compatible": is_compatible,
        "reason": reason,
        "producer_version": producer,
        "consumer_version": consumer,
        "backward_versions": int(backward_versions or 0),
        "forward_versions": int(forward_versions or 0),
        "producer_family": producer_major,
        "consumer_family": consumer_major,
    }


def build_dual_version_reader(
    *,
    legacy_payload: Mapping[str, Any] | None = None,
    current_payload: Mapping[str, Any] | None = None,
    prefer_current: bool = True,
) -> Dict[str, Any]:
    legacy = dict(legacy_payload or {})
    current = dict(current_payload or {})
    has_legacy = bool(legacy)
    has_current = bool(current)
    if prefer_current and has_current:
        selected_version = "current"
        selected_payload = current
    elif has_legacy:
        selected_version = "legacy"
        selected_payload = legacy
    elif has_current:
        selected_version = "current"
        selected_payload = current
    else:
        selected_version = "none"
        selected_payload = {}
    return {
        "schema_version": SCHEMA_VERSION,
        "selected_version": selected_version,
        "selected_payload": selected_payload,
        "has_legacy": has_legacy,
        "has_current": has_current,
        "both_available": has_legacy and has_current,
        "reader_id": _sha1_payload({"legacy": legacy, "current": current, "prefer_current": bool(prefer_current)})[:16],
    }


def build_producer_consumer_version_matrix(
    *,
    producer_versions: Sequence[Any] | None = None,
    consumer_versions: Sequence[Any] | None = None,
    backward_versions: int = 1,
    forward_versions: int = 0,
) -> Dict[str, Any]:
    producers = [str(item).strip() for item in (producer_versions or []) if str(item).strip()]
    consumers = [str(item).strip() for item in (consumer_versions or []) if str(item).strip()]
    rows: List[Dict[str, Any]] = []
    compatible_count = 0
    for producer in producers:
        for consumer in consumers:
            policy = build_compatibility_window_policy(
                producer_version=producer,
                consumer_version=consumer,
                backward_versions=backward_versions,
                forward_versions=forward_versions,
            )
            rows.append(
                {
                    "producer_version": producer,
                    "consumer_version": consumer,
                    "is_compatible": bool(policy["is_compatible"]),
                    "reason": policy["reason"],
                    "producer_family": policy["producer_family"],
                    "consumer_family": policy["consumer_family"],
                }
            )
            compatible_count += int(bool(policy["is_compatible"]))
    return {
        "schema_version": SCHEMA_VERSION,
        "rows": rows,
        "compatible_count": compatible_count,
        "incompatible_count": len(rows) - compatible_count,
        "is_compatible": bool(rows) and compatible_count == len(rows),
        "matrix_id": _sha1_payload({"rows": rows, "backward_versions": int(backward_versions or 0), "forward_versions": int(forward_versions or 0)})[:16],
    }


def build_deprecation_cutover_gate(
    *,
    version_matrix: Mapping[str, Any] | None = None,
    current_consumer_count: int = 0,
    stale_consumer_count: int = 0,
    required_current_count: int = 1,
) -> Dict[str, Any]:
    matrix = dict(version_matrix or {})
    matrix_compatible = bool(matrix.get("is_compatible"))
    current = int(current_consumer_count or 0)
    stale = int(stale_consumer_count or 0)
    required = int(required_current_count or 0)
    all_consumers_current = current >= required and stale == 0
    cutover_allowed = matrix_compatible and all_consumers_current
    if cutover_allowed:
        reason = "cutover_allowed"
    elif not matrix_compatible:
        reason = "version_matrix_incompatible"
    elif stale > 0:
        reason = "stale_consumers_remaining"
    else:
        reason = "insufficient_current_consumers"
    return {
        "schema_version": SCHEMA_VERSION,
        "cutover_allowed": cutover_allowed,
        "reason": reason,
        "current_consumer_count": current,
        "stale_consumer_count": stale,
        "required_current_count": required,
        "version_matrix": matrix,
    }


def build_incremental_rollout_matrix(
    *,
    site_families: Sequence[Any] | None = None,
    task_tiers: Sequence[Any] | None = None,
    scenario_types: Sequence[Any] | None = None,
) -> Dict[str, Any]:
    families = [str(item).strip() for item in (site_families or []) if str(item).strip()]
    tiers = [str(item).strip() for item in (task_tiers or []) if str(item).strip()]
    scenarios = [str(item).strip() for item in (scenario_types or []) if str(item).strip()]
    rows: List[Dict[str, Any]] = []
    for family in families:
        for tier in tiers:
            for scenario in scenarios:
                allow = tier in {"critical", "high"} or scenario in {"smoke", "regression"}
                rows.append(
                    {
                        "site_family": family,
                        "task_tier": tier,
                        "scenario_type": scenario,
                        "allowed": allow,
                    }
                )
    ready = bool(rows) and all(row["allowed"] for row in rows)
    return {
        "schema_version": SCHEMA_VERSION,
        "rows": rows,
        "ready_for_global_rollout": ready,
        "row_count": len(rows),
        "matrix_id": _sha1_payload({"rows": rows})[:16],
    }


def build_brownout_mode_controller(
    *,
    healthy: bool = True,
    high_latency: bool = False,
    high_drift: bool = False,
    high_error_rate: bool = False,
) -> Dict[str, Any]:
    reduced_mode = not bool(healthy) or bool(high_latency or high_drift or high_error_rate)
    enabled_features = ["minimal_actions", "safe_retry", "readback_only"] if reduced_mode else ["full_actions", "retry", "readback", "reporting"]
    if not healthy:
        reason = "system_unhealthy"
    elif high_error_rate:
        reason = "error_rate_high"
    elif high_drift:
        reason = "drift_high"
    elif high_latency:
        reason = "latency_high"
    else:
        reason = "full_mode"
    return {
        "schema_version": SCHEMA_VERSION,
        "reduced_mode": reduced_mode,
        "enabled_features": enabled_features,
        "reason": reason,
        "signals": {
            "healthy": bool(healthy),
            "high_latency": bool(high_latency),
            "high_drift": bool(high_drift),
            "high_error_rate": bool(high_error_rate),
        },
    }


def build_rollback_readiness_check(
    *,
    last_known_good: Mapping[str, Any] | None = None,
    artifact_verifier: Mapping[str, Any] | None = None,
    version_matrix: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    lkg = dict(last_known_good or {})
    verifier = dict(artifact_verifier or {})
    matrix = dict(version_matrix or {})
    has_safe_target = bool(lkg.get("has_safe_target"))
    artifacts_readable = bool(verifier.get("all_readable"))
    matrix_ready = bool(matrix.get("is_compatible"))
    rollback_target = str(lkg.get("rollback_target") or "").strip()
    missing: List[str] = []
    if not has_safe_target:
        missing.append("safe_rollback_target")
    if not artifacts_readable:
        missing.append("readable_artifacts")
    if not matrix_ready:
        missing.append("compatible_version_matrix")
    is_ready = not missing
    if is_ready:
        reason = "rollback_ready"
    elif "safe_rollback_target" in missing:
        reason = "missing_safe_target"
    elif "readable_artifacts" in missing:
        reason = "artifacts_not_readable"
    else:
        reason = "version_matrix_not_ready"
    return {
        "schema_version": SCHEMA_VERSION,
        "is_ready": is_ready,
        "reason": reason,
        "missing_requirements": missing,
        "rollback_target": rollback_target,
        "last_known_good": lkg,
        "artifact_verifier": verifier,
        "version_matrix": matrix,
    }


def build_change_failure_abort_rule(
    *,
    latency_ms: float = 0.0,
    max_latency_ms: float = 0.0,
    drift_score: float = 0.0,
    max_drift_score: float = 0.0,
    error_taxonomy: Mapping[str, Any] | None = None,
    side_effect_watchdog: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    latency = float(latency_ms or 0.0)
    drift = float(drift_score or 0.0)
    threshold_latency = float(max_latency_ms or 0.0)
    threshold_drift = float(max_drift_score or 0.0)
    taxonomy = dict(error_taxonomy or {})
    watchdog = dict(side_effect_watchdog or {})
    reasons: List[str] = []
    if threshold_latency > 0.0 and latency > threshold_latency:
        reasons.append("latency_exceeded")
    if threshold_drift > 0.0 and drift > threshold_drift:
        reasons.append("drift_exceeded")
    if bool(taxonomy.get("has_unknown_labels")):
        reasons.append("unknown_error_taxonomy")
    if bool(watchdog.get("is_blocking")):
        reasons.append(str(watchdog.get("reason") or "side_effect_block"))
    should_abort = bool(reasons)
    if not reasons:
        reasons.append("within_abort_budget")
    return {
        "schema_version": SCHEMA_VERSION,
        "should_abort": should_abort,
        "reasons": reasons,
        "signals": {
            "latency_ms": round(latency, 4),
            "max_latency_ms": round(threshold_latency, 4),
            "drift_score": round(drift, 4),
            "max_drift_score": round(threshold_drift, 4),
        },
        "error_taxonomy": taxonomy,
        "side_effect_watchdog": watchdog,
    }


def build_slow_iteration_abort_rule(
    *,
    iteration_duration_s: float = 0.0,
    max_iteration_duration_s: float = 0.0,
    recovery_chance: float = 0.0,
    no_progress_count: int = 0,
    max_no_progress_count: int = 0,
) -> Dict[str, Any]:
    duration = max(0.0, float(iteration_duration_s or 0.0))
    threshold = max(0.0, float(max_iteration_duration_s or 0.0))
    recovery = max(0.0, min(1.0, float(recovery_chance or 0.0)))
    stalled = max(0, int(no_progress_count or 0))
    stall_limit = max(0, int(max_no_progress_count or 0))
    over_budget = bool(threshold > 0.0 and duration > threshold)
    stalled_too_long = bool(stall_limit > 0 and stalled >= stall_limit)
    should_abort = bool(over_budget and (recovery < 0.35 or stalled_too_long))
    if not over_budget:
        reason = "within_iteration_budget"
    elif should_abort and recovery < 0.35:
        reason = "slow_iteration_no_recovery"
    elif should_abort:
        reason = "slow_iteration_stalled"
    else:
        reason = "slow_but_recoverable"
    return {
        "schema_version": SCHEMA_VERSION,
        "should_abort": should_abort,
        "reason": reason,
        "iteration_duration_s": round(duration, 4),
        "max_iteration_duration_s": round(threshold, 4),
        "recovery_chance": round(recovery, 4),
        "no_progress_count": stalled,
        "max_no_progress_count": stall_limit,
        "signals": {
            "over_budget": over_budget,
            "stalled_too_long": stalled_too_long,
        },
    }


def build_irreversible_action_guard(
    *,
    action_checkpoint: Mapping[str, Any] | None = None,
    resume_policy: Mapping[str, Any] | None = None,
    confirmation_strength: int = 0,
) -> Dict[str, Any]:
    checkpoint = dict(action_checkpoint or {})
    resume = dict(resume_policy or {}) if isinstance(resume_policy, Mapping) else {}
    decision = str(resume.get("decision") or "re-parse").strip().lower()
    requires_double_confidence = bool(checkpoint and decision in {"replay", "skip"})
    enough_confidence = int(confirmation_strength or 0) >= 2
    is_allowed = not requires_double_confidence or enough_confidence
    if requires_double_confidence and not enough_confidence:
        reason = "double_confirmation_required_after_resume"
    elif not checkpoint:
        reason = "missing_checkpoint"
    elif decision == "re-parse":
        reason = "resume_requires_reparse"
    else:
        reason = "irreversible_action_allowed"
    return {
        "schema_version": SCHEMA_VERSION,
        "is_allowed": is_allowed,
        "reason": reason,
        "requires_double_confirmation": requires_double_confidence,
        "confirmation_strength": int(confirmation_strength or 0),
        "resume_decision": decision,
        "checkpoint": checkpoint,
    }


def build_unified_timeline_builder(
    *,
    screenshot: Mapping[str, Any] | None = None,
    controls: Mapping[str, Any] | None = None,
    trace: Mapping[str, Any] | None = None,
    action: Mapping[str, Any] | None = None,
    outcome: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    items: List[Dict[str, Any]] = [
        {"stage": "screenshot", "payload": dict(screenshot or {})},
        {"stage": "controls", "payload": dict(controls or {})},
        {"stage": "trace", "payload": dict(trace or {})},
        {"stage": "action", "payload": dict(action or {})},
        {"stage": "outcome", "payload": dict(outcome or {})},
    ]
    timeline = [
        {
            "index": idx,
            "stage": item["stage"],
            "summary": _first_nonempty(
                item["payload"].get("summary"),
                item["payload"].get("title"),
                item["payload"].get("kind"),
                item["payload"].get("status"),
                item["payload"].get("action_kind"),
            ),
            "payload_hash": _sha1_payload(item["payload"])[:16],
        }
        for idx, item in enumerate(items)
    ]
    timeline_hash = _sha1_payload(timeline)[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "timeline_hash": timeline_hash,
        "timeline": timeline,
        "stage_order": [item["stage"] for item in timeline],
        "is_complete": all(bool(item["payload"]) for item in items),
    }


def build_hotkey_listener_contract(
    *,
    debug_mode: bool = False,
    enable_abort_iteration: bool = True,
    enable_soft_exit: bool = True,
    enable_full_exit: bool = True,
) -> Dict[str, Any]:
    hotkey_actions = {
        "p": "pipeline",
        "o": "region_grow",
        "l": "recorder",
        "i": "rating",
        "k": "control_agent",
        '"': "abort_iteration",
    }
    return {
        "schema_version": SCHEMA_VERSION,
        "listener_type": "hotkey_listener",
        "debug_mode": bool(debug_mode),
        "enable_abort_iteration": bool(enable_abort_iteration),
        "enable_soft_exit": bool(enable_soft_exit),
        "enable_full_exit": bool(enable_full_exit),
        "hotkey_actions": hotkey_actions,
        "soft_exit_key": "}",
        "full_exit_key": "{",
        "full_exit_sequence": "{}",
        "active_hotkey_count": len(hotkey_actions),
    }


def build_early_exit_listener_contract(
    *,
    arm_timeout_s: float = 0.8,
    enable_soft_exit: bool = True,
    enable_full_exit: bool = True,
) -> Dict[str, Any]:
    timeout = max(0.0, float(arm_timeout_s or 0.0))
    return {
        "schema_version": SCHEMA_VERSION,
        "listener_type": "early_exit_listener",
        "arm_key": "{",
        "trigger_key": "}",
        "sequence_timeout_s": round(timeout, 4),
        "enable_soft_exit": bool(enable_soft_exit),
        "enable_full_exit": bool(enable_full_exit),
        "soft_exit_sequence": "}",
        "full_exit_sequence": "{}",
    }


def build_recorder_cdp_bootstrap_contract(
    *,
    start_enabled: bool = True,
    browser_executable_available: bool = True,
    endpoint_probe: bool = False,
    recorder_cdp_port: int = 9222,
) -> Dict[str, Any]:
    endpoint = f"http://127.0.0.1:{int(recorder_cdp_port or 0)}"
    if not start_enabled:
        reason = "cdp_browser_disabled"
        can_launch = False
    elif endpoint_probe:
        reason = "cdp_browser_already_running"
        can_launch = False
    elif not browser_executable_available:
        reason = "browser_executable_missing"
        can_launch = False
    else:
        reason = "cdp_browser_launch_ready"
        can_launch = True
    return {
        "schema_version": SCHEMA_VERSION,
        "endpoint": endpoint,
        "start_enabled": bool(start_enabled),
        "browser_executable_available": bool(browser_executable_available),
        "endpoint_probe": bool(endpoint_probe),
        "can_launch": can_launch,
        "reason": reason,
    }


def build_quiz_page_lock_contract(
    *,
    url_prefix: str,
    matching_target_count: int = 0,
    timeout_s: float = 10.0,
) -> Dict[str, Any]:
    prefix = str(url_prefix or "").strip()
    matches = max(0, int(matching_target_count or 0))
    timeout = max(0.0, float(timeout_s or 0.0))
    if not prefix:
        reason = "missing_url_prefix"
        is_ready = False
    elif matches <= 0:
        reason = "no_matching_page_targets"
        is_ready = False
    else:
        reason = "quiz_page_lock_ready"
        is_ready = True
    return {
        "schema_version": SCHEMA_VERSION,
        "url_prefix": prefix,
        "matching_target_count": matches,
        "timeout_s": round(timeout, 4),
        "is_ready": is_ready,
        "reason": reason,
    }


def build_region_grow_bootstrap_contract(
    *,
    root_path: str = "",
    cuda_root: str = "",
    temp_dir: str = "",
    cupy_cache_dir: str = "",
    cuda_bits_present: bool = False,
) -> Dict[str, Any]:
    root = str(root_path or "").strip()
    cuda = str(cuda_root or "").strip()
    temp = str(temp_dir or "").strip()
    cupy = str(cupy_cache_dir or "").strip()
    has_root = bool(root)
    has_cuda_root = bool(cuda)
    ready = bool(has_root and has_cuda_root and bool(cuda_bits_present))
    if not has_root:
        reason = "missing_root_path"
    elif not has_cuda_root:
        reason = "missing_cuda_root"
    elif not cuda_bits_present:
        reason = "missing_cuda_bits"
    else:
        reason = "region_grow_bootstrap_ready"
    return {
        "schema_version": SCHEMA_VERSION,
        "root_path": root,
        "cuda_root": cuda,
        "temp_dir": temp,
        "cupy_cache_dir": cupy,
        "cuda_bits_present": bool(cuda_bits_present),
        "is_ready": ready,
        "reason": reason,
    }


def build_region_grow_resource_monitor_contract(
    *,
    pid: int,
    interval_s: float,
    output_path: str = "",
    psutil_available: bool = True,
    gpu_ready: bool = False,
) -> Dict[str, Any]:
    interval = max(0.2, float(interval_s or 0.0))
    output = str(output_path or "").strip()
    pid_value = int(pid or 0)
    ready = bool(psutil_available and pid_value > 0 and output)
    if not psutil_available:
        reason = "psutil_unavailable"
    elif pid_value <= 0:
        reason = "invalid_pid"
    elif not output:
        reason = "missing_output_path"
    else:
        reason = "resource_monitor_ready"
    return {
        "schema_version": SCHEMA_VERSION,
        "pid": pid_value,
        "interval_s": round(interval, 4),
        "output_path": output,
        "psutil_available": bool(psutil_available),
        "gpu_ready": bool(gpu_ready),
        "is_ready": ready,
        "reason": reason,
    }


def build_rating_summary_contract(
    *,
    result: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    payload = dict(result or {})
    elements = payload.get("elements") if isinstance(payload.get("elements"), list) else []
    question_candidate = dict(payload.get("question_candidate") or {})
    answer_boxes = [dict(row) for row in payload.get("answer_candidate_boxes") or [] if isinstance(row, Mapping)]
    next_boxes = [dict(row) for row in payload.get("next_candidate_boxes") or [] if isinstance(row, Mapping)]
    dropdown_boxes = [dict(row) for row in payload.get("dropdown_candidate_boxes") or [] if isinstance(row, Mapping)]
    top_labels = dict(payload.get("top_labels") or {}) if isinstance(payload.get("top_labels"), Mapping) else {}
    if not question_candidate and isinstance(elements, list):
        for item in elements:
            if isinstance(item, Mapping) and bool((item.get("predictions") or {}).get("question_candidate")):
                question_candidate = {
                    "id": item.get("id"),
                    "text": item.get("box") or item.get("text"),
                    "bbox": item.get("bbox"),
                }
                break
    if not answer_boxes and isinstance(elements, list):
        for item in elements:
            if not isinstance(item, Mapping):
                continue
            pred = item.get("predictions") if isinstance(item.get("predictions"), Mapping) else {}
            if bool(pred.get("answer_single") or pred.get("answer_multi")):
                answer_boxes.append(
                    {
                        "id": item.get("id"),
                        "text": item.get("box") or item.get("text"),
                        "bbox": item.get("bbox"),
                        "score": float((item.get("scores") or {}).get("answer_single") or (item.get("scores") or {}).get("answer_multi") or 0.0),
                        "marker_kind": item.get("marker_kind"),
                        "marker_shape": item.get("marker_shape"),
                    }
                )
            if bool(pred.get("next_active") or pred.get("next_inactive")):
                next_boxes.append(
                    {
                        "id": item.get("id"),
                        "text": item.get("box") or item.get("text"),
                        "bbox": item.get("bbox"),
                        "score": float((item.get("scores") or {}).get("next_active") or (item.get("scores") or {}).get("next_inactive") or 0.0),
                        "label": "next_active" if pred.get("next_active") else "next_inactive",
                    }
                )
            if bool(pred.get("dropdown")):
                dropdown_boxes.append(
                    {
                        "id": item.get("id"),
                        "text": item.get("box") or item.get("text"),
                        "bbox": item.get("bbox"),
                        "score": float((item.get("scores") or {}).get("dropdown") or 0.0),
                        "label": "dropdown",
                    }
                )
    summary_payload = {
        "schema_version": SCHEMA_VERSION,
        "image": payload.get("image"),
        "total_elements": int(payload.get("total_elements") or 0),
        "background_layout": payload.get("background_layout"),
        "question_candidate": question_candidate,
        "answer_candidate_boxes": answer_boxes,
        "next_candidate_boxes": next_boxes,
        "dropdown_candidate_boxes": dropdown_boxes,
        "top_labels": top_labels,
        "answer_candidate_count": len(answer_boxes),
        "next_candidate_count": len(next_boxes),
        "dropdown_candidate_count": len(dropdown_boxes),
    }
    summary_payload["has_summary_signals"] = bool(
        summary_payload["question_candidate"]
        or summary_payload["answer_candidate_boxes"]
        or summary_payload["next_candidate_boxes"]
        or summary_payload["dropdown_candidate_boxes"]
    )
    return summary_payload


def build_rating_answer_candidates_below_contract(
    *,
    question_elem: Mapping[str, Any] | None = None,
    elements: Sequence[Mapping[str, Any]] | None = None,
) -> Dict[str, Any]:
    question = dict(question_elem or {})
    rows = [dict(row) for row in elements or [] if isinstance(row, Mapping)]
    bbox = list(question.get("bbox") or [])
    q_text = _norm_text(question.get("text"))
    q_id = question.get("id")
    candidates = []
    if len(bbox) == 4:
        q_h = max(1, int(bbox[3]) - int(bbox[1]))
        q_bottom = int(bbox[3])
        q_left = int(bbox[0])
        q_right = int(bbox[2])
        max_vertical_gap = max(60, q_h * 10)
    else:
        q_bottom = 0
        q_left = 0
        q_right = 0
        max_vertical_gap = 60
    for row in rows:
        if row is question:
            continue
        row_bbox = row.get("bbox")
        row_text = str(row.get("text") or "").strip()
        if not isinstance(row_bbox, list) or len(row_bbox) != 4:
            continue
        if len(bbox) != 4:
            continue
        row_top = int(row_bbox[1])
        row_bottom = int(row_bbox[3])
        if row_top < int(bbox[1]) or row_top <= q_bottom:
            continue
        if row_top - q_bottom > max_vertical_gap:
            continue
        row_left = int(row_bbox[0])
        row_right = int(row_bbox[2])
        overlap = max(0, min(q_right, row_right) - max(q_left, row_left))
        min_width = max(1, min(max(1, q_right - q_left), max(1, row_right - row_left)))
        if (overlap / min_width) < 0.4:
            continue
        if not row_text or "?" in row_text:
            continue
        candidates.append(
            {
                "id": row.get("id"),
                "text": row_text,
                "bbox": row_bbox,
                "overlap": round(float(overlap / min_width), 4),
            }
        )
    return {
        "schema_version": SCHEMA_VERSION,
        "question_id": q_id,
        "question_text": q_text,
        "candidate_count": len(candidates),
        "candidate_texts": [row["text"] for row in candidates],
        "candidate_ids": [row["id"] for row in candidates if row.get("id") is not None],
        "has_candidates": bool(candidates),
    }


def build_rating_collect_label_candidates_contract(
    *,
    elements: Sequence[Mapping[str, Any]] | None = None,
    label: str = "dropdown",
    limit: int = 16,
    skip_questionish: bool = False,
) -> Dict[str, Any]:
    rows = [dict(row) for row in elements or [] if isinstance(row, Mapping)]
    target_label = str(label or "").strip()
    collected = []
    for row in rows:
        pred = row.get("predictions") if isinstance(row.get("predictions"), Mapping) else {}
        if not bool(pred.get(target_label)):
            continue
        bbox = row.get("bbox")
        if not (isinstance(bbox, list) and len(bbox) == 4):
            continue
        text = str(row.get("text") or row.get("box") or "").strip()
        if not text:
            continue
        lowered = _norm_text(text)
        if not lowered:
            continue
        if any(token in lowered for token in ("loading", "wait", "skeleton", "placeholder")):
            continue
        if skip_questionish and (
            text.endswith(":")
            or "?" in text
            or lowered.startswith("choose ")
            or lowered.startswith("wybierz ")
            or lowered.startswith("select ")
            or lowered.startswith("pick ")
        ):
            continue
        if target_label == "dropdown" and ("select all" in lowered or "choose one" in lowered):
            continue
        scores = row.get("scores") if isinstance(row.get("scores"), Mapping) else {}
        try:
            score = float(scores.get(target_label, 0.0) or 0.0)
        except Exception:
            score = 0.0
        collected.append(
            {
                "id": str(row.get("id") or f"{target_label}_{len(collected)}"),
                "text": text,
                "bbox": [int(bbox[0]), int(bbox[1]), int(bbox[2]), int(bbox[3])],
                "score": round(score, 4),
                "label": target_label,
            }
        )
    collected.sort(key=lambda item: (-float(item.get("score") or 0.0), int(item["bbox"][1]), int(item["bbox"][0])))
    if limit > 0:
        collected = collected[: int(limit)]
    return {
        "schema_version": SCHEMA_VERSION,
        "label": target_label,
        "limit": int(limit),
        "skip_questionish": bool(skip_questionish),
        "candidate_count": len(collected),
        "candidate_ids": [row["id"] for row in collected],
        "candidate_texts": [row["text"] for row in collected],
        "has_candidates": bool(collected),
    }


def build_rating_answer_scoring_contract(
    *,
    question_elem: Mapping[str, Any] | None = None,
    elements: Sequence[Mapping[str, Any]] | None = None,
) -> Dict[str, Any]:
    question = dict(question_elem or {})
    rows = [dict(row) for row in elements or [] if isinstance(row, Mapping)]
    text = str(question.get("text") or "").strip()
    lowered = _norm_text(text)
    bbox = list(question.get("bbox") or [])
    below_count = 0
    radio_count = 0
    checkbox_count = 0
    bullet_count = 0

    if len(bbox) == 4:
        q_left = int(bbox[0])
        q_right = int(bbox[2])
        q_bottom = int(bbox[3])
        q_height = max(1, int(bbox[3]) - int(bbox[1]))
        max_vertical_gap = max(60, q_height * 10)
    else:
        q_left = q_right = q_bottom = 0
        max_vertical_gap = 60

    for row in rows:
        if row is question:
            continue
        row_bbox = row.get("bbox")
        if not (isinstance(row_bbox, list) and len(row_bbox) == 4 and len(bbox) == 4):
            continue
        row_top = int(row_bbox[1])
        row_left = int(row_bbox[0])
        row_right = int(row_bbox[2])
        row_text = str(row.get("text") or row.get("box") or "").strip()
        if row_top < q_bottom or row_top - q_bottom > max_vertical_gap:
            continue
        overlap = max(0, min(q_right, row_right) - max(q_left, row_left))
        min_width = max(1, min(max(1, q_right - q_left), max(1, row_right - row_left)))
        if (overlap / min_width) < 0.4:
            continue
        if not row_text or "?" in row_text:
            continue
        below_count += 1
        marker_kind = str(row.get("marker_kind") or "none")
        if marker_kind == "radio":
            radio_count += 1
        elif marker_kind == "checkbox":
            checkbox_count += 1
        elif marker_kind == "bullet":
            bullet_count += 1
        else:
            marker_start = row_text[:2].strip().lower()
            if marker_start in {"o", "•", "-", "*"}:
                bullet_count += 1
            if marker_start in {"a)", "b)", "c)", "d)", "1.", "2.", "3.", "4."}:
                radio_count += 1

    single_score = 0.0
    multi_score = 0.0
    if "?" in text:
        single_score += 0.25
        multi_score += 0.25
    if re.search(r"\b(kt[oó]r(y|a)|which one|single choice|choose one)\b", lowered):
        single_score += 0.45
    if re.search(r"\b(kt[oó]re|which ones|select all|multi choice|choose all)\b", lowered):
        multi_score += 0.50
    if below_count == 2:
        single_score += 0.35
        multi_score -= 0.25
    elif below_count in {3, 4}:
        single_score += 0.40
        multi_score += 0.40
    elif 5 <= below_count <= 6:
        single_score += 0.30
        multi_score += 0.45
    elif 7 <= below_count <= 10:
        single_score += 0.15
        multi_score += 0.55
    elif below_count >= 11:
        single_score -= 0.20
        multi_score += 0.60
    if radio_count >= 2:
        single_score += 0.70
        multi_score -= 0.65
    if checkbox_count >= 2:
        single_score -= 0.75
        multi_score += 0.75
    if bullet_count >= 2:
        multi_score += 0.20
    if not lowered or ("?" not in text and below_count == 0):
        single_score = 0.0
        multi_score = 0.0

    def _clamp(value: float) -> float:
        return round(max(0.0, min(0.95, value)), 4)

    return {
        "schema_version": SCHEMA_VERSION,
        "question_text": lowered,
        "below_count": below_count,
        "radio_count": radio_count,
        "checkbox_count": checkbox_count,
        "bullet_count": bullet_count,
        "single_score": _clamp(single_score),
        "multi_score": _clamp(multi_score),
        "single_wins": single_score > multi_score,
        "multi_wins": multi_score > single_score,
    }


def build_rating_marker_shape_contract(
    *,
    marker_bbox: Sequence[int] | None = None,
    marker_hint_text: str = "",
) -> Dict[str, Any]:
    bbox = [int(v) for v in list(marker_bbox or [])[:4] if isinstance(v, (int, float))]
    if len(bbox) != 4:
        return {
            "schema_version": SCHEMA_VERSION,
            "marker_shape": "none",
            "marker_kind": "none",
            "marker_conf": 0.0,
            "detector_status": "empty_roi",
            "detector_fallback_used": 0,
        }
    width = max(1, bbox[2] - bbox[0])
    height = max(1, bbox[3] - bbox[1])
    ratio = width / height
    hint = _norm_text(marker_hint_text)
    is_radio_hint = any(token in hint for token in ("radio", "circle", "round", "single"))
    is_checkbox_hint = any(token in hint for token in ("checkbox", "square", "check", "multi"))
    if is_radio_hint and not is_checkbox_hint:
        shape = "circle"
        kind = "radio"
        conf = 0.82 if 0.75 <= ratio <= 1.25 else 0.71
    elif is_checkbox_hint and not is_radio_hint:
        shape = "square"
        kind = "checkbox"
        conf = 0.84 if 0.80 <= ratio <= 1.25 else 0.69
    elif 0.80 <= ratio <= 1.25:
        shape = "circle" if ratio <= 1.10 else "square"
        kind = "radio" if shape == "circle" else "checkbox"
        conf = 0.73
    elif ratio < 0.80:
        shape = "circle"
        kind = "radio"
        conf = 0.66
    else:
        shape = "square"
        kind = "checkbox"
        conf = 0.66
    return {
        "schema_version": SCHEMA_VERSION,
        "marker_bbox": bbox,
        "marker_shape": shape,
        "marker_kind": kind,
        "marker_conf": round(conf, 4),
        "marker_source": "vision_cpu",
        "detector_status": "ok",
        "detector_fallback_used": 0,
    }


def build_rating_extract_question_and_answers_contract(
    *,
    elements: Sequence[Mapping[str, Any]] | None = None,
) -> Dict[str, Any]:
    rows = [dict(row) for row in elements or [] if isinstance(row, Mapping)]
    def _noise_like(text: str) -> bool:
        low = _norm_text(text)
        return not low or low in {"home", "next", "menu", "start"} or any(tok in low for tok in ("loading", "placeholder", "skeleton"))

    def _questionish(text: str) -> bool:
        low = _norm_text(text)
        return "?" in text or low.endswith(":") or any(tok in low for tok in ("wybierz", "select", "choose", "which", "jakiej", "której", "ktore", "które"))

    def _instruction_prompt(text: str) -> bool:
        low = _norm_text(text)
        return any(tok in low for tok in ("choose one", "select one", "pick one", "one option", "single choice", "multi choice", "choose all", "select all"))

    def _slider_prompt(text: str) -> bool:
        low = _norm_text(text)
        return any(tok in low for tok in ("slider", "suwak", "move slider", "rate this", "ocen"))

    question = {}
    question_score = -1e9
    question_text = ""
    question_bbox: List[int] | None = None
    for row in rows:
        text = str(row.get("text") or row.get("box") or "").strip()
        if not text:
            continue
        if _noise_like(text):
            continue
        lowered = _norm_text(text)
        bbox = row.get("bbox")
        y_top = int(bbox[1]) if isinstance(bbox, list) and len(bbox) == 4 else 10**9
        score = 0.0
        if _questionish(text):
            score += 1.0
        if _instruction_prompt(text):
            score += 0.95
        if text.endswith(":"):
            score += 0.9
        if any(tok in lowered for tok in ("select all", "choose all", "multiple choice", "multi choice", "multi-select")):
            score += 0.9
        if any(tok in lowered for tok in ("single choice", "choose one", "select one", "one option")):
            score += 0.7
        if any(tok in lowered for tok in ("dropdown", "select", "choose", "list box")):
            score += 0.5
        if _slider_prompt(text):
            score += 0.85
        if any(tok in lowered for tok in ("wybierz", "choose", "select", "pick", "zaznacz")):
            score += 0.55
        if len(text) <= 20 and "?" not in text and ":" not in text:
            score -= 0.55
        score += max(0.0, 0.35 - min(0.35, y_top / 2200.0))
        if len(text) > 140:
            score -= 0.35
        if isinstance(bbox, list) and len(bbox) == 4 and (row.get("marker") or {}).get("kind") not in {"none", "", None}:
            score -= 1.0
        if score > question_score:
            question_score = score
            question = row
            question_text = text
            if isinstance(bbox, list) and len(bbox) == 4:
                question_bbox = [int(bbox[0]), int(bbox[1]), int(bbox[2]), int(bbox[3])]

    if not question_text or question_score < 0.2:
        for row in rows:
            text = str(row.get("text") or row.get("box") or "").strip()
            if not text:
                continue
            if is_questionish(text) or text.endswith(":") or is_instruction_prompt(text):
                question = row
                question_text = text
                bbox = row.get("bbox")
                if isinstance(bbox, list) and len(bbox) == 4:
                    question_bbox = [int(bbox[0]), int(bbox[1]), int(bbox[2]), int(bbox[3])]
                question_score = max(question_score, 0.2)
                break

    answers: List[Dict[str, Any]] = []
    seen = set()
    for row in rows:
        text = str(row.get("text") or row.get("box") or "").strip()
        if not text or text == question_text:
            continue
        if _noise_like(text):
            continue
        if _questionish(text) or text.endswith(":") or _instruction_prompt(text):
            continue
        bbox = row.get("bbox")
        if not (isinstance(bbox, list) and len(bbox) == 4):
            continue
        if question_bbox and int(bbox[1]) <= int(question_bbox[3]):
            continue
        if len(text) > 80:
            continue
        key = _norm_text(text)
        if key in seen:
            continue
        seen.add(key)
        marker = row.get("marker") if isinstance(row.get("marker"), Mapping) else {}
        scores = row.get("scores") if isinstance(row.get("scores"), Mapping) else {}
        answers.append(
            {
                "id": str(row.get("id") or f"answer_{len(answers)}"),
                "text": text,
                "bbox": [int(bbox[0]), int(bbox[1]), int(bbox[2]), int(bbox[3])],
                "score": round(float(max(float(scores.get("answer_multi", 0.0) or 0.0), float(scores.get("answer_single", 0.0) or 0.0))), 4),
                "marker_kind": str(marker.get("kind") or "none"),
                "marker_shape": str(marker.get("shape") or "none"),
                "marker_conf": round(float(marker.get("conf") or 0.0), 4) if isinstance(marker, Mapping) else 0.0,
                "marker_status": str(marker.get("status") or "unknown") if isinstance(marker, Mapping) else "unknown",
            }
        )
    answers.sort(key=lambda row: (int(row["bbox"][1]), int(row["bbox"][0])))
    return {
        "schema_version": SCHEMA_VERSION,
        "question_candidate": {
            "id": str(question.get("id") or "question"),
            "text": question_text,
            "bbox": question_bbox,
            "score": round(max(0.0, float(question_score)), 4),
            "source": "rating_extract",
        }
        if question_text and question_bbox
        else None,
        "answer_rows": answers,
        "answer_count": len(answers),
        "has_question": bool(question_text),
        "has_answers": bool(answers),
    }


def build_rating_quiz_type_log_contract(
    *,
    result: Mapping[str, Any] | None = None,
    min_type_conf: float = 0.35,
) -> Dict[str, Any]:
    payload = dict(result or {})
    elements = payload.get("elements") if isinstance(payload.get("elements"), list) else []
    cnt_dropdown = 0
    cnt_single = 0
    cnt_multi = 0
    best_dropdown = 0.0
    best_single = 0.0
    best_multi = 0.0
    for row in elements:
        if not isinstance(row, Mapping):
            continue
        preds = row.get("predictions") if isinstance(row.get("predictions"), Mapping) else {}
        scores = row.get("scores") if isinstance(row.get("scores"), Mapping) else {}
        best_dropdown = max(best_dropdown, float(scores.get("dropdown", 0.0) or 0.0))
        best_single = max(best_single, float(scores.get("answer_single", 0.0) or 0.0))
        best_multi = max(best_multi, float(scores.get("answer_multi", 0.0) or 0.0))
        if bool(preds.get("dropdown")):
            cnt_dropdown += 1
        if bool(preds.get("answer_single")):
            cnt_single += 1
        if bool(preds.get("answer_multi")):
            cnt_multi += 1
    scores_map = {"dropdown": best_dropdown, "single": best_single, "multi": best_multi}
    ordered = sorted(scores_map.items(), key=lambda kv: float(kv[1]), reverse=True)
    top_label, top_score = ordered[0]
    second_score = float(ordered[1][1]) if len(ordered) > 1 else 0.0
    margin = max(0.0, float(top_score) - float(second_score))
    detected = "unknown"
    mode = "unknown"
    reason = "low_conf_unknown"
    conf = float(top_score)
    if cnt_dropdown > 0 and best_dropdown >= max(best_single, best_multi):
        detected = "dropdown"
        mode = "dropdown(select)"
        reason = "dropdown_predictions"
        conf = best_dropdown
    elif cnt_multi > 0 and best_multi >= best_single:
        detected = "multi"
        mode = "checkbox(multi-choice)"
        reason = "multi_predictions"
        conf = best_multi
    elif cnt_single > 0:
        detected = "single"
        mode = "radio(single-choice)"
        reason = "single_predictions"
        conf = best_single
    elif float(top_score) >= float(min_type_conf):
        if top_label == "dropdown":
            detected = "dropdown"
            mode = "dropdown(select)"
        elif top_label == "multi":
            detected = "multi"
            mode = "checkbox(multi-choice)"
        else:
            detected = "single"
            mode = "radio(single-choice)"
        reason = "argmax_soft_signal"
        conf = float(top_score)
    return {
        "schema_version": SCHEMA_VERSION,
        "detected_quiz_type": detected,
        "quiz_type_mode": mode,
        "reason": reason,
        "confidence": round(float(conf), 4),
        "decision_margin": round(float(margin), 4),
        "counts": {"dropdown": cnt_dropdown, "single": cnt_single, "multi": cnt_multi},
        "best_scores": {"dropdown": round(best_dropdown, 4), "single": round(best_single, 4), "multi": round(best_multi, 4)},
        "question_text": "",
        "question_id": None,
        "answer_count": 0,
        "marker_detected_answers": 0,
        "total_answers": 0,
        "is_ready": detected != "unknown",
    }


def build_dropdown_ocr_perform_ocr_contract(
    *,
    ocr_entries: Sequence[Sequence[Any]] | None = None,
    min_conf: float = 0.3,
) -> Dict[str, Any]:
    items = []
    threshold = float(min_conf or 0.0)
    for entry in ocr_entries or []:
        if not isinstance(entry, (list, tuple)) or len(entry) < 3:
            continue
        bbox_points, text, conf = entry[:3]
        try:
            confidence = float(conf)
        except Exception:
            confidence = 0.0
        if confidence < threshold:
            continue
        xs = [int(pt[0]) for pt in bbox_points if isinstance(pt, (list, tuple)) and len(pt) >= 2]
        ys = [int(pt[1]) for pt in bbox_points if isinstance(pt, (list, tuple)) and len(pt) >= 2]
        if not xs or not ys:
            continue
        x1, y1, x2, y2 = min(xs), min(ys), max(xs), max(ys)
        items.append(
            {
                "text": str(text).strip(),
                "conf": round(confidence, 4),
                "ocr_bbox": [x1, y1, x2, y2],
                "center": [(x1 + x2) // 2, (y1 + y2) // 2],
            }
        )
    return {
        "schema_version": SCHEMA_VERSION,
        "min_conf": round(threshold, 4),
        "candidate_count": len(items),
        "texts": [item["text"] for item in items],
        "centers": [item["center"] for item in items],
        "has_candidates": bool(items),
    }


def build_dropdown_ocr_process_with_region_grow_contract(
    *,
    ocr_items: Sequence[Mapping[str, Any]] | None = None,
    region_lookup: Mapping[str, Mapping[str, Any]] | None = None,
) -> Dict[str, Any]:
    lookup = dict(region_lookup or {})
    items = []
    fallback_count = 0
    for item in ocr_items or []:
        row = dict(item or {})
        text = str(row.get("text") or "").strip()
        center = row.get("center")
        region = lookup.get(text) or {}
        if isinstance(center, (list, tuple)) and len(center) == 2 and region:
            row["region_bbox"] = list(region.get("bbox") or row.get("ocr_bbox") or [])
            row["region_mask"] = region.get("mask")
        else:
            row["region_bbox"] = list(row.get("ocr_bbox") or [])
            row["region_mask"] = None
            fallback_count += 1
        items.append(row)
    return {
        "schema_version": SCHEMA_VERSION,
        "candidate_count": len(items),
        "fallback_count": fallback_count,
        "items": items,
        "has_regions": any(bool(item.get("region_bbox")) for item in items),
    }


def build_backward_compat_loader(
    *,
    payload: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    legacy = dict(payload or {})
    migrated = dict(legacy)
    migrations: List[str] = []

    if "recommended_action" not in migrated and "action" in migrated:
        migrated["recommended_action"] = migrated.get("action")
        migrations.append("action_to_recommended_action")

    if "qid" not in migrated:
        meta = migrated.get("meta") if isinstance(migrated.get("meta"), Mapping) else {}
        if meta.get("qid"):
            migrated["qid"] = meta.get("qid")
            migrations.append("meta_qid_to_qid")

    if "bbox4" not in migrated and isinstance(migrated.get("bbox"), (list, tuple)) and len(migrated.get("bbox")) == 4:
        migrated["bbox4"] = [int(float(v)) for v in migrated.get("bbox")]
        migrations.append("bbox_to_bbox4")

    if "schema_version" not in migrated:
        migrated["schema_version"] = "legacy.unversioned"
        migrations.append("inject_legacy_schema_version")

    return {
        "schema_version": SCHEMA_VERSION,
        "migrated_payload": migrated,
        "applied_migrations": migrations,
        "is_migrated": bool(migrations),
    }


def build_self_describing_payload(
    *,
    payload: Mapping[str, Any] | None = None,
    producer: str = "",
    intended_consumer: str = "",
    timestamp_ms: int | None = None,
) -> Dict[str, Any]:
    body = dict(payload or {})
    ts = int(timestamp_ms if timestamp_ms is not None else int(time.time() * 1000))
    envelope = {
        "schema_version": SCHEMA_VERSION,
        "producer": str(producer or "unknown_producer").strip(),
        "intended_consumer": str(intended_consumer or "unknown_consumer").strip(),
        "timestamp_ms": ts,
        "payload": body,
    }
    envelope["payload_fingerprint"] = _sha1_payload(body)[:16]
    return envelope


def build_schema_diff_alarm(
    *,
    previous_payload: Mapping[str, Any] | None = None,
    current_payload: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    prev = dict(previous_payload or {})
    curr = dict(current_payload or {})
    prev_keys = set(prev.keys())
    curr_keys = set(curr.keys())
    removed = sorted(prev_keys - curr_keys)
    added = sorted(curr_keys - prev_keys)
    type_changes: List[Dict[str, Any]] = []
    for key in sorted(prev_keys & curr_keys):
        prev_type = type(prev.get(key)).__name__
        curr_type = type(curr.get(key)).__name__
        if prev_type != curr_type:
            type_changes.append({"key": key, "previous_type": prev_type, "current_type": curr_type})
    is_alarm = bool(removed or added or type_changes)
    return {
        "schema_version": SCHEMA_VERSION,
        "is_alarm": is_alarm,
        "added_keys": added,
        "removed_keys": removed,
        "type_changes": type_changes,
        "reason": "schema_changed" if is_alarm else "schema_unchanged",
    }


def build_api_drift_guard(
    *,
    expected_request_schema: Mapping[str, Any] | None = None,
    expected_response_schema: Mapping[str, Any] | None = None,
    current_request: Mapping[str, Any] | None = None,
    current_response: Mapping[str, Any] | None = None,
    endpoint_role_registry: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    expected_request = dict(expected_request_schema or {})
    expected_response = dict(expected_response_schema or {})
    request = dict(current_request or {})
    response = dict(current_response or {})
    registry = dict(endpoint_role_registry or {})

    request_alarm = build_schema_diff_alarm(previous_payload=expected_request, current_payload=request)
    response_alarm = build_schema_diff_alarm(previous_payload=expected_response, current_payload=response)
    request_drift = bool(request_alarm.get("is_alarm"))
    response_drift = bool(response_alarm.get("is_alarm"))
    drifted = request_drift or response_drift

    expected_role = _first_nonempty(
        registry.get("expected_role"),
        registry.get("role"),
        registry.get("endpoint_role"),
        request.get("role"),
        request.get("request_role"),
    ).strip().lower()
    request_role = _first_nonempty(request.get("role"), request.get("request_role")).strip().lower()
    response_role = _first_nonempty(response.get("role"), response.get("response_role")).strip().lower()
    role_mismatch = bool(expected_role and request_role and expected_role != request_role) or bool(expected_role and response_role and expected_role != response_role)

    changed_request_keys = sorted(set(request_alarm.get("added_keys", [])) | set(request_alarm.get("removed_keys", [])))
    changed_response_keys = sorted(set(response_alarm.get("added_keys", [])) | set(response_alarm.get("removed_keys", [])))
    changed_types = request_alarm.get("type_changes", []) + response_alarm.get("type_changes", [])

    if drifted and role_mismatch:
        severity = "high"
        reason = "api_role_and_schema_drift"
    elif drifted:
        severity = "medium"
        reason = "api_schema_drift"
    elif role_mismatch:
        severity = "medium"
        reason = "api_role_mismatch"
    else:
        severity = "none"
        reason = "api_stable"

    confidence = 1.0
    if severity == "high":
        confidence = 0.95
    elif severity == "medium":
        confidence = 0.8
    elif severity == "none":
        confidence = 0.98

    return {
        "schema_version": SCHEMA_VERSION,
        "severity": severity,
        "reason": reason,
        "confidence": round(confidence, 4),
        "request_drift": request_drift,
        "response_drift": response_drift,
        "role_mismatch": role_mismatch,
        "changed_request_keys": changed_request_keys,
        "changed_response_keys": changed_response_keys,
        "type_changes": changed_types,
        "expected_role": expected_role,
        "request_role": request_role,
        "response_role": response_role,
        "should_escalate": severity in {"high", "medium"},
        "is_stable": severity == "none",
    }


def build_model_promotion_gate(
    *,
    global_acc: float = 0.0,
    block_acc: float = 0.0,
    target_global_acc: float = 0.0,
    target_block_acc: float = 0.0,
) -> Dict[str, Any]:
    g = float(global_acc or 0.0)
    b = float(block_acc or 0.0)
    tg = float(target_global_acc or 0.0)
    tb = float(target_block_acc or 0.0)
    global_ok = g >= tg
    block_ok = b >= tb
    is_promoted = global_ok and block_ok
    reasons: List[str] = []
    if not global_ok:
        reasons.append("global_acc_below_target")
    if not block_ok:
        reasons.append("block_acc_below_target")
    if not reasons:
        reasons.append("all_targets_met")
    return {
        "schema_version": SCHEMA_VERSION,
        "is_promoted": is_promoted,
        "global_acc": round(g, 4),
        "block_acc": round(b, 4),
        "target_global_acc": round(tg, 4),
        "target_block_acc": round(tb, 4),
        "reasons": reasons,
    }


def build_release_manifest(
    *,
    model_path: str = "",
    feature_version: str = "",
    dataset_hash: str = "",
    benchmark_result_id: str = "",
) -> Dict[str, Any]:
    manifest = {
        "model_path": str(model_path or "").strip(),
        "feature_version": str(feature_version or "").strip(),
        "dataset_hash": str(dataset_hash or "").strip(),
        "benchmark_result_id": str(benchmark_result_id or "").strip(),
    }
    required = ["model_path", "feature_version", "dataset_hash", "benchmark_result_id"]
    missing = [name for name in required if not manifest.get(name)]
    manifest_id = _sha1_payload(manifest)[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "release_manifest_id": manifest_id,
        "manifest": manifest,
        "missing_fields": missing,
        "is_complete": not missing,
    }


def build_winning_config_contract(
    *,
    candidate_configs: Sequence[Mapping[str, Any] | str] | None = None,
    objective_metric: str = "",
    registry_contract: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    registry = dict(registry_contract or {})
    objective = str(objective_metric or "").strip().lower()
    rows: List[Dict[str, Any]] = []
    missing_rows: List[str] = []
    for idx, candidate in enumerate(candidate_configs or [], start=1):
        if isinstance(candidate, Mapping):
            payload = dict(candidate)
        else:
            text = str(candidate or "").strip()
            payload = {"config_name": text} if text else {}
        config_name = str(_first_nonempty(payload.get("config_name"), payload.get("name"), payload.get("variant"), f"config_{idx}")).strip()
        if not config_name:
            missing_rows.append(f"candidate_{idx}")
        global_acc = float(_first_nonempty(payload.get("global_acc"), payload.get("global_accuracy"), 0.0) or 0.0)
        block_acc = float(_first_nonempty(payload.get("block_acc"), payload.get("block_accuracy"), 0.0) or 0.0)
        risk_score = float(_first_nonempty(payload.get("risk_score"), payload.get("risk"), 0.0) or 0.0)
        metrics_present = any(key in payload for key in ("global_acc", "global_accuracy", "block_acc", "block_accuracy", "risk_score", "risk"))
        if not metrics_present:
            missing_rows.append(config_name or f"candidate_{idx}")
        rows.append(
            {
                "config_name": config_name,
                "global_acc": round(global_acc, 4),
                "block_acc": round(block_acc, 4),
                "risk_score": round(risk_score, 4),
                "score": round((global_acc * 0.6) + (block_acc * 0.4) - (risk_score * 0.2), 4),
                "is_current": bool(payload.get("is_current", False)),
                "is_holdout_safe": bool(payload.get("is_holdout_safe", True)),
            }
        )

    rows.sort(key=lambda item: (item["score"], item["is_holdout_safe"], item["global_acc"], item["block_acc"]), reverse=True)
    winning_row = rows[0] if rows else {}
    runner_up_row = rows[1] if len(rows) > 1 else {}
    if not rows:
        reason = "winning_config_contract_incomplete"
    elif missing_rows:
        reason = "winning_config_contract_incomplete"
    elif not objective:
        reason = "winning_config_contract_incomplete"
    else:
        reason = "winning_config_contract_selected"
    winning_config_id = _sha1_payload(
        {
            "objective_metric": objective,
            "rows": rows,
            "registry_id": registry.get("registry_id", ""),
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "winning_config_id": winning_config_id,
        "objective_metric": objective,
        "candidate_count": len(rows),
        "rows": rows,
        "winning_config_name": winning_row.get("config_name", ""),
        "winning_score": winning_row.get("score", 0.0),
        "runner_up_name": runner_up_row.get("config_name", ""),
        "runner_up_score": runner_up_row.get("score", 0.0),
        "missing_candidates": sorted(dict.fromkeys(missing_rows)),
        "registry_id": registry.get("registry_id", ""),
        "is_complete": reason == "winning_config_contract_selected",
        "is_selected": reason == "winning_config_contract_selected",
        "should_warn": reason != "winning_config_contract_selected",
        "should_block": reason == "winning_config_contract_incomplete",
        "reason": reason,
    }


def build_experiment_population_splitter(
    *,
    population_rows: Sequence[Mapping[str, Any] | str] | None = None,
    experiment_key: str = "",
    allowed_splits: Sequence[Any] | None = None,
) -> Dict[str, Any]:
    experiment = str(experiment_key or "").strip().lower()
    allowed = [str(item).strip().lower() for item in (allowed_splits or ["holdout", "canary", "shadow", "mainline"]) if str(item).strip()]
    rows: List[Dict[str, Any]] = []
    split_counts = {name: 0 for name in allowed}
    unknown_rows: List[str] = []
    for idx, row in enumerate(population_rows or [], start=1):
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip()
            payload = {"name": text} if text else {}
        row_name = str(_first_nonempty(payload.get("name"), payload.get("id"), payload.get("sample_id"), f"sample_{idx}")).strip()
        raw_split = str(_first_nonempty(payload.get("split"), payload.get("population_split"), payload.get("cohort"), payload.get("group"), payload.get("reason"), row_name)).strip().lower()
        split = "unknown"
        for candidate in allowed:
            if candidate in raw_split:
                split = candidate
                break
        if split == "unknown":
            unknown_rows.append(row_name)
        else:
            split_counts[split] = split_counts.get(split, 0) + 1
        rows.append(
            {
                "name": row_name,
                "split": split,
                "source_split": raw_split,
                "is_known": split != "unknown",
            }
        )

    missing_splits = [name for name in allowed if split_counts.get(name, 0) == 0]
    split_id = _sha1_payload({"experiment_key": experiment, "rows": rows, "allowed_splits": allowed})[:16]
    if not rows:
        reason = "experiment_population_splitter_incomplete"
    elif unknown_rows:
        reason = "experiment_population_splitter_unknown_split"
    elif missing_splits:
        reason = "experiment_population_splitter_partial"
    else:
        reason = "experiment_population_splitter_complete"
    return {
        "schema_version": SCHEMA_VERSION,
        "split_id": split_id,
        "experiment_key": experiment,
        "allowed_splits": allowed,
        "rows": rows,
        "split_counts": split_counts,
        "missing_splits": missing_splits,
        "unknown_rows": unknown_rows,
        "is_complete": reason == "experiment_population_splitter_complete",
        "should_warn": reason != "experiment_population_splitter_complete",
        "should_block": reason == "experiment_population_splitter_unknown_split",
        "reason": reason,
    }


def build_experiment_metrics_isolation(
    *,
    metric_rows: Sequence[Mapping[str, Any] | str] | None = None,
    experiment_key: str = "",
    allowed_channels: Sequence[Any] | None = None,
) -> Dict[str, Any]:
    experiment = str(experiment_key or "").strip().lower()
    channels = [str(item).strip().lower() for item in (allowed_channels or ["research", "production", "shared"]) if str(item).strip()]
    rows: List[Dict[str, Any]] = []
    counts = {channel: 0 for channel in channels}
    leakage_rows: List[str] = []
    for idx, row in enumerate(metric_rows or [], start=1):
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip()
            payload = {"metric_name": text} if text else {}
        metric_name = str(_first_nonempty(payload.get("metric_name"), payload.get("name"), payload.get("key"), f"metric_{idx}")).strip()
        channel = str(_first_nonempty(payload.get("channel"), payload.get("bucket"), payload.get("source"), payload.get("kind"), "")).strip().lower()
        if channel not in counts:
            channel = "shared" if "shared" in counts else channels[0]
        value = payload.get("value", payload.get("metric_value"))
        if channel:
            counts[channel] = counts.get(channel, 0) + 1
        is_leak = bool(payload.get("is_leak") or payload.get("leak") or (channel == "production" and bool(payload.get("is_research"))))
        if is_leak:
            leakage_rows.append(metric_name)
        rows.append(
            {
                "metric_name": metric_name,
                "channel": channel,
                "value": value,
                "is_research": bool(payload.get("is_research", channel == "research")),
                "is_production": bool(payload.get("is_production", channel == "production")),
            }
        )

    research_count = counts.get("research", 0)
    production_count = counts.get("production", 0)
    shared_count = counts.get("shared", 0)
    if not rows:
        reason = "experiment_metrics_isolation_incomplete"
    elif leakage_rows:
        reason = "experiment_metrics_isolation_leak"
    elif research_count == 0:
        reason = "experiment_metrics_isolation_no_research_metrics"
    else:
        reason = "experiment_metrics_isolation_complete"
    isolation_id = _sha1_payload({"experiment_key": experiment, "rows": rows, "channels": channels})[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "isolation_id": isolation_id,
        "experiment_key": experiment,
        "rows": rows,
        "allowed_channels": channels,
        "channel_counts": counts,
        "leakage_rows": leakage_rows,
        "research_count": research_count,
        "production_count": production_count,
        "shared_count": shared_count,
        "is_complete": reason == "experiment_metrics_isolation_complete",
        "should_warn": reason != "experiment_metrics_isolation_complete",
        "should_block": reason == "experiment_metrics_isolation_leak",
        "reason": reason,
    }


def build_no_side_effect_experiment_mode(
    *,
    decision_payload: Mapping[str, Any] | None = None,
    side_effect_log: Sequence[Mapping[str, Any] | str] | None = None,
    expected_side_effect_map: Mapping[str, Any] | None = None,
    experiment_key: str = "",
) -> Dict[str, Any]:
    decision = dict(decision_payload or {})
    expected = dict(expected_side_effect_map or {})
    key = str(experiment_key or "").strip().lower()
    rows: List[Dict[str, Any]] = []
    observed_effects: List[str] = []
    for idx, item in enumerate(side_effect_log or [], start=1):
        if isinstance(item, Mapping):
            payload = dict(item)
        else:
            text = str(item or "").strip()
            payload = {"name": text} if text else {}
        effect_name = str(_first_nonempty(payload.get("effect_name"), payload.get("name"), payload.get("kind"), f"effect_{idx}")).strip().lower()
        observed_effects.append(effect_name)
        rows.append(
            {
                "effect_name": effect_name,
                "severity": str(_first_nonempty(payload.get("severity"), payload.get("impact"), "unknown")).strip().lower(),
                "is_side_effect": bool(payload.get("is_side_effect", True)),
            }
        )
    planned_actions = [str(item).strip() for item in (decision.get("planned_actions") or decision.get("actions") or []) if str(item).strip()]
    mode = str(_first_nonempty(decision.get("mode"), decision.get("execution_mode"), "shadow")).strip().lower()
    expected_effects = [str(item).strip().lower() for item in (expected.get("expected_effects") or expected.get("effects") or []) if str(item).strip()]
    if not key:
        reason = "no_side_effect_experiment_mode_missing_key"
    elif mode not in {"shadow", "dry_run", "observe_only", "simulate"}:
        reason = "no_side_effect_experiment_mode_invalid"
    elif observed_effects:
        reason = "no_side_effect_experiment_mode_leaked_effects"
    else:
        reason = "no_side_effect_experiment_mode_safe"
    mode_id = _sha1_payload(
        {
            "experiment_key": key,
            "mode": mode,
            "planned_actions": planned_actions,
            "expected_effects": expected_effects,
            "rows": rows,
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "mode_id": mode_id,
        "experiment_key": key,
        "mode": mode,
        "planned_actions": planned_actions,
        "expected_effects": expected_effects,
        "observed_effects": observed_effects,
        "rows": rows,
        "is_safe": reason == "no_side_effect_experiment_mode_safe",
        "should_warn": reason != "no_side_effect_experiment_mode_safe",
        "should_block": reason in {"no_side_effect_experiment_mode_invalid", "no_side_effect_experiment_mode_leaked_effects"},
        "reason": reason,
    }


def build_holdout_integrity_guard(
    *,
    holdout_rows: Sequence[Mapping[str, Any] | str] | None = None,
    tuning_rows: Sequence[Mapping[str, Any] | str] | None = None,
    holdout_key: str = "",
    tuning_key: str = "",
) -> Dict[str, Any]:
    holdout_hint = str(holdout_key or "").strip().lower()
    tuning_hint = str(tuning_key or "").strip().lower()

    def _collect_rows(rows: Sequence[Mapping[str, Any] | str] | None, default_kind: str) -> List[Dict[str, Any]]:
        collected: List[Dict[str, Any]] = []
        for row in rows or []:
            if isinstance(row, Mapping):
                collected.append(dict(row))
            else:
                text = str(row or "").strip()
                if text:
                    collected.append({"name": text, "reason": text})
        return collected

    holdout = _collect_rows(holdout_rows, "holdout")
    tuning = _collect_rows(tuning_rows, "tuning")
    holdout_ids = {
        str(_first_nonempty(row.get("sample_id"), row.get("id"), row.get("name"), row.get("row_id"), holdout_hint, "")).strip().lower()
        for row in holdout
        if str(_first_nonempty(row.get("sample_id"), row.get("id"), row.get("name"), row.get("row_id"), holdout_hint, "")).strip()
    }
    tuning_ids = {
        str(_first_nonempty(row.get("sample_id"), row.get("id"), row.get("name"), row.get("row_id"), tuning_hint, "")).strip().lower()
        for row in tuning
        if str(_first_nonempty(row.get("sample_id"), row.get("id"), row.get("name"), row.get("row_id"), tuning_hint, "")).strip()
    }
    overlap = sorted(holdout_ids & tuning_ids)
    guard_id = _sha1_payload(
        {
            "holdout_key": holdout_hint,
            "tuning_key": tuning_hint,
            "holdout_ids": sorted(holdout_ids),
            "tuning_ids": sorted(tuning_ids),
        }
    )[:16]
    if not holdout_ids or not tuning_ids:
        reason = "holdout_integrity_guard_incomplete"
    elif overlap:
        reason = "holdout_integrity_guard_leak"
    else:
        reason = "holdout_integrity_guard_complete"
    return {
        "schema_version": SCHEMA_VERSION,
        "guard_id": guard_id,
        "holdout_key": holdout_hint,
        "tuning_key": tuning_hint,
        "holdout_ids": sorted(holdout_ids),
        "tuning_ids": sorted(tuning_ids),
        "overlap_ids": overlap,
        "holdout_count": len(holdout_ids),
        "tuning_count": len(tuning_ids),
        "is_intact": reason == "holdout_integrity_guard_complete",
        "should_warn": reason != "holdout_integrity_guard_complete",
        "should_block": reason == "holdout_integrity_guard_leak",
        "reason": reason,
    }


def build_adoption_gate_contract(
    *,
    metric_rows: Sequence[Mapping[str, Any] | str] | None = None,
    watchlist_rows: Sequence[Mapping[str, Any] | str] | None = None,
    experiment_key: str = "",
) -> Dict[str, Any]:
    experiment = str(experiment_key or "").strip().lower()
    rows: List[Dict[str, Any]] = []
    watch_rows: List[Dict[str, Any]] = []
    for idx, row in enumerate(metric_rows or [], start=1):
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip()
            payload = {"metric_name": text} if text else {}
        metric_name = str(_first_nonempty(payload.get("metric_name"), payload.get("name"), payload.get("key"), f"metric_{idx}")).strip().lower()
        baseline = float(_first_nonempty(payload.get("baseline"), payload.get("baseline_value"), 0.0) or 0.0)
        candidate = float(_first_nonempty(payload.get("candidate"), payload.get("candidate_value"), 0.0) or 0.0)
        higher_is_better = bool(payload.get("higher_is_better", True))
        watchlist = bool(payload.get("watchlist", False))
        delta = round(candidate - baseline, 4)
        improved = delta > 0 if higher_is_better else delta < 0
        if watchlist:
            watch_rows.append(
                {
                    "metric_name": metric_name,
                    "baseline": round(baseline, 4),
                    "candidate": round(candidate, 4),
                    "delta": delta,
                }
            )
        rows.append(
            {
                "metric_name": metric_name,
                "baseline": round(baseline, 4),
                "candidate": round(candidate, 4),
                "delta": delta,
                "higher_is_better": higher_is_better,
                "watchlist": watchlist,
                "is_improved": improved,
            }
        )
    for idx, row in enumerate(watchlist_rows or [], start=1):
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip()
            payload = {"metric_name": text} if text else {}
        metric_name = str(_first_nonempty(payload.get("metric_name"), payload.get("name"), payload.get("key"), f"watch_{idx}")).strip().lower()
        baseline = float(_first_nonempty(payload.get("baseline"), payload.get("baseline_value"), 0.0) or 0.0)
        candidate = float(_first_nonempty(payload.get("candidate"), payload.get("candidate_value"), 0.0) or 0.0)
        delta = round(candidate - baseline, 4)
        watch_rows.append(
            {
                "metric_name": metric_name,
                "baseline": round(baseline, 4),
                "candidate": round(candidate, 4),
                "delta": delta,
            }
        )
    main_metric_rows = [row for row in rows if not row["watchlist"]]
    main_metric_failures = [row["metric_name"] for row in main_metric_rows if not row["is_improved"]]
    watchlist_harms = [row["metric_name"] for row in watch_rows if row["delta"] > 0]
    adoption_gate_id = _sha1_payload({"experiment_key": experiment, "rows": rows, "watch_rows": watch_rows})[:16]
    if not rows:
        reason = "adoption_gate_contract_incomplete"
    elif main_metric_failures:
        reason = "adoption_gate_contract_main_metric_regression"
    elif watchlist_harms:
        reason = "adoption_gate_contract_watchlist_regression"
    else:
        reason = "adoption_gate_contract_passed"
    return {
        "schema_version": SCHEMA_VERSION,
        "adoption_gate_id": adoption_gate_id,
        "experiment_key": experiment,
        "rows": rows,
        "watchlist_rows": watch_rows,
        "main_metric_failures": main_metric_failures,
        "watchlist_harms": watchlist_harms,
        "main_metric_count": len(main_metric_rows),
        "watchlist_count": len(watch_rows),
        "is_adoptable": reason == "adoption_gate_contract_passed",
        "should_warn": reason != "adoption_gate_contract_passed",
        "should_block": reason in {"adoption_gate_contract_incomplete", "adoption_gate_contract_main_metric_regression", "adoption_gate_contract_watchlist_regression"},
        "reason": reason,
    }


def build_experiment_explanation_packet(
    *,
    explanation_rows: Sequence[Mapping[str, Any] | str] | None = None,
    experiment_key: str = "",
    adoption_gate_contract: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    gate = dict(adoption_gate_contract or {})
    experiment = str(experiment_key or "").strip().lower()
    rows: List[Dict[str, Any]] = []
    changed_rows: List[str] = []
    benefit_rows: List[str] = []
    harm_rows: List[str] = []
    for idx, row in enumerate(explanation_rows or [], start=1):
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip()
            payload = {"name": text} if text else {}
        label = str(_first_nonempty(payload.get("name"), payload.get("reason"), payload.get("summary"), f"row_{idx}")).strip()
        changed = bool(payload.get("changed", payload.get("is_changed", False)))
        benefit = str(_first_nonempty(payload.get("benefit"), payload.get("gain"), payload.get("improvement"), "")).strip()
        harm = str(_first_nonempty(payload.get("harm"), payload.get("loss"), payload.get("risk"), "")).strip()
        if changed:
            changed_rows.append(label)
        if benefit:
            benefit_rows.append(label)
        if harm:
            harm_rows.append(label)
        rows.append(
            {
                "name": label,
                "changed": changed,
                "benefit": benefit,
                "harm": harm,
            }
        )
    gate_reasons = [str(item or "").strip() for item in (gate.get("main_metric_failures") or []) if str(item or "").strip()]
    if not rows:
        reason = "experiment_explanation_packet_incomplete"
    elif not changed_rows:
        reason = "experiment_explanation_packet_missing_change"
    elif not benefit_rows:
        reason = "experiment_explanation_packet_missing_benefit"
    elif gate_reasons:
        reason = "experiment_explanation_packet_gate_regression"
    else:
        reason = "experiment_explanation_packet_ready"
    packet_id = _sha1_payload({"experiment_key": experiment, "rows": rows, "gate_reasons": gate_reasons})[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "packet_id": packet_id,
        "experiment_key": experiment,
        "rows": rows,
        "changed_rows": changed_rows,
        "benefit_rows": benefit_rows,
        "harm_rows": harm_rows,
        "gate_reasons": gate_reasons,
        "is_ready": reason == "experiment_explanation_packet_ready",
        "should_warn": reason != "experiment_explanation_packet_ready",
        "should_block": reason in {"experiment_explanation_packet_incomplete", "experiment_explanation_packet_missing_change", "experiment_explanation_packet_missing_benefit", "experiment_explanation_packet_gate_regression"},
        "reason": reason,
    }


def build_experiment_abort_rule(
    *,
    signal_rows: Sequence[Mapping[str, Any] | str] | None = None,
    experiment_key: str = "",
    abort_threshold: float = 0.5,
) -> Dict[str, Any]:
    experiment = str(experiment_key or "").strip().lower()
    rows: List[Dict[str, Any]] = []
    triggered_reasons: List[str] = []
    for idx, row in enumerate(signal_rows or [], start=1):
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip()
            payload = {"name": text} if text else {}
        signal_name = str(_first_nonempty(payload.get("signal_name"), payload.get("name"), payload.get("reason"), f"signal_{idx}")).strip().lower()
        severity = float(_first_nonempty(payload.get("severity"), payload.get("score"), payload.get("risk"), 0.0) or 0.0)
        flagged = bool(payload.get("flagged", payload.get("should_abort", False)))
        if any(token in signal_name for token in ("drift", "side_effect", "side effect", "slowdown", "semantic", "regression")):
            flagged = True
        if severity >= float(abort_threshold or 0.0):
            flagged = True
        if flagged:
            triggered_reasons.append(signal_name or f"signal_{idx}")
        rows.append(
            {
                "signal_name": signal_name,
                "severity": round(severity, 4),
                "flagged": flagged,
            }
        )
    unique_triggers = sorted(dict.fromkeys(triggered_reasons))
    if not rows:
        reason = "experiment_abort_rule_incomplete"
    elif unique_triggers:
        reason = "experiment_abort_rule_abort"
    else:
        reason = "experiment_abort_rule_continue"
    abort_rule_id = _sha1_payload({"experiment_key": experiment, "rows": rows, "abort_threshold": float(abort_threshold or 0.0)})[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "abort_rule_id": abort_rule_id,
        "experiment_key": experiment,
        "rows": rows,
        "triggered_reasons": unique_triggers,
        "abort_threshold": round(float(abort_threshold or 0.0), 4),
        "is_aborting": reason == "experiment_abort_rule_abort",
        "should_warn": reason != "experiment_abort_rule_continue",
        "should_block": reason == "experiment_abort_rule_abort",
        "reason": reason,
    }


def build_migration_playbook_registry() -> Dict[str, Any]:
    registry = {
        str(name).strip(): {
            "target_schema_version": str(payload.get("target_schema_version") or "").strip(),
            "status": str(payload.get("status") or "").strip(),
            "steps": [str(step).strip() for step in list(payload.get("steps") or []) if str(step).strip()],
        }
        for name, payload in MIGRATION_PLAYBOOK_REGISTRY.items()
    }
    current_playbooks = sorted(name for name, payload in registry.items() if payload["status"] == "current")
    compat_playbooks = sorted(name for name, payload in registry.items() if payload["status"] == "compat")
    return {
        "schema_version": SCHEMA_VERSION,
        "registry": dict(sorted(registry.items())),
        "registry_size": len(registry),
        "current_playbooks": current_playbooks,
        "compat_playbooks": compat_playbooks,
        "has_legacy_support": bool(compat_playbooks),
        "registry_id": _sha1_payload(dict(sorted(registry.items())))[:16],
    }


def build_architecture_change_manifest(
    *,
    change_name: str = "",
    change_summary: str = "",
    touched_entities: Sequence[Any] | None = None,
    supported_downgrade_paths: Sequence[Any] | None = None,
) -> Dict[str, Any]:
    entities = [str(item).strip() for item in (touched_entities or []) if str(item).strip()]
    downgrade_paths = [str(item).strip() for item in (supported_downgrade_paths or []) if str(item).strip()]
    manifest = {
        "change_name": str(change_name or "").strip(),
        "change_summary": str(change_summary or "").strip(),
        "touched_entities": entities,
        "supported_downgrade_paths": downgrade_paths,
    }
    missing = [
        name
        for name in ["change_name", "change_summary", "touched_entities", "supported_downgrade_paths"]
        if not manifest.get(name)
    ]
    change_manifest_id = _sha1_payload(manifest)[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "change_manifest_id": change_manifest_id,
        "manifest": manifest,
        "missing_fields": missing,
        "is_complete": not missing,
    }


def build_change_scope_classifier(
    *,
    change_name: str = "",
    change_summary: str = "",
    touched_entities: Sequence[Any] | None = None,
) -> Dict[str, Any]:
    entity_text = " ".join(str(item or "").strip() for item in (touched_entities or []) if str(item or "").strip())
    corpus = " ".join(
        [
            str(change_name or "").strip().lower(),
            str(change_summary or "").strip().lower(),
            entity_text.lower(),
        ]
    )
    scope_keywords = [
        ("parser", ["parser", "parse", "ocr"]),
        ("executor", ["executor", "execute", "worker", "click", "action"]),
        ("benchmark", ["benchmark", "eval", "metric", "score"]),
        ("schema", ["schema", "contract", "manifest", "version"]),
        ("safety_policy", ["safety", "policy", "guard", "risk", "compliance"]),
    ]
    matched_scopes = [name for name, keywords in scope_keywords if any(keyword in corpus for keyword in keywords)]
    primary_scope = matched_scopes[0] if matched_scopes else "general"
    return {
        "schema_version": SCHEMA_VERSION,
        "primary_scope": primary_scope,
        "matched_scopes": matched_scopes,
        "is_cross_cutting": len(matched_scopes) > 1,
        "scope_count": len(matched_scopes),
        "corpus_fingerprint": _sha1_payload({"change_name": change_name, "change_summary": change_summary, "touched_entities": list(touched_entities or [])})[:16],
    }


def build_affected_contract_inventory(
    *,
    change_name: str = "",
    change_summary: str = "",
    touched_entities: Sequence[Any] | None = None,
    scope: str = "",
) -> Dict[str, Any]:
    entities = [str(item).strip() for item in (touched_entities or []) if str(item).strip()]
    scope_name = str(scope or "").strip().lower() or "general"
    base_contracts = sorted(
        {
            "architecture_change_manifest",
            "change_scope_classifier",
            "release_manifest",
            "compatibility_matrix",
            "schema_diff_alarm",
            "rollback_trigger_policy",
        }
    )
    matched_contracts: List[str] = list(base_contracts)
    for entity in entities:
        norm = entity.lower()
        if "parser" in norm or scope_name == "parser":
            matched_contracts.extend(["required_fields_contract", "missing_semantics_reason", "semantic_consistency_check"])
        if "executor" in norm or scope_name == "executor":
            matched_contracts.extend(["worker_task_packet", "worker_result_packet", "local_scope_lock"])
        if "benchmark" in norm or scope_name == "benchmark":
            matched_contracts.extend(["per_class_gate", "model_promotion_gate", "release_manifest"])
        if "schema" in norm or scope_name == "schema":
            matched_contracts.extend(["screen_state_schema_version_contract", "schema_diff_alarm", "build_self_describing_payload"])
        if "safety" in norm or "policy" in norm or scope_name == "safety_policy":
            matched_contracts.extend(["defer_action_policy", "uncertainty_escalation_packet", "rollback_trigger_policy"])
    deduped_contracts = sorted(dict.fromkeys(matched_contracts))
    return {
        "schema_version": SCHEMA_VERSION,
        "change_name": str(change_name or "").strip(),
        "change_summary": str(change_summary or "").strip(),
        "scope": scope_name,
        "touched_entities": entities,
        "contracts": deduped_contracts,
        "inventory_size": len(deduped_contracts),
        "inventory_id": _sha1_payload(
            {
                "change_name": change_name,
                "change_summary": change_summary,
                "scope": scope_name,
                "touched_entities": entities,
                "contracts": deduped_contracts,
            }
        )[:16],
    }


def build_compatibility_matrix(
    *,
    parser_version: str = "",
    classifier_version: str = "",
    planner_version: str = "",
    feature_version: str = "",
) -> Dict[str, Any]:
    parser = str(parser_version or "").strip()
    classifier = str(classifier_version or "").strip()
    planner = str(planner_version or "").strip()
    feature = str(feature_version or "").strip()

    # Compatibility key = major prefix before first dot/underscore.
    def _compat_key(value: str) -> str:
        text = value.strip().lower()
        if not text:
            return ""
        dot = text.split(".", 1)[0]
        return dot.split("_", 1)[0]

    keys = {
        "parser": _compat_key(parser),
        "classifier": _compat_key(classifier),
        "planner": _compat_key(planner),
        "feature": _compat_key(feature),
    }
    present_keys = [value for value in keys.values() if value]
    compatible = bool(present_keys) and len(set(present_keys)) == 1
    missing_components = [name for name, value in {"parser": parser, "classifier": classifier, "planner": planner, "feature": feature}.items() if not value]
    if missing_components:
        reason = "missing_component_versions"
    elif compatible:
        reason = "compatible_stack"
    else:
        reason = "version_family_mismatch"
    return {
        "schema_version": SCHEMA_VERSION,
        "is_compatible": compatible and not missing_components,
        "reason": reason,
        "versions": {
            "parser": parser,
            "classifier": classifier,
            "planner": planner,
            "feature": feature,
        },
        "compatibility_keys": keys,
        "missing_components": missing_components,
    }


def build_per_class_gate(
    *,
    class_scores: Mapping[str, Any] | None = None,
    class_targets: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    scores = {str(k): float(v) for k, v in dict(class_scores or {}).items()}
    targets = {str(k): float(v) for k, v in dict(class_targets or {}).items()}
    classes = sorted(set(scores) | set(targets))
    rows: List[Dict[str, Any]] = []
    failing: List[str] = []
    for name in classes:
        score = float(scores.get(name, 0.0))
        target = float(targets.get(name, 0.0))
        passed = score >= target
        rows.append(
            {
                "name": name,
                "score": round(score, 4),
                "target": round(target, 4),
                "passed": passed,
            }
        )
        if not passed:
            failing.append(name)
    return {
        "schema_version": SCHEMA_VERSION,
        "is_passing": not failing and bool(rows),
        "rows": rows,
        "failing_classes": failing,
        "class_count": len(rows),
    }


def build_runtime_canary_eval(
    *,
    sample_size: int = 0,
    success_count: int = 0,
    min_sample_size: int = 10,
    min_success_rate: float = 0.8,
) -> Dict[str, Any]:
    size = int(sample_size or 0)
    succ = int(success_count or 0)
    rate = (succ / size) if size > 0 else 0.0
    enough_samples = size >= int(min_sample_size or 0)
    passes = enough_samples and rate >= float(min_success_rate or 0.0)
    if not enough_samples:
        reason = "insufficient_sample_size"
    elif passes:
        reason = "canary_passed"
    else:
        reason = "success_rate_below_threshold"
    return {
        "schema_version": SCHEMA_VERSION,
        "sample_size": size,
        "success_count": succ,
        "success_rate": round(rate, 4),
        "min_sample_size": int(min_sample_size or 0),
        "min_success_rate": float(min_success_rate or 0.0),
        "is_passing": passes,
        "reason": reason,
    }


def build_rollback_trigger_policy(
    *,
    readback_fail_rate: float = 0.0,
    blocked_rate: float = 0.0,
    end_state_mismatch_rate: float = 0.0,
    max_readback_fail_rate: float = 0.2,
    max_blocked_rate: float = 0.25,
    max_end_state_mismatch_rate: float = 0.15,
) -> Dict[str, Any]:
    readback = float(readback_fail_rate or 0.0)
    blocked = float(blocked_rate or 0.0)
    mismatch = float(end_state_mismatch_rate or 0.0)
    reasons: List[str] = []
    if readback > float(max_readback_fail_rate):
        reasons.append("readback_fail_rate_exceeded")
    if blocked > float(max_blocked_rate):
        reasons.append("blocked_rate_exceeded")
    if mismatch > float(max_end_state_mismatch_rate):
        reasons.append("end_state_mismatch_rate_exceeded")
    should_rollback = bool(reasons)
    if not reasons:
        reasons.append("within_rollback_budget")
    return {
        "schema_version": SCHEMA_VERSION,
        "should_rollback": should_rollback,
        "reasons": reasons,
        "rates": {
            "readback_fail_rate": round(readback, 4),
            "blocked_rate": round(blocked, 4),
            "end_state_mismatch_rate": round(mismatch, 4),
        },
        "thresholds": {
            "max_readback_fail_rate": float(max_readback_fail_rate),
            "max_blocked_rate": float(max_blocked_rate),
            "max_end_state_mismatch_rate": float(max_end_state_mismatch_rate),
        },
    }


def build_last_known_good_registry(
    *,
    current_release_id: str = "",
    fallback_release_id: str = "",
    release_history: Sequence[Any] | None = None,
) -> Dict[str, Any]:
    current = str(current_release_id or "").strip()
    fallback = str(fallback_release_id or "").strip()
    history = [str(item or "").strip() for item in (release_history or []) if str(item or "").strip()]
    if fallback and fallback not in history:
        history.append(fallback)
    if current and current not in history:
        history.append(current)
    rollback_target = fallback or (history[-2] if len(history) >= 2 else "")
    has_safe_target = bool(rollback_target and rollback_target != current)
    return {
        "schema_version": SCHEMA_VERSION,
        "current_release_id": current,
        "fallback_release_id": fallback,
        "release_history": history,
        "rollback_target": rollback_target,
        "has_safe_target": has_safe_target,
    }


def build_error_taxonomy_registry(
    *,
    error_labels: Sequence[Any] | None = None,
) -> Dict[str, Any]:
    canonical_map = {
        "no_target": "E_NO_TARGET",
        "missing_target": "E_NO_TARGET",
        "target_conflict": "E_TARGET_CONFLICT",
        "conflict_target": "E_TARGET_CONFLICT",
        "timeout": "E_TIMEOUT",
        "unstable_ui": "E_UNSTABLE_UI",
        "risk_guard": "E_RISK_GUARD",
        "blocked": "E_BLOCKED",
    }
    rows: List[Dict[str, Any]] = []
    unknown: List[str] = []
    for label in error_labels or []:
        raw = str(label or "").strip().lower()
        code = canonical_map.get(raw, "E_UNKNOWN")
        if code == "E_UNKNOWN" and raw:
            unknown.append(raw)
        rows.append({"label": raw, "code": code})
    return {
        "schema_version": SCHEMA_VERSION,
        "rows": rows,
        "unknown_labels": sorted(set(unknown)),
        "has_unknown_labels": bool(unknown),
    }


def build_blocked_reason_catalog(
    *,
    blocked_reasons: Sequence[Any] | None = None,
) -> Dict[str, Any]:
    categories = {
        "no_target": "target_missing",
        "target_conflict": "target_conflict",
        "timeout": "timeout",
        "unstable_ui": "ui_instability",
        "risk_guard": "risk_guard",
    }
    rows: List[Dict[str, Any]] = []
    counts: Dict[str, int] = {}
    for reason in blocked_reasons or []:
        raw = str(reason or "").strip().lower()
        category = categories.get(raw, "other_blocked")
        rows.append({"reason": raw, "category": category})
        counts[category] = int(counts.get(category, 0) + 1)
    return {
        "schema_version": SCHEMA_VERSION,
        "rows": rows,
        "counts": counts,
        "unique_categories": sorted(counts.keys()),
    }


def build_root_cause_mapper(
    *,
    symptom: str = "",
) -> Dict[str, Any]:
    value = str(symptom or "").strip().lower()
    mapping = {
        "ocr_empty": "ocr",
        "ocr_timeout": "ocr",
        "parser_missing_question": "parser",
        "parser_invalid_structure": "parser",
        "model_low_confidence": "model",
        "model_class_mismatch": "model",
        "executor_click_miss": "executor",
        "executor_target_conflict": "executor",
        "site_validation_block": "site",
        "site_captcha_block": "site",
    }
    subsystem = mapping.get(value, "unknown")
    return {
        "schema_version": SCHEMA_VERSION,
        "symptom": value or "unknown_symptom",
        "root_cause_subsystem": subsystem,
        "is_mapped": subsystem != "unknown",
    }


def build_source_precedence_contract(
    *,
    controls_data: Mapping[str, Any] | None = None,
    screen_state: Mapping[str, Any] | None = None,
    page_state: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    active = _active_block(screen_state)
    mappings = {
        "selected_values": {"primary": "current_controls", "fallback": "screen_state"},
        "question_text": {"primary": "screen_state", "fallback": "current_controls"},
        "answer_bbox": {"primary": "screen_state", "fallback": "summary"},
        "next_bbox": {"primary": "screen_state" if active.get("next_bbox") else "page_state", "fallback": "summary"},
        "select_options": {"primary": "page_state" if page_state else "screen_state", "fallback": "current_controls"},
        "qid": {"primary": "current_controls" if controls_data else "page_state", "fallback": "screen_state"},
    }
    return {
        "schema_version": SCHEMA_VERSION,
        "fields": mappings,
    }


def build_wrong_context_recovery_policy(
    *,
    stop_reason: str = "",
    site_consistency_score: float = 1.0,
    active_url: str = "",
    expected_host: str = "",
    wrong_tab_detected: bool = False,
) -> Dict[str, Any]:
    reason = str(stop_reason or "").strip().lower()
    score = float(site_consistency_score or 0.0)
    host_expected = str(expected_host or "").strip().lower()
    host_active = str(active_url or "").strip().lower()
    if wrong_tab_detected or reason == "screen_wrong_tab":
        action = "refocus_tab"
        severity = "warning"
    elif host_expected and host_expected not in host_active:
        action = "pause_session"
        severity = "error"
    elif score < 0.4:
        action = "pause_session"
        severity = "error"
    elif score < 0.72:
        action = "retry_capture"
        severity = "warning"
    else:
        action = "continue"
        severity = "ok"
    return {
        "schema_version": SCHEMA_VERSION,
        "stop_reason": reason or "none",
        "site_consistency_score": round(score, 4),
        "active_url": active_url,
        "expected_host": expected_host,
        "wrong_tab_detected": bool(wrong_tab_detected),
        "recommended_action": action,
        "severity": severity,
    }


def _detect_language_from_text(text: str) -> str:
    lowered = _norm_text(text)
    if not lowered:
        return "unknown"
    polish_markers = ("czy", "ankieta", "pytanie", "odpowiedz", "wybierz", "dzieku")
    english_markers = ("question", "answer", "select", "survey", "thank you")
    if any(marker in lowered for marker in polish_markers) or any(ch in lowered for ch in "ąćęłńóśżź"):
        return "pl"
    if any(marker in lowered for marker in english_markers):
        return "en"
    return "unknown"


def build_session_language_contract(
    *,
    screen_state: Mapping[str, Any] | None = None,
    page_data: Mapping[str, Any] | None = None,
    page_state: Mapping[str, Any] | None = None,
    explicit_language: str = "",
) -> Dict[str, Any]:
    explicit = str(explicit_language or "").strip().lower()
    page_lang = _first_nonempty((page_data or {}).get("lang"), (page_state or {}).get("lang"))
    sample_text = _first_nonempty(
        (screen_state or {}).get("question_text"),
        (page_state or {}).get("pageText"),
        (page_data or {}).get("title"),
    )
    detected = explicit or page_lang or _detect_language_from_text(sample_text)
    return {
        "schema_version": SCHEMA_VERSION,
        "language": detected or "unknown",
        "source": "explicit" if explicit else ("page" if page_lang else "heuristic"),
        "sample_text": sample_text[:160],
    }


def build_locale_identity_resolver(
    *,
    screen_state: Mapping[str, Any] | None = None,
    page_data: Mapping[str, Any] | None = None,
    page_state: Mapping[str, Any] | None = None,
    explicit_language: str = "",
) -> Dict[str, Any]:
    explicit = str(explicit_language or "").strip().lower()
    page_lang = _first_nonempty((page_data or {}).get("lang"), (page_state or {}).get("lang"))
    sample_text = _first_nonempty(
        (screen_state or {}).get("question_text"),
        (page_state or {}).get("pageText"),
        (page_data or {}).get("title"),
    )
    language = explicit or page_lang or _detect_language_from_text(sample_text)
    lowered = _norm_text(sample_text)
    if language == "pl" or any(ch in lowered for ch in "ąćęłńóśźż"):
        alphabet = "latin_extended"
    elif any(ch.isalpha() for ch in sample_text):
        alphabet = "latin"
    else:
        alphabet = "unknown"
    region = language if language in {"pl", "en"} else "unknown"
    return {
        "schema_version": SCHEMA_VERSION,
        "language": language or "unknown",
        "alphabet": alphabet,
        "region": region,
        "source": "explicit" if explicit else ("page" if page_lang else "heuristic"),
        "sample_text": sample_text[:160],
        "locale_id": _sha1_payload({"language": language or "unknown", "alphabet": alphabet, "region": region})[:16],
    }


def build_page_locale_fingerprint(
    *,
    page_data: Mapping[str, Any] | None = None,
    page_state: Mapping[str, Any] | None = None,
    screen_state: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    page = dict(page_data or {})
    state = dict(page_state or {})
    screen = dict(screen_state or {})
    url = _first_nonempty(page.get("url"), state.get("url"))
    parsed = urlparse(url)
    host = str(parsed.hostname or "").strip().lower()
    path = str(parsed.path or "").strip().lower()
    lang = str(_first_nonempty(page.get("lang"), state.get("lang"), screen.get("lang"))).strip().lower()
    text = _first_nonempty(screen.get("question_text"), state.get("pageText"), page.get("title"))
    text_signature = _sha1_payload(_norm_text(text))[:12] if text else ""
    attrs = {
        "host": host,
        "path": path,
        "lang": lang or "unknown",
        "text_signature": text_signature,
    }
    return {
        "schema_version": SCHEMA_VERSION,
        "fingerprint": _sha1_payload(attrs)[:16],
        "attributes": attrs,
        "is_stable": bool(host and path and text_signature),
    }


def build_locale_confidence_score(
    *,
    locale_identity: Mapping[str, Any] | None = None,
    ocr_confidence: float | None = None,
    model_confidence: float | None = None,
    page_lang_confidence: float | None = None,
) -> Dict[str, Any]:
    identity = dict(locale_identity or {})
    language = str(identity.get("language") or "unknown").strip().lower()
    alphabet = str(identity.get("alphabet") or "unknown").strip().lower()
    locale_signal = 0.0
    signals: List[str] = []
    if language in {"pl", "en"}:
        locale_signal += 0.4
        signals.append("known_language")
    if alphabet in {"latin", "latin_extended"}:
        locale_signal += 0.2
        signals.append("known_alphabet")
    if identity.get("region") not in {"", "unknown", None}:
        locale_signal += 0.1
        signals.append("known_region")
    ocr = max(0.0, min(1.0, float(ocr_confidence if ocr_confidence is not None else 0.0)))
    model = max(0.0, min(1.0, float(model_confidence if model_confidence is not None else 0.0)))
    page = max(0.0, min(1.0, float(page_lang_confidence if page_lang_confidence is not None else 0.0)))
    weighted = (ocr * 0.35) + (model * 0.35) + (page * 0.15) + locale_signal
    score = max(0.0, min(1.0, weighted))
    if score >= 0.8:
        reason = "high_locale_confidence"
    elif score >= 0.55:
        reason = "medium_locale_confidence"
    else:
        reason = "low_locale_confidence"
    return {
        "schema_version": SCHEMA_VERSION,
        "score": round(score, 4),
        "reason": reason,
        "is_confident": score >= 0.8,
        "signals": signals,
        "components": {
            "ocr_confidence": round(ocr, 4),
            "model_confidence": round(model, 4),
            "page_lang_confidence": round(page, 4),
            "locale_signal": round(locale_signal, 4),
        },
        "locale_identity": identity,
    }


def build_text_normalization_pipeline(
    *,
    text: str = "",
) -> Dict[str, Any]:
    original = str(text or "")
    normalized = original
    normalized = normalized.replace("\r\n", "\n").replace("\r", "\n")
    normalized = normalized.translate(
        str.maketrans(
            {
                "\u2018": "'",
                "\u2019": "'",
                "\u201c": '"',
                "\u201d": '"',
                "\u2013": "-",
                "\u2014": "-",
                "\u00a0": " ",
                "\t": " ",
            }
        )
    )
    normalized = re.sub(r"\s+", " ", normalized, flags=re.UNICODE).strip()
    normalized = unicodedata.normalize("NFKC", normalized)
    return {
        "schema_version": SCHEMA_VERSION,
        "original_text": original,
        "normalized_text": normalized,
        "original_hash": _sha1_payload(original)[:16],
        "normalized_hash": _sha1_payload(normalized)[:16],
        "changed": normalized != original,
    }


def build_locale_aware_text_canonicalizer(
    *,
    text: str = "",
    locale: str = "",
) -> Dict[str, Any]:
    pipeline = build_text_normalization_pipeline(text=text)
    normalized = str(pipeline.get("normalized_text") or "")
    lowered = normalized.lower()
    decomposed = unicodedata.normalize("NFKD", lowered)
    stripped = "".join(ch for ch in decomposed if not unicodedata.combining(ch))
    canonical = re.sub(r"[^a-z0-9]+", " ", stripped, flags=re.IGNORECASE).strip()
    tokens = [token for token in canonical.split(" ") if token]
    return {
        "schema_version": SCHEMA_VERSION,
        "locale": str(locale or "").strip().lower() or "unknown",
        "original_text": str(text or ""),
        "normalized_text": normalized,
        "canonical_text": canonical,
        "tokens": tokens,
        "token_count": len(tokens),
        "is_locale_aware": bool(locale),
        "pipeline_hash": _sha1_payload({"normalized_text": normalized, "canonical_text": canonical, "locale": str(locale or "").strip().lower() or "unknown"})[:16],
    }


def build_text_corruption_detector(
    *,
    text: str = "",
    locale: str = "",
) -> Dict[str, Any]:
    original = str(text or "")
    pipeline = build_text_normalization_pipeline(text=original)
    canonical = build_locale_aware_text_canonicalizer(text=original, locale=locale)
    normalized = str(pipeline.get("normalized_text") or "")
    canonical_text = str(canonical.get("canonical_text") or "")
    original_alnum = sum(1 for ch in original if ch.isalnum())
    normalized_alnum = sum(1 for ch in normalized if ch.isalnum())
    token_count = int(canonical.get("token_count") or 0)
    symbol_count = sum(1 for ch in original if not ch.isalnum() and not ch.isspace())
    length = max(1, len(original))
    loss_ratio = 1.0 - (normalized_alnum / max(1, original_alnum))
    symbol_ratio = symbol_count / length
    short_token_penalty = 0.2 if token_count == 0 else 0.0
    corruption_score = max(0.0, min(1.0, (loss_ratio * 0.55) + (symbol_ratio * 0.35) + short_token_penalty))
    if corruption_score >= 0.65:
        reason = "text_highly_corrupted"
    elif corruption_score >= 0.35:
        reason = "text_partially_corrupted"
    else:
        reason = "text_ok"
    return {
        "schema_version": SCHEMA_VERSION,
        "corruption_score": round(corruption_score, 4),
        "is_corrupted": corruption_score >= 0.35,
        "reason": reason,
        "signals": {
            "original_alnum": original_alnum,
            "normalized_alnum": normalized_alnum,
            "token_count": token_count,
            "symbol_count": symbol_count,
            "loss_ratio": round(loss_ratio, 4),
            "symbol_ratio": round(symbol_ratio, 4),
        },
        "canonical_text": canonical_text,
        "normalized_text": normalized,
    }


def build_semantic_phrase_registry(
    *,
    locale: str = "",
) -> Dict[str, Any]:
    locale_key = str(locale or "").strip().lower() or "unknown"
    raw_phrases = {
        "next": ["dalej", "next", "continue", "kontynuuj"],
        "submit": ["submit", "wyślij", "wyslij", "zatwierdź", "zatwierdz", "send"],
        "required": ["required", "wymagane", "obowiązkowe", "obowiazkowe", "mandatory"],
        "invalid": ["invalid", "nieprawidłowe", "nieprawidlowe", "błąd", "blad"],
        "thank_you": ["thank you", "dziękujemy", "dziekujemy", "dziekujemy za odpowiedz"],
    }
    categories = {
        "next": "action_next",
        "submit": "action_submit",
        "required": "validation_required",
        "invalid": "validation_invalid",
        "thank_you": "terminal_thank_you",
    }
    entries: List[Dict[str, Any]] = []
    canonical_map: Dict[str, List[str]] = {}
    for category, phrases in raw_phrases.items():
        canonical_phrases: List[str] = []
        for phrase in phrases:
            canonical = build_locale_aware_text_canonicalizer(text=phrase, locale=locale_key)["canonical_text"]
            canonical_phrases.append(canonical)
            entries.append(
                {
                    "category": categories[category],
                    "phrase": phrase,
                    "canonical_phrase": canonical,
                    "locale": locale_key,
                }
            )
        canonical_map[categories[category]] = canonical_phrases
    return {
        "schema_version": SCHEMA_VERSION,
        "locale": locale_key,
        "entries": entries,
        "canonical_map": canonical_map,
        "registry_id": _sha1_payload({"locale": locale_key, "entries": entries})[:16],
    }


def build_multilingual_question_classifier(
    *,
    text: str = "",
    locale: str = "",
) -> Dict[str, Any]:
    locale_key = str(locale or "").strip().lower() or "unknown"
    original_text = str(text or "")
    canonical = build_locale_aware_text_canonicalizer(text=original_text, locale=locale_key)
    registry = build_semantic_phrase_registry(locale=locale_key)
    canonical_text = str(canonical.get("canonical_text") or "")
    tokens = list(canonical.get("tokens") or [])
    token_set = set(tokens)
    matches: List[Dict[str, Any]] = []

    class_map = {
        "action_next": "question_navigation_next",
        "action_submit": "question_navigation_submit",
        "validation_required": "question_validation_required",
        "validation_invalid": "question_validation_invalid",
        "terminal_thank_you": "question_terminal_thank_you",
    }

    def _score_phrase(phrase: str, phrase_tokens: Sequence[str]) -> float:
        if not canonical_text or not phrase:
            return 0.0
        if canonical_text == phrase:
            return 1.0
        if canonical_text.startswith(phrase) or phrase in canonical_text:
            return 0.82
        phrase_token_set = set(phrase_tokens)
        if not phrase_token_set:
            return 0.0
        overlap = len(token_set & phrase_token_set)
        if not overlap:
            return 0.0
        return min(0.78, overlap / max(1, len(phrase_token_set)))

    best: Dict[str, Any] = {}
    for entry in registry.get("entries") or []:
        if not isinstance(entry, Mapping):
            continue
        category = str(entry.get("category") or "").strip()
        phrase = str(entry.get("phrase") or "").strip()
        canonical_phrase = str(entry.get("canonical_phrase") or "").strip()
        phrase_tokens = list(build_locale_aware_text_canonicalizer(text=phrase, locale=locale_key).get("tokens") or [])
        score = _score_phrase(canonical_phrase, phrase_tokens)
        if score <= 0.0:
            continue
        matches.append(
            {
                "category": category,
                "phrase": phrase,
                "canonical_phrase": canonical_phrase,
                "score": round(score, 4),
            }
        )
        if not best or score > float(best.get("score") or 0.0):
            best = {
                "category": category,
                "phrase": phrase,
                "canonical_phrase": canonical_phrase,
                "score": score,
            }

    if not canonical_text:
        classification = "unknown_question"
        reason = "empty_text"
        confidence = 0.0
    elif best:
        classification = str(class_map.get(best["category"], "unknown_question"))
        if float(best["score"]) >= 0.95:
            reason = "exact_phrase_match"
        elif float(best["score"]) >= 0.8:
            reason = "direct_phrase_match"
        else:
            reason = "token_overlap_match"
        confidence = float(best["score"])
    else:
        classification = "unknown_question"
        reason = "no_locale_phrase_match"
        confidence = 0.15 if tokens else 0.0

    return {
        "schema_version": SCHEMA_VERSION,
        "locale": locale_key,
        "classification": classification,
        "question_kind": classification,
        "matched_category": _first_nonempty(best.get("category"), "unknown"),
        "matched_phrase": _first_nonempty(best.get("phrase")),
        "matched_canonical_phrase": _first_nonempty(best.get("canonical_phrase")),
        "confidence": round(confidence, 4),
        "reason": reason,
        "canonical_text": canonical_text,
        "tokens": tokens,
        "matches": matches,
        "registry_id": registry.get("registry_id"),
        "is_locale_aware": bool(canonical.get("is_locale_aware")),
    }


def build_validation_phrase_catalog(
    *,
    locale: str = "",
    layout_family: str = "questionnaire",
) -> Dict[str, Any]:
    locale_key = str(locale or "").strip().lower() or "unknown"
    layout_family_key = str(layout_family or "").strip().lower() or "questionnaire"
    locale_catalogs = {
        "pl": {
            "required": ["required", "wymagane", "obowiazkowe", "pole wymagane", "uzupelnij"],
            "invalid": ["invalid", "nieprawidlowe", "blad", "niepoprawne", "zly format"],
            "thank_you": ["dziekujemy", "dziekujemy za odpowiedz", "thank you"],
        },
        "en": {
            "required": ["required", "mandatory", "field required", "please fill out"],
            "invalid": ["invalid", "incorrect", "wrong format", "not valid"],
            "thank_you": ["thank you", "thanks for answering", "we appreciate your response"],
        },
    }
    base_catalog = locale_catalogs.get(locale_key)
    if base_catalog is None:
        base_catalog = {
            "required": locale_catalogs["en"]["required"] + locale_catalogs["pl"]["required"],
            "invalid": locale_catalogs["en"]["invalid"] + locale_catalogs["pl"]["invalid"],
            "thank_you": locale_catalogs["en"]["thank_you"] + locale_catalogs["pl"]["thank_you"],
        }
    entries: List[Dict[str, Any]] = []
    phrases_by_category: Dict[str, List[str]] = {}
    for category, phrases in base_catalog.items():
        canonical_phrases: List[str] = []
        for phrase in phrases:
            canonical = build_locale_aware_text_canonicalizer(text=phrase, locale=locale_key)["canonical_text"]
            canonical_phrases.append(canonical)
            entries.append(
                {
                    "category": category,
                    "phrase": phrase,
                    "canonical_phrase": canonical,
                    "locale": locale_key,
                    "layout_family": layout_family_key,
                }
            )
        phrases_by_category[category] = canonical_phrases
    return {
        "schema_version": SCHEMA_VERSION,
        "locale": locale_key,
        "layout_family": layout_family_key,
        "entries": entries,
        "phrases_by_category": phrases_by_category,
        "catalog_version": f"{locale_key}:{layout_family_key}:1",
        "catalog_id": _sha1_payload({"locale": locale_key, "layout_family": layout_family_key, "entries": entries})[:16],
    }


def build_locale_independent_control_semantics(
    *,
    screen_state: Mapping[str, Any] | None = None,
    ocr_data: Sequence[Mapping[str, Any] | str] | None = None,
    page_data: Mapping[str, Any] | None = None,
    locale: str = "",
) -> Dict[str, Any]:
    active = _active_block(screen_state)
    control_kind = str(_first_nonempty((screen_state or {}).get("control_kind"), active.get("control_kind"), "unknown")).strip().lower()
    locale_key = str(locale or "").strip().lower() or "unknown"
    ocr_rows: List[Dict[str, Any]] = []
    ocr_texts: List[str] = []
    ocr_confidences: List[float] = []
    ocr_boxes: List[List[int]] = []
    for row in ocr_data or []:
        if isinstance(row, str):
            text_value = row
            confidence = 0.0
            bbox = []
        elif isinstance(row, Mapping):
            text_value = _first_nonempty(row.get("text"), row.get("value"), row.get("label"))
            confidence = float(row.get("confidence") or row.get("score") or 0.0)
            bbox = list(row.get("bbox") or [])
        else:
            continue
        canonical = build_locale_aware_text_canonicalizer(text=text_value, locale=locale_key)
        ocr_rows.append(
            {
                "text": text_value,
                "canonical_text": canonical["canonical_text"],
                "confidence": round(confidence, 4),
                "bbox": bbox,
            }
        )
        if text_value:
            ocr_texts.append(str(text_value))
        if confidence > 0:
            ocr_confidences.append(confidence)
        if len(bbox) == 4:
            ocr_boxes.append([int(float(v)) for v in bbox])

    geometry_signals = {
        "has_next_bbox": bool(active.get("next_bbox") or (screen_state or {}).get("next_bbox")),
        "has_select_bbox": bool(active.get("select_bbox") or (screen_state or {}).get("select_bbox")),
        "has_input_bbox": bool(active.get("input_bbox") or (screen_state or {}).get("input_bbox")),
        "has_answer_bbox": bool(active.get("answer_bbox") or (screen_state or {}).get("answer_bbox")),
        "button_count": len([value for value in (active.get("buttons") or (screen_state or {}).get("buttons") or []) if value]),
        "ocr_box_count": len(ocr_boxes),
    }
    geometry_score = sum(1 for value in geometry_signals.values() if bool(value))
    text_score = len([text for text in ocr_texts if build_locale_aware_text_canonicalizer(text=text, locale=locale_key)["token_count"] > 0])
    control_semantics = "unknown"
    if control_kind in {"dropdown", "select", "combobox"} or geometry_signals["has_select_bbox"]:
        control_semantics = "dropdown_selection"
    elif control_kind in {"text", "textbox", "input"} or geometry_signals["has_input_bbox"]:
        control_semantics = "free_text_input"
    elif control_kind in {"single", "choice", "radio", "checkbox"} or geometry_signals["button_count"] > 0 or geometry_signals["has_answer_bbox"]:
        control_semantics = "discrete_choice"
    elif geometry_signals["has_next_bbox"]:
        control_semantics = "navigation_action"

    control_tokens = build_locale_aware_text_canonicalizer(text=" ".join(ocr_texts), locale=locale_key)["tokens"]
    locale_independent = bool(control_semantics != "unknown" and geometry_score > 0 and (text_score > 0 or len(control_tokens) > 0))
    if control_semantics == "unknown":
        reason = "insufficient_control_signals"
        confidence = 0.0
    elif locale_independent:
        reason = "geometry_and_ocr_agree"
        confidence = min(1.0, 0.35 + (geometry_score * 0.12) + (len(control_tokens) * 0.08) + (sum(ocr_confidences) / max(1, len(ocr_confidences))) * 0.25)
    else:
        reason = "locale_dependent_control"
        confidence = 0.25 if geometry_score or text_score else 0.0

    return {
        "schema_version": SCHEMA_VERSION,
        "locale": locale_key,
        "control_kind": control_kind,
        "control_semantics": control_semantics,
        "is_locale_independent": locale_independent,
        "reason": reason,
        "confidence": round(float(confidence), 4),
        "geometry_signals": geometry_signals,
        "ocr_rows": ocr_rows,
        "ocr_texts": ocr_texts,
        "control_tokens": control_tokens,
        "page_lang": _first_nonempty((page_data or {}).get("lang"), (screen_state or {}).get("lang"), locale_key),
    }


def build_minimal_locale_hint_packet(
    *,
    locale: str = "",
    screen_state: Mapping[str, Any] | None = None,
    page_data: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    locale_key = str(locale or "").strip().lower() or "unknown"
    phrase_registry = build_semantic_phrase_registry(locale=locale_key)
    validation_catalog = build_validation_phrase_catalog(locale=locale_key, layout_family="questionnaire")
    canonical_phrases = {
        "action_next": list((phrase_registry.get("canonical_map") or {}).get("action_next") or []),
        "action_submit": list((phrase_registry.get("canonical_map") or {}).get("action_submit") or []),
        "validation_required": list((validation_catalog.get("phrases_by_category") or {}).get("required") or []),
        "validation_invalid": list((validation_catalog.get("phrases_by_category") or {}).get("invalid") or []),
        "terminal_thank_you": list((validation_catalog.get("phrases_by_category") or {}).get("thank_you") or []),
    }
    active_locale = _first_nonempty(
        (page_data or {}).get("lang"),
        (screen_state or {}).get("lang"),
        (screen_state or {}).get("locale"),
        locale_key,
    )
    return {
        "schema_version": SCHEMA_VERSION,
        "locale": locale_key,
        "active_locale": str(active_locale or "").strip().lower() or locale_key,
        "has_hint": True,
        "reason": "minimal_locale_hint_ready",
        "hint": {
            "locale": locale_key,
            "active_locale": str(active_locale or "").strip().lower() or locale_key,
            "phrase_registry_id": phrase_registry.get("registry_id"),
            "validation_catalog_id": validation_catalog.get("catalog_id"),
            "keywords": {
                "next": canonical_phrases["action_next"][:4],
                "submit": canonical_phrases["action_submit"][:4],
                "required": canonical_phrases["validation_required"][:4],
                "invalid": canonical_phrases["validation_invalid"][:4],
                "thank_you": canonical_phrases["terminal_thank_you"][:4],
            },
            "control_kind": _first_nonempty((screen_state or {}).get("control_kind"), "unknown"),
            "control_semantics": _first_nonempty((screen_state or {}).get("control_semantics"), "unknown"),
        },
        "signals": {
            "locale_available": locale_key != "unknown",
            "active_locale_available": bool(active_locale),
            "has_phrase_registry": bool(phrase_registry.get("entries")),
            "has_validation_catalog": bool(validation_catalog.get("entries")),
        },
    }


def build_locale_coverage_matrix(
    *,
    coverage_records: Sequence[Mapping[str, Any]] | None = None,
    expected_locales: Sequence[Any] | None = None,
    expected_modules: Sequence[Any] | None = None,
    expected_scenarios: Sequence[Any] | None = None,
    min_coverage: float = 0.5,
) -> Dict[str, Any]:
    expected_locale_list = [str(item or "").strip().lower() for item in (expected_locales or []) if str(item or "").strip()]
    expected_module_list = [str(item or "").strip().lower() for item in (expected_modules or []) if str(item or "").strip()]
    expected_scenario_list = [str(item or "").strip().lower() for item in (expected_scenarios or []) if str(item or "").strip()]
    grouped: Dict[str, Dict[str, Any]] = {}
    for record in coverage_records or []:
        if not isinstance(record, Mapping):
            continue
        locale_key = str(_first_nonempty(record.get("locale"), record.get("language"), "unknown")).strip().lower() or "unknown"
        module_key = str(_first_nonempty(record.get("module"), record.get("name"), record.get("component"), "")).strip().lower()
        scenario_key = str(_first_nonempty(record.get("scenario"), record.get("case"), record.get("test"), "")).strip().lower()
        passed = bool(record.get("passed", record.get("covered", False)))
        bucket = grouped.setdefault(
            locale_key,
            {
                "locale": locale_key,
                "modules": set(),
                "passed_modules": set(),
                "scenarios": set(),
                "passed_scenarios": set(),
                "records": [],
            },
        )
        bucket["records"].append({"module": module_key, "scenario": scenario_key, "passed": passed})
        if module_key:
            bucket["modules"].add(module_key)
            if passed:
                bucket["passed_modules"].add(module_key)
        if scenario_key:
            bucket["scenarios"].add(scenario_key)
            if passed:
                bucket["passed_scenarios"].add(scenario_key)

    rows: List[Dict[str, Any]] = []
    locales_in_matrix = sorted(set(expected_locale_list) | set(grouped.keys()))
    for locale_key in locales_in_matrix:
        bucket = grouped.get(
            locale_key,
            {
                "locale": locale_key,
                "modules": set(),
                "passed_modules": set(),
                "scenarios": set(),
                "passed_scenarios": set(),
                "records": [],
            },
        )
        module_coverage = (len(bucket["passed_modules"] & set(expected_module_list)) / len(expected_module_list)) if expected_module_list else (len(bucket["passed_modules"]) / len(bucket["modules"])) if bucket["modules"] else 0.0
        scenario_coverage = (len(bucket["passed_scenarios"] & set(expected_scenario_list)) / len(expected_scenario_list)) if expected_scenario_list else (len(bucket["passed_scenarios"]) / len(bucket["scenarios"])) if bucket["scenarios"] else 0.0
        coverage_score = round((module_coverage + scenario_coverage) / 2.0, 4)
        missing_modules = sorted(set(expected_module_list) - set(bucket["passed_modules"]))
        missing_scenarios = sorted(set(expected_scenario_list) - set(bucket["passed_scenarios"]))
        rows.append(
            {
                "locale": locale_key,
                "coverage_score": coverage_score,
                "module_coverage": round(module_coverage, 4),
                "scenario_coverage": round(scenario_coverage, 4),
                "covered_modules": sorted(bucket["passed_modules"]),
                "covered_scenarios": sorted(bucket["passed_scenarios"]),
                "missing_modules": missing_modules,
                "missing_scenarios": missing_scenarios,
                "is_covered": coverage_score >= float(min_coverage),
            }
        )
    rows.sort(key=lambda item: (item["coverage_score"], item["locale"]), reverse=True)
    uncovered_locales = [row["locale"] for row in rows if not row["is_covered"]]
    return {
        "schema_version": SCHEMA_VERSION,
        "rows": rows,
        "expected_locales": expected_locale_list,
        "expected_modules": expected_module_list,
        "expected_scenarios": expected_scenario_list,
        "min_coverage": round(float(min_coverage), 4),
        "is_complete": not uncovered_locales and bool(rows),
        "covered_locale_count": sum(1 for row in rows if row["is_covered"]),
        "uncovered_locales": uncovered_locales,
        "matrix_id": _sha1_payload({"rows": rows, "expected_locales": expected_locale_list, "expected_modules": expected_module_list, "expected_scenarios": expected_scenario_list})[:16],
    }


def build_cross_locale_regression_gate(
    *,
    coverage_matrix: Mapping[str, Any] | None = None,
    required_locales: Sequence[Any] | None = None,
    min_coverage: float = 0.75,
) -> Dict[str, Any]:
    matrix = dict(coverage_matrix or {})
    required_locale_list = [str(item or "").strip().lower() for item in (required_locales or []) if str(item or "").strip()]
    row_map = {}
    for row in matrix.get("rows") or []:
        if not isinstance(row, Mapping):
            continue
        locale_key = str(row.get("locale") or "").strip().lower()
        if locale_key:
            row_map[locale_key] = dict(row)
    locales_to_check = required_locale_list or list(row_map.keys())
    failures: List[str] = []
    for locale_key in locales_to_check:
        row = row_map.get(locale_key)
        if row is None:
            failures.append(f"missing_locale:{locale_key}")
            continue
        coverage_score = float(row.get("coverage_score") or 0.0)
        if coverage_score < float(min_coverage):
            failures.append(f"low_coverage:{locale_key}:{round(coverage_score, 4)}")
        if row.get("missing_modules"):
            failures.append(f"missing_modules:{locale_key}:{','.join(str(item) for item in row.get('missing_modules') or [])}")
        if row.get("missing_scenarios"):
            failures.append(f"missing_scenarios:{locale_key}:{','.join(str(item) for item in row.get('missing_scenarios') or [])}")
    should_block = bool(failures)
    return {
        "schema_version": SCHEMA_VERSION,
        "should_block": should_block,
        "reason": "cross_locale_regression_detected" if should_block else "cross_locale_coverage_ok",
        "required_locales": locales_to_check,
        "min_coverage": round(float(min_coverage), 4),
        "failures": failures,
        "coverage_matrix_id": matrix.get("matrix_id"),
        "covered_locale_count": int(matrix.get("covered_locale_count") or 0),
    }


def build_per_locale_ocr_quality_baseline(
    *,
    locale_metrics: Sequence[Mapping[str, Any]] | None = None,
    min_recall: float = 0.8,
    max_corruption: float = 0.25,
    max_latency_ms: float = 1200.0,
) -> Dict[str, Any]:
    rows: List[Dict[str, Any]] = []
    for metric in locale_metrics or []:
        if not isinstance(metric, Mapping):
            continue
        locale_key = str(_first_nonempty(metric.get("locale"), metric.get("language"), "unknown")).strip().lower() or "unknown"
        recall = max(0.0, min(1.0, float(metric.get("recall") or metric.get("recall_rate") or 0.0)))
        corruption = max(0.0, min(1.0, float(metric.get("corruption") or metric.get("corruption_rate") or 0.0)))
        latency_ms = max(0.0, float(metric.get("latency_ms") or metric.get("latency") or 0.0))
        meets_recall = recall >= float(min_recall)
        meets_corruption = corruption <= float(max_corruption)
        meets_latency = latency_ms <= float(max_latency_ms)
        stable = bool(meets_recall and meets_corruption and meets_latency)
        rows.append(
            {
                "locale": locale_key,
                "recall": round(recall, 4),
                "corruption": round(corruption, 4),
                "latency_ms": round(latency_ms, 4),
                "meets_recall": meets_recall,
                "meets_corruption": meets_corruption,
                "meets_latency": meets_latency,
                "is_stable": stable,
                "reasons": [
                    reason
                    for reason, passed in (
                        ("recall_too_low", meets_recall),
                        ("corruption_too_high", meets_corruption),
                        ("latency_too_high", meets_latency),
                    )
                    if not passed
                ],
            }
        )
    rows.sort(key=lambda item: (item["is_stable"], item["locale"]), reverse=True)
    unstable_locales = [row["locale"] for row in rows if not row["is_stable"]]
    return {
        "schema_version": SCHEMA_VERSION,
        "rows": rows,
        "min_recall": round(float(min_recall), 4),
        "max_corruption": round(float(max_corruption), 4),
        "max_latency_ms": round(float(max_latency_ms), 4),
        "is_baseline_met": not unstable_locales and bool(rows),
        "unstable_locales": unstable_locales,
        "stable_locale_count": sum(1 for row in rows if row["is_stable"]),
        "baseline_id": _sha1_payload({"rows": rows, "min_recall": float(min_recall), "max_corruption": float(max_corruption), "max_latency_ms": float(max_latency_ms)})[:16],
    }


def build_unknown_locale_fallback_policy(
    *,
    locale: str = "",
    page_data: Mapping[str, Any] | None = None,
    confidence: float = 0.0,
    evidence_strength: float = 0.0,
) -> Dict[str, Any]:
    locale_key = str(locale or "").strip().lower() or "unknown"
    page_locale = str(_first_nonempty((page_data or {}).get("lang"), (page_data or {}).get("locale"), locale_key)).strip().lower() or "unknown"
    conf = max(0.0, min(1.0, float(confidence or 0.0)))
    evidence = max(0.0, min(1.0, float(evidence_strength or 0.0)))
    is_unknown = locale_key == "unknown" or page_locale == "unknown"
    if is_unknown and conf < 0.45 and evidence < 0.45:
        action = "observe_only"
        reason = "unknown_locale_observe_only"
        autonomy = "restricted"
        allowed_actions = ["observe", "defer", "escalate"]
    elif is_unknown:
        action = "defer_and_observe"
        reason = "unknown_locale_defer"
        autonomy = "restricted"
        allowed_actions = ["observe", "defer", "escalate"]
    else:
        action = "proceed_normally"
        reason = "known_locale"
        autonomy = "normal"
        allowed_actions = ["observe", "act", "defer", "escalate"]
    return {
        "schema_version": SCHEMA_VERSION,
        "locale": locale_key,
        "page_locale": page_locale,
        "action": action,
        "reason": reason,
        "autonomy_level": autonomy,
        "allowed_actions": allowed_actions,
        "confidence": round(conf, 4),
        "evidence_strength": round(evidence, 4),
        "is_restricted": autonomy == "restricted",
    }


def build_payload_semantics_contract(
    *,
    answer_payload: Mapping[str, Any] | None,
    screen_state: Mapping[str, Any] | None,
    resolved_answer: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    active = _active_block(screen_state)
    control_kind = _first_nonempty((screen_state or {}).get("control_kind"), active.get("control_kind")) or "choice"
    selected_values = list((answer_payload or {}).get("selected_values") or (answer_payload or {}).get("values") or [])
    text_value = _first_nonempty((answer_payload or {}).get("text"), (answer_payload or {}).get("text_answer"))
    violations: List[str] = []
    options_norm = {_norm_text(value) for value in _option_values(screen_state)}
    if selected_values:
        for value in selected_values:
            if options_norm and _norm_text(value) not in options_norm:
                violations.append(f"unknown_option:{value}")
    if control_kind == "text" and text_value == "":
        violations.append("missing_text_value")
    if control_kind != "text" and text_value:
        violations.append("unexpected_text_value")
    if control_kind in {"single", "choice"} and len(selected_values) > 1:
        violations.append("too_many_values_for_single")
    if control_kind.startswith("dropdown") and not (active.get("select_bbox") or (screen_state or {}).get("select_bbox")):
        violations.append("missing_select_target")
    if control_kind == "text" and not (active.get("input_bbox") or (screen_state or {}).get("input_bbox")):
        violations.append("missing_input_target")
    return {
        "schema_version": SCHEMA_VERSION,
        "ok": not violations,
        "control_kind": control_kind,
        "resolved_source": _first_nonempty((resolved_answer or {}).get("source")),
        "violations": violations,
    }


def build_runtime_decision_payload_contract(decision_payload: Mapping[str, Any] | None) -> Dict[str, Any]:
    payload = dict(decision_payload or {}) if isinstance(decision_payload, Mapping) else {}
    screen_state = payload.get("screen_state") if isinstance(payload.get("screen_state"), Mapping) else None
    region_payload = payload.get("region_payload") if isinstance(payload.get("region_payload"), Mapping) else None
    actions = payload.get("actions") if isinstance(payload.get("actions"), list) else None
    resolved_answer = payload.get("resolved_answer") if isinstance(payload.get("resolved_answer"), Mapping) else {}
    trace = payload.get("trace") if isinstance(payload.get("trace"), Mapping) else {}

    violations: List[str] = []
    if not isinstance(decision_payload, Mapping):
        violations.append("decision_payload_not_mapping")
    if screen_state is None:
        violations.append("missing_screen_state_dict")
    if region_payload is None:
        violations.append("missing_region_payload_dict")
    if actions is None:
        violations.append("missing_actions_list")
    elif any(not isinstance(action, Mapping) for action in actions):
        violations.append("non_mapping_action_entry")
    if "resolved_answer" in payload and not isinstance(payload.get("resolved_answer"), Mapping):
        violations.append("invalid_resolved_answer_dict")
    if "trace" in payload and not isinstance(payload.get("trace"), Mapping):
        violations.append("invalid_trace_dict")

    screen_signature = _first_nonempty((screen_state or {}).get("screen_signature"))
    if not screen_signature:
        violations.append("missing_screen_signature")

    return {
        "schema_version": SCHEMA_VERSION,
        "ok": not violations,
        "violations": violations,
        "screen_signature": screen_signature,
        "screen_state": dict(screen_state or {}),
        "region_payload": dict(region_payload or {}),
        "actions": [dict(action) for action in (actions or []) if isinstance(action, Mapping)],
        "resolved_answer": dict(resolved_answer or {}),
        "trace": dict(trace or {}),
    }


def build_state_freshness_marker(
    *,
    screen_ts: float | None,
    network_ts: float | None = None,
    checkpoint_ts: float | None = None,
    now_ts: float | None = None,
    max_age_s: float = 8.0,
) -> Dict[str, Any]:
    now = float(now_ts if now_ts is not None else time.time())
    ages = {
        "screen_age_s": None if screen_ts is None else round(now - float(screen_ts), 4),
        "network_age_s": None if network_ts is None else round(now - float(network_ts), 4),
        "checkpoint_age_s": None if checkpoint_ts is None else round(now - float(checkpoint_ts), 4),
    }
    stale_reasons = [key for key, value in ages.items() if value is not None and value > float(max_age_s)]
    freshness = {
        key.replace("_age_s", "_fresh"): (value is not None and value <= float(max_age_s))
        for key, value in ages.items()
    }
    return {
        "schema_version": SCHEMA_VERSION,
        "ages": ages,
        "freshness": freshness,
        "is_fresh": not stale_reasons,
        "stale_reasons": stale_reasons,
        "max_age_s": float(max_age_s),
    }


def build_temporal_state_contract(
    *,
    screen_ts: float | None = None,
    session_ts: float | None = None,
    local_offset_s: float | None = None,
    now_ts: float | None = None,
    max_screen_age_s: float = 8.0,
    max_session_age_s: float = 120.0,
) -> Dict[str, Any]:
    now = float(now_ts if now_ts is not None else time.time())
    screen_age_s = None if screen_ts is None else round(now - float(screen_ts), 4)
    session_age_s = None if session_ts is None else round(now - float(session_ts), 4)
    offset_s = float(local_offset_s or 0.0)
    screen_is_fresh = screen_age_s is None or screen_age_s <= float(max_screen_age_s)
    session_is_fresh = session_age_s is None or session_age_s <= float(max_session_age_s)
    temporal_sensitive = not screen_is_fresh or not session_is_fresh or abs(offset_s) >= 60.0
    stale_reasons: List[str] = []
    if screen_age_s is not None and screen_age_s > float(max_screen_age_s):
        stale_reasons.append("screen_age")
    if session_age_s is not None and session_age_s > float(max_session_age_s):
        stale_reasons.append("session_age")
    if abs(offset_s) >= 60.0:
        stale_reasons.append("clock_offset")
    if temporal_sensitive:
        reason = "temporal_state_sensitive"
    else:
        reason = "temporal_state_stable"
    temporal_id = _sha1_payload(
        {
            "screen_age_s": screen_age_s,
            "session_age_s": session_age_s,
            "local_offset_s": round(offset_s, 4),
            "temporal_sensitive": temporal_sensitive,
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "temporal_id": temporal_id,
        "screen_age_s": screen_age_s,
        "session_age_s": session_age_s,
        "local_offset_s": round(offset_s, 4),
        "max_screen_age_s": float(max_screen_age_s),
        "max_session_age_s": float(max_session_age_s),
        "is_screen_fresh": screen_is_fresh,
        "is_session_fresh": session_is_fresh,
        "is_temporal_sensitive": temporal_sensitive,
        "stale_reasons": stale_reasons,
        "reason": reason,
    }


def build_clock_alignment_estimator(
    *,
    browser_ts: float | None = None,
    server_ts: float | None = None,
    trace_ts: float | None = None,
    now_ts: float | None = None,
    max_drift_s: float = 2.5,
) -> Dict[str, Any]:
    now = float(now_ts if now_ts is not None else time.time())
    browser_age_s = None if browser_ts is None else round(now - float(browser_ts), 4)
    server_age_s = None if server_ts is None else round(now - float(server_ts), 4)
    trace_age_s = None if trace_ts is None else round(now - float(trace_ts), 4)
    ages = [value for value in (browser_age_s, server_age_s, trace_age_s) if value is not None]
    drift_s = 0.0 if not ages else round(max(ages) - min(ages), 4)
    aligned = drift_s <= float(max_drift_s)
    if aligned:
        reason = "clock_aligned"
    elif drift_s <= float(max_drift_s) * 2:
        reason = "clock_soft_drift"
    else:
        reason = "clock_severe_drift"
    drift_id = _sha1_payload(
        {
            "browser_age_s": browser_age_s,
            "server_age_s": server_age_s,
            "trace_age_s": trace_age_s,
            "drift_s": drift_s,
            "max_drift_s": float(max_drift_s),
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "drift_id": drift_id,
        "browser_age_s": browser_age_s,
        "server_age_s": server_age_s,
        "trace_age_s": trace_age_s,
        "clock_drift_s": drift_s,
        "max_drift_s": float(max_drift_s),
        "is_aligned": aligned,
        "reason": reason,
        "is_soft_drift": reason == "clock_soft_drift",
        "is_severe_drift": reason == "clock_severe_drift",
    }


def build_temporal_risk_hint(
    *,
    temporal_state: Mapping[str, Any] | None = None,
    freshness_marker: Mapping[str, Any] | None = None,
    task_kind: str = "",
    urgency_hint: str = "",
) -> Dict[str, Any]:
    temporal = dict(temporal_state or {})
    freshness = dict(freshness_marker or {})
    task = str(task_kind or "").strip().lower() or "unknown"
    urgency = str(urgency_hint or "").strip().lower()
    temporal_sensitive = bool(temporal.get("is_temporal_sensitive")) or not bool(freshness.get("is_fresh", True))
    stale_reasons = list(dict.fromkeys([str(item).strip().lower() for item in temporal.get("stale_reasons") or [] if str(item or "").strip()] + [str(item).strip().lower() for item in freshness.get("stale_reasons") or [] if str(item or "").strip()]))
    if urgency in {"urgent", "high", "critical"}:
        risk_score = 0.85 if temporal_sensitive else 0.55
    elif urgency in {"low", "relaxed", "defer"}:
        risk_score = 0.35 if temporal_sensitive else 0.15
    else:
        risk_score = 0.7 if temporal_sensitive else 0.2
    if risk_score >= 0.75:
        risk_level = "high"
        reason = "temporal_risk_high"
    elif risk_score >= 0.4:
        risk_level = "medium"
        reason = "temporal_risk_medium"
    else:
        risk_level = "low"
        reason = "temporal_risk_low"
    hint_id = _sha1_payload(
        {
            "task_kind": task,
            "urgency_hint": urgency,
            "risk_score": round(risk_score, 4),
            "temporal_sensitive": temporal_sensitive,
            "stale_reasons": stale_reasons,
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "hint_id": hint_id,
        "task_kind": task,
        "urgency_hint": urgency or "normal",
        "temporal_sensitive": temporal_sensitive,
        "stale_reasons": stale_reasons,
        "risk_score": round(risk_score, 4),
        "risk_level": risk_level,
        "reason": reason,
        "should_prioritize_now": risk_level == "high" or bool(temporal_sensitive and urgency in {"urgent", "high", "critical"}),
        "should_defer": risk_level == "low" and not temporal_sensitive,
        "should_recheck_before_action": temporal_sensitive,
    }


def build_session_expiry_detector(
    *,
    screen_state: Mapping[str, Any] | None = None,
    page_state: Mapping[str, Any] | None = None,
    banner_text: str = "",
    auth_state: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    screen = dict(screen_state or {})
    page = dict(page_state or {})
    auth = dict(auth_state or {})
    text = " ".join(
        filter(
            None,
            [
                str(banner_text or "").strip(),
                str(_first_nonempty(screen.get("banner_text"), page.get("banner_text"), page.get("message"), "")).strip(),
                str(_first_nonempty(auth.get("status"), auth.get("reason"), auth.get("message"), "")).strip(),
            ],
        )
    ).strip()
    lowered = _norm_text(text)
    expiry_signals = {
        "auth_expiry": any(token in lowered for token in ("expired", "expiry", "session expired", "token expired", "logged out", "reauth")),
        "timeout_business": any(token in lowered for token in ("timeout", "timed out", "expired", "session expired")),
        "expiration_banner": any(token in lowered for token in ("expired", "expiry", "session expired", "expiration", "timeout")),
    }
    detected = any(expiry_signals.values())
    if expiry_signals["auth_expiry"]:
        reason = "auth_expiry_detected"
    elif expiry_signals["timeout_business"]:
        reason = "timeout_detected"
    elif expiry_signals["expiration_banner"]:
        reason = "expiration_banner_detected"
    else:
        reason = "no_expiry_detected"
    detector_id = _sha1_payload(
        {
            "text": lowered,
            "auth_state": sorted(auth.keys()),
            "screen_keys": sorted(screen.keys()),
            "page_keys": sorted(page.keys()),
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "detector_id": detector_id,
        "banner_text": text,
        "lowered_text": lowered,
        "expiry_signals": expiry_signals,
        "is_expired": detected,
        "reason": reason,
        "has_auth_expiry": expiry_signals["auth_expiry"],
        "has_timeout_business": expiry_signals["timeout_business"],
        "has_expiration_banner": expiry_signals["expiration_banner"],
    }


def build_cooldown_policy_registry(
    *,
    submit_seconds: float = 0.0,
    save_seconds: float = 0.0,
    validate_seconds: float = 0.0,
    max_seconds: float = 15.0,
) -> Dict[str, Any]:
    submit = max(0.0, float(submit_seconds or 0.0))
    save = max(0.0, float(save_seconds or 0.0))
    validate = max(0.0, float(validate_seconds or 0.0))
    windows = {
        "submit": submit,
        "save": save,
        "validate": validate,
    }
    max_window = max(windows.values()) if windows else 0.0
    if max_window <= 2.0:
        tier = "short"
        reason = "short_cooldown_windows"
    elif max_window <= float(max_seconds):
        tier = "normal"
        reason = "normal_cooldown_windows"
    else:
        tier = "extended"
        reason = "extended_cooldown_windows"
    registry_id = _sha1_payload(
        {
            "submit": submit,
            "save": save,
            "validate": validate,
            "max_seconds": float(max_seconds),
            "tier": tier,
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "registry_id": registry_id,
        "cooldown_windows_s": windows,
        "max_window_s": round(max_window, 4),
        "max_seconds": float(max_seconds),
        "cooldown_tier": tier,
        "reason": reason,
        "should_pause_before_submit": submit > 0.0,
        "should_pause_before_save": save > 0.0,
        "should_pause_before_validate": validate > 0.0,
        "is_extended": tier == "extended",
        "is_short": tier == "short",
    }


def build_wait_phase_classifier(
    *,
    screen_state: Mapping[str, Any] | None = None,
    page_state: Mapping[str, Any] | None = None,
    network_state: Mapping[str, Any] | None = None,
    elapsed_seconds: float = 0.0,
) -> Dict[str, Any]:
    screen = dict(screen_state or {})
    page = dict(page_state or {})
    network = dict(network_state or {})
    text_blob = " ".join(
        filter(
            None,
            [
                str(_first_nonempty(screen.get("status_text"), screen.get("message"), page.get("message"), "")).strip(),
                str(_first_nonempty(network.get("status"), network.get("phase"), network.get("message"), "")).strip(),
            ],
        )
    ).strip()
    lowered = _norm_text(text_blob)
    elapsed = max(0.0, float(elapsed_seconds or 0.0))
    if elapsed >= 12.0:
        phase = "dead_wait"
        reason = "wait_dead"
    elif any(token in lowered for token in ("rate limit", "too many requests", "429", "throttl")):
        phase = "rate_limit"
        reason = "wait_rate_limited"
    elif any(token in lowered for token in ("sync", "background sync", "syncing")):
        phase = "background_sync"
        reason = "wait_background_sync"
    elif any(token in lowered for token in ("loading", "loading...", "spinner", "please wait", "waiting")):
        phase = "loading"
        reason = "wait_loading"
    else:
        phase = "loading"
        reason = "wait_loading_default"
    classifier_id = _sha1_payload(
        {
            "text": lowered,
            "elapsed_seconds": round(elapsed, 4),
            "phase": phase,
            "network_keys": sorted(network.keys()),
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "classifier_id": classifier_id,
        "phase": phase,
        "reason": reason,
        "elapsed_seconds": round(elapsed, 4),
        "text_blob": text_blob,
        "lowered_text": lowered,
        "is_loading": phase == "loading",
        "is_background_sync": phase == "background_sync",
        "is_rate_limited": phase == "rate_limit",
        "is_dead_wait": phase == "dead_wait",
    }


def build_expiry_vs_error_splitter(
    *,
    expiry_event: Mapping[str, Any] | None = None,
    timeout_event: Mapping[str, Any] | None = None,
    error_event: Mapping[str, Any] | None = None,
    response_event: Mapping[str, Any] | None = None,
    screen_state: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    expiry = dict(expiry_event or {})
    timeout = dict(timeout_event or {})
    error = dict(error_event or {})
    response = dict(response_event or {})
    screen = dict(screen_state or {})
    response_status = str(
        _first_nonempty(
            response.get("status"),
            response.get("status_text"),
            response.get("reason"),
            error.get("status"),
            error.get("status_text"),
            error.get("reason"),
            "",
        )
    ).strip().lower()
    text_blob = " ".join(
        filter(
            None,
            [
                str(_first_nonempty(expiry.get("reason"), expiry.get("banner_text"), expiry.get("lowered_text"), "")).strip(),
                str(_first_nonempty(timeout.get("reason"), timeout.get("message"), timeout.get("status"), "")).strip(),
                str(_first_nonempty(error.get("reason"), error.get("message"), error.get("error_text"), response.get("message"), response.get("status_text"), "")).strip(),
                str(_first_nonempty(screen.get("message"), screen.get("status_text"), "")).strip(),
            ],
        )
    ).strip()
    lowered = _norm_text(text_blob)
    status_code = int(_first_nonempty(response.get("status_code"), error.get("status_code"), 0) or 0)
    expiry_signals = bool(expiry.get("is_expired")) or any(
        token in lowered
        for token in ("expired", "expiry", "session expired", "token expired", "logged out", "reauth", "expiration banner")
    )
    timeout_signals = bool(timeout.get("timed_out") or timeout.get("is_timeout") or timeout.get("deadline_exceeded")) or response_status in {
        "timeout",
        "timed out",
        "timed_out",
    } or status_code in {408, 504} or any(
        token in lowered
        for token in ("timeout", "timed out", "deadline exceeded", "watchdog timeout", "request timed out")
    )
    error_signals = bool(error.get("is_error") or response.get("is_error") or response.get("error")) or (
        status_code >= 400 and status_code not in {408, 504}
    ) or any(
        token in lowered
        for token in ("error", "exception", "failed", "failure", "server error", "validation error", "bad request", "internal server error")
    )
    if (expiry_signals or timeout_signals) and error_signals:
        failure_kind = "mixed_failure"
        failure_family = "mixed"
        reason = "expiry_and_error_present"
    elif expiry_signals:
        failure_kind = "expiry_failure"
        failure_family = "temporal"
        reason = "expiry_failure_detected"
    elif timeout_signals:
        failure_kind = "timeout_failure"
        failure_family = "temporal"
        reason = "timeout_failure_detected"
    elif error_signals:
        failure_kind = "classic_error"
        failure_family = "error"
        reason = "classic_error_detected"
    else:
        failure_kind = "no_issue"
        failure_family = "clear"
        reason = "no_failure_detected"
    splitter_id = _sha1_payload(
        {
            "text": lowered,
            "failure_kind": failure_kind,
            "status_code": status_code,
            "expiry_keys": sorted(expiry.keys()),
            "timeout_keys": sorted(timeout.keys()),
            "error_keys": sorted(error.keys()),
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "splitter_id": splitter_id,
        "failure_kind": failure_kind,
        "failure_family": failure_family,
        "reason": reason,
        "text_blob": text_blob,
        "lowered_text": lowered,
        "response_status": response_status,
        "status_code": status_code,
        "expiry_signals": expiry_signals,
        "timeout_signals": timeout_signals,
        "error_signals": error_signals,
        "is_expiry_failure": failure_kind in {"expiry_failure", "mixed_failure"},
        "is_timeout_failure": failure_kind in {"timeout_failure", "mixed_failure"},
        "is_error_failure": failure_kind in {"classic_error", "mixed_failure"},
        "is_temporal_failure": failure_family == "temporal" or failure_kind == "mixed_failure",
        "is_mixed_failure": failure_kind == "mixed_failure",
    }


def build_deadline_signal_parser(
    *,
    screen_state: Mapping[str, Any] | None = None,
    page_state: Mapping[str, Any] | None = None,
    network_state: Mapping[str, Any] | None = None,
    deadline_seconds: float | None = None,
    remaining_seconds: float | None = None,
) -> Dict[str, Any]:
    screen = dict(screen_state or {})
    page = dict(page_state or {})
    network = dict(network_state or {})
    text_blob = " ".join(
        filter(
            None,
            [
                str(_first_nonempty(screen.get("deadline_text"), screen.get("countdown_text"), screen.get("message"), page.get("message"), "")).strip(),
                str(_first_nonempty(page.get("deadline_text"), page.get("countdown_text"), page.get("message"), network.get("message"), network.get("status"), "")).strip(),
            ],
        )
    ).strip()
    lowered = _norm_text(text_blob)
    deadline_seconds_value = None if deadline_seconds is None else max(0.0, float(deadline_seconds))
    remaining_seconds_value = None if remaining_seconds is None else max(0.0, float(remaining_seconds))
    has_countdown = any(token in lowered for token in ("countdown", "time left", "remaining", "left:", "remaining time"))
    has_deadline_clock = any(token in lowered for token in ("deadline", "due by", "submit by", "before", "by ")) or deadline_seconds_value is not None
    has_limit = any(token in lowered for token in ("time limit", "time-limited", "limited time", "expires in", "expires at", "timer")) or remaining_seconds_value is not None
    if has_countdown and has_deadline_clock:
        signal_kind = "countdown_deadline"
        reason = "countdown_and_deadline_present"
    elif has_countdown:
        signal_kind = "countdown"
        reason = "countdown_signal_detected"
    elif has_deadline_clock:
        signal_kind = "deadline"
        reason = "deadline_signal_detected"
    elif has_limit:
        signal_kind = "time_limit"
        reason = "time_limit_signal_detected"
    else:
        signal_kind = "no_deadline"
        reason = "no_deadline_signal_detected"
    parser_id = _sha1_payload(
        {
            "text": lowered,
            "signal_kind": signal_kind,
            "deadline_seconds": None if deadline_seconds_value is None else round(deadline_seconds_value, 4),
            "remaining_seconds": None if remaining_seconds_value is None else round(remaining_seconds_value, 4),
            "screen_keys": sorted(screen.keys()),
            "page_keys": sorted(page.keys()),
            "network_keys": sorted(network.keys()),
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "parser_id": parser_id,
        "signal_kind": signal_kind,
        "reason": reason,
        "text_blob": text_blob,
        "lowered_text": lowered,
        "deadline_seconds": None if deadline_seconds_value is None else round(deadline_seconds_value, 4),
        "remaining_seconds": None if remaining_seconds_value is None else round(remaining_seconds_value, 4),
        "has_countdown": has_countdown,
        "has_deadline": has_deadline_clock,
        "has_time_limit": has_limit,
        "is_time_sensitive": signal_kind != "no_deadline",
        "is_countdown": signal_kind in {"countdown", "countdown_deadline"},
        "is_deadline": signal_kind in {"deadline", "countdown_deadline"},
        "is_time_limit": signal_kind == "time_limit",
    }


def build_time_sensitive_rule_guard(
    *,
    current_question: Mapping[str, Any] | None = None,
    screen_state: Mapping[str, Any] | None = None,
    page_state: Mapping[str, Any] | None = None,
    deadline_signal: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    question = dict(current_question or {})
    screen = dict(screen_state or {})
    page = dict(page_state or {})
    deadline = dict(deadline_signal or {})
    question_text = " ".join(
        filter(
            None,
            [
                str(_first_nonempty(question.get("question"), question.get("text"), screen.get("question_text"), page.get("question_text"), "")).strip(),
                str(_first_nonempty(question.get("subtitle"), question.get("hint"), screen.get("deadline_text"), page.get("deadline_text"), "")).strip(),
            ],
        )
    ).strip()
    lowered = _norm_text(question_text)
    deadline_kind = str(_first_nonempty(deadline.get("signal_kind"), deadline.get("reason"), "")).strip().lower()
    deadline_detected = bool(deadline.get("is_time_sensitive")) or deadline_kind in {"countdown", "deadline", "time_limit", "countdown_deadline"} or any(
        token in lowered for token in ("deadline", "countdown", "due by", "before", "time left", "remaining time", "expires in")
    )
    question_hint = any(
        token in lowered
        for token in (
            "today",
            "tomorrow",
            "date",
            "time",
            "hour",
            "minute",
            "morning",
            "afternoon",
            "evening",
            "week",
            "month",
            "year",
            "deadline",
            "countdown",
            "expire",
            "expires",
            "due by",
            "before",
        )
    )
    if deadline_detected and question_hint:
        guard_kind = "time_sensitive_deadline"
        reason = "question_and_deadline_time_sensitive"
    elif deadline_detected:
        guard_kind = "deadline_sensitive"
        reason = "deadline_time_sensitive"
    elif question_hint:
        guard_kind = "time_phrase_sensitive"
        reason = "question_time_phrase_sensitive"
    else:
        guard_kind = "not_time_sensitive"
        reason = "no_time_dependency_detected"
    guard_id = _sha1_payload(
        {
            "question_text": lowered,
            "guard_kind": guard_kind,
            "deadline_kind": deadline_kind,
            "screen_keys": sorted(screen.keys()),
            "page_keys": sorted(page.keys()),
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "guard_id": guard_id,
        "guard_kind": guard_kind,
        "reason": reason,
        "question_text": question_text,
        "lowered_text": lowered,
        "deadline_kind": deadline_kind,
        "is_time_sensitive": guard_kind != "not_time_sensitive",
        "has_deadline_signal": deadline_detected,
        "has_question_time_hint": question_hint,
    }


def build_freshness_over_speed_rule(
    *,
    freshness_marker: Mapping[str, Any] | None = None,
    speedup_hint: str = "",
    allow_stale: bool = False,
) -> Dict[str, Any]:
    freshness = dict(freshness_marker or {})
    is_fresh = bool(freshness.get("is_fresh", True))
    stale_reasons = list(freshness.get("stale_reasons") or [])
    hint = str(speedup_hint or "").strip().lower()
    risky_speedup = hint in {"fast_summary_only", "skip_reparse", "use_cached", "defer_refresh"}
    should_block = bool(stale_reasons and risky_speedup and not allow_stale)
    if should_block:
        reason = "freshness_over_speed_blocked"
    elif stale_reasons:
        reason = "stale_but_not_speeding"
    else:
        reason = "freshness_ok"
    return {
        "schema_version": SCHEMA_VERSION,
        "should_block": should_block,
        "reason": reason,
        "speedup_hint": hint,
        "allow_stale": bool(allow_stale),
        "is_fresh": is_fresh,
        "stale_reasons": stale_reasons,
        "freshness_marker": freshness,
    }


def build_decision_cost_model(
    *,
    observation_cost_ms: float = 0.0,
    action_cost_ms: float = 0.0,
    risk_score: float = 0.0,
    freshness_score: float = 0.0,
    preferred_mode: str = "observe",
) -> Dict[str, Any]:
    observe = max(0.0, float(observation_cost_ms or 0.0))
    act = max(0.0, float(action_cost_ms or 0.0))
    risk = max(0.0, min(1.0, float(risk_score or 0.0)))
    freshness = max(0.0, min(1.0, float(freshness_score or 0.0)))
    preferred = str(preferred_mode or "observe").strip().lower()
    adjusted_action_cost = act * (1.0 + (risk * 0.75)) * (1.0 - min(freshness, 0.5) * 0.2)
    adjusted_observation_cost = observe * (1.0 + max(0.0, 0.5 - freshness) * 0.4)
    if preferred == "act" and adjusted_action_cost <= adjusted_observation_cost:
        decision = "act"
        reason = "action_cheaper_than_observation"
    elif preferred == "act" and freshness >= 0.75 and risk <= 0.35:
        decision = "act"
        reason = "action_preferred_by_fresh_context"
    elif adjusted_observation_cost <= adjusted_action_cost:
        decision = "observe"
        reason = "observation_cheaper_or_safer"
    else:
        decision = "act"
        reason = "action_cheaper_or_preferred"
    return {
        "schema_version": SCHEMA_VERSION,
        "decision": decision,
        "reason": reason,
        "observation_cost_ms": round(observe, 4),
        "action_cost_ms": round(act, 4),
        "adjusted_observation_cost_ms": round(adjusted_observation_cost, 4),
        "adjusted_action_cost_ms": round(adjusted_action_cost, 4),
        "risk_score": round(risk, 4),
        "freshness_score": round(freshness, 4),
        "preferred_mode": preferred,
        "signals": {
            "action_cheaper": adjusted_action_cost <= adjusted_observation_cost,
            "observation_cheaper": adjusted_observation_cost <= adjusted_action_cost,
        },
    }


def build_endgame_policy(
    *,
    seconds_left: float = 0.0,
    goal_type: str = "",
    risk_tolerance: float = 0.0,
    progress_need: float = 0.0,
) -> Dict[str, Any]:
    time_left = max(0.0, float(seconds_left or 0.0))
    goal = str(goal_type or "").strip().lower() or "unknown"
    risk = max(0.0, min(1.0, float(risk_tolerance or 0.0)))
    progress = max(0.0, min(1.0, float(progress_need or 0.0)))
    if time_left <= 10.0 and risk < 0.45:
        mode = "minimal_risk"
        reason = "endgame_preserve_safety"
    elif time_left <= 10.0 and progress >= 0.6:
        mode = "minimal_progress"
        reason = "endgame_preserve_progress"
    elif time_left <= 30.0 and goal in {"regression", "verification"}:
        mode = "minimal_risk"
        reason = "endgame_regression_safety"
    else:
        mode = "normal"
        reason = "sufficient_time"
    return {
        "schema_version": SCHEMA_VERSION,
        "mode": mode,
        "reason": reason,
        "seconds_left": round(time_left, 4),
        "goal_type": goal,
        "risk_tolerance": round(risk, 4),
        "progress_need": round(progress, 4),
        "signals": {
            "time_critical": time_left <= 10.0,
            "goal_is_verification": goal in {"regression", "verification"},
            "high_progress_need": progress >= 0.6,
        },
    }


def build_latency_to_outcome_join(
    *,
    stage_records: Sequence[Mapping[str, Any]] | None = None,
) -> Dict[str, Any]:
    rows: List[Dict[str, Any]] = []
    grouped: Dict[str, Dict[str, Any]] = {}
    for record in stage_records or []:
        if not isinstance(record, Mapping):
            continue
        stage = str(_first_nonempty(record.get("stage"), record.get("component"), "unknown")).strip().lower() or "unknown"
        latency_ms = max(0.0, float(record.get("latency_ms") or record.get("latency") or 0.0))
        outcome = str(_first_nonempty(record.get("outcome"), record.get("result"), "unknown")).strip().lower() or "unknown"
        bucket = grouped.setdefault(
            stage,
            {
                "stage": stage,
                "latencies": [],
                "outcomes": {},
            },
        )
        bucket["latencies"].append(latency_ms)
        bucket["outcomes"][outcome] = int(bucket["outcomes"].get(outcome, 0)) + 1
    for stage, bucket in sorted(grouped.items()):
        latencies = sorted(float(item) for item in bucket["latencies"] if item is not None)
        count = len(latencies)
        success_count = int(bucket["outcomes"].get("success", 0))
        failure_count = count - success_count
        rows.append(
            {
                "stage": stage,
                "count": count,
                "average_latency_ms": round((sum(latencies) / count) if count else 0.0, 4),
                "median_latency_ms": round(float(statistics.median(latencies)) if latencies else 0.0, 4),
                "success_count": success_count,
                "failure_count": failure_count,
                "success_rate": round((success_count / count) if count else 0.0, 4),
                "outcomes": bucket["outcomes"],
            }
        )
    rows.sort(key=lambda row: (row["success_rate"], -row["average_latency_ms"]), reverse=True)
    overall_success = sum(row["success_count"] for row in rows)
    overall_count = sum(row["count"] for row in rows)
    return {
        "schema_version": SCHEMA_VERSION,
        "rows": rows,
        "overall_count": overall_count,
        "overall_success_rate": round((overall_success / overall_count) if overall_count else 0.0, 4),
        "is_joined": bool(rows),
        "join_id": _sha1_payload({"rows": rows})[:16],
    }


def build_network_latency_classifier(
    *,
    request_event: Mapping[str, Any] | None = None,
    response_event: Mapping[str, Any] | None = None,
    screen_state: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    request = dict(request_event or {})
    response = dict(response_event or {})
    screen = dict(screen_state or {})

    backend_latency_ms = max(
        0.0,
        float(
            _first_nonempty(
                response.get("latency_ms"),
                response.get("duration_ms"),
                response.get("elapsed_ms"),
                request.get("latency_ms"),
                request.get("duration_ms"),
                request.get("elapsed_ms"),
                0.0,
            )
            or 0.0
        ),
    )
    ui_latency_ms = max(
        0.0,
        float(
            _first_nonempty(
                screen.get("transition_latency_ms"),
                screen.get("ui_latency_ms"),
                screen.get("latency_ms"),
                0.0,
            )
            or 0.0
        ),
    )
    screen_changed = bool(screen.get("screen_changed", screen.get("changed", False)))
    backend_budget_ms = max(
        0.0,
        float(
            _first_nonempty(
                screen.get("backend_budget_ms"),
                response.get("budget_ms"),
                request.get("budget_ms"),
                0.0,
            )
            or 0.0
        ),
    )
    if backend_budget_ms <= 0.0:
        backend_budget_ms = max(250.0, ui_latency_ms or 0.0)
    latency_gap_ms = round(backend_latency_ms - ui_latency_ms, 4)

    if backend_latency_ms <= 0.0 and ui_latency_ms <= 0.0 and not screen_changed:
        classification = "unknown"
        reason = "no_latency_signal"
        confidence = 0.4
    elif backend_latency_ms > max(backend_budget_ms, ui_latency_ms * 1.25) and not screen_changed:
        classification = "backend_latency"
        reason = "backend_slow_with_no_transition"
        confidence = 0.93
    elif not screen_changed and backend_latency_ms <= backend_budget_ms:
        classification = "ui_flow_failure"
        reason = "ui_failed_to_transition"
        confidence = 0.82
    elif backend_latency_ms > backend_budget_ms and screen_changed:
        classification = "mixed_latency"
        reason = "backend_slow_but_ui_transition_present"
        confidence = 0.7
    else:
        classification = "stable"
        reason = "backend_and_ui_within_bounds"
        confidence = 0.96

    return {
        "schema_version": SCHEMA_VERSION,
        "classification": classification,
        "reason": reason,
        "confidence": round(confidence, 4),
        "backend_latency_ms": round(backend_latency_ms, 4),
        "ui_latency_ms": round(ui_latency_ms, 4),
        "backend_budget_ms": round(backend_budget_ms, 4),
        "latency_gap_ms": latency_gap_ms,
        "screen_changed": screen_changed,
        "is_backend_bound": classification == "backend_latency",
        "is_ui_bound": classification == "ui_flow_failure",
        "should_escalate": classification in {"backend_latency", "ui_flow_failure", "mixed_latency"},
        "is_stable": classification == "stable",
    }


def build_retry_chain_tracker(
    *,
    attempts: Sequence[Mapping[str, Any]] | None = None,
    final_event: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    normalized_attempts: List[Dict[str, Any]] = []
    retry_indices: List[int] = []
    retry_markers = 0
    success_seen_at: int | None = None
    terminal_outcome = "unknown"
    for idx, attempt in enumerate(attempts or []):
        if not isinstance(attempt, Mapping):
            continue
        status = str(
            _first_nonempty(
                attempt.get("outcome"),
                attempt.get("status"),
                attempt.get("result"),
                attempt.get("response_status"),
                "unknown",
            )
        ).strip().lower() or "unknown"
        retry_flag = bool(attempt.get("is_retry") or attempt.get("retried") or int(attempt.get("retry_count") or 0) > 0 or idx > 0)
        if retry_flag:
            retry_indices.append(idx)
            retry_markers += 1
        if status in {"success", "ok", "done", "completed"} and success_seen_at is None:
            success_seen_at = idx
        normalized_attempts.append(
            {
                "index": idx,
                "status": status,
                "is_retry": retry_flag,
                "latency_ms": round(max(0.0, float(attempt.get("latency_ms") or attempt.get("duration_ms") or 0.0)), 4),
                "retry_reason": _first_nonempty(attempt.get("retry_reason"), attempt.get("reason"), ""),
            }
        )
    if final_event and isinstance(final_event, Mapping):
        terminal_outcome = str(
            _first_nonempty(
                final_event.get("outcome"),
                final_event.get("status"),
                final_event.get("result"),
                final_event.get("response_status"),
                "unknown",
            )
        ).strip().lower() or "unknown"
    elif normalized_attempts:
        terminal_outcome = str(normalized_attempts[-1]["status"])
    has_retries = len(normalized_attempts) > 1 or retry_markers > 0
    final_success = terminal_outcome in {"success", "ok", "done", "completed"}
    initial_success = bool(normalized_attempts) and str(normalized_attempts[0]["status"]) in {"success", "ok", "done", "completed"}
    if final_success and not has_retries and initial_success:
        classification = "immediate_success"
        reason = "success_without_retry"
    elif final_success and has_retries:
        classification = "retried_success"
        reason = "success_after_retry"
    elif has_retries and terminal_outcome in {"failed", "failure", "error", "timeout", "blocked"}:
        classification = "retried_failure"
        reason = "retry_chain_failed"
    elif not normalized_attempts:
        classification = "unknown"
        reason = "no_attempts"
    else:
        classification = "in_progress"
        reason = "terminal_outcome_not_final"
    silent_retry_detected = bool(has_retries and final_success and not any(item["is_retry"] for item in normalized_attempts[:1]))
    return {
        "schema_version": SCHEMA_VERSION,
        "chain_id": _sha1_payload({"attempts": normalized_attempts, "final_event": dict(final_event or {})})[:16],
        "attempt_count": len(normalized_attempts),
        "retry_count": max(0, len(normalized_attempts) - 1),
        "retry_indices": retry_indices,
        "has_retries": has_retries,
        "silent_retry_detected": silent_retry_detected,
        "classification": classification,
        "reason": reason,
        "final_outcome": terminal_outcome,
        "initial_success": initial_success,
        "final_success": final_success,
        "final_success_after_retry": bool(final_success and has_retries),
        "is_terminal_success": final_success,
        "is_terminal_failure": terminal_outcome in {"failed", "failure", "error", "timeout", "blocked"},
        "attempts": normalized_attempts,
    }


def build_stale_response_guard(
    *,
    request_event: Mapping[str, Any] | None = None,
    response_event: Mapping[str, Any] | None = None,
    screen_state: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    request = dict(request_event or {})
    response = dict(response_event or {})
    screen = dict(screen_state or {})

    current_signature = str(
        _first_nonempty(
            screen.get("screen_signature"),
            screen.get("current_screen_signature"),
            screen.get("active_screen_signature"),
            screen.get("state_hash"),
            "",
        )
    ).strip()
    request_signature = str(
        _first_nonempty(
            request.get("screen_signature"),
            request.get("request_screen_signature"),
            request.get("target_screen_signature"),
            response.get("request_screen_signature"),
            "",
        )
    ).strip()
    response_signature = str(
        _first_nonempty(
            response.get("screen_signature"),
            response.get("response_screen_signature"),
            response.get("applied_screen_signature"),
            response.get("target_screen_signature"),
            "",
        )
    ).strip()
    response_status = str(
        _first_nonempty(
            response.get("outcome"),
            response.get("status"),
            response.get("result"),
            response.get("state"),
            "unknown",
        )
    ).strip().lower() or "unknown"
    late_hint = bool(
        response.get("is_late")
        or response.get("late")
        or response.get("applied_after_screen_change")
        or response.get("stale")
        or screen.get("screen_changed_since_request")
    )
    changed_after_request = bool(
        screen.get("screen_changed_since_request")
        or screen.get("changed_since_request")
        or request.get("screen_changed_since_request")
    )
    signature_mismatch = bool(
        current_signature
        and response_signature
        and response_signature != current_signature
    )
    request_mismatch = bool(
        current_signature
        and request_signature
        and request_signature != current_signature
    )
    is_stale = bool(signature_mismatch or (changed_after_request and response_status in {"success", "ok", "done", "completed"}) or late_hint or (request_mismatch and response_status in {"success", "ok", "done", "completed"}))
    if is_stale and signature_mismatch and (changed_after_request or late_hint or request_mismatch):
        classification = "stale"
        reason = "stale_response_applied_to_outdated_context"
    elif is_stale:
        classification = "stale"
        reason = "stale_response_detected"
    elif current_signature or request_signature or response_signature:
        classification = "fresh"
        reason = "response_matches_current_context"
    else:
        classification = "uncertain"
        reason = "insufficient_context_for_staleness_check"

    return {
        "schema_version": SCHEMA_VERSION,
        "classification": classification,
        "reason": reason,
        "current_screen_signature": current_signature,
        "request_screen_signature": request_signature,
        "response_screen_signature": response_signature,
        "response_status": response_status,
        "signature_mismatch": signature_mismatch,
        "request_mismatch": request_mismatch,
        "late_hint": late_hint,
        "changed_after_request": changed_after_request,
        "is_stale": classification == "stale",
        "should_drop_response": classification == "stale",
        "should_replay_request": classification == "stale" and changed_after_request,
        "is_fresh": classification == "fresh",
    }


def build_ui_vs_network_timeout_splitter(
    *,
    request_event: Mapping[str, Any] | None = None,
    response_event: Mapping[str, Any] | None = None,
    timeout_event: Mapping[str, Any] | None = None,
    screen_state: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    request = dict(request_event or {})
    response = dict(response_event or {})
    timeout = dict(timeout_event or {})
    screen = dict(screen_state or {})

    response_status = str(
        _first_nonempty(response.get("status"), response.get("status_text"), response.get("reason"), "")
    ).strip().lower()
    timeout_scope = str(
        _first_nonempty(timeout.get("scope"), timeout.get("timeout_scope"), request.get("timeout_scope"), screen.get("timeout_scope"), "")
    ).strip().lower()
    ui_signals = [
        request.get("ui_timed_out"),
        request.get("action_timed_out"),
        request.get("watchdog_timeout"),
        screen.get("watchdog_timeout"),
        screen.get("deadline_exceeded"),
        screen.get("screen_changed_since_request") and not bool(response.get("screen_changed")),
        timeout_scope == "ui",
    ]
    network_signals = [
        timeout.get("timed_out"),
        timeout.get("is_timeout"),
        response.get("timed_out"),
        response.get("network_timeout"),
        response_status == "timeout",
        response_status == "timed_out",
        int(_first_nonempty(response.get("status_code"), 0) or 0) in {408, 504},
        timeout_scope == "network",
    ]
    ui_timeout = any(bool(signal) for signal in ui_signals)
    network_timeout = any(bool(signal) for signal in network_signals)
    if ui_timeout and network_timeout:
        timeout_kind = "mixed_timeout"
        reason = "ui_and_network_timeouts_present"
    elif ui_timeout:
        timeout_kind = "ui_timeout"
        reason = "ui_state_timeout"
    elif network_timeout:
        timeout_kind = "network_timeout"
        reason = "backend_timeout"
    else:
        timeout_kind = "no_timeout"
        reason = "timeout_not_observed"
    return {
        "schema_version": SCHEMA_VERSION,
        "timeout_kind": timeout_kind,
        "reason": reason,
        "ui_timeout": ui_timeout,
        "network_timeout": network_timeout,
        "timeout_scope": timeout_scope,
        "response_status": response_status,
        "should_retry_ui": timeout_kind in {"ui_timeout", "mixed_timeout"},
        "should_retry_network": timeout_kind in {"network_timeout", "mixed_timeout"},
        "is_split": timeout_kind != "no_timeout",
    }


def build_endpoint_regression_suite(
    *,
    endpoint_cases: Sequence[Mapping[str, Any]] | None = None,
) -> Dict[str, Any]:
    cases = [dict(case) for case in (endpoint_cases or []) if isinstance(case, Mapping)]
    rows: List[Dict[str, Any]] = []
    passed = 0
    failed = 0
    drift_cases = 0
    for index, case in enumerate(cases, start=1):
        expected_request = dict(
            case.get("expected_request_schema")
            or case.get("expected_request")
            or {}
        )
        expected_response = dict(
            case.get("expected_response_schema")
            or case.get("expected_response")
            or {}
        )
        current_request = dict(case.get("current_request") or expected_request)
        current_response = dict(case.get("current_response") or expected_response)
        endpoint_role_registry = dict(case.get("endpoint_role_registry") or {})
        if not endpoint_role_registry and _first_nonempty(case.get("expected_role"), expected_request.get("role"), current_request.get("role")):
            endpoint_role_registry["expected_role"] = _first_nonempty(case.get("expected_role"), expected_request.get("role"), current_request.get("role"))

        drift_guard = build_api_drift_guard(
            expected_request_schema=expected_request,
            expected_response_schema=expected_response,
            current_request=current_request,
            current_response=current_response,
            endpoint_role_registry=endpoint_role_registry,
        )
        outcome = build_request_outcome_contract(
            request_event=current_request,
            response_event=current_response,
            retry_event=case.get("retry_event"),
            timeout_event=case.get("timeout_event"),
        )
        semantic = build_response_semantic_validator(
            request_event=current_request,
            response_event=current_response,
            screen_state=case.get("screen_state"),
        )

        expected_outcome_type = str(_first_nonempty(case.get("expected_outcome_type"), case.get("expected_outcome"), "")).strip().lower()
        expected_semantic = str(_first_nonempty(case.get("expected_semantic"), "")).strip().lower()
        expected_status_code_value = case.get("expected_status_code")
        try:
            expected_status_code = int(expected_status_code_value) if expected_status_code_value not in (None, "") else None
        except (TypeError, ValueError):
            expected_status_code = None

        issues: List[str] = []
        if not drift_guard.get("is_stable"):
            issues.append("api_drift")
        if expected_outcome_type and outcome.get("outcome_type") != expected_outcome_type:
            issues.append("outcome_mismatch")
        if expected_semantic and semantic.get("semantic") != expected_semantic:
            issues.append("semantic_mismatch")
        if expected_status_code is not None and int(outcome.get("status_code") or 0) != expected_status_code:
            issues.append("status_code_mismatch")

        is_pass = not issues
        if is_pass:
            passed += 1
        else:
            failed += 1
            if "api_drift" in issues:
                drift_cases += 1

        rows.append(
            {
                "index": index,
                "case_id": str(case.get("case_id") or f"case_{index}"),
                "endpoint": _first_nonempty(case.get("endpoint"), current_request.get("url"), current_request.get("endpoint"), ""),
                "role": str(_first_nonempty(endpoint_role_registry.get("expected_role"), current_request.get("role"), "")).strip().lower(),
                "expected_outcome_type": expected_outcome_type,
                "actual_outcome_type": outcome.get("outcome_type"),
                "expected_semantic": expected_semantic,
                "actual_semantic": semantic.get("semantic"),
                "status_code": int(outcome.get("status_code") or 0),
                "is_drift": not bool(drift_guard.get("is_stable")),
                "issues": issues,
                "drift_reason": drift_guard.get("reason"),
                "outcome_reason": outcome.get("reason"),
                "semantic_reason": semantic.get("reason"),
                "request_signature": outcome.get("request_signature"),
                "response_signature": outcome.get("response_signature"),
            }
        )
    total = len(rows)
    if total == 0:
        reason = "empty_regression_suite"
    elif failed == 0:
        reason = "regression_suite_passed"
    else:
        reason = "regression_suite_failed"
    return {
        "schema_version": SCHEMA_VERSION,
        "reason": reason,
        "suite_size": total,
        "passed_cases": passed,
        "failed_cases": failed,
        "drift_cases": drift_cases,
        "rows": rows,
        "is_passing": failed == 0 and total > 0,
    }


def build_backend_perf_comparator(
    *,
    backend_records: Sequence[Mapping[str, Any]] | None = None,
    preferred_backend: str = "",
    max_latency_ms: float = 0.0,
    max_error_rate: float = 0.0,
) -> Dict[str, Any]:
    rows: List[Dict[str, Any]] = []
    for record in backend_records or []:
        if not isinstance(record, Mapping):
            continue
        backend = str(_first_nonempty(record.get("backend"), record.get("name"), record.get("mode"), "unknown")).strip().lower() or "unknown"
        latency_ms = max(0.0, float(record.get("latency_ms") or record.get("latency") or 0.0))
        error_rate = max(0.0, min(1.0, float(record.get("error_rate") or record.get("failure_rate") or 0.0)))
        rows.append(
            {
                "backend": backend,
                "median_ms": round(latency_ms, 4),
                "p95_ms": round(latency_ms, 4),
                "error_rate": round(error_rate, 4),
                "meets_latency": bool(max_latency_ms <= 0.0 or latency_ms <= float(max_latency_ms)),
                "meets_error_rate": bool(max_error_rate <= 0.0 or error_rate <= float(max_error_rate)),
            }
        )
    rows.sort(key=lambda row: (row["meets_latency"] and row["meets_error_rate"], -row["p95_ms"], -row["median_ms"]), reverse=True)
    best_backend = rows[0]["backend"] if rows else ""
    preferred = str(preferred_backend or "").strip().lower()
    preferred_row = next((row for row in rows if row["backend"] == preferred), {})
    return {
        "schema_version": SCHEMA_VERSION,
        "rows": rows,
        "preferred_backend": preferred,
        "best_backend": best_backend,
        "max_latency_ms": round(float(max_latency_ms), 4),
        "max_error_rate": round(float(max_error_rate), 4),
        "preferred_meets_thresholds": bool(preferred_row) and bool(preferred_row.get("meets_latency") and preferred_row.get("meets_error_rate")),
        "is_comparable": bool(rows),
        "comparator_id": _sha1_payload({"rows": rows, "preferred_backend": preferred})[:16],
    }


def build_performance_hint_packet(
    *,
    latency_ms: float = 0.0,
    compute_ms: float = 0.0,
    wait_ms: float = 0.0,
    context: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    latency = max(0.0, float(latency_ms or 0.0))
    compute = max(0.0, float(compute_ms or 0.0))
    wait = max(0.0, float(wait_ms or 0.0))
    ctx = dict(context or {})
    signals = {
        "latency_ms": round(latency, 4),
        "compute_ms": round(compute, 4),
        "wait_ms": round(wait, 4),
    }
    total = latency + compute + wait
    if total <= 0.0:
        bound_type = "unknown"
        reason = "no_performance_signal"
        dominant_signal = "none"
    else:
        priority = {"wait_ms": 0, "latency_ms": 1, "compute_ms": 2}
        dominant_key, dominant_value = max(signals.items(), key=lambda item: (item[1], -priority[item[0]]))
        bound_type = dominant_key.removesuffix("_ms") + "_bound"
        dominant_signal = dominant_key
        if dominant_key == "wait_ms":
            reason = "wait_pressure_dominates"
        elif dominant_key == "latency_ms":
            reason = "latency_pressure_dominates"
        else:
            reason = "compute_pressure_dominates"
        signals["dominant_share"] = round(dominant_value / total, 4)
    packet = {
        "bound_type": bound_type,
        "reason": reason,
        "signals": signals,
        "context": {
            "model_size": _first_nonempty(ctx.get("model_size"), ctx.get("model"), "unknown"),
            "priority": _first_nonempty(ctx.get("priority"), "normal"),
        },
    }
    return {
        "schema_version": SCHEMA_VERSION,
        "bound_type": bound_type,
        "dominant_signal": dominant_signal,
        "packet": packet,
        "packet_hash": _sha1_payload(packet)[:16],
        "is_performance_bound": bound_type != "unknown",
    }


def build_worker_scaling_curve(
    *,
    requested_workers: int | None = None,
    logical_cores: int | None = None,
    ocr_scale_parallelism_cap: int = 2,
    runtime_executor_cap: int | None = None,
) -> Dict[str, Any]:
    cores = max(1, int(logical_cores or os.cpu_count() or 1))
    if requested_workers is None:
        try:
            requested = int(os.environ.get("FULLBOT_REGION_GROW_MAX_WORKERS", "1") or 1)
        except Exception:
            requested = 1
    else:
        requested = int(requested_workers)
    ocr_cap = max(1, int(ocr_scale_parallelism_cap or 1))
    executor_cap = max(1, int(runtime_executor_cap if runtime_executor_cap is not None else min(4, cores)))
    useful_parallel_workers = max(1, min(ocr_cap, executor_cap))
    sample_limit = max(4, useful_parallel_workers + 2)
    points: List[Dict[str, Any]] = []
    for worker_count in range(0, sample_limit + 1):
        if worker_count == 0:
            regime = "disabled"
            marginal_gain = 0.0
            contention_risk = "low"
            guidance = "persistent_workers_off"
        elif worker_count < useful_parallel_workers:
            regime = "scaling"
            marginal_gain = 1.0
            contention_risk = "low"
            guidance = "additional_worker_useful"
        elif worker_count == useful_parallel_workers:
            regime = "sweet_spot"
            marginal_gain = 0.45
            contention_risk = "medium"
            guidance = "best_tradeoff"
        else:
            regime = "contention"
            marginal_gain = 0.0
            contention_risk = "high"
            guidance = "extra_workers_likely_hurt"
        points.append(
            {
                "workers": int(worker_count),
                "regime": regime,
                "marginal_gain": float(marginal_gain),
                "contention_risk": contention_risk,
                "guidance": guidance,
            }
        )
    requested_regime = next(
        (point for point in points if int(point.get("workers", -1)) == requested),
        points[-1] if points else {},
    )
    return {
        "schema_version": SCHEMA_VERSION,
        "logical_cores": int(cores),
        "requested_workers": int(requested),
        "ocr_scale_parallelism_cap": int(ocr_cap),
        "runtime_executor_cap": int(executor_cap),
        "useful_parallel_workers": int(useful_parallel_workers),
        "plateau_after_workers": int(useful_parallel_workers),
        "requested_regime": str(requested_regime.get("regime") or ""),
        "requested_guidance": str(requested_regime.get("guidance") or ""),
        "curve_points": points,
    }


def build_site_identity_registry(
    *,
    start_url: str,
    current_url: str,
    page_state: Mapping[str, Any] | None = None,
    screen_state: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    parsed = urlparse(current_url or start_url or "")
    host = str(parsed.hostname or "").strip().lower()
    pathname_parts = [part for part in str(parsed.path or "").split("/") if part]
    canonical_parts: List[str] = []
    for part in pathname_parts:
        token = str(part or "").strip()
        if token.isdigit():
            canonical_parts.append(":int")
        elif any(ch.isdigit() for ch in token) and "-" in token:
            canonical_parts.append(":mixed")
        else:
            canonical_parts.append(token.lower())
    pathname_pattern = "/" + "/".join(canonical_parts) if canonical_parts else "/"
    allowed_query_keys = {"lang", "locale", "survey", "type"}
    query_pairs = [(str(k).strip().lower(), str(v).strip()) for k, v in parse_qsl(parsed.query or "", keep_blank_values=True)]
    stable_query = [(k, v) for k, v in query_pairs if k in allowed_query_keys]
    stable_query.sort(key=lambda row: (row[0], row[1]))
    canonical_query = urlencode(stable_query, doseq=True)
    stable_site_key = f"{host}{pathname_pattern}"
    if canonical_query:
        stable_site_key = f"{stable_site_key}?{canonical_query}"
    page = dict(page_state or {})
    screen = dict(screen_state or {})
    survey_family = "unknown"
    if len(pathname_parts) >= 3 and str(pathname_parts[0]).lower() == "t" and str(pathname_parts[1]).isdigit():
        survey_family = f"test_quiz_type_{int(pathname_parts[1])}"
    else:
        active_block = screen.get("active_block") if isinstance(screen.get("active_block"), Mapping) else {}
        active_block_family = str((active_block or {}).get("block_family") or screen.get("control_kind") or "").strip().lower()
        if active_block_family:
            survey_family = f"screen_family_{active_block_family}"
    observed_fingerprint = str(
        screen.get("screen_signature")
        or screen.get("active_question_signature")
        or page.get("page_signature")
        or page.get("signature")
        or ""
    ).strip()
    canonical_site_id = "|".join(
        [
            host or "unknown_host",
            pathname_pattern or "/",
            survey_family or "unknown_family",
            observed_fingerprint[:24] or "no_fingerprint",
        ]
    )
    return {
        "schema_version": SCHEMA_VERSION,
        "canonical_site_id": canonical_site_id,
        "host": host,
        "pathname_pattern": pathname_pattern,
        "url_canonicalizer": {
            "host": host,
            "pathname_pattern": pathname_pattern,
            "canonical_query": canonical_query,
            "stable_site_key": stable_site_key,
            "ignored_query_keys": [k for k, _ in query_pairs if k not in allowed_query_keys],
        },
        "survey_family": survey_family,
        "observed_fingerprint": observed_fingerprint,
        "inputs": {
            "start_host": str(urlparse(start_url or "").hostname or "").strip().lower(),
            "current_host": host,
            "page_title": str(page.get("title") or "").strip(),
        },
    }


def build_page_truth_selector(
    *,
    screen_state: Mapping[str, Any] | None = None,
    page_state: Mapping[str, Any] | None = None,
    qa_cache: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    screen = dict(screen_state or {})
    page = dict(page_state or {})
    cache = dict(qa_cache or {})

    def _score_screen(payload: Mapping[str, Any]) -> Dict[str, Any]:
        score = 0.0
        reasons: List[str] = []
        question_text = str(payload.get("question_text") or "").strip()
        options = payload.get("options") if isinstance(payload.get("options"), Sequence) else []
        active_block = payload.get("active_block") if isinstance(payload.get("active_block"), Mapping) else {}
        if question_text:
            score += 2.0
            reasons.append("question_text")
        if options:
            score += 1.5
            reasons.append("options")
        if active_block:
            score += 1.25
            reasons.append("active_block")
        if payload.get("screen_signature") or payload.get("state_hash"):
            score += 1.0
            reasons.append("screen_signature")
        if payload.get("is_stale"):
            score -= 2.5
            reasons.append("stale")
        return {"source": "screen_state", "score": score, "reasons": reasons}

    def _score_page(payload: Mapping[str, Any]) -> Dict[str, Any]:
        score = 0.0
        reasons: List[str] = []
        page_text = str(payload.get("pageText") or payload.get("page_text") or "").strip()
        title = str(payload.get("title") or "").strip()
        if page_text:
            score += 1.5
            reasons.append("page_text")
        if title:
            score += 0.75
            reasons.append("title")
        if payload.get("frames"):
            score += 0.5
            reasons.append("frames")
        if payload.get("is_stale"):
            score -= 2.0
            reasons.append("stale")
        return {"source": "page_state", "score": score, "reasons": reasons}

    def _score_cache(payload: Mapping[str, Any]) -> Dict[str, Any]:
        score = 0.0
        reasons: List[str] = []
        if payload.get("canonical_site_id"):
            score += 1.0
            reasons.append("canonical_site_id")
        if payload.get("layout_family"):
            score += 0.75
            reasons.append("layout_family")
        if payload.get("selected_source"):
            score += 0.5
            reasons.append("selected_source_hint")
        if payload.get("confidence") is not None:
            score += max(0.0, min(1.0, float(payload.get("confidence") or 0.0)))
            reasons.append("confidence")
        if payload.get("is_expired"):
            score -= 2.5
            reasons.append("expired")
        return {"source": "qa_cache", "score": score, "reasons": reasons}

    candidates = []
    if screen:
        candidates.append(_score_screen(screen))
    if page:
        candidates.append(_score_page(page))
    if cache:
        candidates.append(_score_cache(cache))
    candidates.sort(key=lambda row: (-float(row.get("score") or 0.0), str(row.get("source") or "")))
    selected = candidates[0] if candidates else {"source": "unknown", "score": 0.0, "reasons": []}
    return {
        "schema_version": SCHEMA_VERSION,
        "selected_source": str(selected.get("source") or "unknown"),
        "selected_score": round(float(selected.get("score") or 0.0), 4),
        "selected_reasons": list(selected.get("reasons") or []),
        "candidates": candidates,
        "is_decisive": bool(candidates) and len(candidates) == 1 or (len(candidates) > 1 and float(candidates[0].get("score") or 0.0) > float(candidates[1].get("score") or 0.0)),
    }


def build_layout_family_classifier(
    *,
    screen_state: Mapping[str, Any],
    page_state: Mapping[str, Any],
) -> Dict[str, Any]:
    screen = dict(screen_state or {})
    page = dict(page_state or {})
    active_block = screen.get("active_block") if isinstance(screen.get("active_block"), Mapping) else {}
    block_family = str((active_block or {}).get("block_family") or "").strip().lower()
    control_kind = str(screen.get("control_kind") or (active_block or {}).get("control_kind") or "").strip().lower()
    detected_quiz_type = str(screen.get("detected_quiz_type") or screen.get("active_block_type") or "").strip().lower()
    answer_count = int((active_block or {}).get("answer_count") or len(screen.get("options") or []) or 0)
    has_select = bool((active_block or {}).get("select_bbox") or screen.get("select_bbox"))
    has_input = bool((active_block or {}).get("input_bbox") or screen.get("input_bbox"))
    split_parts = ((screen.get("question_split") or {}).get("parts") if isinstance(screen.get("question_split"), Mapping) else []) or []
    split_count = len(split_parts) if isinstance(split_parts, list) else 0

    layout_family = "unknown"
    confidence = 0.55
    reasons: List[str] = []
    if detected_quiz_type in {"single", "multi", "dropdown", "dropdown_scroll", "text", "matrix", "slider", "mixed", "triple"}:
        layout_family = detected_quiz_type
        confidence = 0.96
        reasons.append("detected_quiz_type")
    elif block_family in {"single", "multi", "dropdown", "dropdown_scroll", "text", "matrix", "slider", "mixed", "triple"}:
        layout_family = block_family
        confidence = 0.9
        reasons.append("active_block.block_family")
    elif split_count >= 2:
        layout_family = "split_multi_control"
        confidence = 0.84
        reasons.append("question_split.parts")
    elif has_select and answer_count >= 9:
        layout_family = "dropdown_scroll"
        confidence = 0.82
        reasons.append("select_bbox+answer_count")
    elif has_select:
        layout_family = "dropdown"
        confidence = 0.8
        reasons.append("select_bbox")
    elif has_input:
        layout_family = "text"
        confidence = 0.8
        reasons.append("input_bbox")
    elif control_kind == "choice" and answer_count > 0:
        layout_family = "choice"
        confidence = 0.72
        reasons.append("choice_answers")
    elif control_kind:
        layout_family = control_kind
        confidence = 0.68
        reasons.append("control_kind_fallback")

    return {
        "schema_version": SCHEMA_VERSION,
        "layout_family": layout_family,
        "confidence": round(float(confidence), 4),
        "signals": {
            "control_kind": control_kind,
            "detected_quiz_type": detected_quiz_type,
            "block_family": block_family,
            "answer_count": int(answer_count),
            "has_select": has_select,
            "has_input": has_input,
            "split_part_count": int(split_count),
            "page_title": str(page.get("title") or "").strip(),
        },
        "reasons": reasons,
    }


def build_site_strategy_memory(
    *,
    site_identity_registry: Mapping[str, Any],
    steps: Sequence[Any],
) -> Dict[str, Any]:
    registry = dict(site_identity_registry or {})
    canonical_site_id = str(registry.get("canonical_site_id") or "").strip()
    strategy_rows: Dict[str, Dict[str, Any]] = {}
    fallback_steps = 0
    for index, step in enumerate(steps, start=1):
        if not isinstance(step, Mapping):
            continue
        plan_source = str(step.get("plan_source") or "unknown").strip() or "unknown"
        fallback_used = bool(step.get("fallback_used"))
        if fallback_used:
            fallback_steps += 1
        runtime_state = step.get("runtime_state") if isinstance(step.get("runtime_state"), Mapping) else {}
        runtime_fsm = runtime_state.get("fsm") if isinstance(runtime_state.get("fsm"), Mapping) else {}
        action_result_packet = (
            step.get("action_result_packet") if isinstance(step.get("action_result_packet"), Mapping) else {}
        )
        semantic_success = bool(action_result_packet.get("semantic_success"))
        progressed = bool(runtime_state.get("progressed")) or semantic_success or bool(action_result_packet.get("success"))
        outcome_type = str(action_result_packet.get("outcome_type") or "").strip()
        row = strategy_rows.setdefault(
            plan_source,
            {
                "plan_source": plan_source,
                "attempts": 0,
                "fallback_attempts": 0,
                "progressed_attempts": 0,
                "semantic_success_attempts": 0,
                "complete_state_hits": 0,
                "outcome_counts": {},
                "last_iteration": 0,
            },
        )
        row["attempts"] = int(row["attempts"]) + 1
        row["fallback_attempts"] = int(row["fallback_attempts"]) + int(fallback_used)
        row["progressed_attempts"] = int(row["progressed_attempts"]) + int(progressed)
        row["semantic_success_attempts"] = int(row["semantic_success_attempts"]) + int(semantic_success)
        row["complete_state_hits"] = int(row["complete_state_hits"]) + int(str(runtime_fsm.get("state") or "") == "complete")
        row["last_iteration"] = int(step.get("iteration") or index)
        if outcome_type:
            outcome_counts = row["outcome_counts"] if isinstance(row.get("outcome_counts"), dict) else {}
            outcome_counts[outcome_type] = int(outcome_counts.get(outcome_type) or 0) + 1
            row["outcome_counts"] = outcome_counts

    strategies: List[Dict[str, Any]] = []
    for row in strategy_rows.values():
        attempts = max(int(row.get("attempts") or 0), 1)
        fallback_attempts = int(row.get("fallback_attempts") or 0)
        progressed_attempts = int(row.get("progressed_attempts") or 0)
        semantic_success_attempts = int(row.get("semantic_success_attempts") or 0)
        complete_state_hits = int(row.get("complete_state_hits") or 0)
        outcome_counts = row.get("outcome_counts") if isinstance(row.get("outcome_counts"), dict) else {}
        dominant_outcome_type = ""
        if outcome_counts:
            dominant_outcome_type = sorted(
                outcome_counts.items(),
                key=lambda item: (-int(item[1] or 0), str(item[0] or "")),
            )[0][0]
        score = (semantic_success_attempts * 100) + (progressed_attempts * 10) + (complete_state_hits * 5) - fallback_attempts
        strategies.append(
            {
                "plan_source": str(row.get("plan_source") or "unknown"),
                "attempts": attempts,
                "fallback_attempts": fallback_attempts,
                "progressed_attempts": progressed_attempts,
                "semantic_success_attempts": semantic_success_attempts,
                "complete_state_hits": complete_state_hits,
                "dominant_outcome_type": dominant_outcome_type,
                "fallback_rate": round(float(fallback_attempts) / float(attempts), 4),
                "semantic_success_rate": round(float(semantic_success_attempts) / float(attempts), 4),
                "score": int(score),
                "last_iteration": int(row.get("last_iteration") or 0),
            }
        )
    strategies.sort(
        key=lambda row: (
            -int(row.get("score") or 0),
            -int(row.get("semantic_success_attempts") or 0),
            -int(row.get("progressed_attempts") or 0),
            str(row.get("plan_source") or ""),
        )
    )
    recommended_order = [str(row.get("plan_source") or "unknown") for row in strategies]
    preferred_plan_source = recommended_order[0] if recommended_order else ""
    return {
        "schema_version": SCHEMA_VERSION,
        "memory_scope": "session_run",
        "canonical_site_id": canonical_site_id,
        "preferred_plan_source": preferred_plan_source,
        "recommended_order": recommended_order,
        "strategies": strategies,
        "signals": {
            "total_steps": len([step for step in steps if isinstance(step, Mapping)]),
            "observed_plan_sources": len(strategies),
            "fallback_steps": int(fallback_steps),
        },
    }


def build_site_failure_priors(
    *,
    site_identity_registry: Mapping[str, Any],
    summary: Mapping[str, Any],
) -> Dict[str, Any]:
    registry = dict(site_identity_registry or {})
    summary_data = dict(summary or {})
    canonical_site_id = str(registry.get("canonical_site_id") or "").strip()
    steps = summary_data.get("steps") if isinstance(summary_data.get("steps"), list) else []
    failure_summary = summary_data.get("failure_summary") if isinstance(summary_data.get("failure_summary"), Mapping) else {}
    operational_watchdog = (
        summary_data.get("operational_watchdog") if isinstance(summary_data.get("operational_watchdog"), Mapping) else {}
    )
    live_site_safety_policy = (
        summary_data.get("live_site_safety_policy") if isinstance(summary_data.get("live_site_safety_policy"), Mapping) else {}
    )
    escalation_threshold_policy = (
        summary_data.get("escalation_threshold_policy")
        if isinstance(summary_data.get("escalation_threshold_policy"), Mapping)
        else {}
    )
    error = str(summary_data.get("error") or "").strip()

    stop_reason = "completed" if bool(summary_data.get("completed")) else "unknown_failure"
    source = "summary"
    if error:
        stop_reason = error
    elif failure_summary:
        stop_reason = str(failure_summary.get("what_failed") or stop_reason)
        source = "failure_summary"
    elif operational_watchdog:
        stop_reason = str(operational_watchdog.get("reason") or stop_reason)
        source = "operational_watchdog"

    dominant_watchdog_decision = ""
    decision_counts: Dict[str, int] = {}
    for step in steps:
        if not isinstance(step, Mapping):
            continue
        step_watchdog = step.get("operational_watchdog") if isinstance(step.get("operational_watchdog"), Mapping) else {}
        decision = str(step_watchdog.get("decision") or "").strip()
        if decision:
            decision_counts[decision] = int(decision_counts.get(decision) or 0) + 1
    if decision_counts:
        dominant_watchdog_decision = sorted(
            decision_counts.items(),
            key=lambda item: (-int(item[1] or 0), str(item[0] or "")),
        )[0][0]

    risk_flags: List[str] = []
    if bool(live_site_safety_policy.get("is_blocking")):
        risk_flags.append("live_site_safety_block")
    if bool(live_site_safety_policy.get("requires_review")):
        risk_flags.append("live_site_requires_review")
    if bool(escalation_threshold_policy.get("is_blocking")):
        risk_flags.append("threshold_escalation")
    if str(operational_watchdog.get("decision") or "") in {"fallback", "abort"}:
        risk_flags.append(f"watchdog_{str(operational_watchdog.get('decision') or '').strip()}")
    if error.startswith("Blocked by "):
        risk_flags.append("hard_block")
    if error.startswith("Escalated to operator"):
        risk_flags.append("operator_escalation")
    if error.startswith("Max steps reached"):
        risk_flags.append("max_steps")
    if error.startswith("No screenshot progress"):
        risk_flags.append("stalled_progress")
    if stop_reason == "runtime_stopped":
        risk_flags.append("runtime_stopped")

    next_session_expectation = "normal_start"
    if "hard_block" in risk_flags:
        next_session_expectation = "expect_guard_block"
    elif "operator_escalation" in risk_flags:
        next_session_expectation = "expect_review_gate"
    elif "stalled_progress" in risk_flags or "watchdog_abort" in risk_flags:
        next_session_expectation = "expect_stall_recovery"
    elif "max_steps" in risk_flags or "watchdog_fallback" in risk_flags or "runtime_stopped" in risk_flags:
        next_session_expectation = "expect_fallback_reuse"

    return {
        "schema_version": SCHEMA_VERSION,
        "memory_scope": "session_run",
        "canonical_site_id": canonical_site_id,
        "stop_reason": stop_reason,
        "stop_reason_source": source,
        "failure_summary": {
            "what_failed": str((failure_summary or {}).get("what_failed") or ""),
            "why_failed": str((failure_summary or {}).get("why_failed") or ""),
            "next_best_action": str((failure_summary or {}).get("next_best_action") or ""),
        },
        "dominant_watchdog_decision": dominant_watchdog_decision,
        "risk_flags": sorted(set(flag for flag in risk_flags if flag)),
        "next_session_expectation": next_session_expectation,
        "signals": {
            "completed": bool(summary_data.get("completed")),
            "total_steps": len([step for step in steps if isinstance(step, Mapping)]),
            "has_failure_summary": bool(failure_summary),
            "has_operational_watchdog": bool(operational_watchdog),
        },
    }


def build_known_target_template_cache(
    *,
    site_identity_registry: Mapping[str, Any],
    steps: Sequence[Any],
) -> Dict[str, Any]:
    registry = dict(site_identity_registry or {})
    canonical_site_id = str(registry.get("canonical_site_id") or "").strip()
    template_rows: Dict[str, Dict[str, Any]] = {}
    for index, step in enumerate(steps, start=1):
        if not isinstance(step, Mapping):
            continue
        screen_state = step.get("screen_state") if isinstance(step.get("screen_state"), Mapping) else {}
        active_block = screen_state.get("active_block") if isinstance(screen_state.get("active_block"), Mapping) else {}
        actions = step.get("actions") if isinstance(step.get("actions"), list) else []
        first_action = actions[0] if actions and isinstance(actions[0], Mapping) else {}
        qid = str(
            (active_block or {}).get("id")
            or screen_state.get("active_block_id")
            or screen_state.get("active_question_id")
            or ""
        ).strip()
        control_kind = str(screen_state.get("control_kind") or (active_block or {}).get("control_kind") or "").strip().lower()
        plan_kind = str(step.get("plan_kind") or first_action.get("kind") or "").strip().lower()
        if not (qid or control_kind or plan_kind):
            continue
        template_key = "|".join([qid or "unknown_qid", control_kind or "unknown_control", plan_kind or "unknown_plan"])
        target_bbox = first_action.get("bbox") if isinstance(first_action.get("bbox"), (list, tuple)) else []
        option_texts = [
            str((row or {}).get("text") or "").strip()
            for row in (screen_state.get("options") or [])
            if isinstance(row, Mapping) and str((row or {}).get("text") or "").strip()
        ]
        resolved_answer = step.get("resolved_answer") if isinstance(step.get("resolved_answer"), Mapping) else {}
        answer_hints = [
            str(value).strip()
            for value in (resolved_answer.get("correct_answers") or [])
            if str(value).strip()
        ]
        if not answer_hints:
            for key in ("selected_option", "selected_text", "value", "text"):
                value = str(resolved_answer.get(key) or "").strip()
                if value:
                    answer_hints.append(value)
        row = template_rows.setdefault(
            template_key,
            {
                "template_key": template_key,
                "qid": qid,
                "control_kind": control_kind,
                "plan_kind": plan_kind,
                "sample_count": 0,
                "latest_iteration": 0,
                "plan_reasons": set(),
                "target_bboxes": [],
                "active_block_bbox": [],
                "answer_hints": set(),
                "option_text_signatures": set(),
                "semantic_success_hits": 0,
            },
        )
        row["sample_count"] = int(row["sample_count"]) + 1
        row["latest_iteration"] = int(step.get("iteration") or index)
        if str(step.get("plan_reason") or "").strip():
            row["plan_reasons"].add(str(step.get("plan_reason") or "").strip())
        if isinstance(target_bbox, (list, tuple)) and len(target_bbox) == 4:
            row["target_bboxes"].append([float(target_bbox[0]), float(target_bbox[1]), float(target_bbox[2]), float(target_bbox[3])])
        active_block_bbox = (active_block or {}).get("bbox") if isinstance((active_block or {}).get("bbox"), (list, tuple)) else []
        if isinstance(active_block_bbox, (list, tuple)) and len(active_block_bbox) == 4:
            row["active_block_bbox"] = [float(active_block_bbox[0]), float(active_block_bbox[1]), float(active_block_bbox[2]), float(active_block_bbox[3])]
        for hint in answer_hints:
            row["answer_hints"].add(hint)
        if option_texts:
            row["option_text_signatures"].add(" | ".join(option_texts[:6]))
        action_result_packet = step.get("action_result_packet") if isinstance(step.get("action_result_packet"), Mapping) else {}
        row["semantic_success_hits"] = int(row["semantic_success_hits"]) + int(bool(action_result_packet.get("semantic_success")))

    templates: List[Dict[str, Any]] = []
    for row in template_rows.values():
        target_bboxes = row.get("target_bboxes") if isinstance(row.get("target_bboxes"), list) else []
        anchor_bbox: List[float] = []
        if target_bboxes:
            first_bbox = target_bboxes[0]
            anchor_bbox = [float(first_bbox[0]), float(first_bbox[1]), float(first_bbox[2]), float(first_bbox[3])]
        templates.append(
            {
                "template_key": str(row.get("template_key") or ""),
                "qid": str(row.get("qid") or ""),
                "control_kind": str(row.get("control_kind") or ""),
                "plan_kind": str(row.get("plan_kind") or ""),
                "sample_count": int(row.get("sample_count") or 0),
                "latest_iteration": int(row.get("latest_iteration") or 0),
                "plan_reasons": sorted(str(value) for value in (row.get("plan_reasons") or set()) if str(value)),
                "anchor_target_bbox": anchor_bbox,
                "active_block_bbox": list(row.get("active_block_bbox") or []),
                "answer_hints": sorted(str(value) for value in (row.get("answer_hints") or set()) if str(value)),
                "option_text_signatures": sorted(
                    str(value) for value in (row.get("option_text_signatures") or set()) if str(value)
                ),
                "semantic_success_hits": int(row.get("semantic_success_hits") or 0),
            }
        )
    templates.sort(
        key=lambda row: (
            -int(row.get("sample_count") or 0),
            -int(row.get("semantic_success_hits") or 0),
            str(row.get("template_key") or ""),
        )
    )
    return {
        "schema_version": SCHEMA_VERSION,
        "memory_scope": "session_run",
        "canonical_site_id": canonical_site_id,
        "template_count": len(templates),
        "templates": templates,
        "signals": {
            "total_steps": len([step for step in steps if isinstance(step, Mapping)]),
            "qid_backed_templates": len([row for row in templates if str(row.get("qid") or "")]),
        },
    }


def build_survey_difficulty_memory(
    *,
    site_identity_registry: Mapping[str, Any],
    summary: Mapping[str, Any],
) -> Dict[str, Any]:
    registry = dict(site_identity_registry or {})
    summary_data = dict(summary or {})
    canonical_site_id = str(registry.get("canonical_site_id") or "").strip()
    steps = summary_data.get("steps") if isinstance(summary_data.get("steps"), list) else []
    total_steps = len([step for step in steps if isinstance(step, Mapping)])
    fallback_steps = 0
    progressed_steps = 0
    semantic_success_steps = 0
    blocked_validation_steps = 0
    retry_pressure = 0
    watchdog_pressure = 0
    confidence_values: List[float] = []
    control_kinds: set[str] = set()

    for step in steps:
        if not isinstance(step, Mapping):
            continue
        if bool(step.get("fallback_used")):
            fallback_steps += 1
        runtime_state = step.get("runtime_state") if isinstance(step.get("runtime_state"), Mapping) else {}
        if bool(runtime_state.get("progressed")):
            progressed_steps += 1
        retry_pressure += int(runtime_state.get("attempt_count") or 0)
        screen_state = step.get("screen_state") if isinstance(step.get("screen_state"), Mapping) else {}
        control_kind = str(screen_state.get("control_kind") or "").strip().lower()
        if control_kind:
            control_kinds.add(control_kind)
        confidence_policy = (
            screen_state.get("confidence_fusion_policy")
            if isinstance(screen_state.get("confidence_fusion_policy"), Mapping)
            else {}
        )
        fused_confidence = confidence_policy.get("fused_confidence")
        if isinstance(fused_confidence, (int, float)):
            confidence_values.append(float(fused_confidence))
        action_result_packet = step.get("action_result_packet") if isinstance(step.get("action_result_packet"), Mapping) else {}
        if bool(action_result_packet.get("semantic_success")):
            semantic_success_steps += 1
        validation_outcome = step.get("validation_outcome") if isinstance(step.get("validation_outcome"), Mapping) else {}
        if str(validation_outcome.get("outcome") or "").strip().lower() == "blocked":
            blocked_validation_steps += 1
        operational_watchdog = step.get("operational_watchdog") if isinstance(step.get("operational_watchdog"), Mapping) else {}
        watchdog_decision = str(operational_watchdog.get("decision") or "").strip().lower()
        if watchdog_decision in {"retry", "fallback", "abort"}:
            watchdog_pressure += 1

    difficulty_points = 0.0
    difficulty_points += float(fallback_steps) * 1.5
    difficulty_points += float(blocked_validation_steps) * 1.75
    difficulty_points += float(watchdog_pressure) * 1.5
    difficulty_points += float(retry_pressure) * 0.6
    difficulty_points += max(float(total_steps) - 1.0, 0.0) * 0.35
    difficulty_points -= float(semantic_success_steps) * 0.5
    if confidence_values:
        avg_confidence = sum(confidence_values) / float(len(confidence_values))
        if avg_confidence < 0.5:
            difficulty_points += 1.2
        elif avg_confidence < 0.7:
            difficulty_points += 0.6
    else:
        avg_confidence = 0.0

    error = str(summary_data.get("error") or "").strip()
    if error.startswith("Blocked by "):
        difficulty_points += 2.5
    elif error.startswith("Escalated to operator"):
        difficulty_points += 2.0
    elif error.startswith("Max steps reached") or error.startswith("No screenshot progress"):
        difficulty_points += 1.5

    difficulty_score = max(0.0, min(10.0, round(float(difficulty_points), 4)))
    difficulty_band = "easy"
    if difficulty_score >= 7.0:
        difficulty_band = "hard"
    elif difficulty_score >= 3.5:
        difficulty_band = "medium"

    risk_reasons: List[str] = []
    if fallback_steps:
        risk_reasons.append("fallback_pressure")
    if blocked_validation_steps:
        risk_reasons.append("validation_block")
    if watchdog_pressure:
        risk_reasons.append("watchdog_recovery")
    if retry_pressure >= max(total_steps, 1):
        risk_reasons.append("retry_heavy")
    if avg_confidence and avg_confidence < 0.7:
        risk_reasons.append("low_fused_confidence")
    if error:
        risk_reasons.append("non_clean_finish")

    return {
        "schema_version": SCHEMA_VERSION,
        "memory_scope": "session_run",
        "canonical_site_id": canonical_site_id,
        "difficulty_score": difficulty_score,
        "difficulty_band": difficulty_band,
        "risk_reasons": sorted(set(risk_reasons)),
        "signals": {
            "total_steps": total_steps,
            "fallback_steps": int(fallback_steps),
            "progressed_steps": int(progressed_steps),
            "semantic_success_steps": int(semantic_success_steps),
            "blocked_validation_steps": int(blocked_validation_steps),
            "retry_pressure": int(retry_pressure),
            "watchdog_pressure": int(watchdog_pressure),
            "avg_fused_confidence": round(float(avg_confidence), 4) if confidence_values else 0.0,
            "control_kinds_seen": sorted(control_kinds),
        },
    }


def build_site_guard_profile(
    *,
    site_identity_registry: Mapping[str, Any],
    summary: Mapping[str, Any],
) -> Dict[str, Any]:
    registry = dict(site_identity_registry or {})
    summary_data = dict(summary or {})
    canonical_site_id = str(registry.get("canonical_site_id") or "").strip()
    site_failure_priors = summary_data.get("site_failure_priors") if isinstance(summary_data.get("site_failure_priors"), Mapping) else {}
    domain_allowlist = summary_data.get("domain_allowlist") if isinstance(summary_data.get("domain_allowlist"), Mapping) else {}
    wrong_context_recovery_policy = (
        summary_data.get("wrong_context_recovery_policy")
        if isinstance(summary_data.get("wrong_context_recovery_policy"), Mapping)
        else {}
    )
    allowed_context_policy = (
        summary_data.get("allowed_context_policy") if isinstance(summary_data.get("allowed_context_policy"), Mapping) else {}
    )
    frame_context_guard = summary_data.get("frame_context_guard") if isinstance(summary_data.get("frame_context_guard"), Mapping) else {}
    anti_modal_guard = summary_data.get("anti_modal_guard") if isinstance(summary_data.get("anti_modal_guard"), Mapping) else {}
    consent_barrier_policy = (
        summary_data.get("consent_barrier_policy") if isinstance(summary_data.get("consent_barrier_policy"), Mapping) else {}
    )
    hard_stop_guard = summary_data.get("hard_stop_guard") if isinstance(summary_data.get("hard_stop_guard"), Mapping) else {}
    error = str(summary_data.get("error") or "").strip()

    guard_flags: List[str] = []
    if not bool(domain_allowlist.get("is_allowed", True)):
        guard_flags.append("domain_allowlist_block")
    if not bool(allowed_context_policy.get("is_allowed", True)):
        guard_flags.append("wrong_context_block")
    if bool(allowed_context_policy.get("requires_review")):
        guard_flags.append("wrong_context_review")
    if not bool(frame_context_guard.get("is_allowed", True)):
        guard_flags.append("foreign_frame_block")
    if bool(anti_modal_guard.get("is_blocking")):
        guard_flags.append("unexpected_modal_block")
    if bool(consent_barrier_policy.get("is_blocking")):
        guard_flags.append("consent_barrier_block")
    if bool(hard_stop_guard.get("is_blocking")):
        guard_flags.append(f"hard_stop_{str(hard_stop_guard.get('source') or 'unknown').strip()}")
    if "wrong_tab" in error:
        guard_flags.append("wrong_tab_history")
    if "stale_previous_run" in error:
        guard_flags.append("stale_previous_run_history")

    recommended_extra_blocks: List[str] = []
    if "wrong_context_block" in guard_flags or "wrong_context_review" in guard_flags or "wrong_tab_history" in guard_flags:
        recommended_extra_blocks.append("require_context_revalidation")
    if "foreign_frame_block" in guard_flags:
        recommended_extra_blocks.append("forbid_foreign_frame_clicks")
    if "unexpected_modal_block" in guard_flags or "consent_barrier_block" in guard_flags:
        recommended_extra_blocks.append("pause_on_modal_like_overlay")
    if any(flag.startswith("hard_stop_") for flag in guard_flags):
        recommended_extra_blocks.append("prefer_safe_stop_before_submit")

    profile_level = "low"
    if len(set(guard_flags)) >= 4:
        profile_level = "high"
    elif len(set(guard_flags)) >= 2:
        profile_level = "medium"

    return {
        "schema_version": SCHEMA_VERSION,
        "memory_scope": "session_run",
        "canonical_site_id": canonical_site_id,
        "profile_level": profile_level,
        "guard_flags": sorted(set(flag for flag in guard_flags if flag)),
        "recommended_extra_blocks": sorted(set(recommended_extra_blocks)),
        "signals": {
            "stop_reason": str(site_failure_priors.get("stop_reason") or ""),
            "domain_allowlist_reason": str(domain_allowlist.get("reason") or ""),
            "wrong_context_action": str(wrong_context_recovery_policy.get("recommended_action") or ""),
            "allowed_context_reason": str(allowed_context_policy.get("reason") or ""),
            "frame_context_reason": str(frame_context_guard.get("reason") or ""),
            "anti_modal_reason": str(anti_modal_guard.get("reason") or ""),
            "consent_reason": str(consent_barrier_policy.get("reason") or ""),
            "hard_stop_source": str(hard_stop_guard.get("source") or ""),
        },
    }


def build_site_specific_forbidden_targets(
    *,
    site_identity_registry: Mapping[str, Any],
    summary: Mapping[str, Any],
) -> Dict[str, Any]:
    registry = dict(site_identity_registry or {})
    summary_data = dict(summary or {})
    canonical_site_id = str(registry.get("canonical_site_id") or "").strip()
    steps = summary_data.get("steps") if isinstance(summary_data.get("steps"), list) else []
    anti_modal_guard = summary_data.get("anti_modal_guard") if isinstance(summary_data.get("anti_modal_guard"), Mapping) else {}
    consent_barrier_policy = (
        summary_data.get("consent_barrier_policy") if isinstance(summary_data.get("consent_barrier_policy"), Mapping) else {}
    )
    allowed_action_policy = (
        summary_data.get("allowed_action_policy") if isinstance(summary_data.get("allowed_action_policy"), Mapping) else {}
    )

    forbidden_rows: Dict[str, Dict[str, Any]] = {}

    def _touch(label: str, source: str, reason: str, token: str = "") -> None:
        if not label:
            return
        row = forbidden_rows.setdefault(
            label,
            {
                "label": label,
                "sources": set(),
                "reasons": set(),
                "tokens": set(),
                "hits": 0,
            },
        )
        row["sources"].add(source)
        if reason:
            row["reasons"].add(reason)
        if token:
            row["tokens"].add(token)
        row["hits"] = int(row["hits"]) + 1

    for step in steps:
        if not isinstance(step, Mapping):
            continue
        actions = step.get("actions") if isinstance(step.get("actions"), list) else []
        plan_reason = str(step.get("plan_reason") or "").strip()
        for action in actions:
            if not isinstance(action, Mapping):
                continue
            reason = str(action.get("reason") or plan_reason or "").strip()
            kind = str(action.get("kind") or "").strip().lower()
            label = ""
            if ":" in reason:
                label = str(reason.split(":", 1)[1] or "").strip().lower()
            elif reason and kind == "dom_click_button":
                label = reason.strip().lower()
            if not label:
                continue
            if any(token in label for token in ("buy", "pay", "subscribe", "login", "install", "share", "cookies", "cookie", "accept")):
                matched_token = next(
                    (token for token in ("buy", "pay", "subscribe", "login", "install", "share", "cookies", "cookie", "accept") if token in label),
                    "",
                )
                _touch(label=label, source="step_actions", reason=reason, token=matched_token)

    for token in anti_modal_guard.get("matched_tokens") or []:
        normalized = str(token or "").strip().lower()
        if normalized:
            _touch(label=normalized, source="anti_modal_guard", reason=str(anti_modal_guard.get("reason") or ""), token=normalized)
    consent_reason = str(consent_barrier_policy.get("reason") or "").strip()
    if consent_reason:
        for token in ("accept cookies", "cookie consent", "consent accept", "captcha"):
            if token in consent_reason.lower():
                _touch(label=token, source="consent_barrier_policy", reason=consent_reason, token=token)
    allowed_reason = str(allowed_action_policy.get("reason") or "").strip()
    if allowed_reason.startswith("forbidden_token:"):
        token = str(allowed_reason.split(":", 1)[1] or "").strip().lower()
        if token:
            _touch(label=token, source="allowed_action_policy", reason=allowed_reason, token=token)

    forbidden_targets: List[Dict[str, Any]] = []
    for row in forbidden_rows.values():
        forbidden_targets.append(
            {
                "label": str(row.get("label") or ""),
                "sources": sorted(str(value) for value in (row.get("sources") or set()) if str(value)),
                "reasons": sorted(str(value) for value in (row.get("reasons") or set()) if str(value)),
                "tokens": sorted(str(value) for value in (row.get("tokens") or set()) if str(value)),
                "hits": int(row.get("hits") or 0),
            }
        )
    forbidden_targets.sort(key=lambda row: (-int(row.get("hits") or 0), str(row.get("label") or "")))
    return {
        "schema_version": SCHEMA_VERSION,
        "memory_scope": "session_run",
        "canonical_site_id": canonical_site_id,
        "forbidden_targets": forbidden_targets,
        "signals": {
            "forbidden_count": len(forbidden_targets),
            "has_cookie_overlay_risk": any("cookie" in str(row.get("label") or "") for row in forbidden_targets),
        },
    }


def build_site_noise_signature_db(
    *,
    site_identity_registry: Mapping[str, Any],
    summary: Mapping[str, Any],
) -> Dict[str, Any]:
    registry = dict(site_identity_registry or {})
    summary_data = dict(summary or {})
    canonical_site_id = str(registry.get("canonical_site_id") or "").strip()
    steps = summary_data.get("steps") if isinstance(summary_data.get("steps"), list) else []
    noise_rows: Dict[str, Dict[str, Any]] = {}
    for step in steps:
        if not isinstance(step, Mapping):
            continue
        screen_state = step.get("screen_state") if isinstance(step.get("screen_state"), Mapping) else {}
        runtime_contracts = step.get("runtime_contracts") if isinstance(step.get("runtime_contracts"), Mapping) else {}
        blank_screen_guard = (
            runtime_contracts.get("blank_screen_guard") if isinstance(runtime_contracts.get("blank_screen_guard"), Mapping) else {}
        )
        screen_signature = str(
            screen_state.get("screen_signature")
            or screen_state.get("active_question_signature")
            or step.get("signature_before")
            or ""
        ).strip()
        if not screen_signature:
            continue
        question_text = str(screen_state.get("question_text") or "").strip()
        options = screen_state.get("options") if isinstance(screen_state.get("options"), list) else []
        parse_quality = str(screen_state.get("screen_parse_quality") or "").strip().lower()
        noise_reasons: List[str] = []
        if bool(blank_screen_guard.get("is_blank")):
            noise_reasons.append("blank_screen_guard")
        if not question_text:
            noise_reasons.append("empty_question_text")
        if parse_quality in {"question_only", "empty", "noise"}:
            noise_reasons.append(f"parse_quality:{parse_quality}")
        if not options:
            noise_reasons.append("no_options")
        if not noise_reasons:
            continue
        row = noise_rows.setdefault(
            screen_signature,
            {
                "screen_signature": screen_signature,
                "hits": 0,
                "noise_reasons": set(),
                "question_text_samples": set(),
                "parse_qualities": set(),
                "iterations": [],
            },
        )
        row["hits"] = int(row["hits"]) + 1
        for reason in noise_reasons:
            row["noise_reasons"].add(reason)
        if question_text:
            row["question_text_samples"].add(question_text[:120])
        if parse_quality:
            row["parse_qualities"].add(parse_quality)
        row["iterations"].append(int(step.get("iteration") or 0))

    noise_signatures: List[Dict[str, Any]] = []
    for row in noise_rows.values():
        noise_signatures.append(
            {
                "screen_signature": str(row.get("screen_signature") or ""),
                "hits": int(row.get("hits") or 0),
                "noise_reasons": sorted(str(value) for value in (row.get("noise_reasons") or set()) if str(value)),
                "question_text_samples": sorted(
                    str(value) for value in (row.get("question_text_samples") or set()) if str(value)
                ),
                "parse_qualities": sorted(str(value) for value in (row.get("parse_qualities") or set()) if str(value)),
                "iterations": sorted(int(value) for value in (row.get("iterations") or []) if int(value) > 0),
            }
        )
    noise_signatures.sort(key=lambda row: (-int(row.get("hits") or 0), str(row.get("screen_signature") or "")))
    return {
        "schema_version": SCHEMA_VERSION,
        "memory_scope": "session_run",
        "canonical_site_id": canonical_site_id,
        "noise_signatures": noise_signatures,
        "signals": {
            "noise_signature_count": len(noise_signatures),
            "blank_like_signature_count": len(
                [row for row in noise_signatures if "blank_screen_guard" in (row.get("noise_reasons") or [])]
            ),
        },
    }


def build_site_wait_profile(
    *,
    site_identity_registry: Mapping[str, Any],
    steps: Sequence[Any],
) -> Dict[str, Any]:
    registry = dict(site_identity_registry or {})
    canonical_site_id = str(registry.get("canonical_site_id") or "").strip()
    initial_waits: List[int] = []
    progress_timeouts: List[float] = []
    fallback_waits: List[int] = []
    wait_modes: set[str] = set()

    for step in steps:
        if not isinstance(step, Mapping):
            continue
        wait_profile = step.get("wait_profile") if isinstance(step.get("wait_profile"), Mapping) else {}
        initial_wait_ms = wait_profile.get("initial_wait_ms")
        progress_timeout_s = wait_profile.get("progress_timeout_s")
        fallback_wait_ms = wait_profile.get("fallback_wait_ms")
        wait_mode = str(wait_profile.get("wait_mode") or "").strip().lower()
        if isinstance(initial_wait_ms, (int, float)):
            initial_waits.append(int(initial_wait_ms))
        if isinstance(progress_timeout_s, (int, float)):
            progress_timeouts.append(float(progress_timeout_s))
        if isinstance(fallback_wait_ms, (int, float)):
            fallback_waits.append(int(fallback_wait_ms))
        if wait_mode:
            wait_modes.add(wait_mode)

    def _median_int(values: List[int]) -> int:
        ordered = sorted(values)
        if not ordered:
            return 0
        return int(ordered[len(ordered) // 2])

    def _median_float(values: List[float]) -> float:
        ordered = sorted(values)
        if not ordered:
            return 0.0
        return round(float(ordered[len(ordered) // 2]), 4)

    preferred_wait_mode = ""
    if wait_modes:
        preferred_wait_mode = sorted(wait_modes)[0] if len(wait_modes) == 1 else ("auto_text" if "auto_text" in wait_modes else sorted(wait_modes)[0])

    timeout_multiplier = 1.0
    median_progress_timeout = _median_float(progress_timeouts)
    if median_progress_timeout >= 3.0:
        timeout_multiplier = 2.0
    elif median_progress_timeout >= 1.8:
        timeout_multiplier = 1.5

    stabilization_window_ms = _median_int(initial_waits)
    if fallback_waits:
        stabilization_window_ms = max(stabilization_window_ms, _median_int(fallback_waits))

    return {
        "schema_version": SCHEMA_VERSION,
        "memory_scope": "session_run",
        "canonical_site_id": canonical_site_id,
        "preferred_wait_mode": preferred_wait_mode,
        "stabilization_window_ms": int(stabilization_window_ms),
        "timeout_multiplier": round(float(timeout_multiplier), 4),
        "signals": {
            "observed_steps": len([step for step in steps if isinstance(step, Mapping)]),
            "median_initial_wait_ms": int(_median_int(initial_waits)),
            "median_progress_timeout_s": float(median_progress_timeout),
            "median_fallback_wait_ms": int(_median_int(fallback_waits)),
            "wait_modes_seen": sorted(wait_modes),
        },
    }


def build_memory_promotion_gate(
    *,
    site_identity_registry: Mapping[str, Any],
    summary: Mapping[str, Any],
) -> Dict[str, Any]:
    registry = dict(site_identity_registry or {})
    summary_data = dict(summary or {})
    canonical_site_id = str(registry.get("canonical_site_id") or "").strip()
    site_strategy_memory = summary_data.get("site_strategy_memory") if isinstance(summary_data.get("site_strategy_memory"), Mapping) else {}
    site_failure_priors = summary_data.get("site_failure_priors") if isinstance(summary_data.get("site_failure_priors"), Mapping) else {}
    known_target_template_cache = (
        summary_data.get("known_target_template_cache") if isinstance(summary_data.get("known_target_template_cache"), Mapping) else {}
    )
    survey_difficulty_memory = (
        summary_data.get("survey_difficulty_memory") if isinstance(summary_data.get("survey_difficulty_memory"), Mapping) else {}
    )
    site_guard_profile = summary_data.get("site_guard_profile") if isinstance(summary_data.get("site_guard_profile"), Mapping) else {}
    site_specific_forbidden_targets = (
        summary_data.get("site_specific_forbidden_targets")
        if isinstance(summary_data.get("site_specific_forbidden_targets"), Mapping)
        else {}
    )
    site_noise_signature_db = (
        summary_data.get("site_noise_signature_db") if isinstance(summary_data.get("site_noise_signature_db"), Mapping) else {}
    )
    site_wait_profile = summary_data.get("site_wait_profile") if isinstance(summary_data.get("site_wait_profile"), Mapping) else {}

    promotable: List[str] = []
    blocked: List[str] = []
    reasons: List[str] = []

    strategy_rows = site_strategy_memory.get("strategies") if isinstance(site_strategy_memory.get("strategies"), list) else []
    if strategy_rows and not bool(site_failure_priors.get("risk_flags")):
        promotable.append("site_strategy_memory")
    elif strategy_rows:
        blocked.append("site_strategy_memory")
        reasons.append("strategy_memory_has_risk_flags")

    template_count = int(known_target_template_cache.get("template_count") or 0)
    noise_count = int((site_noise_signature_db.get("signals") or {}).get("noise_signature_count") or 0)
    if template_count > 0 and noise_count == 0:
        promotable.append("known_target_template_cache")
    elif template_count > 0:
        blocked.append("known_target_template_cache")
        reasons.append("target_templates_compete_with_noise")

    forbidden_targets = (
        site_specific_forbidden_targets.get("forbidden_targets")
        if isinstance(site_specific_forbidden_targets.get("forbidden_targets"), list)
        else []
    )
    if forbidden_targets:
        promotable.append("site_specific_forbidden_targets")

    guard_flags = site_guard_profile.get("guard_flags") if isinstance(site_guard_profile.get("guard_flags"), list) else []
    if guard_flags:
        promotable.append("site_guard_profile")

    wait_mode = str(site_wait_profile.get("preferred_wait_mode") or "").strip()
    if wait_mode:
        promotable.append("site_wait_profile")

    difficulty_band = str(survey_difficulty_memory.get("difficulty_band") or "").strip()
    if difficulty_band in {"easy", "medium", "hard"}:
        promotable.append("survey_difficulty_memory")

    if noise_count > 0:
        promotable.append("site_noise_signature_db")

    profile_level = str(site_guard_profile.get("profile_level") or "").strip().lower()
    if profile_level == "high":
        reasons.append("high_guard_profile_requires_review")
    if str(site_failure_priors.get("next_session_expectation") or "").strip() in {"expect_guard_block", "expect_review_gate"}:
        reasons.append("failure_priors_require_manual_review")

    requires_review = bool(reasons)
    promotion_decision = "promote_selected" if promotable and not requires_review else ("review_before_promotion" if promotable else "do_not_promote")
    return {
        "schema_version": SCHEMA_VERSION,
        "memory_scope": "session_run",
        "canonical_site_id": canonical_site_id,
        "promotion_decision": promotion_decision,
        "requires_review": requires_review,
        "promotable_contracts": sorted(set(promotable)),
        "blocked_contracts": sorted(set(blocked)),
        "reasons": sorted(set(reasons)),
        "signals": {
            "strategy_variants": len(strategy_rows),
            "target_template_count": template_count,
            "forbidden_target_count": len(forbidden_targets),
            "noise_signature_count": noise_count,
            "guard_flag_count": len(guard_flags),
            "wait_mode_present": bool(wait_mode),
        },
    }


def build_memory_expiry_policy(
    *,
    site_identity_registry: Mapping[str, Any],
    summary: Mapping[str, Any],
) -> Dict[str, Any]:
    registry = dict(site_identity_registry or {})
    summary_data = dict(summary or {})
    canonical_site_id = str(registry.get("canonical_site_id") or "").strip()
    layout_family_classifier = (
        summary_data.get("layout_family_classifier") if isinstance(summary_data.get("layout_family_classifier"), Mapping) else {}
    )
    url_canonicalizer = summary_data.get("url_canonicalizer") if isinstance(summary_data.get("url_canonicalizer"), Mapping) else {}
    site_failure_priors = summary_data.get("site_failure_priors") if isinstance(summary_data.get("site_failure_priors"), Mapping) else {}
    site_noise_signature_db = (
        summary_data.get("site_noise_signature_db") if isinstance(summary_data.get("site_noise_signature_db"), Mapping) else {}
    )
    site_wait_profile = summary_data.get("site_wait_profile") if isinstance(summary_data.get("site_wait_profile"), Mapping) else {}
    memory_promotion_gate = (
        summary_data.get("memory_promotion_gate") if isinstance(summary_data.get("memory_promotion_gate"), Mapping) else {}
    )

    observed_fingerprint = str(registry.get("observed_fingerprint") or "").strip()
    layout_family = str(layout_family_classifier.get("layout_family") or "").strip()
    stable_site_key = str(url_canonicalizer.get("stable_site_key") or "").strip()
    stop_reason = str(site_failure_priors.get("stop_reason") or "").strip()
    noise_count = int((site_noise_signature_db.get("signals") or {}).get("noise_signature_count") or 0)
    wait_mode = str(site_wait_profile.get("preferred_wait_mode") or "").strip()
    requires_review = bool(memory_promotion_gate.get("requires_review"))

    expiry_pressure = 0
    expiry_reasons: List[str] = []
    if not observed_fingerprint:
        expiry_pressure += 2
        expiry_reasons.append("missing_fingerprint")
    if layout_family in {"unknown", ""}:
        expiry_pressure += 1
        expiry_reasons.append("unknown_layout_family")
    if noise_count > 0:
        expiry_pressure += 2
        expiry_reasons.append("noise_signatures_present")
    if requires_review:
        expiry_pressure += 2
        expiry_reasons.append("promotion_requires_review")
    if stop_reason in {"runtime_stopped", "unknown_failure"}:
        expiry_pressure += 1
        expiry_reasons.append("unstable_stop_reason")
    if wait_mode == "auto_text":
        expiry_pressure += 1
        expiry_reasons.append("site_specific_wait_needed")

    expiry_band = "retain"
    ttl_runs = 5
    if expiry_pressure >= 5:
        expiry_band = "expire_fast"
        ttl_runs = 1
    elif expiry_pressure >= 3:
        expiry_band = "expire_medium"
        ttl_runs = 2

    return {
        "schema_version": SCHEMA_VERSION,
        "memory_scope": "session_run",
        "canonical_site_id": canonical_site_id,
        "stable_site_key": stable_site_key,
        "expiry_band": expiry_band,
        "ttl_runs": int(ttl_runs),
        "expiry_reasons": sorted(set(expiry_reasons)),
        "signals": {
            "observed_fingerprint_present": bool(observed_fingerprint),
            "layout_family": layout_family,
            "noise_signature_count": noise_count,
            "requires_review": requires_review,
            "stop_reason": stop_reason,
            "wait_mode": wait_mode,
        },
    }


def build_novelty_override_rule(
    *,
    site_identity_registry: Mapping[str, Any],
    summary: Mapping[str, Any],
) -> Dict[str, Any]:
    registry = dict(site_identity_registry or {})
    summary_data = dict(summary or {})
    canonical_site_id = str(registry.get("canonical_site_id") or "").strip()
    layout_family_classifier = (
        summary_data.get("layout_family_classifier") if isinstance(summary_data.get("layout_family_classifier"), Mapping) else {}
    )
    site_guard_profile = summary_data.get("site_guard_profile") if isinstance(summary_data.get("site_guard_profile"), Mapping) else {}
    site_noise_signature_db = (
        summary_data.get("site_noise_signature_db") if isinstance(summary_data.get("site_noise_signature_db"), Mapping) else {}
    )
    memory_promotion_gate = (
        summary_data.get("memory_promotion_gate") if isinstance(summary_data.get("memory_promotion_gate"), Mapping) else {}
    )
    memory_expiry_policy = (
        summary_data.get("memory_expiry_policy") if isinstance(summary_data.get("memory_expiry_policy"), Mapping) else {}
    )
    steps = summary_data.get("steps") if isinstance(summary_data.get("steps"), list) else []

    observed_fingerprint = str(registry.get("observed_fingerprint") or "").strip()
    layout_family = str(layout_family_classifier.get("layout_family") or "").strip().lower()
    guard_flags = site_guard_profile.get("guard_flags") if isinstance(site_guard_profile.get("guard_flags"), list) else []
    noise_count = int((site_noise_signature_db.get("signals") or {}).get("noise_signature_count") or 0)
    requires_review = bool(memory_promotion_gate.get("requires_review"))
    expiry_band = str(memory_expiry_policy.get("expiry_band") or "").strip().lower()

    min_site_consistency = 1.0
    for step in steps:
        if not isinstance(step, Mapping):
            continue
        trace = step.get("trace") if isinstance(step.get("trace"), Mapping) else {}
        consistency = trace.get("screen_site_consistency")
        if isinstance(consistency, (int, float)):
            min_site_consistency = min(min_site_consistency, float(consistency))

    novelty_signals: List[str] = []
    if not observed_fingerprint:
        novelty_signals.append("missing_fingerprint")
    if layout_family in {"unknown", ""}:
        novelty_signals.append("unknown_layout_family")
    if noise_count > 0:
        novelty_signals.append("noise_signature_present")
    if requires_review:
        novelty_signals.append("memory_requires_review")
    if expiry_band == "expire_fast":
        novelty_signals.append("memory_expiring_fast")
    if min_site_consistency < 0.7:
        novelty_signals.append("low_site_consistency")
    if len(guard_flags) >= 2:
        novelty_signals.append("multiple_guard_flags")

    should_override_memory = bool(novelty_signals)
    override_strength = "none"
    if len(novelty_signals) >= 4:
        override_strength = "high"
    elif len(novelty_signals) >= 2:
        override_strength = "medium"
    elif novelty_signals:
        override_strength = "low"

    return {
        "schema_version": SCHEMA_VERSION,
        "memory_scope": "session_run",
        "canonical_site_id": canonical_site_id,
        "should_override_memory": should_override_memory,
        "override_strength": override_strength,
        "novelty_signals": sorted(set(novelty_signals)),
        "signals": {
            "observed_fingerprint_present": bool(observed_fingerprint),
            "layout_family": layout_family,
            "noise_signature_count": noise_count,
            "requires_review": requires_review,
            "expiry_band": expiry_band,
            "min_site_consistency": round(float(min_site_consistency), 4),
        },
    }


def build_site_brief_packet(
    *,
    site_identity_registry: Mapping[str, Any],
    summary: Mapping[str, Any],
) -> Dict[str, Any]:
    registry = dict(site_identity_registry or {})
    summary_data = dict(summary or {})
    canonical_site_id = str(registry.get("canonical_site_id") or "").strip()
    site_strategy_memory = summary_data.get("site_strategy_memory") if isinstance(summary_data.get("site_strategy_memory"), Mapping) else {}
    site_failure_priors = summary_data.get("site_failure_priors") if isinstance(summary_data.get("site_failure_priors"), Mapping) else {}
    site_guard_profile = summary_data.get("site_guard_profile") if isinstance(summary_data.get("site_guard_profile"), Mapping) else {}
    site_specific_forbidden_targets = (
        summary_data.get("site_specific_forbidden_targets")
        if isinstance(summary_data.get("site_specific_forbidden_targets"), Mapping)
        else {}
    )
    site_noise_signature_db = (
        summary_data.get("site_noise_signature_db") if isinstance(summary_data.get("site_noise_signature_db"), Mapping) else {}
    )
    site_wait_profile = summary_data.get("site_wait_profile") if isinstance(summary_data.get("site_wait_profile"), Mapping) else {}
    layout_family_classifier = (
        summary_data.get("layout_family_classifier") if isinstance(summary_data.get("layout_family_classifier"), Mapping) else {}
    )
    memory_expiry_policy = (
        summary_data.get("memory_expiry_policy") if isinstance(summary_data.get("memory_expiry_policy"), Mapping) else {}
    )

    preferred_strategy = str(site_strategy_memory.get("preferred_plan_source") or "").strip() or "unknown"
    layout_family = str(layout_family_classifier.get("layout_family") or "").strip() or "unknown"
    wait_mode = str(site_wait_profile.get("preferred_wait_mode") or "").strip() or "default"
    guard_flags = site_guard_profile.get("guard_flags") if isinstance(site_guard_profile.get("guard_flags"), list) else []
    expiry_band = str(memory_expiry_policy.get("expiry_band") or "").strip() or "retain"
    noise_rows = site_noise_signature_db.get("noise_signatures") if isinstance(site_noise_signature_db.get("noise_signatures"), list) else []
    forbidden_rows = (
        site_specific_forbidden_targets.get("forbidden_targets")
        if isinstance(site_specific_forbidden_targets.get("forbidden_targets"), list)
        else []
    )

    known_traps: List[str] = []
    for row in forbidden_rows:
        if not isinstance(row, Mapping):
            continue
        label = str(row.get("label") or "").strip()
        if label:
            known_traps.append(label)
    if guard_flags:
        known_traps.extend([str(flag).strip() for flag in guard_flags if str(flag).strip()])
    if noise_rows:
        known_traps.append("noise_signature_present")

    expected_state_transitions: List[str] = ["observe", "parse", "plan", "execute", "readback"]
    if str(site_failure_priors.get("next_session_expectation") or "").strip():
        expected_state_transitions.append(str(site_failure_priors.get("next_session_expectation") or "").strip())
    if wait_mode == "auto_text":
        expected_state_transitions.append("wait_for_auto_text")
    if expiry_band == "expire_fast":
        expected_state_transitions.append("refresh_memory_before_reuse")
    if layout_family and layout_family != "unknown":
        expected_state_transitions.append(f"layout_family:{layout_family}")

    packet = {
        "canonical_site_id": canonical_site_id,
        "preferred_strategy": preferred_strategy,
        "known_traps": sorted(set(trap for trap in known_traps if trap)),
        "expected_state_transitions": list(dict.fromkeys(expected_state_transitions)),
        "layout_family": layout_family,
        "wait_mode": wait_mode,
        "expiry_band": expiry_band,
    }
    return {
        "schema_version": SCHEMA_VERSION,
        "packet": packet,
        "packet_hash": _sha1_payload(packet)[:16],
        "canonical_site_id": canonical_site_id,
        "preferred_strategy": preferred_strategy,
        "known_traps": packet["known_traps"],
        "expected_state_transitions": packet["expected_state_transitions"],
        "is_minimal": True,
    }


def build_iteration_time_budget_contract(
    *,
    total_budget_s: float = 0.0,
    capture_s: float = 0.0,
    parse_s: float = 0.0,
    execute_s: float = 0.0,
    readback_s: float = 0.0,
) -> Dict[str, Any]:
    budget = {
        "capture_s": max(0.0, float(capture_s or 0.0)),
        "parse_s": max(0.0, float(parse_s or 0.0)),
        "execute_s": max(0.0, float(execute_s or 0.0)),
        "readback_s": max(0.0, float(readback_s or 0.0)),
    }
    total = max(0.0, float(total_budget_s or 0.0))
    used = sum(budget.values())
    remaining = round(total - used, 4)
    is_over_budget = used > total if total > 0 else False
    if total <= 0:
        reason = "missing_total_budget"
    elif is_over_budget:
        reason = "time_budget_exceeded"
    else:
        reason = "within_budget"
    budget["total_s"] = round(total, 4)
    budget["used_s"] = round(used, 4)
    budget["remaining_s"] = remaining
    return {
        "schema_version": SCHEMA_VERSION,
        "reason": reason,
        "is_over_budget": is_over_budget,
        "budget": budget,
        "allocation_order": ["capture_s", "parse_s", "execute_s", "readback_s"],
    }


def build_stage_budget_allocator(
    *,
    total_budget_s: float = 0.0,
    stage_cost_hints: Mapping[str, Any] | None = None,
    stage_order: Sequence[Any] | None = None,
) -> Dict[str, Any]:
    order = [str(item or "").strip().lower() for item in (stage_order or ["capture", "parse", "execute", "readback"]) if str(item or "").strip()]
    hints: Dict[str, float] = {}
    for stage, value in (stage_cost_hints or {}).items():
        try:
            hints[str(stage).strip().lower()] = max(0.0, float(value))
        except (TypeError, ValueError):
            continue
    if not hints:
        hints = {"capture": 1.0, "parse": 2.0, "execute": 4.0, "readback": 1.0}
    weights = [max(0.0, float(hints.get(stage, 1.0))) for stage in order]
    if not any(weights):
        weights = [1.0 for _ in order]
    total = max(0.0, float(total_budget_s or 0.0))
    weight_sum = sum(weights) or 1.0
    allocations: List[Dict[str, Any]] = []
    used = 0.0
    for idx, stage in enumerate(order):
        share = total * (weights[idx] / weight_sum)
        used += share
        allocations.append(
            {
                "stage": stage,
                "weight": round(weights[idx], 4),
                "allocated_s": round(share, 4),
                "hint_s": round(float(hints.get(stage, 0.0)), 4),
            }
        )
    if allocations:
        diff = round(total - sum(item["allocated_s"] for item in allocations), 4)
        allocations[-1]["allocated_s"] = round(float(allocations[-1]["allocated_s"]) + diff, 4)
    preferred_stage = max(allocations, key=lambda item: (float(item["allocated_s"]), float(item["weight"])))["stage"] if allocations else ""
    reason = "budget_allocated" if total > 0 else "missing_total_budget"
    return {
        "schema_version": SCHEMA_VERSION,
        "total_budget_s": round(total, 4),
        "used_s": round(sum(float(item["allocated_s"]) for item in allocations), 4),
        "allocations": allocations,
        "preferred_stage": preferred_stage,
        "is_valid": bool(total > 0 and allocations),
        "reason": reason,
    }


def build_host_runtime_identity(
    *,
    host_state: Mapping[str, Any] | None = None,
    runtime_state: Mapping[str, Any] | None = None,
    driver_state: Mapping[str, Any] | None = None,
    library_versions: Mapping[str, Any] | None = None,
    runtime_profile: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    host = dict(host_state or {})
    runtime = dict(runtime_state or {})
    driver = dict(driver_state or {})
    libraries = dict(library_versions or {})
    profile = dict(runtime_profile or {})
    cpu = _first_nonempty(host.get("cpu"), host.get("cpu_name"), host.get("processor"), runtime.get("cpu"))
    gpu = _first_nonempty(host.get("gpu"), host.get("gpu_name"), host.get("graphics"), runtime.get("gpu"))
    ram_gb = _first_nonempty(host.get("ram_gb"), host.get("memory_gb"), host.get("mem_gb"), runtime.get("ram_gb"), 0.0)
    os_name = _first_nonempty(host.get("os"), host.get("os_name"), host.get("platform"), runtime.get("os"), "")
    driver_versions = {str(key).strip().lower(): str(value or "").strip() for key, value in driver.items() if str(key).strip()}
    library_map = {str(key).strip().lower(): str(value or "").strip() for key, value in libraries.items() if str(key).strip()}
    runtime_backend = _first_nonempty(runtime.get("backend"), runtime.get("runtime_backend"), runtime.get("engine"), profile.get("backend"), "")
    runtime_mode = _first_nonempty(runtime.get("mode"), runtime.get("runtime_mode"), profile.get("mode"), "")
    runtime_profile_name = _first_nonempty(profile.get("profile_name"), profile.get("name"), runtime.get("profile_name"), "")
    is_complete = bool(cpu and os_name and runtime_backend and runtime_mode)
    is_gpu_host = bool(gpu and _norm_text(str(gpu)) not in {"none", "cpu", "software"})
    has_driver_details = bool(driver_versions)
    has_library_details = bool(library_map)
    if is_complete and (has_driver_details or has_library_details):
        reason = "host_runtime_identity_complete"
    elif is_complete:
        reason = "host_runtime_identity_basic"
    else:
        reason = "host_runtime_identity_partial"
    identity_id = _sha1_payload(
        {
            "cpu": _first_nonempty(cpu),
            "gpu": _first_nonempty(gpu),
            "ram_gb": round(float(ram_gb or 0.0), 4),
            "os_name": _first_nonempty(os_name),
            "driver_versions": driver_versions,
            "library_versions": library_map,
            "runtime_backend": _first_nonempty(runtime_backend),
            "runtime_mode": _first_nonempty(runtime_mode),
            "runtime_profile_name": _first_nonempty(runtime_profile_name),
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "identity_id": identity_id,
        "cpu": _first_nonempty(cpu),
        "gpu": _first_nonempty(gpu),
        "ram_gb": round(float(ram_gb or 0.0), 4),
        "os_name": _first_nonempty(os_name),
        "driver_versions": driver_versions,
        "library_versions": library_map,
        "runtime_backend": _first_nonempty(runtime_backend),
        "runtime_mode": _first_nonempty(runtime_mode),
        "runtime_profile_name": _first_nonempty(runtime_profile_name),
        "is_complete": is_complete,
        "is_gpu_host": is_gpu_host,
        "has_driver_details": has_driver_details,
        "has_library_details": has_library_details,
        "reason": reason,
    }


def build_runtime_profile_contract(
    *,
    active_backends: Sequence[Any] | None = None,
    active_models: Sequence[Any] | None = None,
    port_allocations: Mapping[str, Any] | Sequence[Any] | None = None,
    cache_roots: Sequence[Any] | None = None,
    host_runtime_identity: Mapping[str, Any] | None = None,
    runtime_session: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    host = dict(host_runtime_identity or {})
    session = dict(runtime_session or {})

    def _normalize_list(values: Sequence[Any] | None) -> List[str]:
        return [str(item).strip() for item in (values or []) if str(item or "").strip()]

    backend_rows = []
    for item in active_backends or []:
        if isinstance(item, Mapping):
            name = _first_nonempty(item.get("name"), item.get("backend"), item.get("id"), item.get("stage"), "")
            status = _first_nonempty(item.get("status"), item.get("state"), "active")
            backend_rows.append({"name": str(name).strip(), "status": str(status).strip().lower() or "active"})
        else:
            text = str(item or "").strip()
            if text:
                backend_rows.append({"name": text, "status": "active"})

    model_rows = []
    for item in active_models or []:
        if isinstance(item, Mapping):
            name = _first_nonempty(item.get("name"), item.get("model"), item.get("id"), "")
            status = _first_nonempty(item.get("status"), item.get("state"), "active")
            model_rows.append({"name": str(name).strip(), "status": str(status).strip().lower() or "active"})
        else:
            text = str(item or "").strip()
            if text:
                model_rows.append({"name": text, "status": "active"})

    if isinstance(port_allocations, Mapping):
        port_rows = [
            {
                "name": str(key).strip(),
                "port": int(value) if isinstance(value, (int, float)) and not isinstance(value, bool) else str(value or "").strip(),
            }
            for key, value in sorted(port_allocations.items(), key=lambda item: str(item[0]))
            if str(key).strip()
        ]
    else:
        port_rows = []
        for item in port_allocations or []:
            if isinstance(item, Mapping):
                name = _first_nonempty(item.get("name"), item.get("service"), item.get("backend"), item.get("stage"), "")
                port = item.get("port")
                port_rows.append({"name": str(name).strip(), "port": int(port) if isinstance(port, (int, float)) and not isinstance(port, bool) else str(port or "").strip()})
            else:
                text = str(item or "").strip()
                if text:
                    port_rows.append({"name": text, "port": ""})

    cache_list = _normalize_list(cache_roots)
    runtime_tag = str(_first_nonempty(session.get("runtime_tag"), session.get("profile_name"), host.get("runtime_profile_name"), "")).strip()
    active_backend_names = [row["name"] for row in backend_rows if row["name"]]
    active_model_names = [row["name"] for row in model_rows if row["name"]]
    active_port_names = [row["name"] for row in port_rows if row["name"]]
    is_complete = bool(active_backend_names and active_model_names and port_rows and cache_list)
    if is_complete:
        reason = "runtime_profile_contract_complete"
    elif active_backend_names or active_model_names or port_rows or cache_list:
        reason = "runtime_profile_contract_partial"
    else:
        reason = "runtime_profile_contract_empty"
    profile_id = _sha1_payload(
        {
            "backends": backend_rows,
            "models": model_rows,
            "ports": port_rows,
            "cache_roots": cache_list,
            "host_identity": host.get("identity_id") or host.get("identity"),
            "runtime_tag": runtime_tag,
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "profile_id": profile_id,
        "runtime_tag": runtime_tag,
        "backends": backend_rows,
        "models": model_rows,
        "ports": port_rows,
        "cache_roots": cache_list,
        "host_identity_id": str(host.get("identity_id") or host.get("identity_id") or ""),
        "active_backend_count": len(active_backend_names),
        "active_model_count": len(active_model_names),
        "active_port_count": len(active_port_names),
        "cache_root_count": len(cache_list),
        "is_complete": is_complete,
        "reason": reason,
    }


def build_environment_fingerprint(
    *,
    trace_packet: Mapping[str, Any] | None = None,
    benchmark_packet: Mapping[str, Any] | None = None,
    repair_packet: Mapping[str, Any] | None = None,
    host_runtime_identity: Mapping[str, Any] | None = None,
    runtime_profile_contract: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    trace = dict(trace_packet or {})
    benchmark = dict(benchmark_packet or {})
    repair = dict(repair_packet or {})
    host = dict(host_runtime_identity or {})
    runtime = dict(runtime_profile_contract or {})

    trace_id = _first_nonempty(trace.get("trace_id"), trace.get("id"), trace.get("fingerprint"), "")
    benchmark_id = _first_nonempty(benchmark.get("benchmark_id"), benchmark.get("id"), benchmark.get("fingerprint"), "")
    repair_id = _first_nonempty(repair.get("repair_id"), repair.get("id"), repair.get("fingerprint"), "")
    host_identity_id = _first_nonempty(host.get("identity_id"), host.get("identity"), host.get("fingerprint"), "")
    runtime_profile_id = _first_nonempty(runtime.get("profile_id"), runtime.get("runtime_tag"), runtime.get("fingerprint"), "")
    evidence = [
        token
        for token in (
            trace_id,
            benchmark_id,
            repair_id,
            host_identity_id,
            runtime_profile_id,
        )
        if str(token or "").strip()
    ]
    is_complete = bool(trace_id and benchmark_id and repair_id and host_identity_id and runtime_profile_id)
    if is_complete:
        reason = "environment_fingerprint_complete"
    elif evidence:
        reason = "environment_fingerprint_partial"
    else:
        reason = "environment_fingerprint_empty"
    fingerprint_id = _sha1_payload(
        {
            "trace_id": trace_id,
            "benchmark_id": benchmark_id,
            "repair_id": repair_id,
            "host_identity_id": host_identity_id,
            "runtime_profile_id": runtime_profile_id,
            "evidence": evidence,
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "fingerprint_id": fingerprint_id,
        "trace_id": trace_id,
        "benchmark_id": benchmark_id,
        "repair_id": repair_id,
        "host_identity_id": host_identity_id,
        "runtime_profile_id": runtime_profile_id,
        "evidence": evidence,
        "evidence_count": len(evidence),
        "is_complete": is_complete,
        "reason": reason,
    }


def build_resource_contention_monitor(
    *,
    resource_samples: Sequence[Mapping[str, Any]] | None = None,
    host_runtime_identity: Mapping[str, Any] | None = None,
    soft_threshold: float = 0.7,
    hard_threshold: float = 0.9,
) -> Dict[str, Any]:
    host = dict(host_runtime_identity or {})
    rows: List[Dict[str, Any]] = []
    aggregated: Dict[str, List[float]] = {"cpu": [], "gpu": [], "vram": [], "ram": [], "io": []}
    for sample in resource_samples or []:
        if not isinstance(sample, Mapping):
            continue
        def _sample_numeric(*keys: str) -> float | None:
            for key in keys:
                value = sample.get(key)
                if isinstance(value, bool):
                    value = float(value)
                if isinstance(value, (int, float)) and math.isfinite(float(value)):
                    return max(0.0, min(1.0, float(value)))
            return None

        for resource, keys in (
            ("cpu", ("cpu_percent", "cpu", "cpu_load")),
            ("gpu", ("gpu_percent", "gpu", "gpu_load")),
            ("vram", ("vram_percent", "vram", "gpu_memory_percent")),
            ("ram", ("ram_percent", "ram", "memory_percent")),
            ("io", ("io_percent", "io", "io_wait_percent")),
        ):
            value = _sample_numeric(*keys)
            if value is not None:
                aggregated[resource].append(value)
        rows.append(
            {
                "sample_id": _first_nonempty(sample.get("sample_id"), sample.get("id"), sample.get("timestamp"), f"sample_{len(rows)+1}"),
                "cpu_percent": sample.get("cpu_percent", sample.get("cpu", sample.get("cpu_load"))),
                "gpu_percent": sample.get("gpu_percent", sample.get("gpu", sample.get("gpu_load"))),
                "vram_percent": sample.get("vram_percent", sample.get("vram", sample.get("gpu_memory_percent"))),
                "ram_percent": sample.get("ram_percent", sample.get("ram", sample.get("memory_percent"))),
                "io_percent": sample.get("io_percent", sample.get("io", sample.get("io_wait_percent"))),
            }
        )

    def _mean(values: Sequence[float]) -> float:
        return round(float(statistics.fmean(values)), 4) if values else 0.0

    summary = {resource: _mean(values) for resource, values in aggregated.items()}
    hot_resources = [resource for resource, value in summary.items() if value >= float(soft_threshold)]
    critical_resources = [resource for resource, value in summary.items() if value >= float(hard_threshold)]
    if critical_resources:
        contention_kind = "hard_contention"
        reason = "resource_contention_hard"
    elif hot_resources:
        contention_kind = "soft_contention"
        reason = "resource_contention_soft"
    else:
        contention_kind = "none"
        reason = "resource_contention_clear"
    monitor_id = _sha1_payload(
        {
            "summary": summary,
            "hot_resources": hot_resources,
            "critical_resources": critical_resources,
            "host_identity_id": str(host.get("identity_id") or ""),
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "monitor_id": monitor_id,
        "contention_kind": contention_kind,
        "reason": reason,
        "summary": summary,
        "hot_resources": hot_resources,
        "critical_resources": critical_resources,
        "resource_rows": rows,
        "sample_count": len(rows),
        "host_identity_id": str(host.get("identity_id") or ""),
        "has_gpu_pressure": "gpu" in hot_resources or "vram" in hot_resources,
        "has_ram_pressure": "ram" in hot_resources,
        "has_io_pressure": "io" in hot_resources,
        "should_throttle": contention_kind != "none",
    }


def build_host_degradation_classifier(
    *,
    resource_contention_monitor: Mapping[str, Any] | None = None,
    host_runtime_identity: Mapping[str, Any] | None = None,
    thermal_state: Mapping[str, Any] | None = None,
    swap_state: Mapping[str, Any] | None = None,
    throttle_state: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    monitor = dict(resource_contention_monitor or {})
    host = dict(host_runtime_identity or {})
    thermal = dict(thermal_state or {})
    swap = dict(swap_state or {})
    throttle = dict(throttle_state or {})

    contention_kind = str(_first_nonempty(monitor.get("contention_kind"), "")).strip().lower()
    has_contention = contention_kind in {"soft_contention", "hard_contention"}
    thermal_pct = float(_first_nonempty(thermal.get("temperature_percent"), thermal.get("thermal_percent"), thermal.get("load"), 0.0) or 0.0)
    thermal_high = thermal_pct >= 0.8 or bool(thermal.get("is_throttling")) or str(thermal.get("state") or "").strip().lower() in {"thermal", "hot", "overheated"}
    swap_pct = float(_first_nonempty(swap.get("swap_percent"), swap.get("swap_usage"), swap.get("usage_percent"), 0.0) or 0.0)
    swap_high = swap_pct >= 0.6 or bool(swap.get("is_swapping")) or str(swap.get("state") or "").strip().lower() in {"swap", "paging", "swapping"}
    throttle_kind = str(_first_nonempty(throttle.get("throttle_kind"), throttle.get("state"), throttle.get("reason"), "")).strip().lower()
    throttled = bool(throttle.get("is_throttled")) or throttle_kind in {"throttled", "throttle", "thermal", "cpu", "gpu"}
    if thermal_high:
        degradation_kind = "thermal_slowdown"
        reason = "thermal_degradation_detected"
    elif swap_high:
        degradation_kind = "swap_slowdown"
        reason = "swap_degradation_detected"
    elif throttled:
        degradation_kind = "throttling"
        reason = "throttling_detected"
    elif has_contention:
        degradation_kind = "contention"
        reason = "contention_detected"
    else:
        degradation_kind = "none"
        reason = "host_stable"
    classifier_id = _sha1_payload(
        {
            "monitor_id": monitor.get("monitor_id"),
            "degradation_kind": degradation_kind,
            "thermal_pct": round(thermal_pct, 4),
            "swap_pct": round(swap_pct, 4),
            "throttle_kind": throttle_kind,
            "host_identity_id": str(host.get("identity_id") or ""),
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "classifier_id": classifier_id,
        "degradation_kind": degradation_kind,
        "reason": reason,
        "host_identity_id": str(host.get("identity_id") or ""),
        "contention_kind": contention_kind,
        "thermal_percent": round(thermal_pct, 4),
        "swap_percent": round(swap_pct, 4),
        "throttle_kind": throttle_kind,
        "is_degraded": degradation_kind != "none",
        "is_contention": degradation_kind == "contention",
        "is_throttling": degradation_kind == "throttling",
        "is_swap_slowdown": degradation_kind == "swap_slowdown",
        "is_thermal_slowdown": degradation_kind == "thermal_slowdown",
    }


def build_host_risk_hint(
    *,
    host_runtime_identity: Mapping[str, Any] | None = None,
    resource_contention_monitor: Mapping[str, Any] | None = None,
    host_degradation_classifier: Mapping[str, Any] | None = None,
    task_kind: str = "",
    urgency_hint: str = "",
) -> Dict[str, Any]:
    host = dict(host_runtime_identity or {})
    monitor = dict(resource_contention_monitor or {})
    degradation = dict(host_degradation_classifier or {})
    task = str(task_kind or "").strip().lower() or "unknown"
    urgency = str(urgency_hint or "").strip().lower()

    contention_kind = str(_first_nonempty(monitor.get("contention_kind"), "")).strip().lower()
    degradation_kind = str(_first_nonempty(degradation.get("degradation_kind"), degradation.get("reason"), "")).strip().lower()
    resource_sensitive = bool(
        host.get("resource_sensitive")
        or host.get("is_resource_sensitive")
        or contention_kind in {"soft_contention", "hard_contention"}
        or degradation_kind not in {"", "none", "host_stable"}
        or task in {"gpu", "ocr", "browser", "heavy", "model", "training", "render", "download"}
    )

    if urgency in {"urgent", "high", "critical"}:
        risk_score = 0.9 if resource_sensitive else 0.6
    elif urgency in {"low", "relaxed", "defer"}:
        risk_score = 0.35 if resource_sensitive else 0.12
    else:
        risk_score = 0.78 if resource_sensitive else 0.2

    if contention_kind == "hard_contention" or degradation_kind in {"thermal_degradation_detected", "swap_degradation_detected"}:
        risk_score = max(risk_score, 0.92)
    elif contention_kind == "soft_contention" or degradation_kind in {"throttling_detected", "contention_detected"}:
        risk_score = max(risk_score, 0.68)

    if risk_score >= 0.8:
        risk_level = "high"
        reason = "host_risk_high"
    elif risk_score >= 0.45:
        risk_level = "medium"
        reason = "host_risk_medium"
    else:
        risk_level = "low"
        reason = "host_risk_low"

    hint_id = _sha1_payload(
        {
            "host_identity_id": str(host.get("identity_id") or host.get("host_id") or ""),
            "task_kind": task,
            "urgency_hint": urgency,
            "contention_kind": contention_kind,
            "degradation_kind": degradation_kind,
            "risk_score": round(risk_score, 4),
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "hint_id": hint_id,
        "host_identity_id": str(host.get("identity_id") or host.get("host_id") or ""),
        "task_kind": task,
        "urgency_hint": urgency or "normal",
        "contention_kind": contention_kind or "none",
        "degradation_kind": degradation_kind or "none",
        "resource_sensitive": resource_sensitive,
        "risk_score": round(risk_score, 4),
        "risk_level": risk_level,
        "reason": reason,
        "should_attach": True,
        "should_warn": risk_level != "low",
        "should_reroute": risk_level == "high",
        "should_defer": risk_level == "low" and not resource_sensitive,
    }


def build_runtime_collision_guard(
    *,
    port_allocations: Sequence[Mapping[str, Any]] | Mapping[str, Any] | None = None,
    lock_paths: Sequence[Any] | None = None,
    shared_dirs: Sequence[Any] | None = None,
    host_runtime_identity: Mapping[str, Any] | None = None,
    runtime_session: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    host = dict(host_runtime_identity or {})
    session = dict(runtime_session or {})

    def _norm_path(value: Any) -> str:
        text = _first_nonempty(value)
        if not text:
            return ""
        normalized = _norm_text(text).replace("\\", "/")
        normalized = re.sub(r"/+", "/", normalized).rstrip("/")
        return normalized

    def _port_value(value: Any) -> int | None:
        if isinstance(value, bool):
            return None
        if isinstance(value, (int, float)):
            port = int(value)
            return port if port > 0 else None
        text = _first_nonempty(value)
        if text.isdigit():
            port = int(text)
            return port if port > 0 else None
        return None

    port_groups: Dict[int, List[str]] = {}
    port_rows: List[Dict[str, Any]] = []
    if isinstance(port_allocations, Mapping):
        items = sorted(port_allocations.items(), key=lambda item: str(item[0]))
        for key, value in items:
            name = str(key or "").strip() or f"service_{len(port_rows) + 1}"
            port = None
            if isinstance(value, Mapping):
                name = _first_nonempty(value.get("name"), value.get("service"), value.get("role"), name)
                port = _port_value(
                    _first_nonempty(
                        value.get("port"),
                        value.get("listen_port"),
                        value.get("bind_port"),
                        value.get("value"),
                    )
                )
            else:
                port = _port_value(value)
            row = {"name": name, "port": port if port is not None else ""}
            port_rows.append(row)
            if port is not None:
                port_groups.setdefault(port, []).append(name)
    else:
        for idx, item in enumerate(port_allocations or [], start=1):
            if not isinstance(item, Mapping):
                text = str(item or "").strip()
                if text:
                    port_rows.append({"name": text, "port": ""})
                continue
            name = _first_nonempty(item.get("name"), item.get("service"), item.get("role"), item.get("backend"), f"service_{idx}")
            port = _port_value(
                _first_nonempty(
                    item.get("port"),
                    item.get("listen_port"),
                    item.get("bind_port"),
                    item.get("value"),
                )
            )
            port_rows.append({"name": name, "port": port if port is not None else ""})
            if port is not None:
                port_groups.setdefault(port, []).append(name)

    def _collect_path_rows(values: Sequence[Any] | None, kind: str) -> tuple[List[Dict[str, Any]], Dict[str, List[str]]]:
        rows: List[Dict[str, Any]] = []
        groups: Dict[str, List[str]] = {}
        for idx, item in enumerate(values or [], start=1):
            label = f"{kind}_{idx}"
            path_value: Any = item
            if isinstance(item, Mapping):
                label = _first_nonempty(item.get("name"), item.get("service"), item.get("role"), item.get("session_id"), label)
                path_value = _first_nonempty(
                    item.get("path"),
                    item.get("lock_path"),
                    item.get("directory"),
                    item.get("dir"),
                    item.get("cache_root"),
                    item.get("temp_dir"),
                    item.get("value"),
                )
            path = _norm_path(path_value)
            if not path:
                continue
            rows.append({"name": label, "path": path})
            groups.setdefault(path, []).append(label)
        return rows, groups

    lock_rows, lock_groups = _collect_path_rows(lock_paths, "lock")
    shared_rows, shared_groups = _collect_path_rows(shared_dirs, "shared_dir")

    port_collisions = [
        {"port": port, "services": sorted(names)}
        for port, names in sorted(port_groups.items())
        if len(names) >= 2
    ]
    lock_collisions = [
        {"path": path, "entries": sorted(names)}
        for path, names in sorted(lock_groups.items())
        if len(names) >= 2
    ]
    shared_collisions = [
        {"path": path, "entries": sorted(names)}
        for path, names in sorted(shared_groups.items())
        if len(names) >= 2
    ]
    collision_kinds = [
        kind
        for kind, present in (
            ("port_conflict", bool(port_collisions)),
            ("lock_conflict", bool(lock_collisions)),
            ("shared_dir_conflict", bool(shared_collisions)),
        )
        if present
    ]
    if not collision_kinds:
        collision_kind = "none"
        reason = "runtime_collision_clear"
    elif len(collision_kinds) == 1:
        collision_kind = collision_kinds[0]
        reason = f"{collision_kind}_detected"
    else:
        collision_kind = "mixed_conflict"
        reason = "mixed_runtime_collision_detected"
    collisions: List[Dict[str, Any]] = []
    for row in port_collisions:
        collisions.append({"kind": "port_conflict", **row})
    for row in lock_collisions:
        collisions.append({"kind": "lock_conflict", **row})
    for row in shared_collisions:
        collisions.append({"kind": "shared_dir_conflict", **row})
    guard_id = _sha1_payload(
        {
            "host_identity_id": str(host.get("identity_id") or host.get("identity") or ""),
            "runtime_tag": str(_first_nonempty(session.get("runtime_tag"), session.get("profile_name"), host.get("runtime_profile_name"), "")),
            "collision_kind": collision_kind,
            "port_collisions": port_collisions,
            "lock_collisions": lock_collisions,
            "shared_collisions": shared_collisions,
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "guard_id": guard_id,
        "collision_kind": collision_kind,
        "reason": reason,
        "host_identity_id": str(host.get("identity_id") or host.get("identity") or ""),
        "runtime_tag": str(_first_nonempty(session.get("runtime_tag"), session.get("profile_name"), host.get("runtime_profile_name"), "")),
        "port_rows": port_rows,
        "lock_rows": lock_rows,
        "shared_dir_rows": shared_rows,
        "collisions": collisions,
        "port_collision_count": len(port_collisions),
        "lock_collision_count": len(lock_collisions),
        "shared_dir_collision_count": len(shared_collisions),
        "collision_count": len(collisions),
        "has_port_collision": bool(port_collisions),
        "has_lock_collision": bool(lock_collisions),
        "has_shared_dir_collision": bool(shared_collisions),
        "has_collision": bool(collisions),
        "should_block_start": bool(collisions),
    }


def build_resource_aware_degradation_policy(
    *,
    resource_contention_monitor: Mapping[str, Any] | None = None,
    host_degradation_classifier: Mapping[str, Any] | None = None,
    candidate_backends: Sequence[Any] | None = None,
    requested_batch_size: int = 0,
    requested_pipeline_depth: int = 0,
) -> Dict[str, Any]:
    monitor = dict(resource_contention_monitor or {})
    classifier = dict(host_degradation_classifier or {})

    def _backend_name(item: Any) -> str:
        if isinstance(item, Mapping):
            return _first_nonempty(item.get("name"), item.get("backend"), item.get("id"), item.get("role"))
        return _first_nonempty(item)

    backends = [name for name in (_backend_name(item) for item in candidate_backends or []) if name]
    unique_backends = list(dict.fromkeys(backends))
    contention_kind = str(_first_nonempty(monitor.get("contention_kind"), "")).strip().lower()
    degradation_kind = str(_first_nonempty(classifier.get("degradation_kind"), "")).strip().lower()
    if degradation_kind in {"thermal_slowdown", "swap_slowdown"} or contention_kind == "hard_contention":
        pressure_kind = "hard"
        mode = "minimal"
        reason = "hard_pressure_degrade"
        backend_limit = 1
        batch_factor = 0.25
        depth_factor = 0.5
    elif degradation_kind == "throttling" or contention_kind == "soft_contention":
        pressure_kind = "soft"
        mode = "degraded"
        reason = "soft_pressure_degrade"
        backend_limit = 2
        batch_factor = 0.5
        depth_factor = 0.75
    else:
        pressure_kind = "none"
        mode = "normal"
        reason = "host_stable"
        backend_limit = len(unique_backends)
        batch_factor = 1.0
        depth_factor = 1.0

    batch_size = max(0, int(requested_batch_size or 0))
    pipeline_depth = max(0, int(requested_pipeline_depth or 0))
    batch_size_limit = batch_size if batch_size == 0 or mode == "normal" else max(1, int(math.ceil(batch_size * batch_factor)))
    pipeline_depth_limit = pipeline_depth if pipeline_depth == 0 or mode == "normal" else max(1, int(math.ceil(pipeline_depth * depth_factor)))
    allowed_backends = unique_backends[:backend_limit] if backend_limit > 0 else []
    blocked_backends = unique_backends[len(allowed_backends) :]
    policy_id = _sha1_payload(
        {
            "pressure_kind": pressure_kind,
            "mode": mode,
            "backend_limit": backend_limit,
            "allowed_backends": allowed_backends,
            "batch_size_limit": batch_size_limit,
            "pipeline_depth_limit": pipeline_depth_limit,
            "contention_kind": contention_kind,
            "degradation_kind": degradation_kind,
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "policy_id": policy_id,
        "pressure_kind": pressure_kind,
        "mode": mode,
        "reason": reason,
        "contention_kind": contention_kind,
        "degradation_kind": degradation_kind,
        "requested_batch_size": batch_size,
        "requested_pipeline_depth": pipeline_depth,
        "backend_limit": backend_limit,
        "allowed_backends": allowed_backends,
        "blocked_backends": blocked_backends,
        "batch_size_limit": batch_size_limit,
        "pipeline_depth_limit": pipeline_depth_limit,
        "should_shrink_batch": mode != "normal" and batch_size_limit < batch_size,
        "should_shrink_depth": mode != "normal" and pipeline_depth_limit < pipeline_depth,
        "should_limit_backends": mode != "normal" and bool(blocked_backends),
        "is_degraded": mode != "normal",
    }


def build_environment_regression_matrix(
    *,
    scenarios: Sequence[Mapping[str, Any]] | None = None,
    machine_profiles: Sequence[Mapping[str, Any]] | Mapping[str, Any] | None = None,
    host_profiles: Sequence[Mapping[str, Any]] | Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    def _collect_machine_rows(source: Sequence[Mapping[str, Any]] | Mapping[str, Any] | None) -> List[Dict[str, Any]]:
        rows: List[Dict[str, Any]] = []
        if isinstance(source, Mapping):
            items = sorted(source.items(), key=lambda item: str(item[0]))
            for key, value in items:
                profile = dict(value or {}) if isinstance(value, Mapping) else {"name": value}
                profile.setdefault("name", key)
                rows.extend(_collect_machine_rows([profile]))
            return rows
        for idx, item in enumerate(source or [], start=1):
            if not isinstance(item, Mapping):
                continue
            name = _first_nonempty(item.get("name"), item.get("class"), item.get("host_class"), item.get("id"), f"machine_{idx}")
            rows.append(
                {
                    "name": name,
                    "cpu_cores": float(_first_nonempty(item.get("cpu_cores"), item.get("cores"), item.get("cpu"), 0.0) or 0.0),
                    "ram_gb": float(_first_nonempty(item.get("ram_gb"), item.get("memory_gb"), item.get("ram"), 0.0) or 0.0),
                    "gpu_name": _first_nonempty(item.get("gpu_name"), item.get("gpu"), item.get("graphics"), ""),
                    "gpu_memory_gb": float(_first_nonempty(item.get("gpu_memory_gb"), item.get("vram_gb"), item.get("gpu_ram_gb"), 0.0) or 0.0),
                    "os_name": _first_nonempty(item.get("os_name"), item.get("os"), item.get("platform"), ""),
                    "backend": _first_nonempty(item.get("backend"), item.get("runtime_backend"), item.get("engine"), ""),
                    "tags": [str(tag).strip() for tag in item.get("tags", []) if str(tag or "").strip()] if isinstance(item.get("tags"), list) else [],
                }
            )
        return rows

    machine_rows = _collect_machine_rows(machine_profiles)
    if host_profiles:
        host_rows = _collect_machine_rows(host_profiles)
        existing = {row["name"] for row in machine_rows}
        for row in host_rows:
            if row["name"] not in existing:
                machine_rows.append(row)
                existing.add(row["name"])

    def _scenario_name(item: Mapping[str, Any], idx: int) -> str:
        return _first_nonempty(item.get("name"), item.get("scenario"), item.get("id"), f"scenario_{idx}")

    def _req_float(item: Mapping[str, Any], *keys: str) -> float:
        return float(_first_nonempty(*(item.get(key) for key in keys), 0.0) or 0.0)

    scenario_rows: List[Dict[str, Any]] = []
    scenario_summary: List[Dict[str, Any]] = []
    machine_summary: Dict[str, Dict[str, Any]] = {
        row["name"]: {"name": row["name"], "supported_scenarios": [], "blocked_scenarios": []}
        for row in machine_rows
    }

    for idx, scenario in enumerate(scenarios or [], start=1):
        if not isinstance(scenario, Mapping):
            continue
        scenario_name = _scenario_name(scenario, idx)
        req_cpu = _req_float(scenario, "min_cpu_cores", "cpu_cores", "required_cpu_cores")
        req_ram = _req_float(scenario, "min_ram_gb", "ram_gb", "required_ram_gb")
        req_gpu_mem = _req_float(scenario, "min_gpu_memory_gb", "gpu_memory_gb", "required_gpu_memory_gb")
        req_gpu_name = _first_nonempty(scenario.get("gpu_name"), scenario.get("required_gpu"), scenario.get("gpu"), "")
        req_os = _norm_text(_first_nonempty(scenario.get("os_name"), scenario.get("required_os"), scenario.get("os"), ""))
        req_backend = _norm_text(_first_nonempty(scenario.get("backend"), scenario.get("required_backend"), scenario.get("runtime_backend"), ""))
        requires_gpu = bool(scenario.get("requires_gpu")) or bool(req_gpu_name) or req_gpu_mem > 0.0
        supported_classes: List[str] = []
        blocked_classes: List[str] = []
        for machine in machine_rows:
            cpu_ok = bool(req_cpu <= 0.0 or machine["cpu_cores"] >= req_cpu)
            ram_ok = bool(req_ram <= 0.0 or machine["ram_gb"] >= req_ram)
            gpu_name = machine["gpu_name"]
            machine_gpu_ok = bool(gpu_name and _norm_text(gpu_name) not in {"none", "cpu", "software"})
            gpu_ok = bool(not requires_gpu or machine_gpu_ok)
            if req_gpu_name:
                gpu_ok = gpu_ok and _norm_text(gpu_name) == _norm_text(req_gpu_name)
            gpu_mem_ok = bool(req_gpu_mem <= 0.0 or machine["gpu_memory_gb"] >= req_gpu_mem)
            os_ok = bool(not req_os or _norm_text(machine["os_name"]) == req_os)
            backend_ok = bool(not req_backend or _norm_text(machine["backend"]) == req_backend)
            supported = bool(cpu_ok and ram_ok and gpu_ok and gpu_mem_ok and os_ok and backend_ok)
            row = {
                "scenario": scenario_name,
                "machine_profile": machine["name"],
                "supported": supported,
                "requirements": {
                    "min_cpu_cores": round(req_cpu, 4),
                    "min_ram_gb": round(req_ram, 4),
                    "requires_gpu": requires_gpu,
                    "gpu_name": req_gpu_name,
                    "min_gpu_memory_gb": round(req_gpu_mem, 4),
                    "os_name": req_os,
                    "backend": req_backend,
                },
                "machine_profile_details": {
                    "cpu_cores": round(float(machine["cpu_cores"]), 4),
                    "ram_gb": round(float(machine["ram_gb"]), 4),
                    "gpu_name": machine["gpu_name"],
                    "gpu_memory_gb": round(float(machine["gpu_memory_gb"]), 4),
                    "os_name": machine["os_name"],
                    "backend": machine["backend"],
                },
                "reasons": [
                    reason
                    for reason, passed in (
                        ("cpu_too_small", cpu_ok),
                        ("ram_too_small", ram_ok),
                        ("gpu_missing_or_mismatch", gpu_ok),
                        ("gpu_memory_too_small", gpu_mem_ok),
                        ("os_mismatch", os_ok),
                        ("backend_mismatch", backend_ok),
                    )
                    if not passed
                ],
            }
            scenario_rows.append(row)
            if supported:
                supported_classes.append(machine["name"])
                machine_summary[machine["name"]]["supported_scenarios"].append(scenario_name)
            else:
                blocked_classes.append(machine["name"])
                machine_summary[machine["name"]]["blocked_scenarios"].append(scenario_name)
        scenario_summary.append(
            {
                "scenario": scenario_name,
                "supported_classes": supported_classes,
                "blocked_classes": blocked_classes,
                "is_covered": bool(supported_classes),
                "support_count": len(supported_classes),
                "block_count": len(blocked_classes),
            }
        )

    uncovered_scenarios = [row["scenario"] for row in scenario_summary if not row["is_covered"]]
    total_pairs = len(scenario_rows)
    supported_pairs = sum(1 for row in scenario_rows if row["supported"])
    regression_id = _sha1_payload(
        {
            "scenario_rows": scenario_rows,
            "machine_rows": machine_rows,
            "uncovered_scenarios": uncovered_scenarios,
        }
    )[:16]
    if not scenario_rows or not machine_rows:
        reason = "environment_regression_matrix_empty"
    elif uncovered_scenarios:
        reason = "environment_regression_matrix_has_gaps"
    else:
        reason = "environment_regression_matrix_complete"
    return {
        "schema_version": SCHEMA_VERSION,
        "matrix_id": regression_id,
        "reason": reason,
        "scenarios": scenario_summary,
        "machine_profiles": list(machine_summary.values()),
        "rows": scenario_rows,
        "scenario_count": len(scenario_summary),
        "machine_profile_count": len(machine_rows),
        "coverage_rate": round((supported_pairs / total_pairs), 4) if total_pairs else 0.0,
        "is_complete": bool(scenario_rows and machine_rows and not uncovered_scenarios),
        "uncovered_scenarios": uncovered_scenarios,
        "unsupported_pair_count": total_pairs - supported_pairs,
    }


def build_host_replay_bundle(
    *,
    environment_fingerprint: Mapping[str, Any] | None = None,
    host_runtime_identity: Mapping[str, Any] | None = None,
    runtime_profile_contract: Mapping[str, Any] | None = None,
    resource_contention_monitor: Mapping[str, Any] | None = None,
    runtime_collision_guard: Mapping[str, Any] | None = None,
    resource_aware_degradation_policy: Mapping[str, Any] | None = None,
    environment_regression_matrix: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    fingerprint = dict(environment_fingerprint or {})
    host = dict(host_runtime_identity or {})
    profile = dict(runtime_profile_contract or {})
    contention = dict(resource_contention_monitor or {})
    collision = dict(runtime_collision_guard or {})
    policy = dict(resource_aware_degradation_policy or {})
    matrix = dict(environment_regression_matrix or {})

    backend_names = [row.get("name") for row in profile.get("backends", []) if isinstance(row, Mapping) and _first_nonempty(row.get("name"))]
    port_names = [row.get("name") for row in profile.get("ports", []) if isinstance(row, Mapping) and _first_nonempty(row.get("name"))]
    cache_roots = [str(item or "").strip() for item in profile.get("cache_roots", []) if str(item or "").strip()]
    resource_summary = dict(contention.get("summary") or {})
    host_identity_id = _first_nonempty(host.get("identity_id"), fingerprint.get("host_identity_id"), "")
    fingerprint_id = _first_nonempty(fingerprint.get("fingerprint_id"), "")
    profile_id = _first_nonempty(profile.get("profile_id"), "")
    matrix_id = _first_nonempty(matrix.get("matrix_id"), "")
    collision_kind = str(_first_nonempty(collision.get("collision_kind"), "none")).strip().lower()
    uncovered_scenarios = [str(item or "").strip() for item in (matrix.get("uncovered_scenarios") or []) if str(item or "").strip()]
    if collision.get("has_collision"):
        reason = "host_replay_blocked_by_collision"
    elif uncovered_scenarios:
        reason = "host_replay_matrix_gap"
    elif not host_identity_id:
        reason = "missing_host_identity"
    elif not fingerprint_id:
        reason = "missing_environment_fingerprint"
    elif not profile_id:
        reason = "missing_runtime_profile"
    elif bool(policy.get("is_degraded")):
        reason = "host_replay_degraded"
    elif bool(contention.get("should_throttle")):
        reason = "host_replay_contention"
    else:
        reason = "host_replay_bundle_ready"
    is_complete = bool(host_identity_id and fingerprint_id and profile_id and matrix_id)
    is_stable = bool(is_complete and not collision.get("has_collision") and not uncovered_scenarios and not policy.get("is_degraded") and not contention.get("should_throttle"))
    bundle = {
        "schema_version": SCHEMA_VERSION,
        "environment_fingerprint": fingerprint,
        "host_runtime_identity": host,
        "runtime_profile_contract": profile,
        "resource_contention_monitor": contention,
        "runtime_collision_guard": collision,
        "resource_aware_degradation_policy": policy,
        "environment_regression_matrix": matrix,
        "host_identity_id": host_identity_id,
        "fingerprint_id": fingerprint_id,
        "profile_id": profile_id,
        "matrix_id": matrix_id,
        "backend_names": backend_names,
        "port_names": port_names,
        "cache_roots": cache_roots,
        "resource_summary": resource_summary,
        "collision_kind": collision_kind,
        "uncovered_scenarios": uncovered_scenarios,
        "has_collision": bool(collision.get("has_collision")),
        "has_throttle_pressure": bool(contention.get("should_throttle")),
        "is_complete": is_complete,
        "is_stable": is_stable,
        "reason": reason,
    }
    bundle["bundle_id"] = _sha1_payload(bundle)[:16]
    return bundle


def build_code_vs_environment_blame_splitter(
    *,
    failure_cases: Sequence[Mapping[str, Any]] | None = None,
    host_replay_bundle: Mapping[str, Any] | None = None,
    environment_regression_matrix: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    cases = [dict(case) for case in (failure_cases or []) if isinstance(case, Mapping)]
    replay = dict(host_replay_bundle or {})
    matrix = dict(environment_regression_matrix or {})
    code_cases: List[Dict[str, Any]] = []
    environment_cases: List[Dict[str, Any]] = []
    mixed_cases: List[Dict[str, Any]] = []
    unknown_cases: List[Dict[str, Any]] = []

    env_sources = {"environment", "host", "machine", "runtime", "infra", "os", "driver", "browser", "gpu", "cache"}
    code_sources = {"code", "logic", "deterministic", "implementation", "model", "parser", "validator"}

    host_is_unstable = bool(replay.get("has_collision")) or bool(replay.get("has_throttle_pressure")) or not bool(replay.get("is_stable", True))
    uncovered_scenarios = {str(item or "").strip().lower() for item in (matrix.get("uncovered_scenarios") or []) if str(item or "").strip()}

    for case in cases:
        passed = bool(case.get("passed")) if "passed" in case else bool(case.get("success"))
        if passed:
            continue
        failure_source = str(_first_nonempty(case.get("failure_source"), case.get("source"), case.get("cause"), "")).strip().lower()
        env_issue = bool(case.get("environment_issue")) or bool(case.get("host_issue")) or bool(case.get("machine_issue")) or failure_source in env_sources
        code_issue = bool(case.get("code_issue")) or bool(case.get("logic_issue")) or bool(case.get("deterministic")) or failure_source in code_sources
        replay_scenario = str(_first_nonempty(case.get("scenario"), case.get("scenario_id"), case.get("regression_scenario"), "")).strip().lower()
        if replay_scenario and replay_scenario in uncovered_scenarios:
            env_issue = True
        if host_is_unstable and bool(case.get("host_specific")):
            env_issue = True
        if code_issue and not env_issue:
            code_cases.append(case)
        elif env_issue and not code_issue:
            environment_cases.append(case)
        elif code_issue and env_issue:
            mixed_cases.append(case)
        else:
            hint = str(_first_nonempty(case.get("hint"), case.get("note"), case.get("reason"), "")).strip().lower()
            if hint in {"code", "logic", "deterministic", "implementation", "parser", "validator"}:
                code_cases.append(case)
            elif hint in {"environment", "host", "machine", "runtime", "infra", "browser"}:
                environment_cases.append(case)
            else:
                unknown_cases.append(case)

    total_failures = len(code_cases) + len(environment_cases) + len(mixed_cases) + len(unknown_cases)
    if total_failures == 0:
        primary_cause = "none"
        reason = "no_failures_observed"
    elif environment_cases and not code_cases and not mixed_cases:
        primary_cause = "environment"
        reason = "environment_dependent_failure"
    elif code_cases and not environment_cases and not mixed_cases:
        primary_cause = "code"
        reason = "deterministic_code_failure"
    elif mixed_cases or (code_cases and environment_cases):
        primary_cause = "mixed"
        reason = "mixed_code_and_environment_failure"
    else:
        primary_cause = "unknown"
        reason = "failure_cause_unknown"

    splitter_id = _sha1_payload(
        {
            "cases": cases,
            "primary_cause": primary_cause,
            "host_is_unstable": host_is_unstable,
            "uncovered_scenarios": sorted(uncovered_scenarios),
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "splitter_id": splitter_id,
        "primary_cause": primary_cause,
        "reason": reason,
        "code_failure_count": len(code_cases),
        "environment_failure_count": len(environment_cases),
        "mixed_failure_count": len(mixed_cases),
        "unknown_failure_count": len(unknown_cases),
        "code_failure_cases": code_cases,
        "environment_failure_cases": environment_cases,
        "mixed_failure_cases": mixed_cases,
        "unknown_failure_cases": unknown_cases,
        "is_code_failure": primary_cause == "code",
        "is_environment_failure": primary_cause == "environment",
        "is_mixed_failure": primary_cause == "mixed",
        "is_unknown_failure": primary_cause == "unknown",
        "host_is_unstable": host_is_unstable,
    }


def build_environment_gap_promoter(
    *,
    environment_failures: Sequence[Mapping[str, Any] | str] | None = None,
    regression_matrix: Mapping[str, Any] | None = None,
    host_replay_bundle: Mapping[str, Any] | None = None,
    root_cause_unit: Mapping[str, Any] | None = None,
    threshold: int = 2,
) -> Dict[str, Any]:
    matrix = dict(regression_matrix or {})
    replay = dict(host_replay_bundle or {})
    unit = dict(root_cause_unit or {})

    def _collect_rows(rows: Sequence[Mapping[str, Any] | str] | None) -> List[Mapping[str, Any]]:
        collected: List[Mapping[str, Any]] = []
        for row in rows or []:
            if isinstance(row, Mapping):
                collected.append(dict(row))
            else:
                collected.append({"name": str(row), "outcome": "unknown"})
        return collected

    rows = _collect_rows(environment_failures)
    threshold_value = max(1, int(threshold or 1))
    family_hint = str(
        _first_nonempty(
            unit.get("family_key"),
            unit.get("failure_family_key"),
            unit.get("family"),
            unit.get("theme"),
            replay.get("matrix_id"),
            "",
        )
    ).strip().lower()
    uncovered_scenarios = [str(item or "").strip().lower() for item in (matrix.get("uncovered_scenarios") or []) if str(item or "").strip()]

    def _row_key(row: Mapping[str, Any]) -> str:
        return str(
            _first_nonempty(
                row.get("family_key"),
                row.get("failure_family_key"),
                row.get("host_class"),
                row.get("machine_profile"),
                row.get("scenario"),
                row.get("scenario_id"),
                row.get("name"),
                family_hint,
                "",
            )
        ).strip().lower()

    recurring_count = 0
    signal_rows: List[Mapping[str, Any]] = []
    for row in rows:
        key = _row_key(row)
        host_specific = bool(row.get("host_specific")) or bool(row.get("machine_specific")) or bool(row.get("environment_issue"))
        if key and family_hint and key == family_hint:
            recurring_count += 1
            signal_rows.append(row)
        elif host_specific:
            recurring_count += 1
            signal_rows.append(row)
    backlog_count = len(uncovered_scenarios)
    if backlog_count > 0:
        signal_rows.extend({"name": scenario, "outcome": "uncovered"} for scenario in uncovered_scenarios)

    should_promote = bool(recurring_count >= threshold_value or backlog_count >= threshold_value)
    if should_promote:
        promotion_tier = "promote"
        reason = "environment_gap_promote"
    elif recurring_count > 0 or backlog_count > 0:
        promotion_tier = "monitor"
        reason = "environment_gap_monitor"
    else:
        promotion_tier = "ignore"
        reason = "environment_gap_ignore"
    promoter_id = _sha1_payload(
        {
            "family_hint": family_hint,
            "recurring_count": recurring_count,
            "backlog_count": backlog_count,
            "threshold": threshold_value,
            "signal_names": [str(_first_nonempty(row.get("name"), row.get("machine_profile"), row.get("scenario"), row.get("family_key"), "")) for row in signal_rows],
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "promoter_id": promoter_id,
        "family_key": family_hint or "environment",
        "recurring_count": recurring_count,
        "backlog_count": backlog_count,
        "threshold": threshold_value,
        "promotion_tier": promotion_tier,
        "reason": reason,
        "should_promote": should_promote,
        "should_monitor": promotion_tier == "monitor",
        "should_ignore": promotion_tier == "ignore",
        "signal_count": len(signal_rows),
        "signal_notes": [
            str(_first_nonempty(row.get("name"), row.get("machine_profile"), row.get("scenario"), row.get("family_key"), "")) for row in signal_rows
        ],
        "host_is_unstable": bool(replay.get("has_collision")) or bool(replay.get("has_throttle_pressure")) or not bool(replay.get("is_stable", True)),
    }


def build_model_artifact_integrity_guard(
    *,
    model_artifacts: Sequence[Mapping[str, Any]] | Mapping[str, Any] | None = None,
    runtime_versions: Mapping[str, Any] | None = None,
    expected_versions: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    runtime = {str(key).strip().lower(): str(value or "").strip() for key, value in dict(runtime_versions or {}).items() if str(key or "").strip()}
    expectations = {str(key).strip().lower(): str(value or "").strip() for key, value in dict(expected_versions or {}).items() if str(key or "").strip()}

    def _collect_artifacts(source: Sequence[Mapping[str, Any]] | Mapping[str, Any] | None) -> List[Dict[str, Any]]:
        rows: List[Dict[str, Any]] = []
        if isinstance(source, Mapping):
            for key, value in sorted(source.items(), key=lambda item: str(item[0])):
                artifact = dict(value or {}) if isinstance(value, Mapping) else {"path": value}
                artifact.setdefault("name", key)
                rows.extend(_collect_artifacts([artifact]))
            return rows
        for idx, item in enumerate(source or [], start=1):
            if not isinstance(item, Mapping):
                text = str(item or "").strip()
                if text:
                    rows.append({"name": text, "path": text})
                continue
            name = _first_nonempty(item.get("name"), item.get("artifact"), item.get("model"), item.get("id"), f"artifact_{idx}")
            rows.append(
                {
                    "name": name,
                    "path": _first_nonempty(item.get("path"), item.get("file"), item.get("artifact_path"), item.get("model_path"), ""),
                    "version": _first_nonempty(item.get("version"), item.get("artifact_version"), item.get("model_version"), ""),
                    "checksum": _first_nonempty(item.get("checksum"), item.get("sha256"), item.get("digest"), item.get("hash"), ""),
                    "expected_checksum": _first_nonempty(item.get("expected_checksum"), item.get("expected_sha256"), item.get("expected_digest"), item.get("expected_hash"), ""),
                    "runtime_component": _first_nonempty(item.get("runtime_component"), item.get("backend"), item.get("engine"), ""),
                    "required_runtime_version": _first_nonempty(item.get("required_runtime_version"), item.get("runtime_version"), ""),
                    "expected_version": _first_nonempty(item.get("expected_version"), item.get("required_version"), ""),
                }
            )
        return rows

    artifacts = _collect_artifacts(model_artifacts)
    invalid_artifacts: List[Dict[str, Any]] = []
    valid_artifacts: List[Dict[str, Any]] = []

    for artifact in artifacts:
        name = str(artifact.get("name") or "").strip().lower()
        version = str(artifact.get("version") or "").strip()
        checksum = str(artifact.get("checksum") or "").strip().lower()
        expected_checksum = str(artifact.get("expected_checksum") or expectations.get(name, "")).strip().lower()
        expected_version = str(artifact.get("expected_version") or expectations.get(name, "")).strip()
        runtime_component = str(artifact.get("runtime_component") or "").strip().lower()
        runtime_version_required = str(artifact.get("required_runtime_version") or "").strip()
        runtime_version_actual = str(runtime.get(runtime_component) or "").strip()
        checksum_ok = bool(not expected_checksum or checksum == expected_checksum)
        version_ok = bool(not expected_version or version == expected_version)
        runtime_ok = bool(not runtime_version_required or runtime_version_actual == runtime_version_required)
        artifact_status = "ok" if checksum_ok and version_ok and runtime_ok else "invalid"
        row = {
            **artifact,
            "checksum_ok": checksum_ok,
            "version_ok": version_ok,
            "runtime_ok": runtime_ok,
            "status": artifact_status,
            "runtime_version_actual": runtime_version_actual,
        }
        if artifact_status == "ok":
            valid_artifacts.append(row)
        else:
            invalid_artifacts.append(row)

    if not artifacts:
        reason = "missing_model_artifacts"
    elif invalid_artifacts:
        reason = "model_artifact_integrity_mismatch"
    else:
        reason = "model_artifact_integrity_ok"
    guard_id = _sha1_payload(
        {
            "artifacts": artifacts,
            "runtime_versions": runtime,
            "expected_versions": expectations,
            "invalid_artifacts": invalid_artifacts,
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "guard_id": guard_id,
        "reason": reason,
        "artifacts": artifacts,
        "valid_artifacts": valid_artifacts,
        "invalid_artifacts": invalid_artifacts,
        "artifact_count": len(artifacts),
        "valid_artifact_count": len(valid_artifacts),
        "invalid_artifact_count": len(invalid_artifacts),
        "is_integrity_ok": not invalid_artifacts and bool(artifacts),
        "should_block_runtime": bool(invalid_artifacts or not artifacts),
    }


def build_cache_isolation_policy(
    *,
    sessions: Sequence[Mapping[str, Any]] | None = None,
    shared_cache_roots: Sequence[Any] | None = None,
    host_runtime_identity: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    host = dict(host_runtime_identity or {})
    shared_roots = {_norm_text(item).replace("\\", "/").rstrip("/") for item in (shared_cache_roots or []) if _norm_text(item)}
    session_rows: List[Dict[str, Any]] = []
    root_groups: Dict[str, List[str]] = {}
    for idx, session in enumerate(sessions or [], start=1):
        if not isinstance(session, Mapping):
            continue
        session_id = _first_nonempty(session.get("session_id"), session.get("session"), session.get("id"), f"session_{idx}")
        profile_name = _first_nonempty(session.get("profile_name"), session.get("profile"), session.get("name"), "")
        cache_root = _norm_text(
            _first_nonempty(
                session.get("cache_root"),
                session.get("temp_dir"),
                session.get("temp_path"),
                session.get("directory"),
                session.get("cache"),
                session.get("value"),
                "",
            )
        ).replace("\\", "/").rstrip("/")
        if not cache_root:
            cache_root = f"cache/session_{idx}"
        root_groups.setdefault(cache_root, []).append(session_id)
        isolated_root = f"{cache_root}/{_norm_text(session_id).replace(' ', '_') or _norm_text(profile_name).replace(' ', '_') or 'session'}"
        session_rows.append(
            {
                "session_id": session_id,
                "profile_name": profile_name,
                "cache_root": cache_root,
                "isolated_cache_root": isolated_root,
                "is_shared": cache_root in shared_roots,
            }
        )

    shared_rows = [
        {"cache_root": root, "session_ids": sorted(dict.fromkeys(session_ids))}
        for root, session_ids in sorted(root_groups.items())
        if len(dict.fromkeys(session_ids)) >= 2 or root in shared_roots
    ]
    isolated_rows = [row for row in session_rows if not row["is_shared"] and len(root_groups.get(row["cache_root"], [])) <= 1]
    should_isolate = bool(shared_rows)
    if not session_rows:
        reason = "missing_cache_sessions"
    elif shared_rows:
        reason = "cache_isolation_shared_cache_detected"
    else:
        reason = "cache_isolation_ready"
    policy_id = _sha1_payload(
        {
            "sessions": session_rows,
            "shared_rows": shared_rows,
            "host_identity_id": str(host.get("identity_id") or host.get("identity") or ""),
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "policy_id": policy_id,
        "reason": reason,
        "host_identity_id": str(host.get("identity_id") or host.get("identity") or ""),
        "sessions": session_rows,
        "shared_cache_roots": shared_rows,
        "isolated_sessions": isolated_rows,
        "session_count": len(session_rows),
        "shared_cache_root_count": len(shared_rows),
        "is_isolated": not shared_rows and bool(session_rows),
        "should_isolate": should_isolate,
    }


def build_backend_dependency_matrix(
    *,
    backends: Sequence[Mapping[str, Any]] | Mapping[str, Any] | None = None,
    runtime_versions: Mapping[str, Any] | None = None,
    driver_versions: Mapping[str, Any] | None = None,
    library_versions: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    runtime = {str(key).strip().lower(): str(value or "").strip() for key, value in dict(runtime_versions or {}).items() if str(key or "").strip()}
    drivers = {str(key).strip().lower(): str(value or "").strip() for key, value in dict(driver_versions or {}).items() if str(key or "").strip()}
    libraries = {str(key).strip().lower(): str(value or "").strip() for key, value in dict(library_versions or {}).items() if str(key or "").strip()}

    def _compat_key(value: str) -> str:
        text = str(value or "").strip().lower()
        if not text:
            return ""
        return text.split(".", 1)[0].split("_", 1)[0]

    def _collect_backend_rows(source: Sequence[Mapping[str, Any]] | Mapping[str, Any] | None) -> List[Dict[str, Any]]:
        rows: List[Dict[str, Any]] = []
        if isinstance(source, Mapping):
            for key, value in sorted(source.items(), key=lambda item: str(item[0])):
                backend = dict(value or {}) if isinstance(value, Mapping) else {"model_name": value}
                backend.setdefault("name", key)
                rows.extend(_collect_backend_rows([backend]))
            return rows
        for idx, item in enumerate(source or [], start=1):
            if not isinstance(item, Mapping):
                continue
            rows.append(
                {
                    "name": _first_nonempty(item.get("name"), item.get("backend"), item.get("model"), item.get("id"), f"backend_{idx}"),
                    "model_name": _first_nonempty(item.get("model_name"), item.get("model"), item.get("artifact"), item.get("name"), ""),
                    "runtime_component": _first_nonempty(item.get("runtime_component"), item.get("runtime"), item.get("engine"), item.get("component"), ""),
                    "driver_component": _first_nonempty(item.get("driver_component"), item.get("driver"), item.get("gpu"), item.get("component"), ""),
                    "library_component": _first_nonempty(item.get("library_component"), item.get("library"), item.get("package"), item.get("component"), ""),
                    "required_runtime_version": _first_nonempty(item.get("required_runtime_version"), item.get("runtime_version"), item.get("runtime"), ""),
                    "required_driver_version": _first_nonempty(item.get("required_driver_version"), item.get("driver_version"), item.get("driver"), ""),
                    "required_library_version": _first_nonempty(item.get("required_library_version"), item.get("library_version"), item.get("library"), ""),
                }
            )
        return rows

    backend_rows = _collect_backend_rows(backends)
    matrix_rows: List[Dict[str, Any]] = []
    compatible_backends: List[str] = []
    incompatible_backends: List[str] = []
    missing_components: List[str] = []
    for backend in backend_rows:
        name = str(backend["name"]).strip().lower()
        runtime_component = str(backend.get("runtime_component") or name).strip().lower()
        driver_component = str(backend.get("driver_component") or name).strip().lower()
        library_component = str(backend.get("library_component") or name).strip().lower()
        required_runtime = str(backend.get("required_runtime_version") or "").strip()
        required_driver = str(backend.get("required_driver_version") or "").strip()
        required_library = str(backend.get("required_library_version") or "").strip()
        actual_runtime = runtime.get(runtime_component) or runtime.get(name) or runtime.get(str(backend.get("model_name") or "").strip().lower()) or ""
        actual_driver = drivers.get(driver_component) or drivers.get(name) or ""
        actual_library = libraries.get(library_component) or libraries.get(name) or ""
        runtime_ok = bool(not required_runtime or (_compat_key(actual_runtime) and _compat_key(actual_runtime) == _compat_key(required_runtime)))
        driver_ok = bool(not required_driver or (_compat_key(actual_driver) and _compat_key(actual_driver) == _compat_key(required_driver)))
        library_ok = bool(not required_library or (_compat_key(actual_library) and _compat_key(actual_library) == _compat_key(required_library)))
        incompatible = not (runtime_ok and driver_ok and library_ok)
        if required_runtime and not actual_runtime:
            missing_components.append(f"{name}:runtime")
        if required_driver and not actual_driver:
            missing_components.append(f"{name}:driver")
        if required_library and not actual_library:
            missing_components.append(f"{name}:library")
        row = {
            "backend": name,
            "model_name": backend.get("model_name"),
            "runtime_component": runtime_component,
            "driver_component": driver_component,
            "library_component": library_component,
            "required_runtime_version": required_runtime,
            "actual_runtime_version": actual_runtime,
            "required_driver_version": required_driver,
            "actual_driver_version": actual_driver,
            "required_library_version": required_library,
            "actual_library_version": actual_library,
            "runtime_match": runtime_ok,
            "driver_match": driver_ok,
            "library_match": library_ok,
            "is_compatible": not incompatible,
            "reasons": [
                reason
                for reason, passed in (
                    ("runtime_version_mismatch", runtime_ok),
                    ("driver_version_mismatch", driver_ok),
                    ("library_version_mismatch", library_ok),
                )
                if not passed
            ],
        }
        matrix_rows.append(row)
        if row["is_compatible"]:
            compatible_backends.append(name)
        else:
            incompatible_backends.append(name)
    if not matrix_rows:
        reason = "missing_backend_requirements"
    elif missing_components:
        reason = "missing_component_versions"
    elif incompatible_backends:
        reason = "backend_dependency_mismatch"
    else:
        reason = "backend_dependency_matrix_complete"
    matrix_id = _sha1_payload(
        {
            "rows": matrix_rows,
            "runtime_versions": runtime,
            "driver_versions": drivers,
            "library_versions": libraries,
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "matrix_id": matrix_id,
        "reason": reason,
        "rows": matrix_rows,
        "compatible_backends": compatible_backends,
        "incompatible_backends": incompatible_backends,
        "missing_components": sorted(dict.fromkeys(missing_components)),
        "backend_count": len(matrix_rows),
        "compatible_count": len(compatible_backends),
        "incompatible_count": len(incompatible_backends),
        "is_complete": not incompatible_backends and bool(matrix_rows),
    }


def build_cold_vs_warm_runtime_splitter(
    *,
    measurements: Sequence[Mapping[str, Any]] | None = None,
    warmup_runs: int = 1,
) -> Dict[str, Any]:
    rows = [dict(row) for row in (measurements or []) if isinstance(row, Mapping)]
    cold_rows: List[Dict[str, Any]] = []
    warm_rows: List[Dict[str, Any]] = []
    unknown_rows: List[Dict[str, Any]] = []

    def _phase(row: Mapping[str, Any]) -> str:
        phase = str(_first_nonempty(row.get("phase"), row.get("startup_phase"), row.get("state"), "")).strip().lower()
        if phase:
            return phase
        run_index = row.get("run_index")
        if isinstance(run_index, (int, float)) and not isinstance(run_index, bool):
            return "cold" if int(run_index) <= max(1, int(warmup_runs or 1)) else "warm"
        return ""

    for row in rows:
        phase = _phase(row)
        passed = bool(row.get("passed")) if "passed" in row else bool(row.get("success", True))
        run_index = int(row.get("run_index") or 0)
        latency_ms = max(0.0, float(_first_nonempty(row.get("latency_ms"), row.get("latency"), 0.0) or 0.0))
        row_out = {
            "run_index": run_index,
            "phase": phase or "unknown",
            "latency_ms": round(latency_ms, 4),
            "passed": passed,
            "name": _first_nonempty(row.get("name"), row.get("id"), row.get("scenario"), f"run_{run_index or len(rows) + 1}"),
        }
        if phase in {"cold", "startup", "boot", "first_run", "initial"}:
            row_out["classification"] = "cold"
            cold_rows.append(row_out)
        elif phase in {"warm", "steady", "stable", "hot"}:
            row_out["classification"] = "warm"
            warm_rows.append(row_out)
        elif run_index and run_index <= max(1, int(warmup_runs or 1)):
            row_out["classification"] = "cold"
            cold_rows.append(row_out)
        elif run_index:
            row_out["classification"] = "warm"
            warm_rows.append(row_out)
        else:
            row_out["classification"] = "unknown"
            unknown_rows.append(row_out)

    cold_failures = [row for row in cold_rows if not row["passed"]]
    warm_failures = [row for row in warm_rows if not row["passed"]]
    if cold_failures and not warm_failures:
        primary_cause = "cold"
        reason = "cold_runtime_failure"
    elif warm_failures and not cold_failures:
        primary_cause = "warm"
        reason = "warm_runtime_failure"
    elif cold_failures and warm_failures:
        primary_cause = "mixed"
        reason = "mixed_cold_and_warm_failure"
    elif rows:
        primary_cause = "none"
        reason = "no_runtime_failure"
    else:
        primary_cause = "unknown"
        reason = "missing_runtime_measurements"
    splitter_id = _sha1_payload(
        {
            "rows": rows,
            "cold_failures": cold_failures,
            "warm_failures": warm_failures,
            "warmup_runs": int(warmup_runs or 1),
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "splitter_id": splitter_id,
        "primary_cause": primary_cause,
        "reason": reason,
        "warmup_runs": max(1, int(warmup_runs or 1)),
        "cold_run_count": len(cold_rows),
        "warm_run_count": len(warm_rows),
        "unknown_run_count": len(unknown_rows),
        "cold_failures": cold_failures,
        "warm_failures": warm_failures,
        "unknown_rows": unknown_rows,
        "is_cold_failure": primary_cause == "cold",
        "is_warm_failure": primary_cause == "warm",
        "is_mixed_failure": primary_cause == "mixed",
        "is_unknown_failure": primary_cause == "unknown",
    }


def build_evidence_identity_contract(
    *,
    evidence_items: Sequence[Mapping[str, Any]] | None = None,
    iteration_id: str = "",
    timestamp_ms: Any = "",
    required_artifact_types: Sequence[Any] | None = None,
) -> Dict[str, Any]:
    items = [dict(item) for item in (evidence_items or []) if isinstance(item, Mapping)]
    required_types = [str(item or "").strip().lower() for item in (required_artifact_types or ["screenshot", "snapshot", "ocr", "trace"]) if str(item or "").strip()]
    rows: List[Dict[str, Any]] = []
    present_types: List[str] = []
    mismatched_iteration_items: List[str] = []
    mismatched_timestamp_items: List[str] = []
    lineage: List[str] = []
    for idx, item in enumerate(items, start=1):
        artifact_type = str(_first_nonempty(item.get("artifact_type"), item.get("type"), item.get("name"), f"artifact_{idx}")).strip().lower()
        item_iteration = str(_first_nonempty(item.get("iteration_id"), item.get("iteration"), item.get("iter_id"), "")).strip()
        item_timestamp = _first_nonempty(item.get("timestamp_ms"), item.get("timestamp"), item.get("created_at"), timestamp_ms)
        item_lineage = str(_first_nonempty(item.get("source_lineage"), item.get("lineage"), item.get("source_stage"), item.get("origin"), "")).strip()
        rows.append(
            {
                "artifact_type": artifact_type,
                "artifact_id": _first_nonempty(item.get("artifact_id"), item.get("id"), item.get("name"), f"{artifact_type}_{idx}"),
                "content_hash": _first_nonempty(item.get("content_hash"), item.get("hash"), item.get("fingerprint"), ""),
                "iteration_id": item_iteration,
                "timestamp_ms": item_timestamp,
                "source_lineage": item_lineage,
            }
        )
        if artifact_type:
            present_types.append(artifact_type)
        lineage.append(item_lineage or artifact_type)
        if iteration_id and item_iteration and item_iteration != str(iteration_id).strip():
            mismatched_iteration_items.append(artifact_type or f"artifact_{idx}")
        if timestamp_ms not in ("", None) and item_timestamp not in ("", None) and str(item_timestamp) != str(timestamp_ms):
            mismatched_timestamp_items.append(artifact_type or f"artifact_{idx}")

    present_type_set = set(present_types)
    missing_artifact_types = [item for item in required_types if item not in present_type_set]
    if not rows:
        reason = "missing_evidence"
    elif missing_artifact_types:
        reason = "missing_required_artifacts"
    elif mismatched_iteration_items or mismatched_timestamp_items:
        reason = "evidence_lineage_mismatch"
    else:
        reason = "evidence_identity_complete"
    evidence_identity_id = _sha1_payload(
        {
            "iteration_id": str(iteration_id or ""),
            "timestamp_ms": timestamp_ms,
            "required_artifact_types": required_types,
            "rows": rows,
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "evidence_identity_id": evidence_identity_id,
        "iteration_id": str(iteration_id or ""),
        "timestamp_ms": timestamp_ms,
        "required_artifact_types": required_types,
        "present_artifact_types": sorted(dict.fromkeys(present_types)),
        "missing_artifact_types": missing_artifact_types,
        "lineage": [item for item in lineage if item],
        "rows": rows,
        "artifact_count": len(rows),
        "is_complete": bool(rows) and not missing_artifact_types and not mismatched_iteration_items and not mismatched_timestamp_items,
        "is_consistent": not mismatched_iteration_items and not mismatched_timestamp_items,
        "mismatched_iteration_items": mismatched_iteration_items,
        "mismatched_timestamp_items": mismatched_timestamp_items,
        "reason": reason,
    }


def build_artifact_instance_fingerprint(
    *,
    artifact: Mapping[str, Any] | None = None,
    content: Any = None,
    origin_stage: str = "",
    dependencies: Sequence[Any] | None = None,
) -> Dict[str, Any]:
    data = dict(artifact or {})
    artifact_id = _first_nonempty(data.get("artifact_id"), data.get("id"), data.get("name"), data.get("path"), "")
    content_value = data.get("content") if content is None else content
    if isinstance(content_value, (bytes, bytearray)):
        content_bytes = bytes(content_value)
    else:
        content_bytes = _stable_json(content_value).encode("utf-8", errors="ignore")
    size_bytes = len(content_bytes)
    content_hash = hashlib.sha1(content_bytes).hexdigest()
    stage = str(_first_nonempty(origin_stage, data.get("origin_stage"), data.get("stage"), data.get("source_stage"), "")).strip().lower()
    deps = [str(item or "").strip() for item in (dependencies or data.get("dependencies") or []) if str(item or "").strip()]
    dependency_set = sorted(dict.fromkeys(deps))
    source_lineage = str(_first_nonempty(data.get("source_lineage"), data.get("lineage"), data.get("origin"), "")).strip().lower()
    if not content_bytes:
        reason = "missing_artifact_content"
    elif not stage:
        reason = "missing_origin_stage"
    else:
        reason = "artifact_instance_fingerprint_ready"
    fingerprint = _sha1_payload(
        {
            "artifact_id": artifact_id,
            "content_hash": content_hash,
            "size_bytes": size_bytes,
            "origin_stage": stage,
            "dependencies": dependency_set,
            "source_lineage": source_lineage,
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "fingerprint": fingerprint,
        "artifact_id": artifact_id,
        "content_hash": content_hash,
        "size_bytes": size_bytes,
        "origin_stage": stage,
        "source_lineage": source_lineage,
        "dependencies": dependency_set,
        "dependency_count": len(dependency_set),
        "is_complete": bool(content_bytes) and bool(stage),
        "reason": reason,
    }


def build_evidence_confidence_score(
    *,
    evidence_identity_contract: Mapping[str, Any] | None = None,
    freshness_marker: Mapping[str, Any] | None = None,
    consistency_report: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    identity = dict(evidence_identity_contract or {})
    freshness = dict(freshness_marker or {})
    consistency = dict(consistency_report or {})
    required_types = [str(item or "").strip().lower() for item in (identity.get("required_artifact_types") or []) if str(item or "").strip()]
    present_types = {str(item or "").strip().lower() for item in (identity.get("present_artifact_types") or []) if str(item or "").strip()}
    if required_types:
        completeness_score = len(present_types & set(required_types)) / len(required_types)
    else:
        completeness_score = 1.0 if identity.get("is_complete") else 0.0
    is_fresh = bool(freshness.get("is_fresh", True))
    stale_reasons = [str(item).strip().lower() for item in freshness.get("stale_reasons") or [] if str(item or "").strip()]
    freshness_score = 1.0 if is_fresh else (0.5 if stale_reasons else 0.0)
    if "consistency_score" in consistency and isinstance(consistency.get("consistency_score"), (int, float)):
        consistency_score = max(0.0, min(1.0, float(consistency.get("consistency_score") or 0.0)))
    elif identity.get("is_consistent") is False:
        consistency_score = 0.0
    else:
        consistency_score = 1.0 if identity.get("is_consistent", True) else 0.0
    confidence_score = round((completeness_score * 0.45) + (freshness_score * 0.25) + (consistency_score * 0.30), 4)
    if completeness_score < 1.0:
        reason = "incomplete_evidence"
    elif not is_fresh:
        reason = "stale_evidence"
    elif consistency_score < 1.0:
        reason = "inconsistent_evidence"
    else:
        reason = "high_confidence_evidence"
    if confidence_score >= 0.85:
        confidence_tier = "high"
    elif confidence_score >= 0.6:
        confidence_tier = "medium"
    else:
        confidence_tier = "low"
    score_id = _sha1_payload(
        {
            "evidence_identity_id": identity.get("evidence_identity_id"),
            "completeness_score": round(completeness_score, 4),
            "freshness_score": round(freshness_score, 4),
            "consistency_score": round(consistency_score, 4),
            "confidence_score": confidence_score,
            "reason": reason,
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "score_id": score_id,
        "evidence_identity_id": identity.get("evidence_identity_id", ""),
        "completeness_score": round(completeness_score, 4),
        "freshness_score": round(freshness_score, 4),
        "consistency_score": round(consistency_score, 4),
        "confidence_score": confidence_score,
        "confidence_tier": confidence_tier,
        "reason": reason,
        "is_confident": confidence_tier == "high",
        "is_partial": confidence_tier == "medium",
        "is_low_confidence": confidence_tier == "low",
        "stale_reasons": stale_reasons,
        "required_artifact_types": required_types,
        "present_artifact_types": sorted(present_types),
    }


def build_evidence_packet_contract(
    *,
    task_type: str = "",
    evidence_identity_contract: Mapping[str, Any] | None = None,
    required_artifact_types: Sequence[Any] | None = None,
    optional_artifact_types: Sequence[Any] | None = None,
    provided_artifacts: Sequence[Mapping[str, Any]] | None = None,
) -> Dict[str, Any]:
    identity = dict(evidence_identity_contract or {})
    task = str(task_type or "").strip().lower()
    defaults = {
        "capture": ["screenshot", "snapshot", "trace"],
        "ocr": ["screenshot", "ocr", "trace"],
        "decision": ["screenshot", "snapshot", "ocr", "trace"],
        "replay": ["snapshot", "trace", "environment_fingerprint"],
    }
    explicit_required = [str(item or "").strip().lower() for item in (required_artifact_types or []) if str(item or "").strip()]
    explicit_optional = [str(item or "").strip().lower() for item in (optional_artifact_types or []) if str(item or "").strip()]
    required_types = explicit_required or defaults.get(task, ["screenshot", "snapshot", "trace"])
    if provided_artifacts is not None:
        provided_types = [
            str(_first_nonempty(item.get("artifact_type"), item.get("type"), item.get("name"), "")).strip().lower()
            for item in provided_artifacts
            if isinstance(item, Mapping)
        ]
    else:
        provided_types = [str(item or "").strip().lower() for item in (identity.get("present_artifact_types") or []) if str(item or "").strip()]
    provided_set = {item for item in provided_types if item}
    missing_required = [item for item in required_types if item not in provided_set]
    surplus = [item for item in sorted(provided_set) if item not in set(required_types) and item not in set(explicit_optional)]
    if not task:
        reason = "missing_task_type"
    elif missing_required:
        reason = "missing_required_artifacts"
    elif task not in defaults and not explicit_required:
        reason = "unknown_task_type"
    else:
        reason = "evidence_packet_ready"
    packet_id = _sha1_payload(
        {
            "task_type": task,
            "required_artifact_types": required_types,
            "optional_artifact_types": explicit_optional,
            "provided_artifact_types": sorted(provided_set),
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "packet_id": packet_id,
        "task_type": task,
        "required_artifact_types": required_types,
        "optional_artifact_types": explicit_optional,
        "provided_artifact_types": sorted(provided_set),
        "missing_required_artifact_types": missing_required,
        "surplus_artifact_types": surplus,
        "required_artifact_count": len(required_types),
        "provided_artifact_count": len(provided_set),
        "is_complete": bool(task) and not missing_required,
        "should_block_worker": bool(not task or missing_required),
        "reason": reason,
    }


def build_cross_artifact_sync_guard(
    *,
    evidence_items: Sequence[Mapping[str, Any]] | None = None,
    max_timestamp_skew_ms: float = 0.0,
) -> Dict[str, Any]:
    items = [dict(item) for item in (evidence_items or []) if isinstance(item, Mapping)]
    rows: List[Dict[str, Any]] = []
    timestamps: List[float] = []
    iteration_ids: List[str] = []
    version_ids: List[str] = []
    for idx, item in enumerate(items, start=1):
        artifact_type = str(_first_nonempty(item.get("artifact_type"), item.get("type"), item.get("name"), f"artifact_{idx}")).strip().lower()
        timestamp_value = item.get("timestamp_ms")
        if isinstance(timestamp_value, bool):
            timestamp_value = float(timestamp_value)
        timestamp_ms = float(timestamp_value) if isinstance(timestamp_value, (int, float)) and math.isfinite(float(timestamp_value)) else 0.0
        iteration_id = str(_first_nonempty(item.get("iteration_id"), item.get("iteration"), item.get("iter_id"), "")).strip()
        version_id = str(_first_nonempty(item.get("version"), item.get("schema_version"), item.get("artifact_version"), "")).strip()
        rows.append(
            {
                "artifact_type": artifact_type,
                "timestamp_ms": round(timestamp_ms, 4),
                "iteration_id": iteration_id,
                "version_id": version_id,
            }
        )
        if timestamp_ms:
            timestamps.append(timestamp_ms)
        if iteration_id:
            iteration_ids.append(iteration_id)
        if version_id:
            version_ids.append(version_id)

    timestamp_spread_ms = (max(timestamps) - min(timestamps)) if timestamps else 0.0
    unique_iterations = sorted(dict.fromkeys(iteration_ids))
    unique_versions = sorted(dict.fromkeys(version_ids))
    has_timestamp_drift = timestamp_spread_ms > float(max_timestamp_skew_ms or 0.0)
    has_iteration_drift = len(unique_iterations) > 1
    has_version_drift = len(unique_versions) > 1
    if not rows:
        reason = "missing_evidence"
    elif has_timestamp_drift and has_iteration_drift and has_version_drift:
        reason = "mixed_artifact_drift"
    elif has_timestamp_drift:
        reason = "timestamp_artifact_drift"
    elif has_iteration_drift or has_version_drift:
        reason = "version_artifact_drift"
    else:
        reason = "artifact_sync_ok"
    sync_id = _sha1_payload(
        {
            "rows": rows,
            "max_timestamp_skew_ms": float(max_timestamp_skew_ms or 0.0),
            "timestamp_spread_ms": round(timestamp_spread_ms, 4),
            "unique_iterations": unique_iterations,
            "unique_versions": unique_versions,
        }
    )[:16]
    synchronized_types = [
        row["artifact_type"]
        for row in rows
        if row["artifact_type"] and (not has_timestamp_drift or row["timestamp_ms"] <= (min(timestamps) + float(max_timestamp_skew_ms or 0.0)))
    ]
    desynced_types = [row["artifact_type"] for row in rows if row["artifact_type"] not in synchronized_types]
    return {
        "schema_version": SCHEMA_VERSION,
        "sync_id": sync_id,
        "reason": reason,
        "rows": rows,
        "artifact_count": len(rows),
        "timestamp_spread_ms": round(timestamp_spread_ms, 4),
        "max_timestamp_skew_ms": round(float(max_timestamp_skew_ms or 0.0), 4),
        "unique_iteration_ids": unique_iterations,
        "unique_version_ids": unique_versions,
        "synchronized_artifact_types": synchronized_types,
        "desynced_artifact_types": desynced_types,
        "is_synced": not (has_timestamp_drift or has_iteration_drift or has_version_drift) and bool(rows),
        "should_block_pipeline": bool(has_timestamp_drift or has_iteration_drift or has_version_drift),
    }


def build_evidence_consistency_checker(
    *,
    evidence_items: Sequence[Mapping[str, Any]] | None = None,
    expected_state_signature: str = "",
    expected_outcome: str = "",
) -> Dict[str, Any]:
    items = [dict(item) for item in (evidence_items or []) if isinstance(item, Mapping)]
    state_signatures: Dict[str, List[str]] = {}
    outcomes: Dict[str, List[str]] = {}
    rows: List[Dict[str, Any]] = []
    for idx, item in enumerate(items, start=1):
        artifact_type = str(_first_nonempty(item.get("artifact_type"), item.get("type"), item.get("name"), f"artifact_{idx}")).strip().lower()
        state_signature = _norm_text(_first_nonempty(item.get("state_signature"), item.get("state"), item.get("screen_state"), item.get("snapshot"), item.get("content_state"), ""))
        outcome = _norm_text(_first_nonempty(item.get("outcome"), item.get("result"), item.get("decision"), item.get("status"), ""))
        rows.append(
            {
                "artifact_type": artifact_type,
                "state_signature": state_signature,
                "outcome": outcome,
            }
        )
        if state_signature:
            state_signatures.setdefault(state_signature, []).append(artifact_type)
        if outcome:
            outcomes.setdefault(outcome, []).append(artifact_type)

    expected_state_signature_norm = _norm_text(expected_state_signature)
    expected_outcome_norm = _norm_text(expected_outcome)
    observed_state_signatures = sorted(state_signatures)
    observed_outcomes = sorted(outcomes)
    has_state_consensus = len(observed_state_signatures) <= 1
    has_outcome_consensus = len(observed_outcomes) <= 1
    if expected_state_signature_norm and observed_state_signatures and expected_state_signature_norm not in observed_state_signatures:
        state_consistent = False
    else:
        state_consistent = has_state_consensus
    if expected_outcome_norm and observed_outcomes and expected_outcome_norm not in observed_outcomes:
        outcome_consistent = False
    else:
        outcome_consistent = has_outcome_consensus
    consistent = bool(rows) and state_consistent and outcome_consistent
    if not rows:
        reason = "missing_evidence"
    elif not state_consistent and not outcome_consistent:
        reason = "state_and_outcome_disagreement"
    elif not state_consistent:
        reason = "state_disagreement"
    elif not outcome_consistent:
        reason = "outcome_disagreement"
    else:
        reason = "evidence_consistent"
    consistency_id = _sha1_payload(
        {
            "rows": rows,
            "expected_state_signature": expected_state_signature_norm,
            "expected_outcome": expected_outcome_norm,
        }
    )[:16]
    conflicting_types: List[str] = []
    if not consistent:
        canonical_state = expected_state_signature_norm or (observed_state_signatures[0] if observed_state_signatures else "")
        canonical_outcome = expected_outcome_norm or (observed_outcomes[0] if observed_outcomes else "")
        for row in rows:
            state_signature = row.get("state_signature") or ""
            outcome = row.get("outcome") or ""
            if (canonical_state and state_signature and state_signature != canonical_state) or (canonical_outcome and outcome and outcome != canonical_outcome):
                conflicting_types.append(str(row.get("artifact_type") or ""))
        conflicting_types = sorted(dict.fromkeys(item for item in conflicting_types if item))
    return {
        "schema_version": SCHEMA_VERSION,
        "consistency_id": consistency_id,
        "reason": reason,
        "rows": rows,
        "artifact_count": len(rows),
        "expected_state_signature": expected_state_signature_norm,
        "expected_outcome": expected_outcome_norm,
        "observed_state_signatures": observed_state_signatures,
        "observed_outcomes": observed_outcomes,
        "consistent_artifact_types": sorted(
            dict.fromkeys(
                artifact
                for _, artifacts in state_signatures.items()
                if len(artifacts) == 1
                for artifact in artifacts
            )
        ),
        "conflicting_artifact_types": conflicting_types,
        "is_consistent": consistent,
        "should_block_pipeline": not consistent,
    }


def build_stale_artifact_detector(
    *,
    artifacts: Sequence[Mapping[str, Any]] | None = None,
    current_session_id: str = "",
    current_iteration_id: str = "",
    current_version: str = "",
    freshness_marker: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    current_freshness = dict(freshness_marker or {})
    rows: List[Dict[str, Any]] = []
    stale_rows: List[Dict[str, Any]] = []
    fresh_rows: List[Dict[str, Any]] = []
    current_session = str(current_session_id or "").strip()
    current_iteration = str(current_iteration_id or "").strip()
    current_ver = str(current_version or "").strip()
    for idx, artifact in enumerate(artifacts or [], start=1):
        if not isinstance(artifact, Mapping):
            continue
        artifact_type = str(_first_nonempty(artifact.get("artifact_type"), artifact.get("type"), artifact.get("name"), f"artifact_{idx}")).strip().lower()
        session_id = str(_first_nonempty(artifact.get("session_id"), artifact.get("session"), "")).strip()
        iteration_id = str(_first_nonempty(artifact.get("iteration_id"), artifact.get("iteration"), "")).strip()
        version = str(_first_nonempty(artifact.get("version"), artifact.get("source_version"), artifact.get("schema_version"), "")).strip()
        marker = dict(artifact.get("freshness_marker") or {})
        stale_reasons = [
            reason
            for reason, matched in (
                ("session_mismatch", bool(current_session and session_id and session_id != current_session)),
                ("iteration_mismatch", bool(current_iteration and iteration_id and iteration_id != current_iteration)),
                ("version_mismatch", bool(current_ver and version and version != current_ver)),
                ("marker_stale", bool(marker.get("is_stale"))),
                ("global_marker_stale", bool(current_freshness.get("is_stale"))),
            )
            if matched
        ]
        is_stale = bool(stale_reasons)
        row = {
            "artifact_type": artifact_type,
            "artifact_id": _first_nonempty(artifact.get("artifact_id"), artifact.get("id"), artifact.get("name"), f"{artifact_type}_{idx}"),
            "session_id": session_id,
            "iteration_id": iteration_id,
            "version": version,
            "stale_reasons": stale_reasons,
            "is_stale": is_stale,
        }
        rows.append(row)
        if is_stale:
            stale_rows.append(row)
        else:
            fresh_rows.append(row)
    if not rows:
        reason = "missing_artifacts"
    elif stale_rows:
        reason = "stale_artifacts_detected"
    else:
        reason = "fresh_artifacts_only"
    detector_id = _sha1_payload(
        {
            "rows": rows,
            "current_session_id": current_session,
            "current_iteration_id": current_iteration,
            "current_version": current_ver,
            "freshness_marker": current_freshness,
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "detector_id": detector_id,
        "reason": reason,
        "rows": rows,
        "stale_artifacts": stale_rows,
        "fresh_artifacts": fresh_rows,
        "stale_artifact_count": len(stale_rows),
        "fresh_artifact_count": len(fresh_rows),
        "is_stale": bool(stale_rows),
        "should_reject": bool(stale_rows or not rows),
    }


def build_evidence_quarantine_policy(
    *,
    evidence_identity_contract: Mapping[str, Any] | None = None,
    evidence_confidence_score: Mapping[str, Any] | None = None,
    evidence_consistency_checker: Mapping[str, Any] | None = None,
    stale_artifact_detector: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    identity = dict(evidence_identity_contract or {})
    confidence = dict(evidence_confidence_score or {})
    consistency = dict(evidence_consistency_checker or {})
    stale = dict(stale_artifact_detector or {})
    rows = [dict(row) for row in (identity.get("rows") or []) if isinstance(row, Mapping)]
    stale_types = {str(item).strip().lower() for item in (stale.get("stale_artifacts") or []) if isinstance(item, Mapping) for item in [item.get("artifact_type") or item.get("name") or item.get("artifact_id") or ""] if str(item).strip()}
    conflict_types = {str(item).strip().lower() for item in (consistency.get("conflicting_artifact_types") or []) if str(item or "").strip()}
    missing_types = {str(item).strip().lower() for item in (identity.get("missing_artifact_types") or []) if str(item or "").strip()}
    low_confidence = float(confidence.get("confidence_score") or 0.0) < 0.6
    quarantined_types = sorted(dict.fromkeys(stale_types | conflict_types | missing_types))
    if stale_types:
        reason = "stale_evidence_quarantined"
    elif not bool(consistency.get("is_consistent", True)):
        reason = "inconsistent_evidence_quarantined"
    elif low_confidence:
        reason = "low_confidence_evidence_quarantined"
    else:
        reason = "evidence_clear"
    quarantine_id = _sha1_payload(
        {
            "identity_id": identity.get("evidence_identity_id"),
            "score_id": confidence.get("score_id"),
            "consistency_id": consistency.get("consistency_id"),
            "detector_id": stale.get("detector_id"),
            "quarantined_types": quarantined_types,
            "reason": reason,
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "quarantine_id": quarantine_id,
        "reason": reason,
        "quarantined_artifact_types": quarantined_types,
        "quarantined_artifact_count": len(quarantined_types),
        "cleared_artifact_types": sorted(
            {
                str(row.get("artifact_type") or "").strip().lower()
                for row in rows
                if str(row.get("artifact_type") or "").strip().lower() and str(row.get("artifact_type") or "").strip().lower() not in quarantined_types
            }
        ),
        "is_quarantined": bool(quarantined_types) or reason != "evidence_clear",
        "should_divert_to_analysis": bool(quarantined_types) or reason != "evidence_clear",
        "is_clear": reason == "evidence_clear",
        "confidence_score": float(confidence.get("confidence_score") or 0.0),
        "is_consistent": bool(consistency.get("is_consistent", True)),
        "has_stale_artifacts": bool(stale.get("is_stale")),
    }


def build_artifact_integrity_verifier(
    *,
    artifacts: Sequence[Mapping[str, Any]] | None = None,
    expected_checksums: Mapping[str, Any] | None = None,
    min_size_bytes: int = 1,
    min_readability_score: float = 0.0,
) -> Dict[str, Any]:
    expected = {str(key).strip().lower(): str(value or "").strip().lower() for key, value in dict(expected_checksums or {}).items() if str(key or "").strip()}
    rows: List[Dict[str, Any]] = []
    good_rows: List[Dict[str, Any]] = []
    bad_rows: List[Dict[str, Any]] = []
    for idx, artifact in enumerate(artifacts or [], start=1):
        if not isinstance(artifact, Mapping):
            continue
        name = str(_first_nonempty(artifact.get("name"), artifact.get("artifact"), artifact.get("id"), f"artifact_{idx}")).strip().lower()
        path = _first_nonempty(artifact.get("path"), artifact.get("file"), artifact.get("artifact_path"), "")
        checksum = str(_first_nonempty(artifact.get("checksum"), artifact.get("sha256"), artifact.get("digest"), artifact.get("hash"), "")).strip().lower()
        expected_checksum = str(_first_nonempty(artifact.get("expected_checksum"), expected.get(name, ""))).strip().lower()
        size_bytes = int(artifact.get("size_bytes") or artifact.get("size") or len(str(artifact.get("content") or "")) or 0)
        readability_score = float(_first_nonempty(artifact.get("readability_score"), artifact.get("readable_ratio"), 1.0 if artifact.get("is_readable", True) else 0.0) or 0.0)
        checksum_ok = bool(not expected_checksum or checksum == expected_checksum)
        size_ok = size_bytes >= max(0, int(min_size_bytes or 0))
        readability_ok = readability_score >= float(min_readability_score or 0.0)
        is_integrity_ok = bool(checksum_ok and size_ok and readability_ok)
        row = {
            "name": name,
            "path": path,
            "checksum": checksum,
            "expected_checksum": expected_checksum,
            "size_bytes": size_bytes,
            "readability_score": round(readability_score, 4),
            "checksum_ok": checksum_ok,
            "size_ok": size_ok,
            "readability_ok": readability_ok,
            "is_integrity_ok": is_integrity_ok,
            "reasons": [
                reason
                for reason, passed in (
                    ("checksum_mismatch", checksum_ok),
                    ("size_too_small", size_ok),
                    ("not_readable_enough", readability_ok),
                )
                if not passed
            ],
        }
        rows.append(row)
        if is_integrity_ok:
            good_rows.append(row)
        else:
            bad_rows.append(row)
    if not rows:
        reason = "missing_artifacts"
    elif bad_rows:
        reason = "artifact_integrity_violation"
    else:
        reason = "artifact_integrity_ok"
    verifier_id = _sha1_payload(
        {
            "rows": rows,
            "expected_checksums": expected,
            "min_size_bytes": int(min_size_bytes or 0),
            "min_readability_score": float(min_readability_score or 0.0),
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "verifier_id": verifier_id,
        "reason": reason,
        "rows": rows,
        "good_artifacts": good_rows,
        "bad_artifacts": bad_rows,
        "artifact_count": len(rows),
        "good_artifact_count": len(good_rows),
        "bad_artifact_count": len(bad_rows),
        "is_integrity_ok": not bad_rows and bool(rows),
        "should_block_pipeline": bool(bad_rows or not rows),
    }


def build_claim_to_evidence_enforcer(
    *,
    claims: Sequence[Mapping[str, Any] | str] | None = None,
    evidence_identity_contract: Mapping[str, Any] | None = None,
    claim_evidence_links: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    identity = dict(evidence_identity_contract or {})
    links = {str(key).strip().lower(): value for key, value in dict(claim_evidence_links or {}).items() if str(key or "").strip()}
    rows: List[Dict[str, Any]] = []
    blocked_rows: List[Dict[str, Any]] = []
    allowed_rows: List[Dict[str, Any]] = []
    present_types = {str(item).strip().lower() for item in (identity.get("present_artifact_types") or []) if str(item or "").strip()}
    for idx, claim in enumerate(claims or [], start=1):
        if isinstance(claim, Mapping):
            claim_id = _first_nonempty(claim.get("claim_id"), claim.get("id"), f"claim_{idx}")
            claim_text = _first_nonempty(claim.get("claim_text"), claim.get("text"), claim.get("statement"), claim.get("name"), "")
            evidence_id = _first_nonempty(claim.get("evidence_id"), claim.get("artifact_id"), claim.get("proof_id"), "")
            evidence_type = _first_nonempty(claim.get("evidence_type"), claim.get("artifact_type"), claim.get("type"), "")
        else:
            claim_id = f"claim_{idx}"
            claim_text = str(claim or "").strip()
            evidence_id = ""
            evidence_type = ""
        link_key = str(claim_id).strip().lower()
        linked_evidence = links.get(link_key)
        linked_evidence_id = _first_nonempty(
            linked_evidence.get("evidence_id") if isinstance(linked_evidence, Mapping) else "",
            linked_evidence.get("artifact_id") if isinstance(linked_evidence, Mapping) else "",
            linked_evidence if isinstance(linked_evidence, str) else "",
        )
        attached = bool(evidence_id or linked_evidence_id)
        if not evidence_type and evidence_id in present_types:
            evidence_type = evidence_id
        if not evidence_type and linked_evidence_id in present_types:
            evidence_type = linked_evidence_id
        if attached:
            reason = "claim_evidence_linked"
            allowed = True
        else:
            reason = "missing_claim_evidence_link"
            allowed = False
        row = {
            "claim_id": claim_id,
            "claim_text": claim_text,
            "evidence_id": evidence_id or linked_evidence_id,
            "evidence_type": evidence_type,
            "is_allowed": allowed,
            "reason": reason,
        }
        rows.append(row)
        if allowed:
            allowed_rows.append(row)
        else:
            blocked_rows.append(row)
    if not rows:
        reason = "missing_claims"
    elif blocked_rows:
        reason = "claims_without_evidence"
    else:
        reason = "all_claims_evidenced"
    enforcer_id = _sha1_payload(
        {
            "rows": rows,
            "present_types": sorted(present_types),
            "evidence_identity_id": identity.get("evidence_identity_id"),
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "enforcer_id": enforcer_id,
        "reason": reason,
        "rows": rows,
        "allowed_claims": allowed_rows,
        "blocked_claims": blocked_rows,
        "claim_count": len(rows),
        "allowed_count": len(allowed_rows),
        "blocked_count": len(blocked_rows),
        "is_enforced": not blocked_rows and bool(rows),
        "should_block_report": bool(blocked_rows or not rows),
    }


def build_evidence_minification_guard(
    *,
    original_packet: Mapping[str, Any] | None = None,
    minified_packet: Mapping[str, Any] | None = None,
    required_fields: Sequence[Any] | None = None,
    min_retained_ratio: float = 0.5,
) -> Dict[str, Any]:
    original = dict(original_packet or {})
    minified = dict(minified_packet or {})
    required = [str(item or "").strip() for item in (required_fields or ["schema_version", "artifact_id", "reason"]) if str(item or "").strip()]
    original_fields = sorted(str(key) for key in original.keys())
    minified_fields = sorted(str(key) for key in minified.keys())
    original_set = set(original_fields)
    minified_set = set(minified_fields)
    retained_fields = sorted(original_set & minified_set)
    dropped_fields = sorted(original_set - minified_set)
    preserved_required_fields = [field for field in required if field in minified_set]
    missing_required_fields = [field for field in required if field not in minified_set]
    retained_ratio = (len(retained_fields) / len(original_fields)) if original_fields else 0.0
    if not original_fields:
        reason = "missing_original_packet"
    elif missing_required_fields:
        reason = "missing_required_fields"
    elif retained_ratio < float(min_retained_ratio or 0.0):
        reason = "over_minified_packet"
    else:
        reason = "evidence_minification_safe"
    guard_id = _sha1_payload(
        {
            "original_packet": original,
            "minified_packet": minified,
            "required_fields": required,
            "min_retained_ratio": float(min_retained_ratio or 0.0),
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "guard_id": guard_id,
        "reason": reason,
        "original_field_count": len(original_fields),
        "minified_field_count": len(minified_fields),
        "retained_field_count": len(retained_fields),
        "dropped_field_count": len(dropped_fields),
        "retained_fields": retained_fields,
        "dropped_fields": dropped_fields,
        "required_fields": required,
        "preserved_required_fields": preserved_required_fields,
        "missing_required_fields": missing_required_fields,
        "retained_ratio": round(retained_ratio, 4),
        "min_retained_ratio": round(float(min_retained_ratio or 0.0), 4),
        "is_safe": reason == "evidence_minification_safe",
        "should_block_minification": reason != "evidence_minification_safe",
    }


def build_trust_tier_registry(
    *,
    artifacts: Sequence[Mapping[str, Any]] | None = None,
) -> Dict[str, Any]:
    rows: List[Dict[str, Any]] = []
    tier_counts = {"raw": 0, "derived": 0, "suspicious": 0, "confirmed_multi_source": 0}
    suspicious_rows: List[Dict[str, Any]] = []
    for idx, artifact in enumerate(artifacts or [], start=1):
        if not isinstance(artifact, Mapping):
            continue
        name = str(_first_nonempty(artifact.get("name"), artifact.get("artifact"), artifact.get("artifact_type"), artifact.get("id"), f"artifact_{idx}")).strip().lower()
        provenance = artifact.get("provenance_sources") or artifact.get("sources") or artifact.get("lineage") or artifact.get("origin_sources") or []
        if isinstance(provenance, Mapping):
            provenance_list = [str(key).strip() for key in provenance.keys() if str(key or "").strip()]
        elif isinstance(provenance, Sequence) and not isinstance(provenance, (str, bytes, bytearray)):
            provenance_list = [str(item or "").strip() for item in provenance if str(item or "").strip()]
        else:
            provenance_list = [str(provenance).strip()] if str(provenance or "").strip() else []
        source_count = len(dict.fromkeys(provenance_list))
        has_hash = bool(_first_nonempty(artifact.get("content_hash"), artifact.get("hash"), artifact.get("checksum"), artifact.get("fingerprint"), ""))
        is_verified = bool(artifact.get("is_verified") or artifact.get("confirmed") or artifact.get("trusted") or artifact.get("multi_source_verified"))
        is_derived = bool(artifact.get("is_derived") or artifact.get("derived") or artifact.get("generated") or artifact.get("parent_id") or artifact.get("derived_from"))
        is_suspicious = bool(artifact.get("is_suspicious") or artifact.get("suspicious")) or not has_hash or source_count == 0
        if is_suspicious:
            tier = "suspicious"
            reason = "suspicious_artifact"
        elif is_verified and source_count >= 2:
            tier = "confirmed_multi_source"
            reason = "multi_source_confirmed"
        elif is_derived:
            tier = "derived"
            reason = "derived_artifact"
        else:
            tier = "raw"
            reason = "raw_artifact"
        row = {
            "name": name,
            "artifact_id": _first_nonempty(artifact.get("artifact_id"), artifact.get("id"), artifact.get("name"), f"artifact_{idx}"),
            "tier": tier,
            "reason": reason,
            "provenance_sources": provenance_list,
            "source_count": source_count,
            "has_hash": has_hash,
            "is_verified": is_verified,
            "is_derived": is_derived,
            "is_suspicious": is_suspicious,
        }
        rows.append(row)
        tier_counts[tier] += 1
        if is_suspicious:
            suspicious_rows.append(row)
    if not rows:
        reason = "missing_artifacts"
    elif suspicious_rows:
        reason = "trust_tier_registry_warn"
    else:
        reason = "trust_tier_registry_ready"
    registry_id = _sha1_payload({"rows": rows, "tier_counts": tier_counts})[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "registry_id": registry_id,
        "reason": reason,
        "rows": rows,
        "tier_counts": tier_counts,
        "suspicious_artifacts": suspicious_rows,
        "artifact_count": len(rows),
        "suspicious_count": len(suspicious_rows),
        "is_ready": bool(rows) and not suspicious_rows,
        "should_block_report": bool(suspicious_rows or not rows),
    }


def build_evidence_quality_regression_suite(
    *,
    runs: Sequence[Mapping[str, Any]] | None = None,
    min_completeness: float = 0.8,
    min_freshness: float = 0.8,
    min_consistency: float = 0.8,
) -> Dict[str, Any]:
    rows: List[Dict[str, Any]] = []
    failing_runs: List[Dict[str, Any]] = []
    passing_runs: List[Dict[str, Any]] = []
    for idx, run in enumerate(runs or [], start=1):
        if not isinstance(run, Mapping):
            continue
        profile = _first_nonempty(run.get("profile"), run.get("name"), run.get("scenario"), f"run_{idx}")
        completeness = float(_first_nonempty(run.get("completeness_score"), run.get("completeness"), 0.0) or 0.0)
        freshness = float(_first_nonempty(run.get("freshness_score"), run.get("freshness"), 0.0) or 0.0)
        consistency = float(_first_nonempty(run.get("consistency_score"), run.get("consistency"), 0.0) or 0.0)
        pass_run = bool(
            completeness >= float(min_completeness or 0.0)
            and freshness >= float(min_freshness or 0.0)
            and consistency >= float(min_consistency or 0.0)
        )
        row = {
            "profile": profile,
            "completeness_score": round(completeness, 4),
            "freshness_score": round(freshness, 4),
            "consistency_score": round(consistency, 4),
            "passed": pass_run,
        }
        rows.append(row)
        if pass_run:
            passing_runs.append(row)
        else:
            failing_runs.append(row)
    if not rows:
        reason = "missing_evidence_quality_runs"
    elif failing_runs:
        reason = "evidence_quality_regression_detected"
    else:
        reason = "evidence_quality_regression_clear"
    suite_id = _sha1_payload(
        {
            "rows": rows,
            "min_completeness": float(min_completeness or 0.0),
            "min_freshness": float(min_freshness or 0.0),
            "min_consistency": float(min_consistency or 0.0),
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "suite_id": suite_id,
        "reason": reason,
        "rows": rows,
        "failing_runs": failing_runs,
        "passing_runs": passing_runs,
        "run_count": len(rows),
        "failing_count": len(failing_runs),
        "passing_count": len(passing_runs),
        "min_completeness": round(float(min_completeness or 0.0), 4),
        "min_freshness": round(float(min_freshness or 0.0), 4),
        "min_consistency": round(float(min_consistency or 0.0), 4),
        "is_healthy": not failing_runs and bool(rows),
        "should_block_pipeline": bool(failing_runs or not rows),
    }


def build_forensic_replay_bundle(
    *,
    evidence_identity_contract: Mapping[str, Any] | None = None,
    artifact_integrity_verifier: Mapping[str, Any] | None = None,
    evidence_consistency_checker: Mapping[str, Any] | None = None,
    stale_artifact_detector: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    identity = dict(evidence_identity_contract or {})
    integrity = dict(artifact_integrity_verifier or {})
    consistency = dict(evidence_consistency_checker or {})
    stale = dict(stale_artifact_detector or {})
    rows = [dict(row) for row in (identity.get("rows") or []) if isinstance(row, Mapping)]
    integrity_rows = {str(row.get("name") or row.get("artifact_id") or "").strip().lower(): dict(row) for row in (integrity.get("rows") or []) if isinstance(row, Mapping)}
    stale_types = {str(item.get("artifact_type") or item.get("name") or item.get("artifact_id") or "").strip().lower() for item in (stale.get("stale_artifacts") or []) if isinstance(item, Mapping)}
    conflicting_types = {str(item).strip().lower() for item in (consistency.get("conflicting_artifact_types") or []) if str(item or "").strip()}
    approved_rows: List[Dict[str, Any]] = []
    blocked_rows: List[Dict[str, Any]] = []
    for row in rows:
        artifact_type = str(row.get("artifact_type") or "").strip().lower()
        integrity_row = integrity_rows.get(artifact_type) or integrity_rows.get(str(row.get("artifact_id") or "").strip().lower()) or {}
        row_ok = bool(
            artifact_type
            and integrity_row.get("is_integrity_ok", False)
            and artifact_type not in stale_types
            and artifact_type not in conflicting_types
        )
        bundle_row = {
            "artifact_type": artifact_type,
            "artifact_id": row.get("artifact_id"),
            "source_lineage": row.get("source_lineage"),
            "is_approved": row_ok,
            "reasons": [
                reason
                for reason, passed in (
                    ("integrity_failed", bool(integrity_row.get("is_integrity_ok", False))),
                    ("stale_artifact", artifact_type not in stale_types),
                    ("inconsistent_artifact", artifact_type not in conflicting_types),
                )
                if not passed
            ],
        }
        if row_ok:
            approved_rows.append(bundle_row)
        else:
            blocked_rows.append(bundle_row)
    if not rows:
        reason = "missing_evidence_identity"
    elif blocked_rows:
        reason = "forensic_replay_quarantined"
    else:
        reason = "forensic_replay_bundle_ready"
    bundle_id = _sha1_payload(
        {
            "identity_id": identity.get("evidence_identity_id"),
            "approved_rows": approved_rows,
            "blocked_rows": blocked_rows,
            "stale_artifacts": sorted(stale_types),
            "conflicting_artifacts": sorted(conflicting_types),
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "bundle_id": bundle_id,
        "reason": reason,
        "rows": approved_rows,
        "blocked_rows": blocked_rows,
        "artifact_count": len(rows),
        "approved_artifact_count": len(approved_rows),
        "blocked_artifact_count": len(blocked_rows),
        "approved_artifact_types": sorted(row["artifact_type"] for row in approved_rows if row.get("artifact_type")),
        "blocked_artifact_types": sorted(row["artifact_type"] for row in blocked_rows if row.get("artifact_type")),
        "lineage": [str(item.get("source_lineage") or "").strip() for item in rows if str(item.get("source_lineage") or "").strip()],
        "is_ready": bool(rows) and not blocked_rows,
        "should_block_replay": bool(blocked_rows or not rows),
    }


def build_evidence_gap_promoter(
    *,
    evidence_gap_events: Sequence[Mapping[str, Any] | str] | None = None,
    evidence_quality_regression_suite: Mapping[str, Any] | None = None,
    forensic_replay_bundle: Mapping[str, Any] | None = None,
    gap_key_hint: str = "",
    threshold: int = 2,
) -> Dict[str, Any]:
    suite = dict(evidence_quality_regression_suite or {})
    replay = dict(forensic_replay_bundle or {})
    hint = str(gap_key_hint or "").strip().lower()

    def _collect_rows(rows: Sequence[Mapping[str, Any] | str] | None, default_kind: str) -> List[Dict[str, Any]]:
        collected: List[Dict[str, Any]] = []
        for row in rows or []:
            if isinstance(row, Mapping):
                collected.append(dict(row))
            else:
                text = str(row or "").strip()
                if text:
                    collected.append({"name": text, "kind": default_kind, "reason": text})
        return collected

    gap_rows = _collect_rows(evidence_gap_events, "gap")
    failing_runs = _collect_rows(suite.get("failing_runs") or [], "regression")
    blocked_rows = _collect_rows(replay.get("blocked_rows") or [], "replay")

    evidence_rows = gap_rows + failing_runs + blocked_rows

    def _row_key(row: Mapping[str, Any]) -> str:
        return str(
            _first_nonempty(
                row.get("gap_key"),
                row.get("evidence_gap"),
                row.get("family_key"),
                row.get("name"),
                row.get("artifact_type"),
                row.get("reason"),
                hint,
                "",
            )
        ).strip().lower()

    recurring_count = 0
    signal_rows: List[Dict[str, Any]] = []
    for row in evidence_rows:
        key = _row_key(row)
        if hint and key and key == hint:
            recurring_count += 1
            signal_rows.append(row)
        elif not hint:
            recurring_count += 1
            signal_rows.append(row)

    backlog_count = len(failing_runs) + len(blocked_rows)
    threshold_value = max(1, int(threshold or 1))
    should_promote = bool(recurring_count >= threshold_value or backlog_count >= threshold_value)
    if should_promote:
        promotion_tier = "promote"
        reason = "evidence_gap_promote"
    elif recurring_count > 0 or backlog_count > 0:
        promotion_tier = "monitor"
        reason = "evidence_gap_monitor"
    else:
        promotion_tier = "ignore"
        reason = "evidence_gap_ignore"

    promoter_id = _sha1_payload(
        {
            "gap_key_hint": hint,
            "recurring_count": recurring_count,
            "backlog_count": backlog_count,
            "threshold": threshold_value,
            "signal_notes": [
                str(_first_nonempty(row.get("name"), row.get("gap_key"), row.get("reason"), row.get("artifact_type"), "")) for row in signal_rows
            ],
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "promoter_id": promoter_id,
        "gap_key_hint": hint or "evidence",
        "recurring_count": recurring_count,
        "backlog_count": backlog_count,
        "threshold": threshold_value,
        "promotion_tier": promotion_tier,
        "reason": reason,
        "should_promote": should_promote,
        "should_monitor": promotion_tier == "monitor",
        "should_ignore": promotion_tier == "ignore",
        "signal_count": len(signal_rows),
        "signal_notes": [
            str(_first_nonempty(row.get("name"), row.get("gap_key"), row.get("reason"), row.get("artifact_type"), "")) for row in signal_rows
        ],
        "suite_failing_count": len(failing_runs),
        "replay_blocked_count": len(blocked_rows),
    }


def build_geometry_gap_promoter(
    *,
    geometry_gap_events: Sequence[Mapping[str, Any] | str] | None = None,
    region_regression_matrix: Mapping[str, Any] | None = None,
    relative_anchor_map: Mapping[str, Any] | None = None,
    root_cause_unit: Mapping[str, Any] | None = None,
    gap_key_hint: str = "",
    threshold: int = 2,
) -> Dict[str, Any]:
    matrix = dict(region_regression_matrix or {})
    anchor = dict(relative_anchor_map or {})
    unit = dict(root_cause_unit or {})
    hint = str(gap_key_hint or "").strip().lower()

    def _collect_rows(rows: Sequence[Mapping[str, Any] | str] | None, default_kind: str) -> List[Dict[str, Any]]:
        collected: List[Dict[str, Any]] = []
        for row in rows or []:
            if isinstance(row, Mapping):
                collected.append(dict(row))
            else:
                text = str(row or "").strip()
                if text:
                    collected.append({"name": text, "kind": default_kind, "reason": text})
        return collected

    gap_rows = _collect_rows(geometry_gap_events, "geometry")
    region_rows = _collect_rows(matrix.get("uncovered_regions") or [], "region")

    def _row_key(row: Mapping[str, Any]) -> str:
        return str(
            _first_nonempty(
                row.get("gap_key"),
                row.get("region_key"),
                row.get("bbox_key"),
                row.get("name"),
                row.get("reason"),
                hint,
                unit.get("family_key"),
                "",
            )
        ).strip().lower()

    recurring_rows: List[Dict[str, Any]] = []
    for row in gap_rows:
        key = _row_key(row)
        raw_reason = str(_first_nonempty(row.get("reason"), row.get("status"), row.get("message"), "")).strip().lower()
        has_coordinate_drift = bool(row.get("coordinate_drift") or row.get("bbox_shift") or row.get("region_shift") or row.get("anchor_mismatch"))
        lowered = " ".join(
            filter(
                None,
                [
                    str(_first_nonempty(row.get("message"), row.get("status_text"), row.get("description"), row.get("name"), "")).strip(),
                    raw_reason,
                ],
            )
        ).lower()
        drift_signal = has_coordinate_drift or any(
            token in lowered
            for token in (
                "coordinate",
                "bbox",
                "region",
                "shift",
                "drift",
                "mismatch",
                "misaligned",
                "offset",
                "overlap",
                "wrong box",
            )
        )
        if drift_signal and (not hint or key == hint):
            recurring_rows.append(row)

    threshold_value = max(1, int(threshold or 1))
    recurring_count = len(recurring_rows)
    backlog_count = len(region_rows)
    signal_rows = recurring_rows + region_rows
    should_promote = bool(recurring_count >= threshold_value or backlog_count >= threshold_value)
    if should_promote:
        promotion_tier = "promote"
        reason = "geometry_gap_promote"
    elif recurring_count > 0 or backlog_count > 0:
        promotion_tier = "monitor"
        reason = "geometry_gap_monitor"
    else:
        promotion_tier = "ignore"
        reason = "geometry_gap_ignore"

    promoter_id = _sha1_payload(
        {
            "gap_key_hint": hint,
            "recurring_count": recurring_count,
            "backlog_count": backlog_count,
            "threshold": threshold_value,
            "signal_notes": [
                str(_first_nonempty(row.get("name"), row.get("region_key"), row.get("gap_key"), row.get("reason"), "")) for row in signal_rows
            ],
            "anchor_reason": str(_first_nonempty(anchor.get("reason"), anchor.get("identity_mode"), anchor.get("relative_anchor_map_id"), "")).strip().lower(),
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "promoter_id": promoter_id,
        "gap_key_hint": hint or "geometry",
        "recurring_count": recurring_count,
        "backlog_count": backlog_count,
        "threshold": threshold_value,
        "promotion_tier": promotion_tier,
        "reason": reason,
        "should_promote": should_promote,
        "should_monitor": promotion_tier == "monitor",
        "should_ignore": promotion_tier == "ignore",
        "signal_count": len(signal_rows),
        "signal_notes": [
            str(_first_nonempty(row.get("name"), row.get("region_key"), row.get("gap_key"), row.get("reason"), "")) for row in signal_rows
        ],
        "region_count": len(region_rows),
        "anchor_confidence": float(anchor.get("confidence") or 0.0),
        "is_anchor_stable": bool(anchor.get("is_stable")),
    }


def build_domain_gap_promoter(
    *,
    domain_gap_events: Sequence[Mapping[str, Any] | str] | None = None,
    domain_regression_suite: Mapping[str, Any] | None = None,
    domain_replay_bundle: Mapping[str, Any] | None = None,
    domain_key_hint: str = "",
    threshold: int = 2,
) -> Dict[str, Any]:
    suite = dict(domain_regression_suite or {})
    replay = dict(domain_replay_bundle or {})
    hint = str(domain_key_hint or "").strip().lower()

    def _collect_rows(rows: Sequence[Mapping[str, Any] | str] | None, default_kind: str) -> List[Dict[str, Any]]:
        collected: List[Dict[str, Any]] = []
        for row in rows or []:
            if isinstance(row, Mapping):
                collected.append(dict(row))
            else:
                text = str(row or "").strip()
                if text:
                    collected.append({"name": text, "kind": default_kind, "reason": text})
        return collected

    gap_rows = _collect_rows(domain_gap_events, "domain")
    failing_runs = _collect_rows(suite.get("failing_runs") or [], "regression")
    blocked_rows = _collect_rows(replay.get("blocked_rows") or [], "replay")
    transition_rows = _collect_rows(replay.get("expected_transitions") or replay.get("actual_transitions") or [], "transition")

    def _row_key(row: Mapping[str, Any]) -> str:
        return str(
            _first_nonempty(
                row.get("domain_key"),
                row.get("family_key"),
                row.get("gap_key"),
                row.get("transition_key"),
                row.get("name"),
                row.get("reason"),
                hint,
                "",
            )
        ).strip().lower()

    recurring_rows: List[Dict[str, Any]] = []
    for row in gap_rows:
        key = _row_key(row)
        lowered = " ".join(
            filter(
                None,
                [
                    str(_first_nonempty(row.get("message"), row.get("status_text"), row.get("description"), row.get("name"), "")).strip(),
                    str(_first_nonempty(row.get("reason"), row.get("status"), "")).strip(),
                ],
            )
        ).lower()
        domain_signal = bool(
            row.get("domain_mismatch")
            or row.get("semantic_drift")
            or row.get("branch_intent_mismatch")
            or row.get("respondent_state_mismatch")
            or row.get("business_logic_break")
            or row.get("is_domain_failure")
        ) or any(
            token in lowered
            for token in (
                "domain",
                "business",
                "semantic",
                "intent",
                "branch",
                "respondent",
                "state mismatch",
                "logic drift",
                "mismatch",
            )
        )
        if domain_signal and (not hint or key == hint):
            recurring_rows.append(row)

    threshold_value = max(1, int(threshold or 1))
    recurring_count = len(recurring_rows)
    backlog_count = len(failing_runs) + len(blocked_rows) + len(transition_rows)
    signal_rows = recurring_rows + failing_runs + blocked_rows + transition_rows
    should_promote = bool(recurring_count >= threshold_value or backlog_count >= threshold_value)
    if should_promote:
        promotion_tier = "promote"
        reason = "domain_gap_promote"
    elif recurring_count > 0 or backlog_count > 0:
        promotion_tier = "monitor"
        reason = "domain_gap_monitor"
    else:
        promotion_tier = "ignore"
        reason = "domain_gap_ignore"

    promoter_id = _sha1_payload(
        {
            "domain_key_hint": hint,
            "recurring_count": recurring_count,
            "backlog_count": backlog_count,
            "threshold": threshold_value,
            "signal_notes": [
                str(
                    _first_nonempty(
                        row.get("name"),
                        row.get("domain_key"),
                        row.get("gap_key"),
                        row.get("transition_key"),
                        row.get("reason"),
                        "",
                    )
                )
                for row in signal_rows
            ],
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "promoter_id": promoter_id,
        "domain_key_hint": hint or "domain",
        "recurring_count": recurring_count,
        "backlog_count": backlog_count,
        "threshold": threshold_value,
        "promotion_tier": promotion_tier,
        "reason": reason,
        "should_promote": should_promote,
        "should_monitor": promotion_tier == "monitor",
        "should_ignore": promotion_tier == "ignore",
        "signal_count": len(signal_rows),
        "signal_notes": [
            str(
                _first_nonempty(
                    row.get("name"),
                    row.get("domain_key"),
                    row.get("gap_key"),
                    row.get("transition_key"),
                    row.get("reason"),
                    "",
                )
            )
            for row in signal_rows
        ],
        "suite_failing_count": len(failing_runs),
        "replay_blocked_count": len(blocked_rows),
        "transition_count": len(transition_rows),
    }


def build_domain_regression_suite(
    *,
    regression_cases: Sequence[Mapping[str, Any] | str] | None = None,
    respondent_state_model: Mapping[str, Any] | None = None,
    branch_intent_model: Mapping[str, Any] | None = None,
    domain_key_hint: str = "",
    threshold: int = 2,
) -> Dict[str, Any]:
    suite = dict(respondent_state_model or {})
    branch = dict(branch_intent_model or {})
    hint = str(domain_key_hint or "").strip().lower()
    threshold_value = max(1, int(threshold or 1))

    rows: List[Dict[str, Any]] = []
    passed = 0
    failed = 0
    respondent_state_drifts = 0
    branch_intent_drifts = 0

    for index, case in enumerate(regression_cases or [], start=1):
        if isinstance(case, Mapping):
            row = dict(case)
        else:
            text = str(case or "").strip()
            row = {"name": text, "reason": text} if text else {}
        if not row:
            continue

        case_id = str(_first_nonempty(row.get("case_id"), row.get("profile_id"), row.get("name"), f"domain_case_{index}")).strip()
        profile_id = str(_first_nonempty(row.get("profile_id"), case_id)).strip()
        expected_respondent_state = row.get("expected_respondent_state")
        actual_respondent_state = row.get("actual_respondent_state")
        expected_branch_intent = row.get("expected_branch_intent")
        actual_branch_intent = row.get("actual_branch_intent")

        respondent_state_mismatch = bool(
            row.get("respondent_state_mismatch")
            or (
                expected_respondent_state is not None
                and actual_respondent_state is not None
                and expected_respondent_state != actual_respondent_state
            )
        )
        branch_intent_mismatch = bool(
            row.get("branch_intent_mismatch")
            or (
                expected_branch_intent is not None
                and actual_branch_intent is not None
                and expected_branch_intent != actual_branch_intent
            )
        )
        drift = respondent_state_mismatch or branch_intent_mismatch
        if drift:
            failed += 1
        else:
            passed += 1
        respondent_state_drifts += int(respondent_state_mismatch)
        branch_intent_drifts += int(branch_intent_mismatch)

        lowered = " ".join(
            filter(
                None,
                [
                    str(_first_nonempty(row.get("message"), row.get("status_text"), row.get("description"), row.get("name"), "")).strip(),
                    str(_first_nonempty(row.get("reason"), row.get("status"), "")).strip(),
                ],
            )
        ).lower()
        if not row.get("domain_key") and hint and hint not in lowered:
            domain_key = hint
        else:
            domain_key = str(_first_nonempty(row.get("domain_key"), row.get("branch_key"), row.get("name"), hint, "")).strip().lower()

        rows.append(
            {
                "index": index,
                "case_id": case_id,
                "profile_id": profile_id,
                "domain_key": domain_key,
                "respondent_state_mismatch": respondent_state_mismatch,
                "branch_intent_mismatch": branch_intent_mismatch,
                "is_drift": drift,
                "reason": "regression_passed" if not drift else "domain_regression_detected",
                "expected_respondent_state": expected_respondent_state,
                "actual_respondent_state": actual_respondent_state,
                "expected_branch_intent": expected_branch_intent,
                "actual_branch_intent": actual_branch_intent,
            }
        )

    total = len(rows)
    if total == 0:
        reason = "empty_regression_suite"
    elif failed == 0 and total >= threshold_value:
        reason = "regression_suite_passed"
    elif failed == 0:
        reason = "regression_suite_monitor"
    else:
        reason = "regression_suite_failed"

    suite_id = _sha1_payload(
        {
            "domain_key_hint": hint,
            "threshold": threshold_value,
            "passed_cases": passed,
            "failed_cases": failed,
            "rows": [
                {
                    "case_id": row["case_id"],
                    "domain_key": row["domain_key"],
                    "respondent_state_mismatch": row["respondent_state_mismatch"],
                    "branch_intent_mismatch": row["branch_intent_mismatch"],
                }
                for row in rows
            ],
            "suite": sorted(str(key) for key in suite.keys()),
            "branch": sorted(str(key) for key in branch.keys()),
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "suite_id": suite_id,
        "domain_key_hint": hint or "domain",
        "suite_size": total,
        "passed_cases": passed,
        "failed_cases": failed,
        "respondent_state_drift_cases": respondent_state_drifts,
        "branch_intent_drift_cases": branch_intent_drifts,
        "threshold": threshold_value,
        "reason": reason,
        "is_passing": failed == 0 and total >= threshold_value,
        "should_warn": reason == "regression_suite_monitor",
        "should_block": reason == "regression_suite_failed",
        "rows": rows,
    }


def build_policy_gap_promoter(
    *,
    policy_gap_events: Sequence[Mapping[str, Any] | str] | None = None,
    policy_trace_contract: Mapping[str, Any] | None = None,
    decision_stability_suite: Mapping[str, Any] | None = None,
    counterfactual_evidence_suite: Mapping[str, Any] | None = None,
    policy_key_hint: str = "",
    threshold: int = 2,
) -> Dict[str, Any]:
    trace = dict(policy_trace_contract or {})
    stability = dict(decision_stability_suite or {})
    counterfactual = dict(counterfactual_evidence_suite or {})
    hint = str(policy_key_hint or "").strip().lower()

    def _collect_rows(rows: Sequence[Mapping[str, Any] | str] | None, default_kind: str) -> List[Dict[str, Any]]:
        collected: List[Dict[str, Any]] = []
        for row in rows or []:
            if isinstance(row, Mapping):
                collected.append(dict(row))
            else:
                text = str(row or "").strip()
                if text:
                    collected.append({"name": text, "kind": default_kind, "reason": text})
        return collected

    gap_rows = _collect_rows(policy_gap_events, "policy")
    trace_steps = [dict(row) for row in (trace.get("trace_steps") or []) if isinstance(row, Mapping)]
    rejected_candidates = [str(item or "").strip().lower() for item in (trace.get("rejected_candidates") or []) if str(item or "").strip()]
    stability_rows = [dict(row) for row in (stability.get("rows") or []) if isinstance(row, Mapping)]
    counter_rows = [dict(row) for row in (counterfactual.get("rows") or []) if isinstance(row, Mapping)]

    def _row_key(row: Mapping[str, Any]) -> str:
        return str(
            _first_nonempty(
                row.get("policy_key"),
                row.get("policy"),
                row.get("gap_key"),
                row.get("name"),
                row.get("reason"),
                hint,
                "",
            )
        ).strip().lower()

    recurring_rows: List[Dict[str, Any]] = []
    for row in gap_rows:
        key = _row_key(row)
        lowered = " ".join(
            filter(
                None,
                [
                    str(_first_nonempty(row.get("message"), row.get("status_text"), row.get("description"), row.get("name"), "")).strip(),
                    str(_first_nonempty(row.get("reason"), row.get("status"), "")).strip(),
                ],
            )
        ).lower()
        policy_signal = bool(
            row.get("policy_conflict")
            or row.get("arbitration_needed")
            or row.get("policy_ambiguity")
            or row.get("rule_conflict")
            or row.get("is_policy_failure")
        ) or any(
            token in lowered
            for token in (
                "policy",
                "conflict",
                "arbit",
                "ambigu",
                "rule",
                "inconsistent",
                "contradiction",
                "decision split",
            )
        )
        if policy_signal and (not hint or key == hint):
            recurring_rows.append(row)

    threshold_value = max(1, int(threshold or 1))
    recurring_count = len(recurring_rows)
    trace_override_count = int(trace.get("override_count") or 0)
    trace_vote_count = int(trace.get("vote_count") or 0)
    stability_count = len([row for row in stability_rows if not bool(row.get("stable", True))])
    counter_change_count = int(counterfactual.get("changed_count") or 0)
    backlog_count = trace_override_count + len(rejected_candidates) + stability_count + counter_change_count
    signal_rows = recurring_rows + trace_steps + stability_rows + counter_rows
    should_promote = bool(recurring_count >= threshold_value or backlog_count >= threshold_value)
    if should_promote:
        promotion_tier = "promote"
        reason = "policy_gap_promote"
    elif recurring_count > 0 or backlog_count > 0:
        promotion_tier = "monitor"
        reason = "policy_gap_monitor"
    else:
        promotion_tier = "ignore"
        reason = "policy_gap_ignore"

    promoter_id = _sha1_payload(
        {
            "policy_key_hint": hint,
            "recurring_count": recurring_count,
            "backlog_count": backlog_count,
            "threshold": threshold_value,
            "signal_notes": [
                str(_first_nonempty(row.get("name"), row.get("policy_key"), row.get("gap_key"), row.get("reason"), "")) for row in signal_rows
            ],
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "promoter_id": promoter_id,
        "policy_key_hint": hint or "policy",
        "recurring_count": recurring_count,
        "backlog_count": backlog_count,
        "threshold": threshold_value,
        "promotion_tier": promotion_tier,
        "reason": reason,
        "should_promote": should_promote,
        "should_monitor": promotion_tier == "monitor",
        "should_ignore": promotion_tier == "ignore",
        "signal_count": len(signal_rows),
        "signal_notes": [
            str(_first_nonempty(row.get("name"), row.get("policy_key"), row.get("gap_key"), row.get("reason"), "")) for row in signal_rows
        ],
        "trace_vote_count": trace_vote_count,
        "trace_override_count": trace_override_count,
        "stability_issue_count": stability_count,
        "counterfactual_change_count": counter_change_count,
    }


def build_experiment_gap_promoter(
    *,
    experiment_gap_events: Sequence[Mapping[str, Any] | str] | None = None,
    adoption_gate_contract: Mapping[str, Any] | None = None,
    experiment_abort_rule: Mapping[str, Any] | None = None,
    experiment_explanation_packet: Mapping[str, Any] | None = None,
    experiment_key_hint: str = "",
    threshold: int = 2,
) -> Dict[str, Any]:
    gate = dict(adoption_gate_contract or {})
    abort_rule = dict(experiment_abort_rule or {})
    explanation = dict(experiment_explanation_packet or {})
    hint = str(experiment_key_hint or "").strip().lower()

    def _collect_rows(rows: Sequence[Mapping[str, Any] | str] | None, default_kind: str) -> List[Dict[str, Any]]:
        collected: List[Dict[str, Any]] = []
        for row in rows or []:
            if isinstance(row, Mapping):
                collected.append(dict(row))
            else:
                text = str(row or "").strip()
                if text:
                    collected.append({"name": text, "kind": default_kind, "reason": text})
        return collected

    gap_rows = _collect_rows(experiment_gap_events, "experiment")
    gate_rows = _collect_rows(gate.get("rows") or [], "gate")
    explanation_rows = _collect_rows(explanation.get("rows") or [], "explanation")
    abort_flags = [str(item or "").strip().lower() for item in (abort_rule.get("reasons") or []) if str(item or "").strip()]

    def _row_key(row: Mapping[str, Any]) -> str:
        return str(
            _first_nonempty(
                row.get("experiment_key"),
                row.get("experiment"),
                row.get("gap_key"),
                row.get("name"),
                row.get("reason"),
                hint,
                "",
            )
        ).strip().lower()

    recurring_rows: List[Dict[str, Any]] = []
    for row in gap_rows:
        key = _row_key(row)
        lowered = " ".join(
            filter(
                None,
                [
                    str(_first_nonempty(row.get("message"), row.get("status_text"), row.get("description"), row.get("name"), "")).strip(),
                    str(_first_nonempty(row.get("reason"), row.get("status"), "")).strip(),
                ],
            )
        ).lower()
        experiment_signal = bool(
            row.get("tuning_hotspot")
            or row.get("experiment_regression")
            or row.get("overfit")
            or row.get("is_experiment_failure")
            or row.get("is_chronic")
        ) or any(
            token in lowered
            for token in (
                "experiment",
                "tuning",
                "hotspot",
                "overfit",
                "drift",
                "regression",
                "adoption",
                "abort",
                "side effect",
            )
        )
        if experiment_signal and (not hint or key == hint):
            recurring_rows.append(row)

    threshold_value = max(1, int(threshold or 1))
    recurring_count = len(recurring_rows)
    gate_failure_count = len([row for row in gate_rows if not bool(row.get("passed", row.get("is_passing", False)))])
    explanation_count = len([row for row in explanation_rows if bool(row.get("changed", row.get("is_different", False)))])
    abort_count = len(abort_flags)
    backlog_count = gate_failure_count + explanation_count + abort_count
    signal_rows = recurring_rows + gate_rows + explanation_rows
    should_promote = bool(recurring_count >= threshold_value or backlog_count >= threshold_value)
    if should_promote:
        promotion_tier = "promote"
        reason = "experiment_gap_promote"
    elif recurring_count > 0 or backlog_count > 0:
        promotion_tier = "monitor"
        reason = "experiment_gap_monitor"
    else:
        promotion_tier = "ignore"
        reason = "experiment_gap_ignore"

    promoter_id = _sha1_payload(
        {
            "experiment_key_hint": hint,
            "recurring_count": recurring_count,
            "backlog_count": backlog_count,
            "threshold": threshold_value,
            "signal_notes": [
                str(_first_nonempty(row.get("name"), row.get("experiment_key"), row.get("gap_key"), row.get("reason"), "")) for row in signal_rows
            ],
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "promoter_id": promoter_id,
        "experiment_key_hint": hint or "experiment",
        "recurring_count": recurring_count,
        "backlog_count": backlog_count,
        "threshold": threshold_value,
        "promotion_tier": promotion_tier,
        "reason": reason,
        "should_promote": should_promote,
        "should_monitor": promotion_tier == "monitor",
        "should_ignore": promotion_tier == "ignore",
        "signal_count": len(signal_rows),
        "signal_notes": [
            str(_first_nonempty(row.get("name"), row.get("experiment_key"), row.get("gap_key"), row.get("reason"), "")) for row in signal_rows
        ],
        "gate_failure_count": gate_failure_count,
        "explanation_change_count": explanation_count,
        "abort_reason_count": abort_count,
    }


def build_experiment_identity_contract(
    *,
    experiment_rows: Sequence[Mapping[str, Any] | str] | None = None,
    experiment_key: str = "",
    population_key: str = "",
    objective: str = "",
    scope_hint: str = "",
) -> Dict[str, Any]:
    hint = str(experiment_key or "").strip().lower()
    population = str(population_key or "").strip().lower()
    objective_text = str(objective or "").strip()
    scope = str(scope_hint or "").strip().lower()

    def _collect_rows(rows: Sequence[Mapping[str, Any] | str] | None) -> List[Dict[str, Any]]:
        collected: List[Dict[str, Any]] = []
        for row in rows or []:
            if isinstance(row, Mapping):
                collected.append(dict(row))
            else:
                text = str(row or "").strip()
                if text:
                    collected.append({"name": text, "reason": text})
        return collected

    rows = _collect_rows(experiment_rows)

    def _row_value(row: Mapping[str, Any], *keys: str) -> str:
        return str(_first_nonempty(*(row.get(key) for key in keys), "")).strip()

    if not hint:
        for row in rows:
            hint = _row_value(row, "experiment_key", "experiment", "name", "label", "reason").strip().lower()
            if hint:
                break
    if not population:
        for row in rows:
            population = _row_value(row, "population_key", "population", "cohort", "group", "holdout", "canary", "name", "reason").strip().lower()
            if population:
                break
    if not objective_text:
        for row in rows:
            objective_text = _row_value(row, "objective", "goal", "target", "metric_goal", "reason")
            if objective_text:
                break
    if not scope:
        for row in rows:
            scope = _row_value(row, "scope_hint", "scope", "stage", "mode").strip().lower()
            if scope:
                break

    if not hint:
        reason = "missing_experiment_key"
    elif not population:
        reason = "missing_population_key"
    elif not objective_text:
        reason = "missing_objective"
    else:
        reason = "experiment_identity_complete"

    experiment_identity_id = _sha1_payload(
        {
            "experiment_key": hint,
            "population_key": population,
            "objective": objective_text,
            "scope_hint": scope,
            "rows": rows,
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "experiment_identity_id": experiment_identity_id,
        "experiment_key": hint,
        "population_key": population,
        "objective": objective_text,
        "scope_hint": scope,
        "rows": rows,
        "row_count": len(rows),
        "is_complete": reason == "experiment_identity_complete",
        "should_warn": reason != "experiment_identity_complete",
        "should_block": reason != "experiment_identity_complete",
        "reason": reason,
    }


def build_isolated_change_manifest(
    *,
    change_name: str = "",
    change_summary: str = "",
    changed_parameters: Sequence[Any] | None = None,
    changed_models: Sequence[Any] | None = None,
    changed_policies: Sequence[Any] | None = None,
    control_group: Sequence[Any] | None = None,
    experiment_scope_hint: str = "",
) -> Dict[str, Any]:
    parameters = [str(item).strip() for item in (changed_parameters or []) if str(item).strip()]
    models = [str(item).strip() for item in (changed_models or []) if str(item).strip()]
    policies = [str(item).strip() for item in (changed_policies or []) if str(item).strip()]
    controls = [str(item).strip() for item in (control_group or []) if str(item).strip()]
    scope_hint = str(experiment_scope_hint or "").strip().lower()
    manifest = {
        "change_name": str(change_name or "").strip(),
        "change_summary": str(change_summary or "").strip(),
        "changed_parameters": parameters,
        "changed_models": models,
        "changed_policies": policies,
        "control_group": controls,
        "experiment_scope_hint": scope_hint,
    }
    missing = [
        name
        for name in ["change_name", "change_summary", "changed_parameters", "changed_models", "changed_policies"]
        if not manifest.get(name)
    ]
    overlap_items = sorted(set(parameters) & set(models) | set(parameters) & set(policies) | set(models) & set(policies))
    isolated_change_manifest_id = _sha1_payload(manifest)[:16]
    if missing:
        reason = "isolated_change_manifest_incomplete"
    elif overlap_items:
        reason = "isolated_change_manifest_overlapping_changes"
    else:
        reason = "isolated_change_manifest_complete"
    return {
        "schema_version": SCHEMA_VERSION,
        "isolated_change_manifest_id": isolated_change_manifest_id,
        "manifest": manifest,
        "missing_fields": missing,
        "overlap_items": overlap_items,
        "is_complete": not missing,
        "is_isolated": not missing and not overlap_items,
        "should_warn": bool(overlap_items),
        "should_block": bool(missing or overlap_items),
        "reason": reason,
    }


def build_experiment_trace_stamp(
    *,
    experiment_identity_contract: Mapping[str, Any] | None = None,
    session_manifest: Mapping[str, Any] | None = None,
    artifact_ids: Sequence[Any] | None = None,
    report_ids: Sequence[Any] | None = None,
    benchmark_ids: Sequence[Any] | None = None,
    trace_note: str = "",
) -> Dict[str, Any]:
    identity = dict(experiment_identity_contract or {})
    session = dict(session_manifest or {})
    artifact_list = [str(item).strip() for item in (artifact_ids or []) if str(item).strip()]
    report_list = [str(item).strip() for item in (report_ids or []) if str(item).strip()]
    benchmark_list = [str(item).strip() for item in (benchmark_ids or []) if str(item).strip()]
    note = str(trace_note or "").strip()
    experiment_identity_id = str(_first_nonempty(identity.get("experiment_identity_id"), identity.get("experiment_id"), "")).strip()
    session_id = str(_first_nonempty(session.get("session_id"), session.get("trace_id"), session.get("run_id"), "")).strip()
    attached_kinds = [kind for kind, items in (
        ("artifact", artifact_list),
        ("report", report_list),
        ("benchmark", benchmark_list),
    ) if items]
    missing = []
    if not experiment_identity_id:
        missing.append("experiment_identity_id")
    if not session_id:
        missing.append("session_id")
    if not artifact_list:
        missing.append("artifact_ids")
    if not report_list:
        missing.append("report_ids")
    if not benchmark_list:
        missing.append("benchmark_ids")
    if missing:
        reason = "experiment_trace_stamp_incomplete"
    else:
        reason = "experiment_trace_stamp_attached"
    trace_stamp_id = _sha1_payload(
        {
            "experiment_identity_id": experiment_identity_id,
            "session_id": session_id,
            "artifact_ids": artifact_list,
            "report_ids": report_list,
            "benchmark_ids": benchmark_list,
            "trace_note": note,
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "trace_stamp_id": trace_stamp_id,
        "experiment_identity_id": experiment_identity_id,
        "session_id": session_id,
        "artifact_ids": artifact_list,
        "report_ids": report_list,
        "benchmark_ids": benchmark_list,
        "attached_kinds": attached_kinds,
        "missing_links": missing,
        "trace_note": note,
        "is_attached": reason == "experiment_trace_stamp_attached",
        "should_warn": reason != "experiment_trace_stamp_attached",
        "should_block": reason != "experiment_trace_stamp_attached",
        "reason": reason,
    }


def build_experiment_scope_hint(
    *,
    scope_hint: str = "",
    experiment_identity_contract: Mapping[str, Any] | None = None,
    change_summary: str = "",
) -> Dict[str, Any]:
    identity = dict(experiment_identity_contract or {})
    hint = str(scope_hint or "").strip().lower()
    identity_scope = str(_first_nonempty(identity.get("scope_hint"), identity.get("scope"), identity.get("experiment_scope"), "")).strip().lower()
    summary = str(change_summary or "").strip().lower()
    combined = " ".join(item for item in [hint, identity_scope, summary] if item)
    scope_mode = "unknown"
    if any(token in combined for token in ("production", "prod", "mainline", "live")):
        scope_mode = "production"
    elif any(token in combined for token in ("canary", "shadow", "holdout")):
        scope_mode = "canary"
    elif any(token in combined for token in ("lab", "laboratory", "sandbox", "offline")):
        scope_mode = "laboratory"
    elif hint or identity_scope:
        scope_mode = "general"

    touches_production = scope_mode == "production"
    touches_canary = scope_mode == "canary"
    touches_laboratory = scope_mode == "laboratory"
    if scope_mode == "unknown":
        reason = "experiment_scope_hint_unknown"
    elif touches_production:
        reason = "experiment_scope_hint_production"
    elif touches_canary:
        reason = "experiment_scope_hint_canary"
    elif touches_laboratory:
        reason = "experiment_scope_hint_laboratory"
    else:
        reason = "experiment_scope_hint_general"
    scope_id = _sha1_payload(
        {
            "scope_hint": hint,
            "identity_scope": identity_scope,
            "change_summary": summary,
            "scope_mode": scope_mode,
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "scope_id": scope_id,
        "scope_hint": hint or identity_scope,
        "scope_mode": scope_mode,
        "touches_production": touches_production,
        "touches_canary": touches_canary,
        "touches_laboratory": touches_laboratory,
        "reason": reason,
        "is_known": scope_mode != "unknown",
        "should_warn": scope_mode == "unknown",
        "should_block": False,
    }


def build_parameter_registry_contract(
    *,
    parameter_rows: Sequence[Mapping[str, Any] | str] | None = None,
    registry_name: str = "",
    registry_scope: str = "",
) -> Dict[str, Any]:
    name = str(registry_name or "").strip().lower() or "parameter_registry"
    scope = str(registry_scope or "").strip().lower()

    rows: List[Dict[str, Any]] = []
    missing_fields: List[str] = []
    out_of_range_parameters: List[str] = []
    active_parameter_names: List[str] = []
    for idx, row in enumerate(parameter_rows or [], start=1):
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip()
            payload = {"name": text} if text else {}
        param_name = str(_first_nonempty(payload.get("parameter_name"), payload.get("name"), payload.get("key"), f"parameter_{idx}")).strip()
        meaning = str(_first_nonempty(payload.get("meaning"), payload.get("description"), payload.get("reason"), "")).strip()
        min_value = payload.get("min_value", payload.get("min"))
        max_value = payload.get("max_value", payload.get("max"))
        current_value = payload.get("current_value", payload.get("value"))
        is_active = bool(payload.get("active", payload.get("is_active", True)))
        row_missing: List[str] = []
        if not param_name:
            row_missing.append("parameter_name")
        if not meaning:
            row_missing.append("meaning")
        if min_value in ("", None):
            row_missing.append("min_value")
        if max_value in ("", None):
            row_missing.append("max_value")
        if current_value in ("", None):
            row_missing.append("current_value")
        if row_missing:
            missing_fields.extend(row_missing)
        is_valid_range = False
        try:
            if min_value not in ("", None) and max_value not in ("", None) and current_value not in ("", None):
                min_f = float(min_value)
                max_f = float(max_value)
                current_f = float(current_value)
                is_valid_range = min_f <= current_f <= max_f
        except (TypeError, ValueError):
            is_valid_range = False
        if is_active:
            active_parameter_names.append(param_name)
        if not is_valid_range:
            out_of_range_parameters.append(param_name)
        rows.append(
            {
                "parameter_name": param_name,
                "meaning": meaning,
                "min_value": min_value,
                "max_value": max_value,
                "current_value": current_value,
                "active": is_active,
                "scope": str(_first_nonempty(payload.get("scope"), scope, "")).strip().lower(),
            }
        )

    registry_id = _sha1_payload(
        {
            "registry_name": name,
            "registry_scope": scope,
            "rows": rows,
        }
    )[:16]
    if not rows:
        reason = "empty_parameter_registry"
    elif missing_fields:
        reason = "parameter_registry_incomplete"
    elif out_of_range_parameters:
        reason = "parameter_registry_out_of_range"
    else:
        reason = "parameter_registry_complete"
    return {
        "schema_version": SCHEMA_VERSION,
        "registry_id": registry_id,
        "registry_name": name,
        "registry_scope": scope,
        "rows": rows,
        "parameter_count": len(rows),
        "active_parameter_names": sorted(dict.fromkeys(active_parameter_names)),
        "active_parameter_count": len(dict.fromkeys(active_parameter_names)),
        "missing_fields": sorted(dict.fromkeys(missing_fields)),
        "out_of_range_parameters": sorted(dict.fromkeys(out_of_range_parameters)),
        "is_complete": reason == "parameter_registry_complete",
        "should_warn": bool(missing_fields or out_of_range_parameters),
        "should_block": bool(missing_fields),
        "reason": reason,
    }


def build_parameter_tradeoff_model(
    *,
    tradeoff_rows: Sequence[Mapping[str, Any] | str] | None = None,
    focus_parameter: str = "",
    objective_metric: str = "",
    registry_contract: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    registry = dict(registry_contract or {})
    focus = str(focus_parameter or "").strip().lower()
    objective = str(objective_metric or "").strip().lower()
    rows: List[Dict[str, Any]] = []
    for idx, row in enumerate(tradeoff_rows or [], start=1):
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip()
            payload = {"parameter_name": text} if text else {}
        parameter_name = str(_first_nonempty(payload.get("parameter_name"), payload.get("name"), payload.get("key"), f"parameter_{idx}")).strip().lower()
        recall_delta = float(_first_nonempty(payload.get("recall_delta"), payload.get("delta_recall"), 0.0) or 0.0)
        precision_delta = float(_first_nonempty(payload.get("precision_delta"), payload.get("delta_precision"), 0.0) or 0.0)
        latency_delta_ms = float(_first_nonempty(payload.get("latency_delta_ms"), payload.get("delta_latency_ms"), payload.get("latency_delta"), 0.0) or 0.0)
        risk_delta = float(_first_nonempty(payload.get("risk_delta"), payload.get("delta_risk"), 0.0) or 0.0)
        rows.append(
            {
                "parameter_name": parameter_name,
                "recall_delta": round(recall_delta, 4),
                "precision_delta": round(precision_delta, 4),
                "latency_delta_ms": round(latency_delta_ms, 4),
                "risk_delta": round(risk_delta, 4),
                "direction": str(_first_nonempty(payload.get("direction"), payload.get("trend"), "")).strip().lower(),
            }
        )

    net_recall_delta = round(sum(row["recall_delta"] for row in rows), 4)
    net_precision_delta = round(sum(row["precision_delta"] for row in rows), 4)
    net_latency_delta_ms = round(sum(row["latency_delta_ms"] for row in rows), 4)
    net_risk_delta = round(sum(row["risk_delta"] for row in rows), 4)
    dominant_axis = "balanced"
    magnitudes = {
        "recall": abs(net_recall_delta),
        "precision": abs(net_precision_delta),
        "latency": abs(net_latency_delta_ms),
        "risk": abs(net_risk_delta),
    }
    if any(magnitudes.values()):
        dominant_axis = max(magnitudes.items(), key=lambda item: item[1])[0]
    if not rows:
        reason = "parameter_tradeoff_model_incomplete"
    elif not focus or not objective:
        reason = "parameter_tradeoff_model_incomplete"
    elif net_risk_delta > 0.25 or net_latency_delta_ms > 150.0:
        reason = "parameter_tradeoff_model_risky"
    else:
        reason = "parameter_tradeoff_model_balanced"
    model_id = _sha1_payload(
        {
            "focus_parameter": focus,
            "objective_metric": objective,
            "rows": rows,
            "registry_id": registry.get("registry_id", ""),
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "model_id": model_id,
        "focus_parameter": focus,
        "objective_metric": objective,
        "rows": rows,
        "net_recall_delta": net_recall_delta,
        "net_precision_delta": net_precision_delta,
        "net_latency_delta_ms": net_latency_delta_ms,
        "net_risk_delta": net_risk_delta,
        "dominant_axis": dominant_axis,
        "registry_id": registry.get("registry_id", ""),
        "is_complete": bool(rows) and bool(focus) and bool(objective),
        "is_balanced": reason == "parameter_tradeoff_model_balanced",
        "should_warn": reason != "parameter_tradeoff_model_balanced",
        "should_block": reason == "parameter_tradeoff_model_risky",
        "reason": reason,
    }


def build_tuning_guard_policy(
    *,
    tuning_rows: Sequence[Mapping[str, Any] | str] | None = None,
    registry_contract: Mapping[str, Any] | None = None,
    max_step_size: float = 0.2,
    max_changes_per_iteration: int = 3,
    max_blast_radius: int = 2,
) -> Dict[str, Any]:
    registry = dict(registry_contract or {})
    active_registry = {str(item).strip().lower() for item in (registry.get("active_parameter_names") or []) if str(item).strip()}
    rows: List[Dict[str, Any]] = []
    changed_parameters: List[str] = []
    unknown_parameters: List[str] = []
    max_observed_step = 0.0
    blast_radius_items: set[str] = set()
    for idx, row in enumerate(tuning_rows or [], start=1):
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip()
            payload = {"parameter_name": text} if text else {}
        parameter_name = str(_first_nonempty(payload.get("parameter_name"), payload.get("name"), payload.get("key"), f"parameter_{idx}")).strip().lower()
        step_size = abs(float(_first_nonempty(payload.get("step_size"), payload.get("delta"), payload.get("change_size"), 0.0) or 0.0))
        target_group = str(_first_nonempty(payload.get("target_group"), payload.get("radius_key"), payload.get("scope"), parameter_name)).strip().lower()
        changed_parameters.append(parameter_name)
        if active_registry and parameter_name and parameter_name not in active_registry:
            unknown_parameters.append(parameter_name)
        max_observed_step = max(max_observed_step, step_size)
        blast_radius_items.add(target_group or parameter_name)
        rows.append(
            {
                "parameter_name": parameter_name,
                "step_size": round(step_size, 4),
                "target_group": target_group or parameter_name,
            }
        )

    change_count = len(rows)
    blast_radius = len(blast_radius_items)
    within_step = max_observed_step <= float(max_step_size or 0.0)
    within_count = change_count <= int(max_changes_per_iteration or 0)
    within_radius = blast_radius <= int(max_blast_radius or 0)
    no_unknowns = not unknown_parameters
    if not rows:
        reason = "tuning_guard_policy_empty"
    elif not no_unknowns:
        reason = "tuning_guard_policy_unknown_parameter"
    elif not within_step or not within_count or not within_radius:
        reason = "tuning_guard_policy_blocked"
    elif max_observed_step >= float(max_step_size or 0.0) * 0.8 or change_count == int(max_changes_per_iteration or 0) or blast_radius == int(max_blast_radius or 0):
        reason = "tuning_guard_policy_warn"
    else:
        reason = "tuning_guard_policy_allowed"
    guard_id = _sha1_payload(
        {
            "rows": rows,
            "max_step_size": float(max_step_size or 0.0),
            "max_changes_per_iteration": int(max_changes_per_iteration or 0),
            "max_blast_radius": int(max_blast_radius or 0),
            "registry_id": registry.get("registry_id", ""),
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "guard_id": guard_id,
        "rows": rows,
        "changed_parameters": changed_parameters,
        "unknown_parameters": sorted(dict.fromkeys(unknown_parameters)),
        "change_count": change_count,
        "blast_radius": blast_radius,
        "max_observed_step_size": round(max_observed_step, 4),
        "max_step_size": round(float(max_step_size or 0.0), 4),
        "max_changes_per_iteration": int(max_changes_per_iteration or 0),
        "max_blast_radius": int(max_blast_radius or 0),
        "is_allowed": reason == "tuning_guard_policy_allowed",
        "should_warn": reason == "tuning_guard_policy_warn",
        "should_block": reason not in {"tuning_guard_policy_allowed", "tuning_guard_policy_warn"},
        "reason": reason,
    }


def build_ignorance_gap_promoter(
    *,
    unknown_state_packet: Mapping[str, Any] | None = None,
    ignorance_regression_suite: Mapping[str, Any] | None = None,
    sparse_evidence_replay_bundle: Mapping[str, Any] | None = None,
    gap_key_hint: str = "",
    threshold: int = 2,
) -> Dict[str, Any]:
    packet = dict(unknown_state_packet or {})
    suite = dict(ignorance_regression_suite or {})
    replay = dict(sparse_evidence_replay_bundle or {})
    hint = str(gap_key_hint or "").strip().lower()

    def _collect_rows(rows: Sequence[Mapping[str, Any] | str] | None, default_kind: str) -> List[Dict[str, Any]]:
        collected: List[Dict[str, Any]] = []
        for row in rows or []:
            if isinstance(row, Mapping):
                collected.append(dict(row))
            else:
                text = str(row or "").strip()
                if text:
                    collected.append({"name": text, "kind": default_kind, "reason": text})
        return collected

    packet_rows = _collect_rows(
        packet.get("rows")
        or packet.get("unknown_items")
        or packet.get("unknowns")
        or packet.get("missing_items")
        or packet.get("gaps")
        or [],
        "unknown",
    )
    failing_rows = _collect_rows(suite.get("failing_runs") or suite.get("rows") or [], "regression")
    replay_rows = _collect_rows(
        replay.get("rows")
        or replay.get("failed_paths")
        or replay.get("fallbacks")
        or replay.get("attempts")
        or [],
        "replay",
    )

    def _row_key(row: Mapping[str, Any]) -> str:
        return str(
            _first_nonempty(
                row.get("gap_key"),
                row.get("unknown_key"),
                row.get("state_key"),
                row.get("name"),
                row.get("reason"),
                hint,
                "",
            )
        ).strip().lower()

    recurring_rows: List[Dict[str, Any]] = []
    for row in packet_rows:
        key = _row_key(row)
        lowered = " ".join(
            filter(
                None,
                [
                    str(_first_nonempty(row.get("message"), row.get("status_text"), row.get("description"), row.get("name"), "")).strip(),
                    str(_first_nonempty(row.get("reason"), row.get("status"), "")).strip(),
                ],
            )
        ).lower()
        ignorance_signal = bool(
            row.get("is_unknown")
            or row.get("is_blank")
            or row.get("is_empty")
            or row.get("is_sparse")
            or row.get("unknown_state")
            or row.get("no_evidence")
        ) or any(
            token in lowered
            for token in (
                "unknown",
                "blank",
                "empty",
                "missing",
                "sparse",
                "no evidence",
                "unclear",
                "ambiguous",
                "cannot tell",
                "unreadable",
            )
        )
        if ignorance_signal and (not hint or key == hint):
            recurring_rows.append(row)

    threshold_value = max(1, int(threshold or 1))
    recurring_count = len(recurring_rows)
    backlog_count = len(failing_rows) + len(replay_rows)
    signal_rows = recurring_rows + failing_rows + replay_rows
    should_promote = bool(recurring_count >= threshold_value or backlog_count >= threshold_value)
    if should_promote:
        promotion_tier = "promote"
        reason = "ignorance_gap_promote"
    elif recurring_count > 0 or backlog_count > 0:
        promotion_tier = "monitor"
        reason = "ignorance_gap_monitor"
    else:
        promotion_tier = "ignore"
        reason = "ignorance_gap_ignore"

    promoter_id = _sha1_payload(
        {
            "gap_key_hint": hint,
            "recurring_count": recurring_count,
            "backlog_count": backlog_count,
            "threshold": threshold_value,
            "signal_notes": [
                str(_first_nonempty(row.get("name"), row.get("gap_key"), row.get("unknown_key"), row.get("reason"), "")) for row in signal_rows
            ],
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "promoter_id": promoter_id,
        "gap_key_hint": hint or "ignorance",
        "recurring_count": recurring_count,
        "backlog_count": backlog_count,
        "threshold": threshold_value,
        "promotion_tier": promotion_tier,
        "reason": reason,
        "should_promote": should_promote,
        "should_monitor": promotion_tier == "monitor",
        "should_ignore": promotion_tier == "ignore",
        "signal_count": len(signal_rows),
        "signal_notes": [
            str(_first_nonempty(row.get("name"), row.get("gap_key"), row.get("unknown_key"), row.get("reason"), "")) for row in signal_rows
        ],
        "packet_unknown_count": len(packet_rows),
        "suite_failing_count": len(failing_rows),
        "replay_gap_count": len(replay_rows),
    }


def build_knowledge_sync_gap_promoter(
    *,
    knowledge_gap_events: Sequence[Mapping[str, Any] | str] | None = None,
    context_consistency_regression_suite: Mapping[str, Any] | None = None,
    context_drift_packet: Mapping[str, Any] | None = None,
    tree_key_hint: str = "",
    threshold: int = 2,
) -> Dict[str, Any]:
    regression = dict(context_consistency_regression_suite or {})
    drift = dict(context_drift_packet or {})
    hint = str(tree_key_hint or "").strip().lower()

    def _collect_rows(rows: Sequence[Mapping[str, Any] | str] | None, default_kind: str) -> List[Dict[str, Any]]:
        collected: List[Dict[str, Any]] = []
        for row in rows or []:
            if isinstance(row, Mapping):
                collected.append(dict(row))
            else:
                text = str(row or "").strip()
                if text:
                    collected.append({"name": text, "kind": default_kind, "reason": text})
        return collected

    gap_rows = _collect_rows(knowledge_gap_events, "knowledge")
    regression_rows = _collect_rows(regression.get("failing_runs") or regression.get("rows") or [], "regression")
    drift_rows = _collect_rows(drift.get("rows") or drift.get("packets") or drift.get("issues") or [], "drift")

    def _row_key(row: Mapping[str, Any]) -> str:
        return str(
            _first_nonempty(
                row.get("tree_key"),
                row.get("context_key"),
                row.get("knowledge_key"),
                row.get("gap_key"),
                row.get("name"),
                row.get("reason"),
                hint,
                "",
            )
        ).strip().lower()

    recurring_rows: List[Dict[str, Any]] = []
    for row in gap_rows:
        key = _row_key(row)
        lowered = " ".join(
            filter(
                None,
                [
                    str(_first_nonempty(row.get("message"), row.get("status_text"), row.get("description"), row.get("name"), "")).strip(),
                    str(_first_nonempty(row.get("reason"), row.get("status"), "")).strip(),
                ],
            )
        ).lower()
        knowledge_signal = bool(
            row.get("context_drift")
            or row.get("knowledge_drift")
            or row.get("snapshot_mismatch")
            or row.get("version_skew")
            or row.get("is_knowledge_gap")
            or row.get("is_context_gap")
        ) or any(
            token in lowered
            for token in (
                "context",
                "drift",
                "snapshot",
                "version",
                "stale",
                "mismatch",
                "sync",
                "desync",
                "out of date",
                "different version",
            )
        )
        if knowledge_signal and (not hint or key == hint):
            recurring_rows.append(row)

    threshold_value = max(1, int(threshold or 1))
    recurring_count = len(recurring_rows)
    backlog_count = len(regression_rows) + len(drift_rows)
    signal_rows = recurring_rows + regression_rows + drift_rows
    should_promote = bool(recurring_count >= threshold_value or backlog_count >= threshold_value)
    if should_promote:
        promotion_tier = "promote"
        reason = "knowledge_sync_gap_promote"
    elif recurring_count > 0 or backlog_count > 0:
        promotion_tier = "monitor"
        reason = "knowledge_sync_gap_monitor"
    else:
        promotion_tier = "ignore"
        reason = "knowledge_sync_gap_ignore"

    promoter_id = _sha1_payload(
        {
            "tree_key_hint": hint,
            "recurring_count": recurring_count,
            "backlog_count": backlog_count,
            "threshold": threshold_value,
            "signal_notes": [
                str(_first_nonempty(row.get("name"), row.get("tree_key"), row.get("context_key"), row.get("gap_key"), row.get("reason"), "")) for row in signal_rows
            ],
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "promoter_id": promoter_id,
        "tree_key_hint": hint or "knowledge",
        "recurring_count": recurring_count,
        "backlog_count": backlog_count,
        "threshold": threshold_value,
        "promotion_tier": promotion_tier,
        "reason": reason,
        "should_promote": should_promote,
        "should_monitor": promotion_tier == "monitor",
        "should_ignore": promotion_tier == "ignore",
        "signal_count": len(signal_rows),
        "signal_notes": [
            str(_first_nonempty(row.get("name"), row.get("tree_key"), row.get("context_key"), row.get("gap_key"), row.get("reason"), "")) for row in signal_rows
        ],
        "regression_count": len(regression_rows),
        "drift_count": len(drift_rows),
    }


def build_context_consistency_regression_suite(
    *,
    regression_cases: Sequence[Mapping[str, Any] | str] | None = None,
    snapshot_identity: Mapping[str, Any] | None = None,
    leaf_hint: str = "",
    threshold: int = 2,
) -> Dict[str, Any]:
    hint = str(leaf_hint or "").strip().lower()
    snapshot = dict(snapshot_identity or {})

    def _collect_rows(rows: Sequence[Mapping[str, Any] | str] | None) -> List[Dict[str, Any]]:
        collected: List[Dict[str, Any]] = []
        for row in rows or []:
            if isinstance(row, Mapping):
                collected.append(dict(row))
            else:
                text = str(row or "").strip()
                if text:
                    collected.append({"name": text, "reason": text})
        return collected

    cases = _collect_rows(regression_cases)

    def _row_key(row: Mapping[str, Any]) -> Tuple[str, str]:
        leaf_key = str(
            _first_nonempty(
                row.get("leaf_key"),
                row.get("tree_key"),
                row.get("context_key"),
                row.get("knowledge_key"),
                row.get("name"),
                hint,
                "",
            )
        ).strip().lower()
        snapshot_key = str(
            _first_nonempty(
                row.get("snapshot_key"),
                row.get("knowledge_snapshot_id"),
                row.get("snapshot_id"),
                row.get("tree_version"),
                snapshot.get("snapshot_key"),
                snapshot.get("knowledge_snapshot_id"),
                snapshot.get("snapshot_id"),
                "",
            )
        ).strip().lower()
        return leaf_key, snapshot_key

    grouped: Dict[Tuple[str, str], List[Dict[str, Any]]] = {}
    rows: List[Dict[str, Any]] = []
    for index, case in enumerate(cases, start=1):
        leaf_key, snapshot_key = _row_key(case)
        result = str(_first_nonempty(case.get("result"), case.get("outcome"), case.get("status"), case.get("reason"), "")).strip().lower()
        expected = str(_first_nonempty(case.get("expected_result"), case.get("expected_outcome"), case.get("expected_status"), "")).strip().lower()
        grouped.setdefault((leaf_key, snapshot_key), []).append(case)
        rows.append(
            {
                "index": index,
                "case_id": str(_first_nonempty(case.get("case_id"), case.get("name"), f"context_case_{index}")),
                "leaf_key": leaf_key,
                "snapshot_key": snapshot_key,
                "result": result,
                "expected_result": expected,
                "reason": "context_consistency_case_recorded",
            }
        )

    conflicting_groups: List[Dict[str, Any]] = []
    missing_groups: List[Dict[str, Any]] = []
    consistent_groups: List[Dict[str, Any]] = []
    for (leaf_key, snapshot_key), group_rows in grouped.items():
        missing_identity = not leaf_key or not snapshot_key
        results = {
            str(_first_nonempty(row.get("result"), row.get("outcome"), row.get("status"), row.get("reason"), "")).strip().lower()
            for row in group_rows
            if str(_first_nonempty(row.get("result"), row.get("outcome"), row.get("status"), row.get("reason"), "")).strip()
        }
        expected_values = {
            str(_first_nonempty(row.get("expected_result"), row.get("expected_outcome"), row.get("expected_status"), "")).strip().lower()
            for row in group_rows
            if str(_first_nonempty(row.get("expected_result"), row.get("expected_outcome"), row.get("expected_status"), "")).strip()
        }
        expected_conflict = bool(expected_values and len(results) == 1 and next(iter(results)) not in expected_values)
        if missing_identity:
            missing_groups.append({"leaf_key": leaf_key, "snapshot_key": snapshot_key})
        elif len(results) > 1 or expected_conflict:
            conflicting_groups.append({"leaf_key": leaf_key, "snapshot_key": snapshot_key, "result_count": len(results)})
        else:
            consistent_groups.append({"leaf_key": leaf_key, "snapshot_key": snapshot_key, "result_count": len(results)})

    threshold_value = max(1, int(threshold or 1))
    total_groups = len(grouped)
    conflict_count = len(conflicting_groups)
    missing_count = len(missing_groups)
    consistent_count = len(consistent_groups)

    if total_groups == 0:
        reason = "context_consistency_regression_suite_missing"
    elif conflict_count > 0:
        reason = "context_consistency_regression_suite_conflict"
    elif missing_count > 0:
        reason = "context_consistency_regression_suite_partial"
    elif consistent_count >= threshold_value:
        reason = "context_consistency_regression_suite_passed"
    else:
        reason = "context_consistency_regression_suite_monitor"

    suite_id = _sha1_payload(
        {
            "hint": hint,
            "threshold": threshold_value,
            "grouped": [
                {
                    "leaf_key": leaf_key,
                    "snapshot_key": snapshot_key,
                    "results": sorted(
                        {
                            str(_first_nonempty(row.get("result"), row.get("outcome"), row.get("status"), row.get("reason"), "")).strip().lower()
                            for row in group_rows
                            if str(_first_nonempty(row.get("result"), row.get("outcome"), row.get("status"), row.get("reason"), "")).strip()
                        }
                    ),
                }
                for (leaf_key, snapshot_key), group_rows in grouped.items()
            ],
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "suite_id": suite_id,
        "leaf_hint": hint or "context",
        "snapshot_identity": snapshot,
        "regression_cases": cases,
        "group_count": total_groups,
        "consistent_group_count": consistent_count,
        "conflict_group_count": conflict_count,
        "missing_group_count": missing_count,
        "threshold": threshold_value,
        "reason": reason,
        "is_passing": reason == "context_consistency_regression_suite_passed",
        "should_warn": reason == "context_consistency_regression_suite_monitor",
        "should_block": reason in {"context_consistency_regression_suite_conflict", "context_consistency_regression_suite_partial"},
        "rows": rows,
        "conflicting_groups": conflicting_groups,
        "missing_groups": missing_groups,
        "consistent_groups": consistent_groups,
    }


def build_tree_evolution_compat_guard(
    *,
    open_tasks: Sequence[Mapping[str, Any] | str] | None = None,
    current_tree_revision: str = "",
    proposed_tree_revision: str = "",
    compatibility_registry: Mapping[str, Any] | None = None,
    leaf_hint: str = "",
) -> Dict[str, Any]:
    hint = str(leaf_hint or "").strip().lower()
    current_revision = str(current_tree_revision or "").strip().lower()
    proposed_revision = str(proposed_tree_revision or "").strip().lower()
    registry = dict(compatibility_registry or {})

    def _collect_rows(rows: Sequence[Mapping[str, Any] | str] | None) -> List[Dict[str, Any]]:
        collected: List[Dict[str, Any]] = []
        for row in rows or []:
            if isinstance(row, Mapping):
                collected.append(dict(row))
            else:
                text = str(row or "").strip()
                if text:
                    collected.append({"name": text, "reason": text})
        return collected

    tasks = _collect_rows(open_tasks)
    compatible_rows: List[Dict[str, Any]] = []
    warning_rows: List[Dict[str, Any]] = []
    blocking_rows: List[Dict[str, Any]] = []

    registry_rows = dict(registry.get("rows") or registry.get("tasks") or registry.get("entries") or {})

    for index, task in enumerate(tasks, start=1):
        task_id = str(_first_nonempty(task.get("task_id"), task.get("leaf_key"), task.get("name"), f"task_{index}")).strip().lower()
        registry_row = registry_rows.get(task_id, {}) if isinstance(registry_rows, Mapping) else {}
        if not isinstance(registry_row, Mapping):
            registry_row = {}
        allowed_source = task.get("allowed_tree_revisions") or task.get("compatible_tree_revisions") or task.get("supported_tree_revisions") or registry_row.get("allowed_tree_revisions") or registry_row.get("compatible_tree_revisions") or registry_row.get("supported_tree_revisions") or []
        blocked_source = task.get("blocked_tree_revisions") or registry_row.get("blocked_tree_revisions") or []
        allowed = [str(value).strip().lower() for value in allowed_source if str(value).strip()]
        blocked = [str(value).strip().lower() for value in blocked_source if str(value).strip()]
        required = str(_first_nonempty(task.get("required_tree_revision"), task.get("tree_revision"), registry.get("required_tree_revision"), "")).strip().lower()
        compatibility_known = bool(allowed or blocked or required)
        incompatible = bool(
            (proposed_revision and allowed and proposed_revision not in allowed)
            or (proposed_revision and blocked and proposed_revision in blocked)
            or (required and proposed_revision and required != proposed_revision)
            or (required and not proposed_revision and required)
        )
        if incompatible:
            blocking_rows.append(
                {
                    "task_id": task_id,
                    "required_tree_revision": required,
                    "proposed_tree_revision": proposed_revision,
                    "allowed_tree_revisions": allowed,
                    "blocked_tree_revisions": blocked,
                }
            )
        elif compatibility_known:
            compatible_rows.append(
                {
                    "task_id": task_id,
                    "required_tree_revision": required,
                    "proposed_tree_revision": proposed_revision,
                    "allowed_tree_revisions": allowed,
                    "blocked_tree_revisions": blocked,
                }
            )
        else:
            warning_rows.append(
                {
                    "task_id": task_id,
                    "required_tree_revision": required,
                    "proposed_tree_revision": proposed_revision,
                    "allowed_tree_revisions": allowed,
                    "blocked_tree_revisions": blocked,
                }
            )

    if not tasks:
        reason = "tree_evolution_compat_guard_empty"
    elif blocking_rows:
        reason = "tree_evolution_compat_guard_blocked"
    elif warning_rows:
        reason = "tree_evolution_compat_guard_warn"
    else:
        reason = "tree_evolution_compat_guard_ready"

    guard_id = _sha1_payload(
        {
            "hint": hint,
            "current_tree_revision": current_revision,
            "proposed_tree_revision": proposed_revision,
            "tasks": [
                {
                    "task_id": str(_first_nonempty(task.get("task_id"), task.get("leaf_key"), task.get("name"), "")).strip().lower(),
                    "required_tree_revision": str(_first_nonempty(task.get("required_tree_revision"), task.get("tree_revision"), "")).strip().lower(),
                    "allowed_tree_revisions": sorted(
                        {
                            str(value).strip().lower()
                            for value in (
                                task.get("allowed_tree_revisions")
                                or task.get("compatible_tree_revisions")
                                or task.get("supported_tree_revisions")
                                or []
                            )
                            if str(value).strip()
                        }
                    ),
                    "blocked_tree_revisions": sorted(
                        {
                            str(value).strip().lower()
                            for value in (task.get("blocked_tree_revisions") or [])
                            if str(value).strip()
                        }
                    ),
                }
                for task in tasks
            ],
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "guard_id": guard_id,
        "leaf_hint": hint or "tree",
        "current_tree_revision": current_revision,
        "proposed_tree_revision": proposed_revision,
        "task_count": len(tasks),
        "compatible_task_count": len(compatible_rows),
        "warning_task_count": len(warning_rows),
        "blocking_task_count": len(blocking_rows),
        "reason": reason,
        "is_ready": reason == "tree_evolution_compat_guard_ready",
        "should_warn": reason == "tree_evolution_compat_guard_warn",
        "should_block": reason == "tree_evolution_compat_guard_blocked",
        "compatible_tasks": compatible_rows,
        "warning_tasks": warning_rows,
        "blocking_tasks": blocking_rows,
    }


def build_context_drift_packet(
    *,
    drift_entries: Sequence[Mapping[str, Any] | str] | None = None,
    snapshot_identity: Mapping[str, Any] | None = None,
    leaf_hint: str = "",
    threshold: int = 1,
) -> Dict[str, Any]:
    hint = str(leaf_hint or "").strip().lower()
    snapshot = dict(snapshot_identity or {})

    def _collect_rows(rows: Sequence[Mapping[str, Any] | str] | None) -> List[Dict[str, Any]]:
        collected: List[Dict[str, Any]] = []
        for row in rows or []:
            if isinstance(row, Mapping):
                collected.append(dict(row))
            else:
                text = str(row or "").strip()
                if text:
                    collected.append({"name": text, "reason": text})
        return collected

    entries = _collect_rows(drift_entries)
    rows: List[Dict[str, Any]] = []
    stale_rows: List[Dict[str, Any]] = []
    refresh_rows: List[Dict[str, Any]] = []
    fresh_rows: List[Dict[str, Any]] = []

    for index, entry in enumerate(entries, start=1):
        actor = str(_first_nonempty(entry.get("actor"), entry.get("worker"), entry.get("owner"), entry.get("name"), f"actor_{index}")).strip().lower()
        artifact = str(_first_nonempty(entry.get("artifact"), entry.get("task"), entry.get("tree_key"), entry.get("context_key"), hint, "")).strip().lower()
        stale = bool(entry.get("stale") or entry.get("expired") or entry.get("version_skew") or entry.get("is_stale"))
        refresh = bool(entry.get("refresh_required") or entry.get("needs_refresh") or entry.get("should_refresh"))
        snapshot_key = str(
            _first_nonempty(
                entry.get("snapshot_key"),
                entry.get("knowledge_snapshot_id"),
                entry.get("snapshot_id"),
                snapshot.get("snapshot_key"),
                snapshot.get("knowledge_snapshot_id"),
                snapshot.get("snapshot_id"),
                "",
            )
        ).strip().lower()
        row = {
            "index": index,
            "actor": actor,
            "artifact": artifact,
            "snapshot_key": snapshot_key,
            "stale": stale,
            "refresh_required": refresh,
            "reason": "context_drift_packet_recorded",
        }
        rows.append(row)
        if stale:
            stale_rows.append(row)
        elif refresh:
            refresh_rows.append(row)
        else:
            fresh_rows.append(row)

    threshold_value = max(1, int(threshold or 1))
    if not entries:
        reason = "context_drift_packet_missing"
    elif stale_rows and len(stale_rows) >= threshold_value:
        reason = "context_drift_packet_stale"
    elif refresh_rows:
        reason = "context_drift_packet_refresh_needed"
    elif fresh_rows:
        reason = "context_drift_packet_ready"
    else:
        reason = "context_drift_packet_partial"

    packet_id = _sha1_payload(
        {
            "hint": hint,
            "snapshot": snapshot,
            "rows": [
                {
                    "actor": row["actor"],
                    "artifact": row["artifact"],
                    "snapshot_key": row["snapshot_key"],
                    "stale": row["stale"],
                    "refresh_required": row["refresh_required"],
                }
                for row in rows
            ],
            "threshold": threshold_value,
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "packet_id": packet_id,
        "leaf_hint": hint or "context",
        "snapshot_identity": snapshot,
        "drift_entries": entries,
        "rows": rows,
        "packets": rows,
        "issues": stale_rows + refresh_rows,
        "stale_count": len(stale_rows),
        "refresh_count": len(refresh_rows),
        "fresh_count": len(fresh_rows),
        "threshold": threshold_value,
        "reason": reason,
        "is_ready": reason == "context_drift_packet_ready",
        "should_warn": reason in {"context_drift_packet_refresh_needed", "context_drift_packet_partial"},
        "should_block": reason in {"context_drift_packet_stale", "context_drift_packet_missing"},
    }


def build_mission_gap_promoter(
    *,
    mission_gap_events: Sequence[Mapping[str, Any] | str] | None = None,
    mission_regression_suite: Mapping[str, Any] | None = None,
    mission_alignment_guard: Mapping[str, Any] | None = None,
    mission_drift_packet: Mapping[str, Any] | None = None,
    mission_key_hint: str = "",
    threshold: int = 2,
) -> Dict[str, Any]:
    regression = dict(mission_regression_suite or {})
    guard = dict(mission_alignment_guard or {})
    drift = dict(mission_drift_packet or {})
    hint = str(mission_key_hint or "").strip().lower()

    def _collect_rows(rows: Sequence[Mapping[str, Any] | str] | None, default_kind: str) -> List[Dict[str, Any]]:
        collected: List[Dict[str, Any]] = []
        for row in rows or []:
            if isinstance(row, Mapping):
                collected.append(dict(row))
            else:
                text = str(row or "").strip()
                if text:
                    collected.append({"name": text, "kind": default_kind, "reason": text})
        return collected

    gap_rows = _collect_rows(mission_gap_events, "mission")
    regression_rows = _collect_rows(regression.get("failing_runs") or regression.get("rows") or [], "regression")
    guard_rows = _collect_rows(guard.get("blocked_rows") or guard.get("rows") or [], "guard")
    drift_rows = _collect_rows(drift.get("rows") or drift.get("packets") or drift.get("issues") or [], "drift")

    def _row_key(row: Mapping[str, Any]) -> str:
        return str(
            _first_nonempty(
                row.get("mission_key"),
                row.get("mode_key"),
                row.get("goal_key"),
                row.get("gap_key"),
                row.get("name"),
                row.get("reason"),
                hint,
                "",
            )
        ).strip().lower()

    recurring_rows: List[Dict[str, Any]] = []
    for row in gap_rows:
        key = _row_key(row)
        lowered = " ".join(
            filter(
                None,
                [
                    str(_first_nonempty(row.get("message"), row.get("status_text"), row.get("description"), row.get("name"), "")).strip(),
                    str(_first_nonempty(row.get("reason"), row.get("status"), "")).strip(),
                ],
            )
        ).lower()
        mission_signal = bool(
            row.get("mission_mismatch")
            or row.get("mode_mismatch")
            or row.get("goal_drift")
            or row.get("is_mission_failure")
            or row.get("is_mode_failure")
        ) or any(
            token in lowered
            for token in (
                "mission",
                "mode",
                "goal",
                "intent",
                "drift",
                "mismatch",
                "switching",
                "wrong mode",
                "off mission",
                "target drift",
            )
        )
        if mission_signal and (not hint or key == hint):
            recurring_rows.append(row)

    threshold_value = max(1, int(threshold or 1))
    recurring_count = len(recurring_rows)
    backlog_count = len(regression_rows) + len(guard_rows) + len(drift_rows)
    signal_rows = recurring_rows + regression_rows + guard_rows + drift_rows
    should_promote = bool(recurring_count >= threshold_value or backlog_count >= threshold_value)
    if should_promote:
        promotion_tier = "promote"
        reason = "mission_gap_promote"
    elif recurring_count > 0 or backlog_count > 0:
        promotion_tier = "monitor"
        reason = "mission_gap_monitor"
    else:
        promotion_tier = "ignore"
        reason = "mission_gap_ignore"

    promoter_id = _sha1_payload(
        {
            "mission_key_hint": hint,
            "recurring_count": recurring_count,
            "backlog_count": backlog_count,
            "threshold": threshold_value,
            "signal_notes": [
                str(_first_nonempty(row.get("name"), row.get("mission_key"), row.get("mode_key"), row.get("gap_key"), row.get("reason"), "")) for row in signal_rows
            ],
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "promoter_id": promoter_id,
        "mission_key_hint": hint or "mission",
        "recurring_count": recurring_count,
        "backlog_count": backlog_count,
        "threshold": threshold_value,
        "promotion_tier": promotion_tier,
        "reason": reason,
        "should_promote": should_promote,
        "should_monitor": promotion_tier == "monitor",
        "should_ignore": promotion_tier == "ignore",
        "signal_count": len(signal_rows),
        "signal_notes": [
            str(_first_nonempty(row.get("name"), row.get("mission_key"), row.get("mode_key"), row.get("gap_key"), row.get("reason"), "")) for row in signal_rows
        ],
        "regression_count": len(regression_rows),
        "guard_block_count": len(guard_rows),
        "drift_count": len(drift_rows),
    }


def build_causality_gap_promoter(
    *,
    causality_gap_events: Sequence[Mapping[str, Any] | str] | None = None,
    causality_regression_suite: Mapping[str, Any] | None = None,
    causal_brief_packet: Mapping[str, Any] | None = None,
    causality_key_hint: str = "",
    threshold: int = 2,
) -> Dict[str, Any]:
    regression = dict(causality_regression_suite or {})
    brief = dict(causal_brief_packet or {})
    hint = str(causality_key_hint or "").strip().lower()

    def _collect_rows(rows: Sequence[Mapping[str, Any] | str] | None, default_kind: str) -> List[Dict[str, Any]]:
        collected: List[Dict[str, Any]] = []
        for row in rows or []:
            if isinstance(row, Mapping):
                collected.append(dict(row))
            else:
                text = str(row or "").strip()
                if text:
                    collected.append({"name": text, "kind": default_kind, "reason": text})
        return collected

    gap_rows = _collect_rows(causality_gap_events, "causality")
    regression_rows = _collect_rows(regression.get("failing_runs") or regression.get("rows") or [], "regression")
    brief_rows = _collect_rows(brief.get("rows") or brief.get("hypotheses") or brief.get("counterfactuals") or [], "brief")

    def _row_key(row: Mapping[str, Any]) -> str:
        return str(
            _first_nonempty(
                row.get("causality_key"),
                row.get("cause_key"),
                row.get("hypothesis_key"),
                row.get("gap_key"),
                row.get("name"),
                row.get("reason"),
                hint,
                "",
            )
        ).strip().lower()

    recurring_rows: List[Dict[str, Any]] = []
    for row in gap_rows:
        key = _row_key(row)
        lowered = " ".join(
            filter(
                None,
                [
                    str(_first_nonempty(row.get("message"), row.get("status_text"), row.get("description"), row.get("name"), "")).strip(),
                    str(_first_nonempty(row.get("reason"), row.get("status"), "")).strip(),
                ],
            )
        ).lower()
        causality_signal = bool(
            row.get("causal_confidence_low")
            or row.get("attribution_weak")
            or row.get("counterfactual_missing")
            or row.get("is_causality_gap")
            or row.get("is_attribution_gap")
        ) or any(
            token in lowered
            for token in (
                "correlat",
                "attribution",
                "causal",
                "cause",
                "counterfactual",
                "hypothesis",
                "weak evidence",
                "not enough evidence",
                "uncertain",
            )
        )
        if causality_signal and (not hint or key == hint):
            recurring_rows.append(row)

    threshold_value = max(1, int(threshold or 1))
    recurring_count = len(recurring_rows)
    backlog_count = len(regression_rows) + len(brief_rows)
    signal_rows = recurring_rows + regression_rows + brief_rows
    should_promote = bool(recurring_count >= threshold_value or backlog_count >= threshold_value)
    if should_promote:
        promotion_tier = "promote"
        reason = "causality_gap_promote"
    elif recurring_count > 0 or backlog_count > 0:
        promotion_tier = "monitor"
        reason = "causality_gap_monitor"
    else:
        promotion_tier = "ignore"
        reason = "causality_gap_ignore"

    promoter_id = _sha1_payload(
        {
            "causality_key_hint": hint,
            "recurring_count": recurring_count,
            "backlog_count": backlog_count,
            "threshold": threshold_value,
            "signal_notes": [
                str(_first_nonempty(row.get("name"), row.get("causality_key"), row.get("cause_key"), row.get("gap_key"), row.get("reason"), "")) for row in signal_rows
            ],
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "promoter_id": promoter_id,
        "causality_key_hint": hint or "causality",
        "recurring_count": recurring_count,
        "backlog_count": backlog_count,
        "threshold": threshold_value,
        "promotion_tier": promotion_tier,
        "reason": reason,
        "should_promote": should_promote,
        "should_monitor": promotion_tier == "monitor",
        "should_ignore": promotion_tier == "ignore",
        "signal_count": len(signal_rows),
        "signal_notes": [
            str(_first_nonempty(row.get("name"), row.get("causality_key"), row.get("cause_key"), row.get("gap_key"), row.get("reason"), "")) for row in signal_rows
        ],
        "regression_count": len(regression_rows),
        "brief_count": len(brief_rows),
    }


def build_compliance_gap_promoter(
    *,
    compliance_gap_events: Sequence[Mapping[str, Any] | str] | None = None,
    compliance_regression_suite: Mapping[str, Any] | None = None,
    compliance_risk_packet: Mapping[str, Any] | None = None,
    compliance_redaction_contract: Mapping[str, Any] | None = None,
    compliance_key_hint: str = "",
    threshold: int = 2,
) -> Dict[str, Any]:
    regression = dict(compliance_regression_suite or {})
    risk = dict(compliance_risk_packet or {})
    redaction = dict(compliance_redaction_contract or {})
    hint = str(compliance_key_hint or "").strip().lower()

    def _collect_rows(rows: Sequence[Mapping[str, Any] | str] | None, default_kind: str) -> List[Dict[str, Any]]:
        collected: List[Dict[str, Any]] = []
        for row in rows or []:
            if isinstance(row, Mapping):
                collected.append(dict(row))
            else:
                text = str(row or "").strip()
                if text:
                    collected.append({"name": text, "kind": default_kind, "reason": text})
        return collected

    gap_rows = _collect_rows(compliance_gap_events, "compliance")
    regression_rows = _collect_rows(regression.get("failing_runs") or regression.get("rows") or [], "regression")
    risk_rows = _collect_rows(risk.get("rows") or risk.get("zones") or risk.get("issues") or [], "risk")
    redaction_rows = _collect_rows(redaction.get("rows") or redaction.get("fields") or redaction.get("artifacts") or [], "redaction")

    def _row_key(row: Mapping[str, Any]) -> str:
        return str(
            _first_nonempty(
                row.get("compliance_key"),
                row.get("policy_key"),
                row.get("surface_key"),
                row.get("gap_key"),
                row.get("name"),
                row.get("reason"),
                hint,
                "",
            )
        ).strip().lower()

    recurring_rows: List[Dict[str, Any]] = []
    for row in gap_rows:
        key = _row_key(row)
        lowered = " ".join(
            filter(
                None,
                [
                    str(_first_nonempty(row.get("message"), row.get("status_text"), row.get("description"), row.get("name"), "")).strip(),
                    str(_first_nonempty(row.get("reason"), row.get("status"), "")).strip(),
                ],
            )
        ).lower()
        compliance_signal = bool(
            row.get("policy_violation")
            or row.get("sensitive_surface")
            or row.get("redaction_failure")
            or row.get("compliance_risk")
            or row.get("is_compliance_gap")
        ) or any(
            token in lowered
            for token in (
                "compliance",
                "policy",
                "sensitive",
                "redaction",
                "risk",
                "violation",
                "privacy",
                "regulated",
                "blocked",
                "secret",
            )
        )
        if compliance_signal and (not hint or key == hint):
            recurring_rows.append(row)

    threshold_value = max(1, int(threshold or 1))
    recurring_count = len(recurring_rows)
    backlog_count = len(regression_rows) + len(risk_rows) + len(redaction_rows)
    signal_rows = recurring_rows + regression_rows + risk_rows + redaction_rows
    should_promote = bool(recurring_count >= threshold_value or backlog_count >= threshold_value)
    if should_promote:
        promotion_tier = "promote"
        reason = "compliance_gap_promote"
    elif recurring_count > 0 or backlog_count > 0:
        promotion_tier = "monitor"
        reason = "compliance_gap_monitor"
    else:
        promotion_tier = "ignore"
        reason = "compliance_gap_ignore"

    promoter_id = _sha1_payload(
        {
            "compliance_key_hint": hint,
            "recurring_count": recurring_count,
            "backlog_count": backlog_count,
            "threshold": threshold_value,
            "signal_notes": [
                str(_first_nonempty(row.get("name"), row.get("compliance_key"), row.get("policy_key"), row.get("gap_key"), row.get("reason"), "")) for row in signal_rows
            ],
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "promoter_id": promoter_id,
        "compliance_key_hint": hint or "compliance",
        "recurring_count": recurring_count,
        "backlog_count": backlog_count,
        "threshold": threshold_value,
        "promotion_tier": promotion_tier,
        "reason": reason,
        "should_promote": should_promote,
        "should_monitor": promotion_tier == "monitor",
        "should_ignore": promotion_tier == "ignore",
        "signal_count": len(signal_rows),
        "signal_notes": [
            str(_first_nonempty(row.get("name"), row.get("compliance_key"), row.get("policy_key"), row.get("gap_key"), row.get("reason"), "")) for row in signal_rows
        ],
        "regression_count": len(regression_rows),
        "risk_count": len(risk_rows),
        "redaction_count": len(redaction_rows),
    }


def build_tree_spec_gap_promoter(
    *,
    leaf_contract_results: Sequence[Mapping[str, Any] | str] | None = None,
    tree_spec_packet: Mapping[str, Any] | None = None,
    roadmap_backlog: Sequence[Mapping[str, Any] | str] | None = None,
    tree_key_hint: str = "",
    threshold: int = 2,
) -> Dict[str, Any]:
    packet = dict(tree_spec_packet or {})
    hint = str(tree_key_hint or "").strip().lower()

    def _collect_rows(rows: Sequence[Mapping[str, Any] | str] | None, default_kind: str) -> List[Dict[str, Any]]:
        collected: List[Dict[str, Any]] = []
        for row in rows or []:
            if isinstance(row, Mapping):
                collected.append(dict(row))
            else:
                text = str(row or "").strip()
                if text:
                    collected.append({"name": text, "kind": default_kind, "reason": text})
        return collected

    leaf_rows = _collect_rows(leaf_contract_results, "leaf")
    backlog_rows = _collect_rows(roadmap_backlog, "backlog")

    def _row_key(row: Mapping[str, Any]) -> str:
        return str(
            _first_nonempty(
                row.get("tree_key"),
                row.get("leaf_group"),
                row.get("leaf_family"),
                row.get("spec_key"),
                row.get("leaf_id"),
                row.get("name"),
                row.get("reason"),
                hint,
                "",
            )
        ).strip().lower()

    failing_rows: List[Dict[str, Any]] = []
    for row in leaf_rows:
        key = _row_key(row)
        passed = bool(row.get("is_one_to_one", row.get("passed", row.get("is_passing", True))))
        reason = str(_first_nonempty(row.get("reason"), row.get("status"), row.get("note"), "")).strip().lower()
        warning_reason = reason in {
            "context_too_large",
            "outcome_mismatch",
            "missing_leaf_id",
            "missing_expected_outcome",
            "missing_actual_outcome",
            "leaf_contract_failed",
        }
        spec_signal = bool(
            row.get("spec_too_large")
            or row.get("tree_unstable")
            or row.get("unrunnable")
            or row.get("is_spec_gap")
            or not passed
        ) or warning_reason
        if spec_signal and (not hint or key == hint):
            failing_rows.append(row)

    threshold_value = max(1, int(threshold or 1))
    recurring_count = len(failing_rows)
    backlog_count = len([row for row in backlog_rows if not hint or _row_key(row) == hint or str(_first_nonempty(row.get("kind"), row.get("type"), "")).strip().lower() == "leaf"])
    signal_rows = failing_rows + backlog_rows
    should_promote = bool(recurring_count >= threshold_value or backlog_count >= threshold_value)
    if should_promote:
        promotion_tier = "promote"
        reason = "tree_spec_gap_promote"
    elif recurring_count > 0 or backlog_count > 0:
        promotion_tier = "monitor"
        reason = "tree_spec_gap_monitor"
    else:
        promotion_tier = "ignore"
        reason = "tree_spec_gap_ignore"

    promoter_id = _sha1_payload(
        {
            "tree_key_hint": hint,
            "recurring_count": recurring_count,
            "backlog_count": backlog_count,
            "threshold": threshold_value,
            "signal_notes": [
                str(_first_nonempty(row.get("name"), row.get("leaf_id"), row.get("spec_key"), row.get("reason"), "")) for row in signal_rows
            ],
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "promoter_id": promoter_id,
        "tree_key_hint": hint or "tree",
        "recurring_count": recurring_count,
        "backlog_count": backlog_count,
        "threshold": threshold_value,
        "promotion_tier": promotion_tier,
        "reason": reason,
        "should_promote": should_promote,
        "should_monitor": promotion_tier == "monitor",
        "should_ignore": promotion_tier == "ignore",
        "signal_count": len(signal_rows),
        "signal_notes": [
            str(_first_nonempty(row.get("name"), row.get("leaf_id"), row.get("spec_key"), row.get("reason"), "")) for row in signal_rows
        ],
        "failing_leaf_count": len(failing_rows),
        "backlog_leaf_count": backlog_count,
        "tree_spec_is_large": bool(packet.get("is_large") or packet.get("is_unrunnable") or packet.get("has_many_leaves")),
    }


def build_site_latency_profile(
    *,
    site_records: Sequence[Mapping[str, Any]] | None = None,
    host_budget_s: float = 0.0,
    family_budget_s: float = 0.0,
) -> Dict[str, Any]:
    host_groups: Dict[str, List[float]] = {}
    family_groups: Dict[str, List[float]] = {}
    for record in site_records or []:
        if not isinstance(record, Mapping):
            continue
        host = str(_first_nonempty(record.get("host"), record.get("site_host"), record.get("domain"), "unknown")).strip().lower() or "unknown"
        family = str(_first_nonempty(record.get("survey_family"), record.get("family"), record.get("site_family"), "unknown")).strip().lower() or "unknown"
        latency = max(0.0, float(record.get("latency_ms") or record.get("latency") or record.get("duration_ms") or 0.0))
        host_groups.setdefault(host, []).append(latency)
        family_groups.setdefault(family, []).append(latency)

    def _profile(values: Sequence[float], budget_s: float) -> Dict[str, Any]:
        ordered = sorted(float(item) for item in values if item is not None)
        if not ordered:
            return {
                "count": 0,
                "median_ms": 0.0,
                "p95_ms": 0.0,
                "budget_ms": round(max(0.0, float(budget_s)) * 1000.0, 4),
                "is_stable": False,
            }
        median_ms = float(statistics.median(ordered))
        if len(ordered) == 1:
            p95_ms = ordered[0]
        else:
            p95_index = min(len(ordered) - 1, max(0, math.ceil(len(ordered) * 0.95) - 1))
            p95_ms = ordered[p95_index]
        budget_ms = round(max(0.0, float(budget_s)) * 1000.0, 4)
        return {
            "count": len(ordered),
            "median_ms": round(median_ms, 4),
            "p95_ms": round(float(p95_ms), 4),
            "budget_ms": budget_ms,
            "is_stable": bool(budget_ms <= 0.0 or p95_ms <= budget_ms),
        }

    host_profiles = [
        {
            "host": host,
            **_profile(values, host_budget_s),
        }
        for host, values in sorted(host_groups.items())
    ]
    family_profiles = [
        {
            "survey_family": family,
            **_profile(values, family_budget_s),
        }
        for family, values in sorted(family_groups.items())
    ]
    unstable_hosts = [row["host"] for row in host_profiles if not row["is_stable"]]
    unstable_families = [row["survey_family"] for row in family_profiles if not row["is_stable"]]
    return {
        "schema_version": SCHEMA_VERSION,
        "host_profiles": host_profiles,
        "family_profiles": family_profiles,
        "host_budget_s": round(float(host_budget_s), 4),
        "family_budget_s": round(float(family_budget_s), 4),
        "is_stable": not unstable_hosts and not unstable_families and bool(host_profiles or family_profiles),
        "unstable_hosts": unstable_hosts,
        "unstable_families": unstable_families,
        "profile_id": _sha1_payload({"host_profiles": host_profiles, "family_profiles": family_profiles, "host_budget_s": float(host_budget_s), "family_budget_s": float(family_budget_s)})[:16],
    }


def build_component_latency_registry(
    *,
    component_records: Sequence[Mapping[str, Any]] | None = None,
    max_latency_ms: float = 0.0,
    max_error_rate: float = 0.0,
) -> Dict[str, Any]:
    grouped: Dict[str, Dict[str, Any]] = {}
    for record in component_records or []:
        if not isinstance(record, Mapping):
            continue
        component = str(_first_nonempty(record.get("component"), record.get("stage"), record.get("name"), "unknown")).strip().lower() or "unknown"
        latency_ms = max(0.0, float(record.get("latency_ms") or record.get("latency") or 0.0))
        passed = bool(record.get("passed", record.get("success", True)))
        bucket = grouped.setdefault(
            component,
            {
                "component": component,
                "latencies_ms": [],
                "total_count": 0,
                "error_count": 0,
            },
        )
        bucket["latencies_ms"].append(latency_ms)
        bucket["total_count"] += 1
        if not passed:
            bucket["error_count"] += 1
    rows: List[Dict[str, Any]] = []
    for component, bucket in sorted(grouped.items()):
        ordered = sorted(float(item) for item in bucket["latencies_ms"] if item is not None)
        median_ms = float(statistics.median(ordered)) if ordered else 0.0
        if len(ordered) == 1:
            p95_ms = ordered[0]
        elif ordered:
            p95_index = min(len(ordered) - 1, max(0, math.ceil(len(ordered) * 0.95) - 1))
            p95_ms = ordered[p95_index]
        else:
            p95_ms = 0.0
        total_count = int(bucket["total_count"] or 0)
        error_count = int(bucket["error_count"] or 0)
        error_rate = (error_count / total_count) if total_count else 0.0
        meets_latency = bool(max_latency_ms <= 0.0 or p95_ms <= float(max_latency_ms))
        meets_error_rate = bool(max_error_rate <= 0.0 or error_rate <= float(max_error_rate))
        rows.append(
            {
                "component": component,
                "count": total_count,
                "median_ms": round(median_ms, 4),
                "p95_ms": round(float(p95_ms), 4),
                "error_count": error_count,
                "error_rate": round(error_rate, 4),
                "meets_latency": meets_latency,
                "meets_error_rate": meets_error_rate,
                "is_stable": bool(meets_latency and meets_error_rate),
                "reasons": [
                    reason
                    for reason, passed in (
                        ("latency_too_high", meets_latency),
                        ("error_rate_too_high", meets_error_rate),
                    )
                    if not passed
                ],
            }
        )
    unstable_components = [row["component"] for row in rows if not row["is_stable"]]
    return {
        "schema_version": SCHEMA_VERSION,
        "rows": rows,
        "max_latency_ms": round(float(max_latency_ms), 4),
        "max_error_rate": round(float(max_error_rate), 4),
        "is_stable": not unstable_components and bool(rows),
        "unstable_components": unstable_components,
        "registry_id": _sha1_payload({"rows": rows, "max_latency_ms": float(max_latency_ms), "max_error_rate": float(max_error_rate)})[:16],
    }


def build_execution_mode_switcher(
    *,
    startup_cost_ms: float = 0.0,
    task_volume: int = 0,
    inline_cost_budget_ms: float = 0.0,
    daemon_startup_threshold_ms: float = 0.0,
    daemon_task_threshold: int = 0,
) -> Dict[str, Any]:
    startup = max(0.0, float(startup_cost_ms or 0.0))
    volume = max(0, int(task_volume or 0))
    inline_budget = max(0.0, float(inline_cost_budget_ms or 0.0))
    daemon_threshold = max(0.0, float(daemon_startup_threshold_ms or 0.0))
    daemon_volume_threshold = max(0, int(daemon_task_threshold or 0))
    prefer_daemon = bool((daemon_threshold > 0.0 and startup >= daemon_threshold) or (daemon_volume_threshold > 0 and volume >= daemon_volume_threshold))
    prefer_inline = bool(not prefer_daemon and (inline_budget <= 0.0 or startup <= inline_budget))
    if prefer_daemon:
        mode = "daemon"
        reason = "startup_cost_or_volume_high"
    elif prefer_inline:
        mode = "inline"
        reason = "startup_cost_low_and_volume_small"
    else:
        mode = "daemon"
        reason = "startup_cost_above_inline_budget"
    return {
        "schema_version": SCHEMA_VERSION,
        "mode": mode,
        "reason": reason,
        "startup_cost_ms": round(startup, 4),
        "task_volume": volume,
        "inline_cost_budget_ms": round(inline_budget, 4),
        "daemon_startup_threshold_ms": round(daemon_threshold, 4),
        "daemon_task_threshold": daemon_volume_threshold,
        "signals": {
            "prefer_daemon": prefer_daemon,
            "prefer_inline": prefer_inline,
        },
    }


def build_timeout_policy_registry(
    *,
    policies: Sequence[Mapping[str, Any]] | None = None,
    default_timeout_ms: float = 0.0,
) -> Dict[str, Any]:
    rows: List[Dict[str, Any]] = []
    source_map: Dict[str, Dict[str, Any]] = {}
    for policy in policies or []:
        if not isinstance(policy, Mapping):
            continue
        source = str(_first_nonempty(policy.get("source"), policy.get("owner"), policy.get("name"), "unknown")).strip().lower() or "unknown"
        stage = str(_first_nonempty(policy.get("stage"), policy.get("component"), policy.get("target"), "unknown")).strip().lower() or "unknown"
        timeout_ms = max(0.0, float(policy.get("timeout_ms") or policy.get("max_timeout_ms") or policy.get("latency_ms") or 0.0))
        source_map.setdefault(source, {"source": source, "stages": []})
        source_map[source]["stages"].append({"stage": stage, "timeout_ms": round(timeout_ms, 4)})
        rows.append(
            {
                "source": source,
                "stage": stage,
                "timeout_ms": round(timeout_ms, 4),
            }
        )
    normalized_sources = []
    for source, item in sorted(source_map.items()):
        stages = item["stages"]
        normalized_sources.append(
            {
                "source": source,
                "stages": sorted(stages, key=lambda row: (row["timeout_ms"], row["stage"])),
                "stage_count": len(stages),
                "max_timeout_ms": round(max((row["timeout_ms"] for row in stages), default=0.0), 4),
                "min_timeout_ms": round(min((row["timeout_ms"] for row in stages), default=0.0), 4),
            }
        )
    default_timeout = max(0.0, float(default_timeout_ms or 0.0))
    drift_sources = [row["source"] for row in normalized_sources if any(abs(float(stage["timeout_ms"]) - default_timeout) > 0.0 for stage in row["stages"]) and default_timeout > 0.0]
    return {
        "schema_version": SCHEMA_VERSION,
        "rows": rows,
        "sources": normalized_sources,
        "default_timeout_ms": round(default_timeout, 4),
        "has_default": default_timeout > 0.0,
        "has_policies": bool(rows),
        "is_single_source_of_truth": bool(rows) and len({row["timeout_ms"] for row in rows}) <= 1,
        "drift_sources": drift_sources,
        "registry_id": _sha1_payload({"rows": rows, "default_timeout_ms": default_timeout})[:16],
    }


def build_adaptive_pipeline_depth(
    *,
    budget_remaining_s: float = 0.0,
    risk_score: float = 0.0,
    freshness_score: float = 0.0,
    ocr_confidence: float = 0.0,
    min_budget_for_full_ocr_s: float = 0.0,
    min_risk_for_full_ocr: float = 0.0,
) -> Dict[str, Any]:
    budget = max(0.0, float(budget_remaining_s or 0.0))
    risk = max(0.0, min(1.0, float(risk_score or 0.0)))
    freshness = max(0.0, min(1.0, float(freshness_score or 0.0)))
    ocr = max(0.0, min(1.0, float(ocr_confidence or 0.0)))
    full_budget = max(0.0, float(min_budget_for_full_ocr_s or 0.0))
    full_risk = max(0.0, min(1.0, float(min_risk_for_full_ocr or 0.0)))
    if budget >= full_budget and risk >= full_risk and freshness >= 0.5 and ocr >= 0.75:
        depth = "full_ocr"
        reason = "budget_and_risk_support_full_ocr"
    elif budget <= 0.0:
        depth = "fast_summary_only"
        reason = "no_budget_remaining"
    elif risk < 0.35 and freshness >= 0.7 and ocr >= 0.6:
        depth = "fast_summary_only"
        reason = "low_risk_high_freshness"
    else:
        depth = "hybrid_ocr"
        reason = "mixed_signal_pipeline"
    return {
        "schema_version": SCHEMA_VERSION,
        "pipeline_depth": depth,
        "reason": reason,
        "budget_remaining_s": round(budget, 4),
        "risk_score": round(risk, 4),
        "freshness_score": round(freshness, 4),
        "ocr_confidence": round(ocr, 4),
        "min_budget_for_full_ocr_s": round(full_budget, 4),
        "min_risk_for_full_ocr": round(full_risk, 4),
        "signals": {
            "can_afford_full_ocr": budget >= full_budget,
            "risk_supports_full_ocr": risk >= full_risk,
            "freshness_supports_fast_path": freshness >= 0.7,
        },
    }


def build_checkpoint_stability_window(
    *,
    checkpoint_ts: float | None = None,
    screen_ts: float | None = None,
    now_ts: float | None = None,
    window_s: float = 1.5,
) -> Dict[str, Any]:
    now = float(now_ts if now_ts is not None else time.time())
    checkpoint_age = None if checkpoint_ts is None else round(now - float(checkpoint_ts), 4)
    screen_age = None if screen_ts is None else round(now - float(screen_ts), 4)
    checkpoint_fresh = checkpoint_age is not None and checkpoint_age <= float(window_s)
    screen_fresh = screen_age is not None and screen_age <= float(window_s)
    is_stable = bool(checkpoint_fresh and screen_fresh)
    if checkpoint_age is None and screen_age is None:
        reason = "missing_timestamps"
    elif not checkpoint_fresh or not screen_fresh:
        reason = "outside_stability_window"
    else:
        reason = "inside_stability_window"
    return {
        "schema_version": SCHEMA_VERSION,
        "checkpoint_age_s": checkpoint_age,
        "screen_age_s": screen_age,
        "window_s": float(window_s),
        "checkpoint_fresh": checkpoint_fresh,
        "screen_fresh": screen_fresh,
        "is_stable": is_stable,
        "reason": reason,
    }


def build_post_retry_state_recheck(
    *,
    pre_state: Mapping[str, Any] | None = None,
    post_state: Mapping[str, Any] | None = None,
    freshness_marker: Mapping[str, Any] | None = None,
    retry_action: Any = "",
) -> Dict[str, Any]:
    pre = dict(pre_state or {})
    post = dict(post_state or {})
    freshness = dict(freshness_marker or {}) if isinstance(freshness_marker, Mapping) else {}
    pre_hash = _sha1_payload(pre)[:16]
    post_hash = _sha1_payload(post)[:16]
    changed = pre_hash != post_hash
    is_fresh = bool(freshness.get("is_fresh", True))
    stale_reasons = list(freshness.get("stale_reasons") or [])
    post_outcome = _first_nonempty(post.get("outcome"), post.get("action_outcome"), post.get("status"), "unknown")
    should_reparse = not is_fresh or not post
    should_retry_same_action = bool(is_fresh and changed and post_outcome not in {"blocked", "error", "timeout"})
    should_stop_retry = bool(not is_fresh or post_outcome in {"blocked", "error", "timeout"} or not changed)
    if should_stop_retry and not stale_reasons and not changed:
        reason = "no_state_change_after_retry"
    elif not is_fresh:
        reason = "stale_state_after_retry"
    elif post_outcome in {"blocked", "error", "timeout"}:
        reason = f"retry_outcome_{post_outcome}"
    else:
        reason = "state_updated_after_retry"
    return {
        "schema_version": SCHEMA_VERSION,
        "retry_action": _first_nonempty(retry_action),
        "pre_state_hash": pre_hash,
        "post_state_hash": post_hash,
        "state_changed": changed,
        "is_fresh": is_fresh,
        "stale_reasons": stale_reasons,
        "post_outcome": post_outcome,
        "should_reparse": should_reparse,
        "should_retry_same_action": should_retry_same_action,
        "should_stop_retry": should_stop_retry,
        "reason": reason,
    }


def build_cold_start_sanitizer(
    *,
    current_session_id: Any = "",
    artifacts: Sequence[Mapping[str, Any]] | None = None,
) -> Dict[str, Any]:
    sid = _first_nonempty(current_session_id)
    kept: List[Dict[str, Any]] = []
    removed: List[Dict[str, Any]] = []
    for idx, artifact in enumerate(artifacts or []):
        if not isinstance(artifact, Mapping):
            continue
        source_session = _first_nonempty(artifact.get("source_session"), artifact.get("session_id"), artifact.get("session"))
        path = _first_nonempty(artifact.get("path"), artifact.get("artifact"), artifact.get("name"), f"artifact_{idx}")
        is_stale = bool(source_session and sid and source_session != sid)
        row = {
            "index": idx,
            "path": path,
            "source_session": source_session,
            "status": "removed" if is_stale else "kept",
        }
        if is_stale:
            removed.append(row)
        else:
            kept.append(row)
    should_reset = bool(removed)
    reason = "stale_current_run_outputs" if removed else "clean_start"
    return {
        "schema_version": SCHEMA_VERSION,
        "current_session_id": sid,
        "should_reset_current_run": should_reset,
        "reason": reason,
        "removed_count": len(removed),
        "kept_count": len(kept),
        "removed_artifacts": removed,
        "kept_artifacts": kept,
    }


def build_shard_completeness_proof(
    *,
    shard_rows: Sequence[Mapping[str, Any]] | None = None,
    expected_count: int | None = None,
    shard_id: Any = "",
) -> Dict[str, Any]:
    rows: List[Dict[str, Any]] = []
    issues: List[str] = []
    row_ids: List[str] = []
    for idx, row in enumerate(shard_rows or []):
        if not isinstance(row, Mapping):
            issues.append(f"row_{idx}_not_mapping")
            continue
        row_id = _first_nonempty(row.get("id"), row.get("row_id"), row.get("sample_id"), f"row_{idx}")
        row_ids.append(row_id)
        state_hash = _first_nonempty(row.get("state_hash"), row.get("screen_signature"))
        rows.append(
            {
                "index": idx,
                "id": row_id,
                "session_id": _first_nonempty(row.get("session_id"), row.get("session")),
                "state_hash": state_hash,
            }
        )
        if not row_id:
            issues.append(f"row_{idx}_missing_id")
        if not state_hash:
            issues.append(f"row_{idx}_missing_state_hash")
    unique_ids = len(set(row_ids))
    if expected_count is not None and int(expected_count) != len(rows):
        issues.append("row_count_mismatch")
    if unique_ids != len(rows):
        issues.append("duplicate_row_ids")
    content_hash = _sha1_payload(rows)[:16]
    is_complete = not issues and (expected_count is None or int(expected_count) == len(rows))
    return {
        "schema_version": SCHEMA_VERSION,
        "shard_id": _first_nonempty(shard_id),
        "expected_count": None if expected_count is None else int(expected_count),
        "row_count": len(rows),
        "unique_row_count": unique_ids,
        "content_hash": content_hash,
        "issues": issues,
        "is_complete": is_complete,
        "rows": rows,
    }


def build_action_attempt_registry(
    *,
    attempts: Sequence[Mapping[str, Any]] | None = None,
    logical_action_id: Any = "",
) -> Dict[str, Any]:
    action_id = _first_nonempty(logical_action_id)
    rows: List[Dict[str, Any]] = []
    seen: Dict[str, int] = {}
    for idx, attempt in enumerate(attempts or []):
        if not isinstance(attempt, Mapping):
            continue
        row_action_id = _first_nonempty(
            attempt.get("logical_action_id"),
            attempt.get("action_id"),
            attempt.get("planned_action_id"),
            action_id,
            f"action_{idx}",
        )
        attempt_kind = _first_nonempty(attempt.get("attempt_kind"), attempt.get("kind"), "unknown")
        status = _first_nonempty(attempt.get("status"), "unknown")
        rows.append(
            {
                "index": idx,
                "logical_action_id": row_action_id,
                "attempt_kind": attempt_kind,
                "status": status,
                "outcome": _first_nonempty(attempt.get("outcome"), attempt.get("result")),
            }
        )
        seen[row_action_id] = int(seen.get(row_action_id, 0) + 1)
    planned_count = sum(1 for row in rows if row["attempt_kind"] == "planned")
    executed_count = sum(1 for row in rows if row["attempt_kind"] == "executed")
    duplicate_action_ids = sorted([key for key, count in seen.items() if count >= 2])
    return {
        "schema_version": SCHEMA_VERSION,
        "logical_action_id": action_id,
        "attempt_count": len(rows),
        "planned_count": planned_count,
        "executed_count": executed_count,
        "duplicate_action_ids": duplicate_action_ids,
        "is_registry_complete": bool(rows) and not duplicate_action_ids,
        "registry_key": _sha1_payload({"logical_action_id": action_id, "attempts": rows})[:16],
        "attempts": rows,
    }


def build_cache_invalidation_policy(
    *,
    cache_key: str = "",
    current_screenshot_hash: str = "",
    cached_screenshot_hash: str = "",
    crop_settings: Mapping[str, Any] | None = None,
    cached_crop_settings: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    current_crop = dict(crop_settings or {})
    cached_crop = dict(cached_crop_settings or {})
    hash_changed = bool(cached_screenshot_hash) and bool(current_screenshot_hash) and cached_screenshot_hash != current_screenshot_hash
    crop_changed = bool(current_crop or cached_crop) and current_crop != cached_crop
    should_invalidate = bool(hash_changed or crop_changed or not cache_key)
    if not cache_key:
        reason = "missing_cache_key"
    elif hash_changed and crop_changed:
        reason = "screenshot_hash_and_crop_changed"
    elif hash_changed:
        reason = "screenshot_hash_changed"
    elif crop_changed:
        reason = "crop_settings_changed"
    else:
        reason = "cache_valid"
    return {
        "schema_version": SCHEMA_VERSION,
        "cache_key": str(cache_key or "").strip(),
        "should_invalidate": should_invalidate,
        "reason": reason,
        "signals": {
            "hash_changed": hash_changed,
            "crop_changed": crop_changed,
            "has_cached_hash": bool(cached_screenshot_hash),
        },
    }


def build_qa_cache_compatibility_check(
    *,
    qa_cache: Mapping[str, Any] | None,
    expected_schema_version: str = SCHEMA_VERSION,
) -> Dict[str, Any]:
    cache = dict(qa_cache or {}) if isinstance(qa_cache, Mapping) else {}
    items = cache.get("items") if isinstance(cache.get("items"), Mapping) else {}
    cache_schema_version = str(cache.get("schema_version") or "").strip()
    has_items = bool(items)
    version_ok = not cache_schema_version or cache_schema_version == str(expected_schema_version).strip()
    compatible = bool(has_items and version_ok)
    if not cache_schema_version:
        reason = "missing_schema_version"
    elif not version_ok:
        reason = "schema_version_mismatch"
    elif not has_items:
        reason = "missing_items"
    else:
        reason = "compatible"
    return {
        "schema_version": SCHEMA_VERSION,
        "expected_schema_version": str(expected_schema_version).strip(),
        "cache_schema_version": cache_schema_version,
        "is_compatible": compatible,
        "reason": reason,
        "signals": {
            "has_items": has_items,
            "version_ok": version_ok,
        },
    }


def build_screen_to_domain_mapping(
    *,
    screen_state: Mapping[str, Any] | None,
    page_state: Mapping[str, Any] | None = None,
    controls_data: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    active = _active_block(screen_state)
    return {
        "schema_version": SCHEMA_VERSION,
        "question": {
            "qid": _first_nonempty(
                ((controls_data or {}).get("meta") or {}).get("qid") if isinstance((controls_data or {}).get("meta"), Mapping) else "",
                (page_state or {}).get("qid"),
            ),
            "signature": _first_nonempty((screen_state or {}).get("active_question_signature"), active.get("question_signature")),
            "prompt_text": _first_nonempty(active.get("prompt_text"), (screen_state or {}).get("question_text")),
        },
        "answers": [
            {
                "text": _first_nonempty(item.get("text"), item.get("label"), item.get("value")),
                "bbox": list(item.get("bbox") or []),
                "domain_role": "answer_option",
            }
            for item in (active.get("answers") or active.get("options") or [])
            if isinstance(item, Mapping)
        ],
        "navigation": {
            "next_bbox": active.get("next_bbox") or (page_state or {}).get("next_bbox") or (page_state or {}).get("nextBbox"),
            "back_bbox": active.get("back_bbox") or (page_state or {}).get("backBbox"),
            "draft_bbox": active.get("draft_bbox") or (page_state or {}).get("draftBbox"),
            "select_bbox": active.get("select_bbox") or (page_state or {}).get("selectBbox"),
            "input_bbox": active.get("input_bbox") or (page_state or {}).get("textboxBbox"),
        },
    }


def detect_blank_screen(
    *,
    screen_state: Mapping[str, Any] | None = None,
    page_state: Mapping[str, Any] | None = None,
    image_stats: Mapping[str, Any] | None = None,
    ocr_rows: Sequence[Mapping[str, Any] | str] | None = None,
) -> Dict[str, Any]:
    screen = screen_state or {}
    page = page_state or {}
    mean = float((image_stats or {}).get("mean") or 0.0)
    std = float((image_stats or {}).get("std") or 0.0)
    text_items = []
    for row in ocr_rows or []:
        if isinstance(row, Mapping):
            text_items.append(_first_nonempty(row.get("text")))
        else:
            text_items.append(str(row or ""))
    text_blob = " ".join(filter(None, text_items + [_first_nonempty(page.get("pageText"), screen.get("question_text"))]))
    lowered = _norm_text(text_blob)
    reasons: List[str] = []
    kind = "not_blank"
    if mean <= 6.0 and std <= 4.0 and not lowered:
        kind = "black_screen"
        reasons.append("dark_low_variance")
    elif mean >= 249.0 and std <= 4.5 and not lowered:
        kind = "white_screen"
        reasons.append("bright_low_variance")
    elif any(token in lowered for token in ("loading", "please wait", "ładowanie", "loader")) and not screen.get("active_question_signature"):
        kind = "loader_only"
        reasons.append("loader_text_without_question")
    elif not lowered and not screen.get("active_question_signature") and not page.get("qid"):
        kind = "empty_screen"
        reasons.append("no_text_or_question")
    confidence = 0.0 if kind == "not_blank" else (0.93 if "low_variance" in "".join(reasons) else 0.81)
    return {
        "schema_version": SCHEMA_VERSION,
        "is_blank": kind != "not_blank",
        "kind": kind,
        "confidence": round(confidence, 4),
        "reasons": reasons,
    }


def build_broken_screen_shape_guard(screen_state: Mapping[str, Any] | None) -> Dict[str, Any]:
    active = _active_block(screen_state)
    issues: List[str] = []
    answers = active.get("answers") or active.get("options") or []
    has_prompt = bool(_first_nonempty(active.get("prompt_text"), (screen_state or {}).get("question_text")))
    has_controls = bool(answers or active.get("input_bbox") or active.get("select_bbox") or active.get("next_bbox"))
    if answers and not has_prompt:
        issues.append("answers_without_prompt")
    if has_prompt and not has_controls:
        issues.append("prompt_without_controls")
    if (screen_state or {}).get("control_kind") == "text" and not active.get("input_bbox"):
        issues.append("text_without_input_bbox")
    if (screen_state or {}).get("control_kind", "").startswith("dropdown") and not active.get("select_bbox"):
        issues.append("dropdown_without_select_bbox")
    return {
        "schema_version": SCHEMA_VERSION,
        "is_broken": bool(issues),
        "issues": issues,
        "severity": "error" if issues else "ok",
    }


def build_empty_signal_identity(
    *,
    screen_state: Mapping[str, Any] | None = None,
    page_state: Mapping[str, Any] | None = None,
    ocr_rows: Sequence[Mapping[str, Any] | str] | None = None,
    target_rows: Sequence[Mapping[str, Any] | str] | None = None,
    network_rows: Sequence[Mapping[str, Any] | str] | None = None,
    blank_screen_detection: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    screen = dict(screen_state or {})
    page = dict(page_state or {})
    blank = dict(blank_screen_detection or {})
    ocr_count = len([row for row in (ocr_rows or []) if row])
    target_count = len([row for row in (target_rows or []) if row])
    network_count = len([row for row in (network_rows or []) if row])
    question_text = str(_first_nonempty(screen.get("question_text"), page.get("pageText"), "")).strip()
    is_blank = bool(blank.get("is_blank"))

    empty_kind = "signal_present"
    reasons: List[str] = []
    if is_blank:
        empty_kind = "empty_screenshot"
        reasons.append("blank_screen_detected")
    elif ocr_count == 0:
        empty_kind = "missing_ocr"
        reasons.append("no_ocr_rows")
    elif target_count == 0:
        empty_kind = "missing_targets"
        reasons.append("no_target_rows")
    elif network_count == 0:
        empty_kind = "missing_network_events"
        reasons.append("no_network_rows")
    elif not question_text:
        empty_kind = "missing_question_text"
        reasons.append("no_question_text")

    identity_id = _sha1_payload(
        {
            "empty_kind": empty_kind,
            "ocr_count": ocr_count,
            "target_count": target_count,
            "network_count": network_count,
            "is_blank": is_blank,
            "question_text": question_text,
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "identity_id": identity_id,
        "empty_kind": empty_kind,
        "ocr_count": ocr_count,
        "target_count": target_count,
        "network_event_count": network_count,
        "has_question_text": bool(question_text),
        "is_empty_signal": empty_kind != "signal_present",
        "reasons": reasons,
        "should_warn": empty_kind != "signal_present",
        "should_block": empty_kind in {"empty_screenshot", "missing_ocr"},
    }


def build_evidence_absence_taxonomy(
    *,
    absence_rows: Sequence[Mapping[str, Any] | str] | None = None,
    evidence_identity: Mapping[str, Any] | None = None,
    ignorance_packet: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    identity = dict(evidence_identity or {})
    ignorance = dict(ignorance_packet or {})
    rows: List[Dict[str, Any]] = []
    counts = {"no_data": 0, "low_data": 0, "corrupted_data": 0, "contradictory_data": 0, "hidden_data": 0}

    def _classify(text: str, payload: Mapping[str, Any]) -> str:
        lowered = text.lower()
        if bool(payload.get("is_corrupted")) or any(token in lowered for token in ("corrupt", "broken", "garbled", "invalid")):
            return "corrupted_data"
        if bool(payload.get("is_contradictory")) or any(token in lowered for token in ("contradict", "conflict", "mismatch", "inconsistent")):
            return "contradictory_data"
        if bool(payload.get("is_hidden")) or any(token in lowered for token in ("hidden", "masked", "redacted", "obscured")):
            return "hidden_data"
        if bool(payload.get("is_low")) or any(token in lowered for token in ("low", "sparse", "partial", "limited")):
            return "low_data"
        return "no_data"

    for idx, row in enumerate(absence_rows or [], start=1):
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip()
            payload = {"name": text} if text else {}
        name = str(_first_nonempty(payload.get("name"), payload.get("reason"), payload.get("kind"), f"absence_{idx}")).strip()
        kind = _classify(name, payload)
        counts[kind] = int(counts.get(kind, 0) + 1)
        rows.append(
            {
                "name": name,
                "kind": kind,
                "reason": str(_first_nonempty(payload.get("reason"), payload.get("status"), name)),
            }
        )

    unknown_rows = [str(item or "").strip() for item in (ignorance.get("unknown_items") or ignorance.get("rows") or []) if str(item or "").strip()]
    if not rows and not unknown_rows and not identity:
        reason = "evidence_absence_taxonomy_incomplete"
    elif counts["no_data"] or counts["low_data"] or counts["corrupted_data"] or counts["contradictory_data"] or counts["hidden_data"]:
        reason = "evidence_absence_taxonomy_classified"
    else:
        reason = "evidence_absence_taxonomy_empty"
    taxonomy_id = _sha1_payload(
        {
            "rows": rows,
            "unknown_rows": unknown_rows,
            "evidence_identity_id": identity.get("evidence_identity_id", ""),
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "taxonomy_id": taxonomy_id,
        "rows": rows,
        "counts": counts,
        "unknown_rows": unknown_rows,
        "evidence_identity_id": identity.get("evidence_identity_id", ""),
        "is_classified": bool(rows),
        "should_warn": bool(rows) or bool(unknown_rows),
        "should_block": counts["corrupted_data"] > 0 or counts["contradictory_data"] > 0,
        "reason": reason,
    }


def build_ignorance_contract(
    *,
    signal_rows: Sequence[Mapping[str, Any] | str] | None = None,
    selected_outcome: str | None = None,
    evidence_absence_taxonomy: Mapping[str, Any] | None = None,
    min_signal_count: int = 1,
) -> Dict[str, Any]:
    taxonomy = dict(evidence_absence_taxonomy or {})
    rows = [row for row in (signal_rows or []) if row]
    signal_count = len(rows)
    selected = str(_first_nonempty(selected_outcome, taxonomy.get("selected_outcome"), "nie_wiem")).strip().lower()
    allowed_outcomes = ["nie_wiem", "defer", "observe_more"]
    zero_signal = signal_count < max(1, int(min_signal_count or 0))
    if zero_signal and selected not in allowed_outcomes:
        reason = "ignorance_contract_forced_action_blocked"
    elif zero_signal:
        reason = "ignorance_contract_zero_signal_allowed"
    else:
        reason = "ignorance_contract_signal_present"
    return {
        "schema_version": SCHEMA_VERSION,
        "contract_id": _sha1_payload(
            {
                "signal_count": signal_count,
                "selected_outcome": selected,
                "taxonomy_id": taxonomy.get("taxonomy_id", ""),
            }
        )[:16],
        "signal_count": signal_count,
        "selected_outcome": selected,
        "allowed_outcomes": allowed_outcomes,
        "zero_signal": zero_signal,
        "should_warn": zero_signal,
        "should_block": zero_signal and selected not in allowed_outcomes,
        "reason": reason,
    }


def build_sparse_context_hint(
    *,
    evidence_identity: Mapping[str, Any] | None = None,
    evidence_absence_taxonomy: Mapping[str, Any] | None = None,
    ignorance_contract: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    identity = dict(evidence_identity or {})
    taxonomy = dict(evidence_absence_taxonomy or {})
    ignorance = dict(ignorance_contract or {})
    sparse_score = 0
    sparse_score += 1 if not identity else 0
    sparse_score += 1 if taxonomy.get("should_warn") else 0
    sparse_score += 1 if ignorance.get("should_warn") else 0
    sparse_score += 1 if ignorance.get("should_block") else 0
    context_state = "adequate"
    if sparse_score >= 3:
        context_state = "sparse"
    elif sparse_score >= 1:
        context_state = "partial"
    return {
        "schema_version": SCHEMA_VERSION,
        "hint_id": _sha1_payload(
            {
                "evidence_identity_id": identity.get("evidence_identity_id", ""),
                "taxonomy_id": taxonomy.get("taxonomy_id", ""),
                "contract_id": ignorance.get("contract_id", ""),
                "context_state": context_state,
            }
        )[:16],
        "context_state": context_state,
        "sparse_score": sparse_score,
        "should_defer": context_state != "adequate",
        "should_observe_more": context_state != "adequate" or bool(ignorance.get("should_block")),
        "reason": "sparse_context_hint_" + context_state,
    }


def build_degenerate_merge_detector(
    *,
    merged_rows: Sequence[Mapping[str, Any] | str] | None = None,
    merge_identity: Mapping[str, Any] | None = None,
    evidence_absence_taxonomy: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    identity = dict(merge_identity or {})
    taxonomy = dict(evidence_absence_taxonomy or {})
    rows: List[Dict[str, Any]] = []
    counts = {"duplicate": 0, "overlap": 0, "conflict": 0, "unknown": 0}
    seen_names: Set[str] = set()
    for idx, row in enumerate(merged_rows or [], start=1):
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip()
            payload = {"name": text} if text else {}
        name = str(_first_nonempty(payload.get("name"), payload.get("reason"), payload.get("kind"), f"merge_{idx}")).strip()
        lowered = name.lower()
        kind = "unknown"
        if name in seen_names or bool(payload.get("is_duplicate")):
            kind = "duplicate"
        elif bool(payload.get("is_overlapping")) or any(token in lowered for token in ("overlap", "merged", "combine")):
            kind = "overlap"
        elif bool(payload.get("is_conflicting")) or any(token in lowered for token in ("conflict", "contradict", "mismatch")):
            kind = "conflict"
        seen_names.add(name)
        counts[kind] = int(counts.get(kind, 0) + 1)
        rows.append(
            {
                "name": name,
                "kind": kind,
                "reason": str(_first_nonempty(payload.get("reason"), payload.get("status"), name)),
            }
        )
    if not rows and not identity and not taxonomy:
        reason = "degenerate_merge_detector_incomplete"
    elif counts["duplicate"] or counts["overlap"] or counts["conflict"]:
        reason = "degenerate_merge_detector_degenerate"
    else:
        reason = "degenerate_merge_detector_clean"
    return {
        "schema_version": SCHEMA_VERSION,
        "merge_id": _sha1_payload(
            {
                "rows": rows,
                "merge_identity_id": identity.get("merge_id", identity.get("identity_id", "")),
                "taxonomy_id": taxonomy.get("taxonomy_id", ""),
            }
        )[:16],
        "rows": rows,
        "counts": counts,
        "merge_identity_id": identity.get("merge_id", identity.get("identity_id", "")),
        "should_warn": bool(rows),
        "should_block": bool(counts["duplicate"] or counts["overlap"] or counts["conflict"]),
        "reason": reason,
    }


def build_silent_failure_classifier(
    *,
    ui_events: Sequence[Mapping[str, Any] | str] | None = None,
    network_events: Sequence[Mapping[str, Any] | str] | None = None,
    heartbeat_events: Sequence[Mapping[str, Any] | str] | None = None,
    is_hung: bool | None = None,
) -> Dict[str, Any]:
    ui_count = len([row for row in (ui_events or []) if row])
    network_count = len([row for row in (network_events or []) if row])
    heartbeat_count = len([row for row in (heartbeat_events or []) if row])
    silence_count = ui_count + network_count + heartbeat_count
    hung = bool(is_hung) if is_hung is not None else silence_count == 0
    if silence_count == 0 and hung:
        failure_kind = "pipeline_hang"
        reason = "silent_failure_pipeline_hang"
    elif silence_count == 0:
        failure_kind = "quiet_idle"
        reason = "silent_failure_quiet_idle"
    elif hung:
        failure_kind = "partial_silence"
        reason = "silent_failure_partial_silence"
    else:
        failure_kind = "active"
        reason = "silent_failure_active"
    return {
        "schema_version": SCHEMA_VERSION,
        "failure_id": _sha1_payload(
            {
                "ui_count": ui_count,
                "network_count": network_count,
                "heartbeat_count": heartbeat_count,
                "failure_kind": failure_kind,
            }
        )[:16],
        "ui_count": ui_count,
        "network_count": network_count,
        "heartbeat_count": heartbeat_count,
        "failure_kind": failure_kind,
        "is_silent_failure": failure_kind in {"pipeline_hang", "partial_silence", "quiet_idle"},
        "should_warn": failure_kind != "active",
        "should_block": failure_kind == "pipeline_hang",
        "reason": reason,
    }


def build_low_evidence_action_cap(
    *,
    evidence_rows: Sequence[Mapping[str, Any] | str] | None = None,
    trust_tier: str = "",
    max_action_count: int = 2,
    min_evidence_count: int = 2,
) -> Dict[str, Any]:
    rows = [row for row in (evidence_rows or []) if row]
    evidence_count = len(rows)
    tier = str(trust_tier or "").strip().lower()
    capped_tiers = {"low", "minimal", "unknown", ""}
    capped = evidence_count < max(1, int(min_evidence_count or 0)) or tier in capped_tiers
    action_cap = 1 if capped else max(1, int(max_action_count or 0))
    canonical_actions = ["observe_more", "defer", "ask_lead", "proceed"]
    permitted_actions = canonical_actions[: min(len(canonical_actions), action_cap)]
    if capped:
        reason = "low_evidence_action_cap_applied"
    else:
        reason = "low_evidence_action_cap_not_needed"
    return {
        "schema_version": SCHEMA_VERSION,
        "cap_id": _sha1_payload(
            {
                "evidence_count": evidence_count,
                "trust_tier": tier,
                "action_cap": action_cap,
            }
        )[:16],
        "evidence_count": evidence_count,
        "trust_tier": tier,
        "action_cap": action_cap,
        "permitted_actions": permitted_actions,
        "is_capped": capped,
        "should_warn": capped,
        "should_block": capped and evidence_count == 0,
        "reason": reason,
    }


def build_observe_more_budget_policy(
    *,
    evidence_rows: Sequence[Mapping[str, Any] | str] | None = None,
    observe_count: int = 0,
    max_observe_count: int = 2,
    has_refresh_signal: bool = False,
) -> Dict[str, Any]:
    rows = [row for row in (evidence_rows or []) if row]
    evidence_count = len(rows)
    count = max(0, int(observe_count or 0))
    limit = max(0, int(max_observe_count or 0))
    budget_remaining = max(0, limit - count)
    if has_refresh_signal and evidence_count == 0:
        outcome = "refresh_artifacts"
        reason = "refresh_signal_without_evidence"
    elif budget_remaining > 0:
        outcome = "allow_observe_more"
        reason = "budget_remaining"
    else:
        outcome = "force_defer"
        reason = "observe_budget_exhausted"
    return {
        "schema_version": SCHEMA_VERSION,
        "budget_id": _sha1_payload(
            {
                "evidence_count": evidence_count,
                "observe_count": count,
                "max_observe_count": limit,
            }
        )[:16],
        "evidence_count": evidence_count,
        "observe_count": count,
        "max_observe_count": limit,
        "budget_remaining": budget_remaining,
        "outcome": outcome,
        "should_observe_more": outcome == "allow_observe_more",
        "should_force_defer": outcome == "force_defer",
        "should_refresh": outcome == "refresh_artifacts",
        "reason": reason,
    }


def build_local_vs_global_unknown_splitter(
    *,
    unknown_state_packet: Mapping[str, Any] | None = None,
    gap_key_hint: str = "",
    target_scope: str = "",
) -> Dict[str, Any]:
    packet = dict(unknown_state_packet or {})
    hint = str(gap_key_hint or "").strip().lower()
    scope_hint = str(target_scope or "").strip().lower()
    rows: List[Dict[str, Any]] = []
    local_count = 0
    global_count = 0
    for idx, row in enumerate(packet.get("rows") or packet.get("unknown_items") or [], start=1):
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip()
            payload = {"name": text} if text else {}
        name = str(_first_nonempty(payload.get("name"), payload.get("reason"), payload.get("kind"), f"unknown_{idx}")).strip()
        lowered = name.lower()
        kind = "global" if any(token in lowered for token in ("global", "whole", "entire", "all")) else "local"
        if bool(payload.get("is_global")):
            kind = "global"
        if bool(payload.get("is_local")):
            kind = "local"
        if kind == "global":
            global_count += 1
        else:
            local_count += 1
        rows.append({"name": name, "kind": kind, "reason": str(_first_nonempty(payload.get("reason"), name))})
    if scope_hint == "global" or global_count > local_count:
        selected_scope = "global"
    elif scope_hint == "local" or local_count > 0:
        selected_scope = "local"
    else:
        selected_scope = "unknown"
    return {
        "schema_version": SCHEMA_VERSION,
        "split_id": _sha1_payload(
            {
                "rows": rows,
                "hint": hint,
                "selected_scope": selected_scope,
            }
        )[:16],
        "rows": rows,
        "local_count": local_count,
        "global_count": global_count,
        "selected_scope": selected_scope,
        "should_promote_global": selected_scope == "global",
        "should_promote_local": selected_scope == "local",
        "reason": "local_vs_global_unknown_splitter_" + selected_scope,
    }


def build_unknown_state_packet(
    *,
    unknown_rows: Sequence[Mapping[str, Any] | str] | None = None,
    attempts: Sequence[Mapping[str, Any] | str] | None = None,
    fallback_rows: Sequence[Mapping[str, Any] | str] | None = None,
    gap_key_hint: str = "",
) -> Dict[str, Any]:
    rows: List[Dict[str, Any]] = []
    attempt_rows: List[Dict[str, Any]] = []
    fallbacks: List[Dict[str, Any]] = []
    for idx, row in enumerate(unknown_rows or [], start=1):
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip()
            payload = {"name": text} if text else {}
        name = str(_first_nonempty(payload.get("name"), payload.get("reason"), payload.get("kind"), f"unknown_{idx}")).strip()
        rows.append({"name": name, "reason": str(_first_nonempty(payload.get("reason"), name))})
    for idx, row in enumerate(attempts or [], start=1):
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip()
            payload = {"name": text} if text else {}
        name = str(_first_nonempty(payload.get("name"), payload.get("reason"), payload.get("kind"), f"attempt_{idx}")).strip()
        attempt_rows.append({"name": name, "reason": str(_first_nonempty(payload.get("reason"), name))})
    for idx, row in enumerate(fallback_rows or [], start=1):
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip()
            payload = {"name": text} if text else {}
        name = str(_first_nonempty(payload.get("name"), payload.get("reason"), payload.get("kind"), f"fallback_{idx}")).strip()
        fallbacks.append({"name": name, "reason": str(_first_nonempty(payload.get("reason"), name))})
    unknown_count = len(rows)
    attempt_count = len(attempt_rows)
    fallback_count = len(fallbacks)
    if unknown_count == 0 and attempt_count == 0 and fallback_count == 0:
        recommendation = "observe_more"
        reason = "unknown_state_packet_empty"
    elif unknown_count > attempt_count + fallback_count:
        recommendation = "observe_more"
        reason = "unknown_state_packet_needs_more_signal"
    elif fallback_count > 0:
        recommendation = "defer"
        reason = "unknown_state_packet_has_fallbacks"
    else:
        recommendation = "escalate"
        reason = "unknown_state_packet_requires_lead_attention"
    return {
        "schema_version": SCHEMA_VERSION,
        "packet_id": _sha1_payload(
            {
                "unknown_rows": rows,
                "attempts": attempt_rows,
                "fallback_rows": fallbacks,
                "gap_key_hint": str(gap_key_hint or "").strip().lower(),
            }
        )[:16],
        "unknown_rows": rows,
        "attempts": attempt_rows,
        "fallback_rows": fallbacks,
        "unknown_count": unknown_count,
        "attempt_count": attempt_count,
        "fallback_count": fallback_count,
        "recommendation": recommendation,
        "should_observe_more": recommendation == "observe_more",
        "should_defer": recommendation == "defer",
        "should_escalate": recommendation == "escalate",
        "reason": reason,
    }


def build_ignorance_regression_suite(
    *,
    failing_runs: Sequence[Mapping[str, Any] | str] | None = None,
    passing_runs: Sequence[Mapping[str, Any] | str] | None = None,
    min_failures: int = 1,
) -> Dict[str, Any]:
    failing: List[Dict[str, Any]] = []
    passing: List[Dict[str, Any]] = []
    for idx, row in enumerate(failing_runs or [], start=1):
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip()
            payload = {"name": text} if text else {}
        name = str(_first_nonempty(payload.get("profile"), payload.get("name"), payload.get("reason"), f"fail_{idx}")).strip()
        failing.append({"name": name, "reason": str(_first_nonempty(payload.get("reason"), name))})
    for idx, row in enumerate(passing_runs or [], start=1):
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip()
            payload = {"name": text} if text else {}
        name = str(_first_nonempty(payload.get("profile"), payload.get("name"), payload.get("reason"), f"pass_{idx}")).strip()
        passing.append({"name": name, "reason": str(_first_nonempty(payload.get("reason"), name))})
    failing_count = len(failing)
    passing_count = len(passing)
    min_needed = max(1, int(min_failures or 0))
    is_regressed = failing_count >= min_needed and failing_count >= passing_count
    reason = "ignorance_regression_suite_regressed" if is_regressed else "ignorance_regression_suite_stable"
    return {
        "schema_version": SCHEMA_VERSION,
        "suite_id": _sha1_payload(
            {
                "failing_runs": failing,
                "passing_runs": passing,
                "min_failures": min_needed,
            }
        )[:16],
        "failing_runs": failing,
        "passing_runs": passing,
        "failing_count": failing_count,
        "passing_count": passing_count,
        "min_failures": min_needed,
        "is_regressed": is_regressed,
        "should_warn": failing_count > 0,
        "should_block": is_regressed,
        "reason": reason,
    }


def build_unknown_vs_broken_app_splitter(
    *,
    evidence_absence_taxonomy: Mapping[str, Any] | None = None,
    silent_failure_classifier: Mapping[str, Any] | None = None,
    unknown_state_packet: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    taxonomy = dict(evidence_absence_taxonomy or {})
    silent = dict(silent_failure_classifier or {})
    packet = dict(unknown_state_packet or {})
    unknown_count = int(len(taxonomy.get("rows") or packet.get("unknown_rows") or []))
    broken_signal = bool(silent.get("should_block")) or str(silent.get("failure_kind") or "").strip().lower() == "pipeline_hang"
    if broken_signal and unknown_count > 0:
        split = "mixed"
    elif broken_signal:
        split = "broken_app"
    elif unknown_count > 0 or packet.get("recommendation") in {"observe_more", "defer"}:
        split = "unknown_state"
    else:
        split = "clear_state"
    return {
        "schema_version": SCHEMA_VERSION,
        "split_id": _sha1_payload(
            {
                "unknown_count": unknown_count,
                "broken_signal": broken_signal,
                "split": split,
            }
        )[:16],
        "unknown_count": unknown_count,
        "broken_signal": broken_signal,
        "split": split,
        "is_unknown": split in {"unknown_state", "mixed"},
        "is_broken_app": split in {"broken_app", "mixed"},
        "reason": "unknown_vs_broken_app_splitter_" + split,
    }


def build_sparse_evidence_replay_bundle(
    *,
    probe_rows: Sequence[Mapping[str, Any] | str] | None = None,
    fallback_rows: Sequence[Mapping[str, Any] | str] | None = None,
    failed_paths: Sequence[Mapping[str, Any] | str] | None = None,
) -> Dict[str, Any]:
    def _collect(rows: Sequence[Mapping[str, Any] | str] | None, default_kind: str) -> List[Dict[str, Any]]:
        collected: List[Dict[str, Any]] = []
        for idx, row in enumerate(rows or [], start=1):
            if isinstance(row, Mapping):
                payload = dict(row)
            else:
                text = str(row or "").strip()
                payload = {"name": text} if text else {}
            name = str(_first_nonempty(payload.get("name"), payload.get("reason"), payload.get("kind"), f"{default_kind}_{idx}")).strip()
            collected.append({"name": name, "reason": str(_first_nonempty(payload.get("reason"), name))})
        return collected

    probes = _collect(probe_rows or [], "probe")
    fallbacks = _collect(fallback_rows or [], "fallback")
    failed = _collect(failed_paths or [], "failed")
    replay_count = len(probes) + len(fallbacks) + len(failed)
    if failed:
        outcome = "replay"
        reason = "sparse_evidence_replay_bundle_failed_paths"
    elif replay_count == 0:
        outcome = "missing"
        reason = "sparse_evidence_replay_bundle_empty"
    else:
        outcome = "capture"
        reason = "sparse_evidence_replay_bundle_captures_sparse_signal"
    return {
        "schema_version": SCHEMA_VERSION,
        "bundle_id": _sha1_payload(
            {
                "probes": probes,
                "fallbacks": fallbacks,
                "failed": failed,
            }
        )[:16],
        "probes": probes,
        "fallbacks": fallbacks,
        "failed_paths": failed,
        "probe_count": len(probes),
        "fallback_count": len(fallbacks),
        "failed_path_count": len(failed),
        "outcome": outcome,
        "should_replay": outcome == "replay",
        "should_capture": outcome == "capture",
        "reason": reason,
    }


def build_knowledge_snapshot_identity(
    *,
    repo_commit: str = "",
    tree_version: str = "",
    active_artifacts: Sequence[Mapping[str, Any] | str] | None = None,
    contract_versions: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    artifacts: List[Dict[str, Any]] = []
    for idx, row in enumerate(active_artifacts or [], start=1):
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip()
            payload = {"name": text} if text else {}
        name = str(_first_nonempty(payload.get("name"), payload.get("artifact"), payload.get("kind"), f"artifact_{idx}")).strip()
        artifacts.append({"name": name, "reason": str(_first_nonempty(payload.get("reason"), name))})
    versions = dict(contract_versions or {})
    complete = bool(str(repo_commit or "").strip()) and bool(str(tree_version or "").strip()) and bool(artifacts) and bool(versions)
    return {
        "schema_version": SCHEMA_VERSION,
        "snapshot_id": _sha1_payload(
            {
                "repo_commit": str(repo_commit or "").strip(),
                "tree_version": str(tree_version or "").strip(),
                "artifacts": artifacts,
                "contract_versions": versions,
            }
        )[:16],
        "repo_commit": str(repo_commit or "").strip(),
        "tree_version": str(tree_version or "").strip(),
        "active_artifacts": artifacts,
        "contract_versions": versions,
        "is_complete": complete,
        "should_warn": not complete,
        "should_block": not complete,
        "reason": "knowledge_snapshot_identity_complete" if complete else "knowledge_snapshot_identity_incomplete",
    }


def build_context_version_stamp(
    *,
    task_context: Mapping[str, Any] | None = None,
    report_context: Mapping[str, Any] | None = None,
    replay_context: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    task = dict(task_context or {})
    report = dict(report_context or {})
    replay = dict(replay_context or {})
    task_version = str(_first_nonempty(task.get("version"), task.get("snapshot_version"), ""))
    report_version = str(_first_nonempty(report.get("version"), report.get("snapshot_version"), ""))
    replay_version = str(_first_nonempty(replay.get("version"), replay.get("snapshot_version"), ""))
    aligned_versions = [version for version in (task_version, report_version, replay_version) if version]
    aligned = len(aligned_versions) >= 2 and len(set(aligned_versions)) == 1
    status = "aligned" if aligned else ("partial" if aligned_versions else "missing")
    return {
        "schema_version": SCHEMA_VERSION,
        "stamp_id": _sha1_payload(
            {
                "task_version": task_version,
                "report_version": report_version,
                "replay_version": replay_version,
            }
        )[:16],
        "task_version": task_version,
        "report_version": report_version,
        "replay_version": replay_version,
        "status": status,
        "is_aligned": aligned,
        "should_warn": status != "aligned",
        "should_block": status == "missing",
        "reason": "context_version_stamp_" + status,
    }


def build_agent_context_fingerprint(
    *,
    task_scope: Mapping[str, Any] | None = None,
    knowledge_snapshot: Mapping[str, Any] | None = None,
    runtime_state: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    scope = dict(task_scope or {})
    snapshot = dict(knowledge_snapshot or {})
    runtime = dict(runtime_state or {})
    scope_name = str(_first_nonempty(scope.get("name"), scope.get("scope"), scope.get("id"), "")).strip()
    snapshot_id = str(_first_nonempty(snapshot.get("snapshot_id"), snapshot.get("identity_id"), "")).strip()
    runtime_version = str(_first_nonempty(runtime.get("version"), runtime.get("snapshot_version"), "")).strip()
    ready = bool(scope_name) and bool(snapshot_id) and bool(runtime_version)
    return {
        "schema_version": SCHEMA_VERSION,
        "fingerprint_id": _sha1_payload(
            {
                "scope_name": scope_name,
                "snapshot_id": snapshot_id,
                "runtime_version": runtime_version,
            }
        )[:16],
        "scope_name": scope_name,
        "snapshot_id": snapshot_id,
        "runtime_version": runtime_version,
        "is_ready": ready,
        "should_warn": not ready,
        "should_block": not ready,
        "reason": "agent_context_fingerprint_ready" if ready else "agent_context_fingerprint_incomplete",
    }


def build_knowledge_minimum_contract(
    *,
    repo_commit: str = "",
    tree_version: str = "",
    contract_versions: Mapping[str, Any] | None = None,
    active_artifacts: Sequence[Mapping[str, Any] | str] | None = None,
) -> Dict[str, Any]:
    versions = dict(contract_versions or {})
    artifacts = [row for row in (active_artifacts or []) if row]
    has_baseline = bool(str(repo_commit or "").strip()) and bool(str(tree_version or "").strip())
    version_count = len(versions)
    artifact_count = len(artifacts)
    is_ready = has_baseline and version_count > 0 and artifact_count > 0
    return {
        "schema_version": SCHEMA_VERSION,
        "minimum_id": _sha1_payload(
            {
                "repo_commit": str(repo_commit or "").strip(),
                "tree_version": str(tree_version or "").strip(),
                "version_count": version_count,
                "artifact_count": artifact_count,
            }
        )[:16],
        "repo_commit": str(repo_commit or "").strip(),
        "tree_version": str(tree_version or "").strip(),
        "version_count": version_count,
        "artifact_count": artifact_count,
        "is_ready": is_ready,
        "should_warn": not is_ready,
        "should_block": not is_ready,
        "reason": "knowledge_minimum_contract_ready" if is_ready else "knowledge_minimum_contract_incomplete",
    }


def build_stale_context_detector(
    *,
    current_context: Mapping[str, Any] | None = None,
    snapshot_context: Mapping[str, Any] | None = None,
    max_age_s: float = 0.0,
) -> Dict[str, Any]:
    current = dict(current_context or {})
    snapshot = dict(snapshot_context or {})
    current_version = str(_first_nonempty(current.get("version"), current.get("snapshot_version"), ""))
    snapshot_version = str(_first_nonempty(snapshot.get("version"), snapshot.get("snapshot_version"), ""))
    age_s = max(0.0, float(_first_nonempty(current.get("age_s"), current.get("age"), 0.0)))
    version_mismatch = bool(current_version and snapshot_version and current_version != snapshot_version)
    stale = version_mismatch or age_s > float(max_age_s or 0.0)
    return {
        "schema_version": SCHEMA_VERSION,
        "stale_id": _sha1_payload(
            {
                "current_version": current_version,
                "snapshot_version": snapshot_version,
                "age_s": round(age_s, 4),
                "max_age_s": round(float(max_age_s or 0.0), 4),
            }
        )[:16],
        "current_version": current_version,
        "snapshot_version": snapshot_version,
        "age_s": round(age_s, 4),
        "max_age_s": round(float(max_age_s or 0.0), 4),
        "version_mismatch": version_mismatch,
        "is_stale": stale,
        "is_fresh": not stale,
        "should_warn": stale,
        "should_block": stale,
        "reason": "stale_context_detector_stale" if stale else "stale_context_detector_fresh",
    }


def build_cross_agent_context_diff(
    *,
    agent_contexts: Sequence[Mapping[str, Any] | str] | None = None,
) -> Dict[str, Any]:
    rows: List[Dict[str, Any]] = []
    versions: Dict[str, List[str]] = {}
    mismatched_agents: List[str] = []
    for idx, row in enumerate(agent_contexts or [], start=1):
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip()
            payload = {"name": text} if text else {}
        agent = str(_first_nonempty(payload.get("agent"), payload.get("name"), payload.get("role"), f"agent_{idx}")).strip()
        version = str(_first_nonempty(payload.get("version"), payload.get("snapshot_version"), "")).strip()
        snapshot_id = str(_first_nonempty(payload.get("snapshot_id"), payload.get("identity_id"), "")).strip()
        rows.append({"agent": agent, "version": version, "snapshot_id": snapshot_id})
        versions.setdefault(version or "missing", []).append(agent)
    if len(versions) > 1:
        for version, agents in versions.items():
            if len(agents) == 1:
                mismatched_agents.extend(agents)
    has_diff = len(versions) > 1
    return {
        "schema_version": SCHEMA_VERSION,
        "diff_id": _sha1_payload({"rows": rows, "versions": versions})[:16],
        "rows": rows,
        "versions": versions,
        "mismatched_agents": mismatched_agents,
        "has_diff": has_diff,
        "should_warn": has_diff,
        "should_block": False,
        "reason": "cross_agent_context_diff_" + ("mismatch" if has_diff else "aligned"),
    }


def build_context_merge_guard(
    *,
    report_packets: Sequence[Mapping[str, Any] | str] | None = None,
    knowledge_snapshot: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    snapshot = dict(knowledge_snapshot or {})
    snapshot_id = str(_first_nonempty(snapshot.get("snapshot_id"), snapshot.get("identity_id"), "")).strip()
    rows: List[Dict[str, Any]] = []
    blocked = False
    for idx, row in enumerate(report_packets or [], start=1):
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip()
            payload = {"name": text} if text else {}
        name = str(_first_nonempty(payload.get("name"), payload.get("reason"), payload.get("kind"), f"report_{idx}")).strip()
        report_snapshot_id = str(_first_nonempty(payload.get("snapshot_id"), payload.get("knowledge_snapshot_id"), "")).strip()
        mismatch = bool(snapshot_id and report_snapshot_id and report_snapshot_id != snapshot_id)
        blocked = blocked or mismatch
        rows.append({"name": name, "snapshot_id": report_snapshot_id, "mismatch": mismatch})
    return {
        "schema_version": SCHEMA_VERSION,
        "guard_id": _sha1_payload({"rows": rows, "snapshot_id": snapshot_id})[:16],
        "snapshot_id": snapshot_id,
        "rows": rows,
        "is_safe_to_merge": not blocked,
        "should_block": blocked,
        "reason": "context_merge_guard_blocked" if blocked else "context_merge_guard_safe",
    }


def build_replay_context_anchor(
    *,
    replay_bundle: Mapping[str, Any] | None = None,
    knowledge_snapshot: Mapping[str, Any] | None = None,
    session_id: str = "",
) -> Dict[str, Any]:
    replay = dict(replay_bundle or {})
    snapshot = dict(knowledge_snapshot or {})
    snapshot_id = str(_first_nonempty(snapshot.get("snapshot_id"), snapshot.get("identity_id"), "")).strip()
    replay_id = str(_first_nonempty(replay.get("bundle_id"), replay.get("replay_id"), "")).strip()
    session = str(session_id or "").strip()
    anchored = bool(snapshot_id) and bool(replay_id) and bool(session)
    return {
        "schema_version": SCHEMA_VERSION,
        "anchor_id": _sha1_payload({"snapshot_id": snapshot_id, "replay_id": replay_id, "session_id": session})[:16],
        "snapshot_id": snapshot_id,
        "replay_id": replay_id,
        "session_id": session,
        "is_anchored": anchored,
        "should_warn": not anchored,
        "should_block": not anchored,
        "reason": "replay_context_anchor_anchored" if anchored else "replay_context_anchor_missing",
    }


def build_context_refresh_policy(
    *,
    current_context: Mapping[str, Any] | None = None,
    snapshot_context: Mapping[str, Any] | None = None,
    open_tasks: Sequence[Mapping[str, Any] | str] | None = None,
) -> Dict[str, Any]:
    current = dict(current_context or {})
    snapshot = dict(snapshot_context or {})
    tasks = [row for row in (open_tasks or []) if row]
    current_version = str(_first_nonempty(current.get("version"), current.get("snapshot_version"), "")).strip()
    snapshot_version = str(_first_nonempty(snapshot.get("version"), snapshot.get("snapshot_version"), "")).strip()
    is_stale = bool(current_version and snapshot_version and current_version != snapshot_version)
    task_count = len(tasks)
    if is_stale and task_count > 0:
        action = "restart_worker"
        reason = "stale_context_with_open_tasks"
    elif is_stale:
        action = "refresh_snapshot"
        reason = "stale_context_without_tasks"
    elif task_count > 0:
        action = "diff_only"
        reason = "fresh_context_with_open_tasks"
    else:
        action = "hold"
        reason = "fresh_context_idle"
    return {
        "schema_version": SCHEMA_VERSION,
        "policy_id": _sha1_payload(
            {
                "current_version": current_version,
                "snapshot_version": snapshot_version,
                "task_count": task_count,
                "action": action,
            }
        )[:16],
        "current_version": current_version,
        "snapshot_version": snapshot_version,
        "task_count": task_count,
        "action": action,
        "should_refresh": action in {"restart_worker", "refresh_snapshot"},
        "should_restart_worker": action == "restart_worker",
        "reason": reason,
    }


def build_tree_version_registry(
    *,
    tree_versions: Sequence[Mapping[str, Any] | str] | None = None,
) -> Dict[str, Any]:
    rows: List[Dict[str, Any]] = []
    seen: Set[str] = set()
    for idx, row in enumerate(tree_versions or [], start=1):
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip()
            payload = {"name": text} if text else {}
        version = str(_first_nonempty(payload.get("version"), payload.get("name"), payload.get("tree_version"), f"tree_{idx}")).strip()
        if version in seen:
            continue
        seen.add(version)
        rows.append(
            {
                "version": version,
                "reason": str(_first_nonempty(payload.get("reason"), payload.get("status"), version)),
                "active": bool(payload.get("active", True)),
            }
        )
    latest_version = rows[-1]["version"] if rows else ""
    return {
        "schema_version": SCHEMA_VERSION,
        "registry_id": _sha1_payload({"rows": rows, "latest_version": latest_version})[:16],
        "rows": rows,
        "latest_version": latest_version,
        "version_count": len(rows),
        "is_empty": not rows,
        "should_warn": not rows,
        "reason": "tree_version_registry_populated" if rows else "tree_version_registry_empty",
    }


def build_evidence_context_compatibility_check(
    *,
    evidence_rows: Sequence[Mapping[str, Any] | str] | None = None,
    current_context: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    context = dict(current_context or {})
    snapshot_version = str(_first_nonempty(context.get("version"), context.get("snapshot_version"), "")).strip()
    rows: List[Dict[str, Any]] = []
    compatible_count = 0
    incompatible_count = 0
    for idx, row in enumerate(evidence_rows or [], start=1):
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip()
            payload = {"name": text} if text else {}
        name = str(_first_nonempty(payload.get("name"), payload.get("reason"), payload.get("kind"), f"evidence_{idx}")).strip()
        evidence_version = str(_first_nonempty(payload.get("version"), payload.get("snapshot_version"), "")).strip()
        compatible = bool(not snapshot_version or not evidence_version or evidence_version == snapshot_version)
        compatible_count += int(compatible)
        incompatible_count += int(not compatible)
        rows.append({"name": name, "version": evidence_version, "compatible": compatible})
    return {
        "schema_version": SCHEMA_VERSION,
        "check_id": _sha1_payload({"rows": rows, "snapshot_version": snapshot_version})[:16],
        "rows": rows,
        "snapshot_version": snapshot_version,
        "compatible_count": compatible_count,
        "incompatible_count": incompatible_count,
        "is_compatible": incompatible_count == 0,
        "should_warn": incompatible_count > 0,
        "should_block": incompatible_count > 0,
        "reason": "evidence_context_compatibility_check_compatible" if incompatible_count == 0 else "evidence_context_compatibility_check_incompatible",
    }


def build_context_trust_decay_model(
    *,
    age_s: float = 0.0,
    evidence_context_compatibility_check: Mapping[str, Any] | None = None,
    max_trust: float = 1.0,
) -> Dict[str, Any]:
    compatibility = dict(evidence_context_compatibility_check or {})
    age = max(0.0, float(age_s or 0.0))
    trust = max(0.0, min(float(max_trust or 1.0), float(max_trust or 1.0) * max(0.0, 1.0 - (age / 20.0))))
    if bool(compatibility.get("should_block")):
        trust *= 0.5
    if age >= 20.0:
        tier = "expired"
    elif age >= 10.0:
        tier = "low"
    elif age >= 3.0:
        tier = "medium"
    else:
        tier = "high"
    if trust <= 0.2:
        confidence_band = "very_low"
    elif trust <= 0.5:
        confidence_band = "low"
    elif trust <= 0.8:
        confidence_band = "medium"
    else:
        confidence_band = "high"
    return {
        "schema_version": SCHEMA_VERSION,
        "model_id": _sha1_payload({"age_s": round(age, 4), "trust": round(trust, 4), "tier": tier})[:16],
        "age_s": round(age, 4),
        "trust": round(trust, 4),
        "tier": tier,
        "confidence_band": confidence_band,
        "should_warn": tier in {"low", "expired"} or bool(compatibility.get("should_warn")),
        "should_block": tier == "expired" or bool(compatibility.get("should_block")),
        "reason": "context_trust_decay_model_" + tier,
    }


def build_mission_identity_contract(
    *,
    mission_name: str = "",
    mission_mode: str = "",
    objective: str = "",
    mission_tags: Sequence[str] | None = None,
) -> Dict[str, Any]:
    name = str(mission_name or "").strip()
    mode = str(mission_mode or "").strip().lower()
    objective_text = str(objective or "").strip()
    tags = [str(tag or "").strip().lower() for tag in (mission_tags or []) if str(tag or "").strip()]
    is_defined = bool(name and mode and objective_text)
    return {
        "schema_version": SCHEMA_VERSION,
        "mission_id": _sha1_payload({"name": name, "mode": mode, "objective": objective_text, "tags": tags})[:16],
        "mission_name": name,
        "mission_mode": mode,
        "objective": objective_text,
        "mission_tags": tags,
        "is_defined": is_defined,
        "should_warn": not is_defined,
        "should_block": not is_defined,
        "reason": "mission_identity_contract_defined" if is_defined else "mission_identity_contract_incomplete",
    }


def build_mission_mode_registry(
    *,
    mission_modes: Sequence[Mapping[str, Any] | str] | None = None,
    active_mode: str = "",
) -> Dict[str, Any]:
    rows: List[Dict[str, Any]] = []
    seen: Set[str] = set()
    active = str(active_mode or "").strip().lower()
    for idx, row in enumerate(mission_modes or [], start=1):
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip()
            payload = {"name": text} if text else {}
        mode = str(_first_nonempty(payload.get("mode"), payload.get("name"), f"mode_{idx}")).strip().lower()
        if mode in seen:
            continue
        seen.add(mode)
        rows.append(
            {
                "mode": mode,
                "reason": str(_first_nonempty(payload.get("reason"), payload.get("description"), mode)),
            }
        )
    registry_modes = [row["mode"] for row in rows]
    valid_active = active in registry_modes if active else bool(registry_modes)
    return {
        "schema_version": SCHEMA_VERSION,
        "registry_id": _sha1_payload({"rows": rows, "active_mode": active})[:16],
        "rows": rows,
        "active_mode": active,
        "mode_count": len(rows),
        "is_valid": valid_active,
        "should_warn": not valid_active,
        "should_block": not valid_active,
        "reason": "mission_mode_registry_valid" if valid_active else "mission_mode_registry_invalid",
    }


def build_mission_context_stamp(
    *,
    mission_identity: Mapping[str, Any] | None = None,
    trace_packet: Mapping[str, Any] | None = None,
    replay_bundle: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    mission = dict(mission_identity or {})
    trace = dict(trace_packet or {})
    replay = dict(replay_bundle or {})
    mission_id = str(_first_nonempty(mission.get("mission_id"), mission.get("identity_id"), "")).strip()
    trace_id = str(_first_nonempty(trace.get("trace_id"), trace.get("packet_id"), "")).strip()
    replay_id = str(_first_nonempty(replay.get("bundle_id"), replay.get("replay_id"), "")).strip()
    aligned = bool(mission_id) and bool(trace_id) and bool(replay_id)
    return {
        "schema_version": SCHEMA_VERSION,
        "stamp_id": _sha1_payload({"mission_id": mission_id, "trace_id": trace_id, "replay_id": replay_id})[:16],
        "mission_id": mission_id,
        "trace_id": trace_id,
        "replay_id": replay_id,
        "is_aligned": aligned,
        "should_warn": not aligned,
        "should_block": not aligned,
        "reason": "mission_context_stamp_aligned" if aligned else "mission_context_stamp_missing",
    }


def build_mission_hint_packet(
    *,
    mission_identity: Mapping[str, Any] | None = None,
    success_criteria: Sequence[str] | None = None,
    prohibited_actions: Sequence[str] | None = None,
) -> Dict[str, Any]:
    mission = dict(mission_identity or {})
    name = str(_first_nonempty(mission.get("mission_name"), mission.get("name"), "")).strip()
    mode = str(_first_nonempty(mission.get("mission_mode"), mission.get("mode"), "")).strip().lower()
    criteria = [str(item or "").strip() for item in (success_criteria or []) if str(item or "").strip()]
    forbidden = [str(item or "").strip().lower() for item in (prohibited_actions or []) if str(item or "").strip()]
    actionable = bool(name and mode and criteria)
    return {
        "schema_version": SCHEMA_VERSION,
        "hint_id": _sha1_payload({"name": name, "mode": mode, "criteria": criteria, "forbidden": forbidden})[:16],
        "mission_name": name,
        "mission_mode": mode,
        "success_criteria": criteria,
        "prohibited_actions": forbidden,
        "is_actionable": actionable,
        "should_warn": not actionable,
        "should_block": not actionable,
        "reason": "mission_hint_packet_actionable" if actionable else "mission_hint_packet_incomplete",
    }


def build_mission_action_allowlist(
    *,
    mission_identity: Mapping[str, Any] | None = None,
    action_registry: Mapping[str, Any] | None = None,
    default_allowed_actions: Sequence[str] | None = None,
) -> Dict[str, Any]:
    mission = dict(mission_identity or {})
    registry = dict(action_registry or {})
    mode = str(_first_nonempty(mission.get("mission_mode"), mission.get("mode"), "")).strip().lower()
    objective = str(_first_nonempty(mission.get("objective"), mission.get("goal"), mission.get("description"), "")).strip().lower()
    mode_actions = registry.get(mode) if isinstance(registry, Mapping) else None
    if not isinstance(mode_actions, Mapping):
        mode_actions = {}
    allowed = [
        str(item or "").strip().lower()
        for item in (
            mode_actions.get("allowed_actions")
            or mode_actions.get("actions")
            or mode_actions.get("allowlist")
            or default_allowed_actions
            or []
        )
        if str(item or "").strip()
    ]
    if not allowed:
        allowed = ["observe", "defer", "escalate"]
    blocked = [
        str(item or "").strip().lower()
        for item in (
            mode_actions.get("blocked_actions")
            or mode_actions.get("disallowed_actions")
            or []
        )
        if str(item or "").strip()
    ]
    action_classes = []
    for action in allowed:
        if action in {"observe", "inspect", "collect", "audit", "trace", "measure", "profile"}:
            action_classes.append({"action": action, "class": "diagnostic"})
        elif action in {"submit", "fix", "advance", "complete", "resume", "continue", "progress"}:
            action_classes.append({"action": action, "class": "progress"})
        elif action in {"defer", "escalate", "wait"}:
            action_classes.append({"action": action, "class": "control"})
        else:
            action_classes.append({"action": action, "class": "other"})

    if mode_actions:
        reason = "mission_action_allowlist_defined"
        should_warn = False
    elif allowed:
        reason = "mission_action_allowlist_defaulted"
        should_warn = True
    else:
        reason = "mission_action_allowlist_missing"
        should_warn = True

    allowlist_id = _sha1_payload(
        {
            "mode": mode,
            "objective": objective,
            "allowed": allowed,
            "blocked": blocked,
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "allowlist_id": allowlist_id,
        "mission_mode": mode,
        "objective": objective,
        "allowed_actions": allowed,
        "blocked_actions": blocked,
        "action_classes": action_classes,
        "is_defined": bool(mode_actions or allowed),
        "should_warn": should_warn,
        "should_block": False,
        "reason": reason,
    }


def build_mission_success_contract(
    *,
    mission_identity: Mapping[str, Any] | None = None,
    observed_outcomes: Sequence[Mapping[str, Any] | str] | None = None,
    mode_rules: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    mission = dict(mission_identity or {})
    rules = dict(mode_rules or {})
    mode = str(_first_nonempty(mission.get("mission_mode"), mission.get("mode"), "")).strip().lower()
    objective = str(_first_nonempty(mission.get("objective"), mission.get("goal"), mission.get("description"), "")).strip().lower()

    default_rules = {
        "exploration": {"success_markers": ["discover", "find", "surface", "observe"], "blocked_markers": ["submit", "finalize"]},
        "forensic": {"success_markers": ["trace", "evidence", "reproduce", "root cause"], "blocked_markers": ["submit"]},
        "smoke": {"success_markers": ["pass", "green", "stable", "complete"], "blocked_markers": ["fail", "broken"]},
        "verify": {"success_markers": ["pass", "green", "stable", "complete"], "blocked_markers": ["fail", "broken"]},
        "calibration": {"success_markers": ["measure", "tune", "calibrate", "profile"], "blocked_markers": ["submit", "finalize"]},
        "evidence": {"success_markers": ["evidence", "trace", "capture", "record"], "blocked_markers": ["submit"]},
    }
    mode_rule = dict(default_rules.get(mode, default_rules["verify"]))
    custom_rule = dict(rules.get(mode) or {})
    success_markers = [
        str(item or "").strip().lower()
        for item in (custom_rule.get("success_markers") or mode_rule.get("success_markers") or [])
        if str(item or "").strip()
    ]
    blocked_markers = [
        str(item or "").strip().lower()
        for item in (custom_rule.get("blocked_markers") or mode_rule.get("blocked_markers") or [])
        if str(item or "").strip()
    ]

    rows: List[Dict[str, Any]] = []
    success_hits = 0
    blocked_hits = 0
    neutral_hits = 0
    for index, outcome in enumerate(observed_outcomes or [], start=1):
        if isinstance(outcome, Mapping):
            payload = dict(outcome)
        else:
            text = str(outcome or "").strip()
            payload = {"name": text} if text else {}
        text_parts = [
            str(payload.get("name") or "").strip().lower(),
            str(payload.get("outcome") or "").strip().lower(),
            str(payload.get("result") or "").strip().lower(),
            str(payload.get("reason") or "").strip().lower(),
            str(payload.get("description") or "").strip().lower(),
            str(payload.get("details") or "").strip().lower(),
        ]
        text = " ".join(part for part in text_parts if part)
        hit_success = any(marker in text for marker in success_markers)
        hit_blocked = any(marker in text for marker in blocked_markers)
        if hit_success and not hit_blocked:
            status = "success"
            success_hits += 1
        elif hit_blocked:
            status = "blocked"
            blocked_hits += 1
        else:
            status = "neutral"
            neutral_hits += 1
        rows.append(
            {
                "index": index,
                "name": str(_first_nonempty(payload.get("name"), payload.get("outcome"), payload.get("result"), f"outcome_{index}")),
                "status": status,
                "text": text,
            }
        )

    total = len(rows)
    success_score = round(success_hits / total, 4) if total else 0.0
    if total == 0:
        reason = "mission_success_contract_empty"
    elif blocked_hits > 0 and success_hits == 0:
        reason = "mission_success_contract_blocked"
    elif success_hits > 0:
        reason = "mission_success_contract_satisfied"
    else:
        reason = "mission_success_contract_partial"

    contract_id = _sha1_payload(
        {
            "mode": mode,
            "objective": objective,
            "success_markers": success_markers,
            "blocked_markers": blocked_markers,
            "rows": rows,
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "contract_id": contract_id,
        "mission_mode": mode,
        "objective": objective,
        "success_markers": success_markers,
        "blocked_markers": blocked_markers,
        "observed_count": total,
        "success_hits": success_hits,
        "blocked_hits": blocked_hits,
        "neutral_hits": neutral_hits,
        "success_score": success_score,
        "reason": reason,
        "is_successful": reason == "mission_success_contract_satisfied",
        "should_warn": reason in {"mission_success_contract_partial", "mission_success_contract_empty"},
        "should_block": reason == "mission_success_contract_blocked",
        "rows": rows,
    }


def build_mission_outcome_interpreter(
    *,
    mission_identity: Mapping[str, Any] | None = None,
    mission_success_contract: Mapping[str, Any] | None = None,
    technical_outcome: Mapping[str, Any] | None = None,
    evidence_rows: Sequence[Mapping[str, Any] | str] | None = None,
) -> Dict[str, Any]:
    mission = dict(mission_identity or {})
    contract = dict(mission_success_contract or {})
    outcome = dict(technical_outcome or {})
    mode = str(_first_nonempty(mission.get("mission_mode"), mission.get("mode"), contract.get("mission_mode"), "")).strip().lower()
    technical_status = str(_first_nonempty(outcome.get("status"), outcome.get("result"), outcome.get("outcome"), contract.get("reason"), "")).strip().lower()
    evidence_count = len([row for row in (evidence_rows or []) if row])
    research_modes = {"exploration", "forensic", "calibration", "evidence"}
    technical_success = technical_status in {"success", "passed", "pass", "green", "complete", "ok"}
    technical_failure = technical_status in {"fail", "failed", "broken", "error", "blocked"}
    mission_success = bool(contract.get("is_successful"))

    if technical_success and mission_success:
        interpretation = "mission_success"
        reason = "mission_outcome_interpreter_success"
    elif technical_failure and mode in research_modes and evidence_count > 0:
        interpretation = "research_success"
        reason = "mission_outcome_interpreter_research_success"
        mission_success = True
    elif technical_failure:
        interpretation = "mission_failure"
        reason = "mission_outcome_interpreter_failure"
        mission_success = False
    elif mission_success:
        interpretation = "mission_success"
        reason = "mission_outcome_interpreter_mission_success"
    else:
        interpretation = "mission_partial"
        reason = "mission_outcome_interpreter_partial"

    interpreter_id = _sha1_payload(
        {
            "mode": mode,
            "technical_status": technical_status,
            "interpretation": interpretation,
            "evidence_count": evidence_count,
            "contract_reason": str(contract.get("reason") or ""),
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "interpreter_id": interpreter_id,
        "mission_mode": mode,
        "technical_status": technical_status,
        "interpretation": interpretation,
        "evidence_count": evidence_count,
        "is_mission_success": mission_success,
        "should_warn": interpretation == "mission_partial",
        "should_block": interpretation == "mission_failure",
        "reason": reason,
    }


def build_objective_scorecard(
    *,
    mission_identity: Mapping[str, Any] | None = None,
    mission_success_contract: Mapping[str, Any] | None = None,
    mission_outcome_interpreter: Mapping[str, Any] | None = None,
    evidence_rows: Sequence[Mapping[str, Any] | str] | None = None,
    observed_outcomes: Sequence[Mapping[str, Any] | str] | None = None,
) -> Dict[str, Any]:
    mission = dict(mission_identity or {})
    contract = dict(mission_success_contract or {})
    interpreter = dict(mission_outcome_interpreter or {})
    mode = str(_first_nonempty(mission.get("mission_mode"), mission.get("mode"), contract.get("mission_mode"), interpreter.get("mission_mode"), "")).strip().lower()
    objective = str(_first_nonempty(mission.get("objective"), mission.get("goal"), mission.get("description"), "")).strip().lower()
    evidence_items = [row for row in (evidence_rows or []) if row]
    outcome_items = [row for row in (observed_outcomes or []) if row]
    mission_success = bool(contract.get("is_successful") or interpreter.get("is_mission_success"))
    success_score = float(contract.get("success_score") or 0.0)
    evidence_count = len(evidence_items)
    outcome_count = len(outcome_items)

    evidence_quality = 0.0
    for row in evidence_items:
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip().lower()
            payload = {"name": text} if text else {}
        text = " ".join(
            part
            for part in [
                str(payload.get("name") or "").strip().lower(),
                str(payload.get("kind") or "").strip().lower(),
                str(payload.get("reason") or "").strip().lower(),
            ]
            if part
        )
        if any(token in text for token in ("evidence", "trace", "record", "log", "capture", "proof")):
            evidence_quality += 1.0
        elif text:
            evidence_quality += 0.5
    evidence_quality = round((evidence_quality / evidence_count) if evidence_count else 0.0, 4)

    risk_flags = []
    for row in outcome_items:
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip().lower()
            payload = {"name": text} if text else {}
        text = " ".join(
            part
            for part in [
                str(payload.get("name") or "").strip().lower(),
                str(payload.get("result") or "").strip().lower(),
                str(payload.get("outcome") or "").strip().lower(),
                str(payload.get("reason") or "").strip().lower(),
            ]
            if part
        )
        if any(token in text for token in ("fail", "broken", "error", "blocked", "drift", "partial")):
            risk_flags.append(text or "risk")

    coverage = round(min(1.0, (evidence_count + outcome_count) / max(1.0, evidence_count + outcome_count + len(risk_flags) + 1)), 4)
    realization = round((success_score + (1.0 if mission_success else 0.0) + evidence_quality) / 3.0, 4)
    if mission_success and not risk_flags:
        status = "objective_scorecard_green"
    elif risk_flags and not mission_success:
        status = "objective_scorecard_red"
    else:
        status = "objective_scorecard_amber"
    scorecard_id = _sha1_payload(
        {
            "mode": mode,
            "objective": objective,
            "evidence_count": evidence_count,
            "outcome_count": outcome_count,
            "risk_flags": risk_flags,
            "coverage": coverage,
            "realization": realization,
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "scorecard_id": scorecard_id,
        "mission_mode": mode,
        "objective": objective,
        "evidence_count": evidence_count,
        "outcome_count": outcome_count,
        "evidence_quality": evidence_quality,
        "coverage": coverage,
        "realization": realization,
        "risk_flags": risk_flags,
        "mission_success": mission_success,
        "status": status,
        "is_complete": status == "objective_scorecard_green",
        "should_warn": status != "objective_scorecard_green",
        "should_block": status == "objective_scorecard_red",
    }


def build_mission_progress_estimator(
    *,
    mission_identity: Mapping[str, Any] | None = None,
    objective_scorecard: Mapping[str, Any] | None = None,
    milestone_rows: Sequence[Mapping[str, Any] | str] | None = None,
) -> Dict[str, Any]:
    mission = dict(mission_identity or {})
    scorecard = dict(objective_scorecard or {})
    mode = str(_first_nonempty(mission.get("mission_mode"), mission.get("mode"), scorecard.get("mission_mode"), "")).strip().lower()
    objective = str(_first_nonempty(mission.get("objective"), mission.get("goal"), mission.get("description"), scorecard.get("objective"), "")).strip().lower()
    rows: List[Dict[str, Any]] = []
    complete_rows: List[Dict[str, Any]] = []
    partial_rows: List[Dict[str, Any]] = []
    blocked_rows: List[Dict[str, Any]] = []

    for index, milestone in enumerate(milestone_rows or [], start=1):
        if isinstance(milestone, Mapping):
            payload = dict(milestone)
        else:
            text = str(milestone or "").strip()
            payload = {"name": text} if text else {}
        name = str(_first_nonempty(payload.get("name"), payload.get("milestone"), payload.get("step"), f"milestone_{index}")).strip()
        text = " ".join(
            part
            for part in [
                name.lower(),
                str(_first_nonempty(payload.get("reason"), payload.get("status"), payload.get("result"), "")).strip().lower(),
                str(_first_nonempty(payload.get("description"), payload.get("details"), "")).strip().lower(),
            ]
            if part
        )
        done = bool(payload.get("done") or payload.get("complete") or payload.get("completed") or payload.get("passed"))
        blocked = bool(payload.get("blocked") or payload.get("stalled") or payload.get("failed") or payload.get("is_blocked"))
        if blocked:
            state = "blocked"
            blocked_rows.append({"name": name, "text": text})
        elif done:
            state = "complete"
            complete_rows.append({"name": name, "text": text})
        else:
            state = "partial"
            partial_rows.append({"name": name, "text": text})
        rows.append({"index": index, "name": name, "state": state, "text": text})

    if rows:
        progress_score = round(len(complete_rows) / len(rows), 4)
    else:
        progress_score = round(float(scorecard.get("coverage") or scorecard.get("realization") or 0.0), 4)
    remaining_score = round(max(0.0, 1.0 - progress_score), 4)
    if not rows and not scorecard:
        reason = "mission_progress_estimator_missing"
    elif blocked_rows and progress_score < 1.0:
        reason = "mission_progress_estimator_blocked"
    elif progress_score >= 0.8:
        reason = "mission_progress_estimator_near_complete"
    elif progress_score >= 0.4:
        reason = "mission_progress_estimator_progressing"
    else:
        reason = "mission_progress_estimator_early"

    estimator_id = _sha1_payload(
        {
            "mode": mode,
            "objective": objective,
            "rows": rows,
            "progress_score": progress_score,
            "remaining_score": remaining_score,
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "estimator_id": estimator_id,
        "mission_mode": mode,
        "objective": objective,
        "progress_score": progress_score,
        "remaining_score": remaining_score,
        "complete_count": len(complete_rows),
        "partial_count": len(partial_rows),
        "blocked_count": len(blocked_rows),
        "reason": reason,
        "is_complete": progress_score >= 0.8 and not blocked_rows,
        "should_warn": reason in {"mission_progress_estimator_early", "mission_progress_estimator_progressing", "mission_progress_estimator_missing"},
        "should_block": reason == "mission_progress_estimator_blocked",
        "rows": rows,
        "complete_rows": complete_rows,
        "partial_rows": partial_rows,
        "blocked_rows": blocked_rows,
    }


def build_mission_regression_suite(
    *,
    regression_cases: Sequence[Mapping[str, Any] | str] | None = None,
    mission_identity: Mapping[str, Any] | None = None,
    threshold: int = 2,
) -> Dict[str, Any]:
    mission = dict(mission_identity or {})
    mission_mode = str(_first_nonempty(mission.get("mission_mode"), mission.get("mode"), "")).strip().lower()
    objective = str(_first_nonempty(mission.get("objective"), mission.get("goal"), mission.get("description"), "")).strip().lower()
    cases: List[Dict[str, Any]] = []
    passing = 0
    failing = 0
    threshold_value = max(1, int(threshold or 1))

    for index, case in enumerate(regression_cases or [], start=1):
        if isinstance(case, Mapping):
            payload = dict(case)
        else:
            text = str(case or "").strip()
            payload = {"name": text} if text else {}
        observed_mode = str(_first_nonempty(payload.get("mission_mode"), payload.get("mode"), mission_mode, "")).strip().lower()
        expected_mode = str(_first_nonempty(payload.get("expected_mission_mode"), payload.get("expected_mode"), mission_mode, "")).strip().lower()
        strategy = str(_first_nonempty(payload.get("strategy"), payload.get("selected_strategy"), payload.get("policy_name"), "")).strip().lower()
        expected_strategy = str(_first_nonempty(payload.get("expected_strategy"), payload.get("expected_policy"), payload.get("expected_policy_name"), "")).strip().lower()
        report = str(_first_nonempty(payload.get("report"), payload.get("report_id"), payload.get("summary"), "")).strip().lower()
        expected_report = str(_first_nonempty(payload.get("expected_report"), payload.get("expected_summary"), "")).strip().lower()
        drift = bool(
            payload.get("mission_drift")
            or payload.get("strategy_drift")
            or payload.get("report_drift")
            or (expected_mode and observed_mode and expected_mode != observed_mode)
            or (expected_strategy and strategy and expected_strategy != strategy)
            or (expected_report and report and expected_report != report)
        )
        if drift:
            failing += 1
        else:
            passing += 1
        cases.append(
            {
                "index": index,
                "case_id": str(_first_nonempty(payload.get("case_id"), payload.get("name"), f"mission_case_{index}")),
                "mission_mode": observed_mode,
                "expected_mission_mode": expected_mode,
                "strategy": strategy,
                "expected_strategy": expected_strategy,
                "report": report,
                "expected_report": expected_report,
                "is_drift": drift,
                "reason": "mission_regression_case_passed" if not drift else "mission_regression_case_drift",
            }
        )

    total = len(cases)
    if total == 0:
        reason = "mission_regression_suite_missing"
    elif failing > 0:
        reason = "mission_regression_suite_failed"
    elif passing >= threshold_value:
        reason = "mission_regression_suite_passed"
    else:
        reason = "mission_regression_suite_monitor"

    suite_id = _sha1_payload(
        {
            "mission_mode": mission_mode,
            "objective": objective,
            "threshold": threshold_value,
            "cases": [
                {
                    "case_id": row["case_id"],
                    "mission_mode": row["mission_mode"],
                    "expected_mission_mode": row["expected_mission_mode"],
                    "strategy": row["strategy"],
                    "expected_strategy": row["expected_strategy"],
                    "report": row["report"],
                    "expected_report": row["expected_report"],
                }
                for row in cases
            ],
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "suite_id": suite_id,
        "mission_mode": mission_mode,
        "objective": objective,
        "case_count": total,
        "passing_count": passing,
        "failing_count": failing,
        "threshold": threshold_value,
        "reason": reason,
        "is_passing": reason == "mission_regression_suite_passed",
        "should_warn": reason == "mission_regression_suite_monitor",
        "should_block": reason == "mission_regression_suite_failed",
        "rows": cases,
    }


def build_mission_alignment_guard(
    *,
    mission_identity: Mapping[str, Any] | None = None,
    strategy_router: Mapping[str, Any] | None = None,
    regression_suite: Mapping[str, Any] | None = None,
    allow_observe_only: bool = False,
) -> Dict[str, Any]:
    mission = dict(mission_identity or {})
    router = dict(strategy_router or {})
    regression = dict(regression_suite or {})
    mission_mode = str(_first_nonempty(mission.get("mission_mode"), mission.get("mode"), router.get("mission_mode"), "")).strip().lower()
    objective = str(_first_nonempty(mission.get("objective"), mission.get("goal"), mission.get("description"), "")).strip().lower()
    selected_strategy = str(_first_nonempty(router.get("selected_strategy"), router.get("selected_policy_name"), "")).strip().lower()
    selected_profile = str(_first_nonempty(router.get("selected_data_profile"), router.get("data_profile"), "")).strip().lower()
    regression_failed = bool(regression.get("failing_count"))
    strategy_guarded = bool(selected_strategy) and not allow_observe_only
    alignment_score = 1.0
    if regression_failed:
        alignment_score -= 0.5
    if not selected_strategy:
        alignment_score -= 0.25
    if mission_mode in {"exploration", "forensic", "calibration", "evidence"} and selected_profile in {"smoke", "balanced"}:
        alignment_score -= 0.15
    if allow_observe_only:
        alignment_score += 0.1
    alignment_score = round(max(0.0, min(1.0, alignment_score)), 4)
    if regression_failed or alignment_score < 0.5:
        reason = "mission_alignment_guard_blocked"
    elif alignment_score < 0.9:
        reason = "mission_alignment_guard_warn"
    else:
        reason = "mission_alignment_guard_ready"
    guard_id = _sha1_payload(
        {
            "mission_mode": mission_mode,
            "objective": objective,
            "selected_strategy": selected_strategy,
            "selected_profile": selected_profile,
            "alignment_score": alignment_score,
            "regression_failed": regression_failed,
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "guard_id": guard_id,
        "mission_mode": mission_mode,
        "objective": objective,
        "selected_strategy": selected_strategy,
        "selected_data_profile": selected_profile,
        "alignment_score": alignment_score,
        "reason": reason,
        "is_aligned": reason == "mission_alignment_guard_ready",
        "should_warn": reason == "mission_alignment_guard_warn",
        "should_block": reason == "mission_alignment_guard_blocked",
    }


def build_mission_drift_packet(
    *,
    mission_identity: Mapping[str, Any] | None = None,
    mission_regression_suite: Mapping[str, Any] | None = None,
    mission_alignment_guard: Mapping[str, Any] | None = None,
    drift_events: Sequence[Mapping[str, Any] | str] | None = None,
) -> Dict[str, Any]:
    mission = dict(mission_identity or {})
    regression = dict(mission_regression_suite or {})
    guard = dict(mission_alignment_guard or {})
    mission_mode = str(_first_nonempty(mission.get("mission_mode"), mission.get("mode"), regression.get("mission_mode"), guard.get("mission_mode"), "")).strip().lower()
    objective = str(_first_nonempty(mission.get("objective"), mission.get("goal"), mission.get("description"), regression.get("objective"), guard.get("objective"), "")).strip().lower()
    rows: List[Dict[str, Any]] = []
    drift_rows: List[Dict[str, Any]] = []
    for index, event in enumerate(drift_events or [], start=1):
        if isinstance(event, Mapping):
            payload = dict(event)
        else:
            text = str(event or "").strip()
            payload = {"name": text} if text else {}
        name = str(_first_nonempty(payload.get("name"), payload.get("event"), payload.get("reason"), f"drift_{index}")).strip().lower()
        drift_kind = str(_first_nonempty(payload.get("kind"), payload.get("drift_kind"), payload.get("type"), "")).strip().lower()
        stage = str(_first_nonempty(payload.get("stage"), payload.get("location"), payload.get("step"), "")).strip().lower()
        severity = str(_first_nonempty(payload.get("severity"), payload.get("level"), "")).strip().lower()
        detected = bool(payload.get("detected", True)) or bool(drift_kind or stage or severity)
        row = {
            "index": index,
            "name": name,
            "kind": drift_kind,
            "stage": stage,
            "severity": severity,
            "detected": detected,
        }
        rows.append(row)
        if detected:
            drift_rows.append(row)
    drift_count = len(drift_rows) + int(bool(regression.get("failing_count"))) + int(bool(guard.get("should_block")))
    if not rows and not regression and not guard:
        reason = "mission_drift_packet_missing"
    elif drift_count > 0:
        reason = "mission_drift_packet_drifted"
    else:
        reason = "mission_drift_packet_stable"
    packet_id = _sha1_payload(
        {
            "mission_mode": mission_mode,
            "objective": objective,
            "rows": rows,
            "regression": {
                "reason": str(regression.get("reason") or ""),
                "failing_count": int(regression.get("failing_count") or 0),
            },
            "guard_reason": str(guard.get("reason") or ""),
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "packet_id": packet_id,
        "mission_mode": mission_mode,
        "objective": objective,
        "drift_count": drift_count,
        "reason": reason,
        "is_drifted": reason == "mission_drift_packet_drifted",
        "should_warn": reason != "mission_drift_packet_stable",
        "should_block": reason == "mission_drift_packet_drifted",
        "rows": rows,
        "drift_rows": drift_rows,
    }


def build_mission_strategy_router(
    *,
    mission_identity: Mapping[str, Any] | None = None,
    available_strategies: Sequence[Mapping[str, Any] | str] | None = None,
    default_strategy: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    mission = dict(mission_identity or {})
    mode = str(_first_nonempty(mission.get("mission_mode"), mission.get("mode"), "")).strip().lower()
    objective = str(_first_nonempty(mission.get("objective"), mission.get("goal"), mission.get("description"), "")).strip().lower()
    tags = {
        str(tag or "").strip().lower()
        for tag in (mission.get("mission_tags") or mission.get("tags") or [])
        if str(tag or "").strip()
    }
    objective_tokens = set(filter(None, re.split(r"[^a-z0-9]+", objective)))

    def _float_or_zero(value: Any) -> float:
        try:
            return float(value) if value is not None and str(value).strip() else 0.0
        except (TypeError, ValueError):
            return 0.0

    candidates: List[Dict[str, Any]] = []
    for index, strategy in enumerate(available_strategies or [], start=1):
        if isinstance(strategy, Mapping):
            payload = dict(strategy)
        else:
            text = str(strategy or "").strip()
            payload = {"name": text} if text else {}
        name = str(_first_nonempty(payload.get("name"), payload.get("strategy"), payload.get("policy_name"), f"strategy_{index}")).strip().lower()
        supported_modes = {
            str(item or "").strip().lower()
            for item in (
                payload.get("supported_modes")
                or payload.get("mission_modes")
                or payload.get("modes")
                or []
            )
            if str(item or "").strip()
        }
        data_profile = str(_first_nonempty(payload.get("data_profile"), payload.get("test_data_profile"), payload.get("dataset"), "")).strip().lower()
        threshold = round(_float_or_zero(_first_nonempty(payload.get("threshold"), payload.get("score_threshold"), payload.get("min_score"), None)), 4)
        keywords = {
            str(item or "").strip().lower()
            for item in (payload.get("keywords") or payload.get("tags") or [])
            if str(item or "").strip()
        }
        score = 0
        if mode and mode in supported_modes:
            score += 8
        if mode in {"explore", "exploration"} and {"explore", "exploration"} & supported_modes:
            score += 4
        if mode in {"smoke", "regression", "calibration", "forensic", "verify"} and mode in supported_modes:
            score += 4
        if objective_tokens & keywords:
            score += 3
        if tags & keywords:
            score += 2
        if payload.get("preferred"):
            score += 1
        candidates.append(
            {
                "name": name,
                "supported_modes": sorted(supported_modes),
                "data_profile": data_profile,
                "threshold": threshold,
                "keywords": sorted(keywords),
                "score": score,
                "policy_name": str(_first_nonempty(payload.get("policy_name"), payload.get("policy"), name)).strip().lower(),
            }
        )

    if not candidates:
        fallback = dict(default_strategy or {})
        selected = {
            "name": str(_first_nonempty(fallback.get("name"), fallback.get("strategy"), fallback.get("policy_name"), "default_strategy")).strip().lower(),
            "policy_name": str(_first_nonempty(fallback.get("policy_name"), fallback.get("policy"), fallback.get("name"), "default_strategy")).strip().lower(),
            "data_profile": str(_first_nonempty(fallback.get("data_profile"), fallback.get("test_data_profile"), "balanced")).strip().lower(),
            "threshold": round(_float_or_zero(_first_nonempty(fallback.get("threshold"), fallback.get("score_threshold"), 0.0)), 4),
            "score": 0,
        }
        reason = "mission_strategy_router_fallback"
        should_warn = True
        should_block = False
    else:
        candidates.sort(key=lambda row: (row["score"], row["name"]), reverse=True)
        selected = candidates[0]
        if selected["score"] > 0:
            reason = "mission_strategy_router_selected"
            should_warn = False
            should_block = False
        else:
            reason = "mission_strategy_router_monitor"
            should_warn = True
            should_block = False

    router_id = _sha1_payload(
        {
            "mode": mode,
            "objective": objective,
            "tags": sorted(tags),
            "selected": selected,
            "candidates": candidates,
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "router_id": router_id,
        "mission_mode": mode,
        "objective": objective,
        "mission_tags": sorted(tags),
        "selected_strategy": selected.get("name", ""),
        "selected_policy_name": selected.get("policy_name", ""),
        "selected_data_profile": selected.get("data_profile", ""),
        "selected_threshold": selected.get("threshold", 0.0),
        "candidate_count": len(candidates),
        "selected_score": selected.get("score", 0),
        "reason": reason,
        "is_ready": reason == "mission_strategy_router_selected",
        "should_warn": should_warn,
        "should_block": should_block,
        "rows": candidates,
    }


def build_objective_continuity_guard(
    *,
    mission_identity: Mapping[str, Any] | None = None,
    decision_rows: Sequence[Mapping[str, Any] | str] | None = None,
    strategy_router: Mapping[str, Any] | None = None,
    drift_threshold: float = 0.7,
) -> Dict[str, Any]:
    mission = dict(mission_identity or {})
    router = dict(strategy_router or {})
    mode = str(_first_nonempty(mission.get("mission_mode"), mission.get("mode"), router.get("mission_mode"), "")).strip().lower()
    objective = str(_first_nonempty(mission.get("objective"), mission.get("goal"), mission.get("description"), router.get("objective"), "")).strip().lower()
    objective_tokens = {token for token in re.split(r"[^a-z0-9]+", objective) if token}
    rows: List[Dict[str, Any]] = []
    aligned_rows: List[Dict[str, Any]] = []
    drift_rows: List[Dict[str, Any]] = []
    threshold_value = min(1.0, max(0.0, float(drift_threshold or 0.0)))

    for index, row in enumerate(decision_rows or [], start=1):
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip()
            payload = {"name": text} if text else {}
        text = " ".join(
            filter(
                None,
                [
                    str(_first_nonempty(payload.get("name"), payload.get("action"), payload.get("description"), "")).strip().lower(),
                    str(_first_nonempty(payload.get("reason"), payload.get("result"), payload.get("outcome"), "")).strip().lower(),
                ],
            )
        ).strip()
        matched_tokens = sorted(token for token in objective_tokens if token in text)
        drift_signal = bool(
            payload.get("objective_drift")
            or payload.get("mission_drift")
            or payload.get("off_mission")
            or payload.get("goal_shift")
            or any(token in text for token in ("drift", "off mission", "other goal", "different goal", "side quest", "detour"))
        )
        aligned = bool(matched_tokens or payload.get("mission_aligned") or payload.get("objective_match"))
        row_record = {
            "index": index,
            "decision": str(_first_nonempty(payload.get("name"), payload.get("action"), payload.get("description"), f"decision_{index}")),
            "text": text,
            "matched_tokens": matched_tokens,
            "drift_signal": drift_signal,
            "aligned": aligned and not drift_signal,
        }
        rows.append(row_record)
        if row_record["aligned"]:
            aligned_rows.append(row_record)
        elif drift_signal:
            drift_rows.append(row_record)

    total = len(rows)
    aligned_count = len(aligned_rows)
    drift_count = len(drift_rows)
    continuity_score = round(aligned_count / total, 4) if total else 0.0
    if total == 0:
        reason = "objective_continuity_guard_empty"
    elif drift_count > 0 and continuity_score < threshold_value:
        reason = "objective_continuity_guard_drift"
    elif continuity_score >= threshold_value:
        reason = "objective_continuity_guard_continuous"
    else:
        reason = "objective_continuity_guard_monitor"

    guard_id = _sha1_payload(
        {
            "mode": mode,
            "objective": objective,
            "threshold": threshold_value,
            "rows": [
                {
                    "decision": row["decision"],
                    "matched_tokens": row["matched_tokens"],
                    "drift_signal": row["drift_signal"],
                    "aligned": row["aligned"],
                }
                for row in rows
            ],
            "router": {
                "selected_strategy": str(router.get("selected_strategy") or ""),
                "selected_policy_name": str(router.get("selected_policy_name") or ""),
            },
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "guard_id": guard_id,
        "mission_mode": mode,
        "objective": objective,
        "threshold": threshold_value,
        "decision_count": total,
        "aligned_count": aligned_count,
        "drift_count": drift_count,
        "continuity_score": continuity_score,
        "reason": reason,
        "is_continuous": reason == "objective_continuity_guard_continuous",
        "should_warn": reason in {"objective_continuity_guard_monitor", "objective_continuity_guard_empty"},
        "should_block": reason == "objective_continuity_guard_drift",
        "rows": rows,
        "aligned_rows": aligned_rows,
        "drift_rows": drift_rows,
    }


def build_observe_vs_progress_splitter(
    *,
    mission_identity: Mapping[str, Any] | None = None,
    action_rows: Sequence[Mapping[str, Any] | str] | None = None,
    strategy_router: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    mission = dict(mission_identity or {})
    router = dict(strategy_router or {})
    mode = str(_first_nonempty(mission.get("mission_mode"), mission.get("mode"), router.get("mission_mode"), "")).strip().lower()
    observe_bias = mode in {"explore", "exploration", "forensic", "calibration", "discover"}
    observe_tokens = {
        "inspect",
        "inspect",
        "investigate",
        "collect",
        "measure",
        "profile",
        "trace",
        "debug",
        "audit",
        "observe",
        "review",
        "forensic",
        "replay",
    }
    progress_tokens = {
        "fix",
        "submit",
        "advance",
        "complete",
        "apply",
        "proceed",
        "resume",
        "update",
        "progress",
        "continue",
        "finish",
    }
    rows: List[Dict[str, Any]] = []
    observe_rows: List[Dict[str, Any]] = []
    progress_rows: List[Dict[str, Any]] = []
    for index, action in enumerate(action_rows or [], start=1):
        if isinstance(action, Mapping):
            payload = dict(action)
        else:
            text = str(action or "").strip()
            payload = {"name": text} if text else {}
        text = " ".join(
            filter(
                None,
                [
                    str(_first_nonempty(payload.get("name"), payload.get("action"), payload.get("description"), "")).strip().lower(),
                    str(_first_nonempty(payload.get("reason"), payload.get("result"), payload.get("outcome"), "")).strip().lower(),
                ],
            )
        )
        observe_score = sum(int(token in text) for token in observe_tokens) + (2 if observe_bias else 0)
        progress_score = sum(int(token in text) for token in progress_tokens)
        if bool(payload.get("is_observation") or payload.get("observe_only") or payload.get("diagnostic")):
            observe_score += 3
        if bool(payload.get("is_progress") or payload.get("actionable") or payload.get("progress")):
            progress_score += 3
        if observe_score >= progress_score:
            kind = "observe"
            observe_rows.append(
                {
                    "index": index,
                    "name": str(_first_nonempty(payload.get("name"), payload.get("action"), payload.get("description"), f"action_{index}")),
                    "score": observe_score,
                    "text": text,
                }
            )
        else:
            kind = "progress"
            progress_rows.append(
                {
                    "index": index,
                    "name": str(_first_nonempty(payload.get("name"), payload.get("action"), payload.get("description"), f"action_{index}")),
                    "score": progress_score,
                    "text": text,
                }
            )
        rows.append(
            {
                "index": index,
                "name": str(_first_nonempty(payload.get("name"), payload.get("action"), payload.get("description"), f"action_{index}")),
                "kind": kind,
                "observe_score": observe_score,
                "progress_score": progress_score,
                "text": text,
            }
        )

    if not rows:
        reason = "observe_vs_progress_splitter_empty"
    elif observe_rows and progress_rows:
        reason = "observe_vs_progress_splitter_mixed"
    elif observe_rows:
        reason = "observe_vs_progress_splitter_observe"
    else:
        reason = "observe_vs_progress_splitter_progress"

    splitter_id = _sha1_payload(
        {
            "mode": mode,
            "rows": rows,
            "observe_count": len(observe_rows),
            "progress_count": len(progress_rows),
        }
    )[:16]
    return {
        "schema_version": SCHEMA_VERSION,
        "splitter_id": splitter_id,
        "mission_mode": mode,
        "observe_count": len(observe_rows),
        "progress_count": len(progress_rows),
        "reason": reason,
        "is_mixed": reason == "observe_vs_progress_splitter_mixed",
        "should_warn": bool(observe_rows and progress_rows),
        "should_block": False,
        "rows": rows,
        "observe_rows": observe_rows,
        "progress_rows": progress_rows,
    }


def build_causal_hypothesis_identity(
    *,
    cause: str = "",
    mechanism: str = "",
    predicted_outcome: str = "",
    evidence_rows: Sequence[Mapping[str, Any] | str] | None = None,
) -> Dict[str, Any]:
    rows = [row for row in (evidence_rows or []) if row]
    cause_text = str(cause or "").strip()
    mechanism_text = str(mechanism or "").strip()
    outcome_text = str(predicted_outcome or "").strip()
    evidence_count = len(rows)
    is_complete = bool(cause_text and mechanism_text and outcome_text and evidence_count > 0)
    return {
        "schema_version": SCHEMA_VERSION,
        "hypothesis_id": _sha1_payload(
            {
                "cause": cause_text,
                "mechanism": mechanism_text,
                "predicted_outcome": outcome_text,
                "evidence_count": evidence_count,
            }
        )[:16],
        "cause": cause_text,
        "mechanism": mechanism_text,
        "predicted_outcome": outcome_text,
        "evidence_count": evidence_count,
        "is_complete": is_complete,
        "should_warn": not is_complete,
        "should_block": not is_complete,
        "reason": "causal_hypothesis_identity_complete" if is_complete else "causal_hypothesis_identity_incomplete",
    }


def build_cause_effect_contract(
    *,
    event_name: str = "",
    expected_outcome: str = "",
    effect_direction: str = "",
    confidence: float = 0.0,
) -> Dict[str, Any]:
    event = str(event_name or "").strip()
    outcome = str(expected_outcome or "").strip()
    direction = str(effect_direction or "").strip().lower()
    conf = max(0.0, min(1.0, float(confidence or 0.0)))
    valid_direction = direction in {"increase", "decrease", "hold", "reverse"}
    is_complete = bool(event and outcome and valid_direction and conf > 0.0)
    return {
        "schema_version": SCHEMA_VERSION,
        "contract_id": _sha1_payload(
            {
                "event": event,
                "outcome": outcome,
                "direction": direction,
                "confidence": round(conf, 4),
            }
        )[:16],
        "event_name": event,
        "expected_outcome": outcome,
        "effect_direction": direction,
        "confidence": round(conf, 4),
        "is_complete": is_complete,
        "should_warn": not is_complete,
        "should_block": not is_complete,
        "reason": "cause_effect_contract_complete" if is_complete else "cause_effect_contract_incomplete",
    }


def build_causal_claim_schema(
    *,
    causal_claims: Sequence[Mapping[str, Any] | str] | None = None,
    counterexamples: Sequence[Mapping[str, Any] | str] | None = None,
) -> Dict[str, Any]:
    claims: List[Dict[str, Any]] = []
    counter_rows: List[Dict[str, Any]] = []
    for idx, row in enumerate(causal_claims or [], start=1):
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip()
            payload = {"name": text} if text else {}
        name = str(_first_nonempty(payload.get("name"), payload.get("cause"), payload.get("reason"), f"claim_{idx}")).strip()
        claims.append({"name": name, "reason": str(_first_nonempty(payload.get("reason"), name))})
    for idx, row in enumerate(counterexamples or [], start=1):
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip()
            payload = {"name": text} if text else {}
        name = str(_first_nonempty(payload.get("name"), payload.get("reason"), payload.get("kind"), f"counter_{idx}")).strip()
        counter_rows.append({"name": name, "reason": str(_first_nonempty(payload.get("reason"), name))})
    complete = bool(claims) and bool(counter_rows)
    return {
        "schema_version": SCHEMA_VERSION,
        "schema_id": _sha1_payload({"claims": claims, "counterexamples": counter_rows})[:16],
        "claims": claims,
        "counterexamples": counter_rows,
        "claim_count": len(claims),
        "counterexample_count": len(counter_rows),
        "is_complete": complete,
        "should_warn": not complete,
        "should_block": not complete,
        "reason": "causal_claim_schema_complete" if complete else "causal_claim_schema_incomplete",
    }


def build_causality_hint_packet(
    *,
    causal_hypothesis_identity: Mapping[str, Any] | None = None,
    controlled_intervention_registry: Mapping[str, Any] | None = None,
    diagnosis_mode: str = "",
) -> Dict[str, Any]:
    hypothesis = dict(causal_hypothesis_identity or {})
    interventions = dict(controlled_intervention_registry or {})
    mode = str(diagnosis_mode or "").strip().lower()
    hypothesis_id = str(_first_nonempty(hypothesis.get("hypothesis_id"), hypothesis.get("identity_id"), "")).strip()
    intervention_count = int(len(interventions.get("rows") or interventions.get("interventions") or []))
    is_ready = bool(hypothesis_id) and intervention_count > 0 and bool(mode)
    return {
        "schema_version": SCHEMA_VERSION,
        "packet_id": _sha1_payload(
            {
                "hypothesis_id": hypothesis_id,
                "intervention_count": intervention_count,
                "mode": mode,
            }
        )[:16],
        "hypothesis_id": hypothesis_id,
        "intervention_count": intervention_count,
        "diagnosis_mode": mode,
        "is_ready": is_ready,
        "should_warn": not is_ready,
        "should_block": not is_ready,
        "reason": "causality_hint_packet_ready" if is_ready else "causality_hint_packet_incomplete",
    }


def build_controlled_intervention_registry(
    *,
    intervention_rows: Sequence[Mapping[str, Any] | str] | None = None,
    hypothesis_id: str = "",
    measurement_metric: str = "",
) -> Dict[str, Any]:
    rows: List[Dict[str, Any]] = []
    for idx, row in enumerate(intervention_rows or [], start=1):
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip()
            payload = {"name": text} if text else {}
        name = str(_first_nonempty(payload.get("name"), payload.get("variable"), payload.get("reason"), f"intervention_{idx}")).strip()
        rows.append(
            {
                "name": name,
                "variable": str(_first_nonempty(payload.get("variable"), payload.get("name"), name)).strip(),
                "reason": str(_first_nonempty(payload.get("reason"), name)),
            }
        )
    ready = bool(rows) and bool(str(hypothesis_id or "").strip()) and bool(str(measurement_metric or "").strip())
    return {
        "schema_version": SCHEMA_VERSION,
        "registry_id": _sha1_payload({"rows": rows, "hypothesis_id": hypothesis_id, "measurement_metric": measurement_metric})[:16],
        "rows": rows,
        "hypothesis_id": str(hypothesis_id or "").strip(),
        "measurement_metric": str(measurement_metric or "").strip(),
        "intervention_count": len(rows),
        "is_ready": ready,
        "should_warn": not ready,
        "should_block": not ready,
        "reason": "controlled_intervention_registry_ready" if ready else "controlled_intervention_registry_incomplete",
    }


def build_paired_counterfactual_runner(
    *,
    control_rows: Sequence[Mapping[str, Any] | str] | None = None,
    treatment_rows: Sequence[Mapping[str, Any] | str] | None = None,
    metric_name: str = "",
) -> Dict[str, Any]:
    controls = [row for row in (control_rows or []) if row]
    treatments = [row for row in (treatment_rows or []) if row]
    pair_count = min(len(controls), len(treatments))
    ready = pair_count > 0 and bool(str(metric_name or "").strip())
    return {
        "schema_version": SCHEMA_VERSION,
        "runner_id": _sha1_payload({"controls": controls, "treatments": treatments, "metric_name": metric_name})[:16],
        "control_count": len(controls),
        "treatment_count": len(treatments),
        "pair_count": pair_count,
        "metric_name": str(metric_name or "").strip(),
        "is_ready": ready,
        "should_warn": not ready,
        "should_block": not ready,
        "reason": "paired_counterfactual_runner_ready" if ready else "paired_counterfactual_runner_incomplete",
    }


def build_single_variable_change_guard(
    *,
    change_rows: Sequence[Mapping[str, Any] | str] | None = None,
    allowed_change_count: int = 1,
) -> Dict[str, Any]:
    rows = [row for row in (change_rows or []) if row]
    change_count = len(rows)
    allowed = max(1, int(allowed_change_count or 0))
    is_isolated = change_count <= allowed
    return {
        "schema_version": SCHEMA_VERSION,
        "guard_id": _sha1_payload({"rows": rows, "allowed": allowed})[:16],
        "change_count": change_count,
        "allowed_change_count": allowed,
        "is_isolated": is_isolated,
        "should_warn": not is_isolated,
        "should_block": not is_isolated,
        "reason": "single_variable_change_guard_isolated" if is_isolated else "single_variable_change_guard_confounded",
    }


def build_delayed_effect_tracker(
    *,
    upstream_changes: Sequence[Mapping[str, Any] | str] | None = None,
    downstream_effects: Sequence[Mapping[str, Any] | str] | None = None,
    max_lag_s: float = 0.0,
) -> Dict[str, Any]:
    upstream = [row for row in (upstream_changes or []) if row]
    downstream = [row for row in (downstream_effects or []) if row]
    lag_s = max(0.0, float(max_lag_s or 0.0))
    linked = bool(upstream) and bool(downstream)
    return {
        "schema_version": SCHEMA_VERSION,
        "tracker_id": _sha1_payload({"upstream": upstream, "downstream": downstream, "max_lag_s": round(lag_s, 4)})[:16],
        "upstream_count": len(upstream),
        "downstream_count": len(downstream),
        "max_lag_s": round(lag_s, 4),
        "is_linked": linked,
        "should_warn": not linked or lag_s > 0.0,
        "should_block": False,
        "reason": "delayed_effect_tracker_linked" if linked else "delayed_effect_tracker_unlinked",
    }


def build_repair_attribution_model(
    *,
    repair_actions: Sequence[Mapping[str, Any] | str] | None = None,
    observed_gain: float = 0.0,
) -> Dict[str, Any]:
    actions: List[Dict[str, Any]] = []
    for idx, row in enumerate(repair_actions or [], start=1):
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip()
            payload = {"name": text} if text else {}
        name = str(_first_nonempty(payload.get("name"), payload.get("action"), payload.get("reason"), f"repair_{idx}")).strip()
        confidence = max(0.0, min(1.0, float(_first_nonempty(payload.get("confidence"), payload.get("score"), 0.0))))
        actions.append({"name": name, "confidence": round(confidence, 4)})
    total_confidence = sum(action["confidence"] for action in actions)
    gain = max(0.0, float(observed_gain or 0.0))
    if total_confidence > 0.0:
        shares = [round((action["confidence"] / total_confidence) * gain, 4) for action in actions]
    else:
        shares = [0.0 for _ in actions]
    return {
        "schema_version": SCHEMA_VERSION,
        "model_id": _sha1_payload({"actions": actions, "observed_gain": round(gain, 4)})[:16],
        "actions": actions,
        "observed_gain": round(gain, 4),
        "attributed_gain": shares,
        "is_complete": bool(actions),
        "should_warn": not bool(actions),
        "should_block": False,
        "reason": "repair_attribution_model_complete" if actions else "repair_attribution_model_empty",
    }


def build_side_effect_causality_linker(
    *,
    change_rows: Sequence[Mapping[str, Any] | str] | None = None,
    failure_rows: Sequence[Mapping[str, Any] | str] | None = None,
    side_effect_rows: Sequence[Mapping[str, Any] | str] | None = None,
) -> Dict[str, Any]:
    changes = [row for row in (change_rows or []) if row]
    failures = [row for row in (failure_rows or []) if row]
    effects = [row for row in (side_effect_rows or []) if row]
    links = min(len(changes), len(failures), max(1, len(effects) or 1)) if changes and failures else 0
    return {
        "schema_version": SCHEMA_VERSION,
        "link_id": _sha1_payload({"changes": changes, "failures": failures, "effects": effects})[:16],
        "change_count": len(changes),
        "failure_count": len(failures),
        "side_effect_count": len(effects),
        "link_count": links,
        "is_linked": links > 0,
        "should_warn": links == 0,
        "should_block": False,
        "reason": "side_effect_causality_linker_linked" if links > 0 else "side_effect_causality_linker_unlinked",
    }


def build_primary_vs_secondary_cause_splitter(
    *,
    cause_rows: Sequence[Mapping[str, Any] | str] | None = None,
) -> Dict[str, Any]:
    primary: List[Dict[str, Any]] = []
    secondary: List[Dict[str, Any]] = []
    for idx, row in enumerate(cause_rows or [], start=1):
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip()
            payload = {"name": text} if text else {}
        name = str(_first_nonempty(payload.get("name"), payload.get("cause"), payload.get("reason"), f"cause_{idx}")).strip()
        is_primary = bool(payload.get("is_primary")) or float(_first_nonempty(payload.get("confidence"), 0.0)) >= 0.7
        item = {"name": name, "reason": str(_first_nonempty(payload.get("reason"), name))}
        (primary if is_primary else secondary).append(item)
    return {
        "schema_version": SCHEMA_VERSION,
        "split_id": _sha1_payload({"primary": primary, "secondary": secondary})[:16],
        "primary": primary,
        "secondary": secondary,
        "primary_count": len(primary),
        "secondary_count": len(secondary),
        "is_split": bool(primary) and bool(secondary),
        "should_warn": bool(secondary),
        "should_block": False,
        "reason": "primary_vs_secondary_cause_splitter_split" if secondary else "primary_vs_secondary_cause_splitter_single",
    }


def build_causal_confidence_calibrator(
    *,
    claim_rows: Sequence[Mapping[str, Any] | str] | None = None,
    baseline_confidence: float = 0.0,
    evidence_strength: float = 0.0,
) -> Dict[str, Any]:
    claims = [row for row in (claim_rows or []) if row]
    baseline = max(0.0, min(1.0, float(baseline_confidence or 0.0)))
    strength = max(0.0, min(1.0, float(evidence_strength or 0.0)))
    calibrated = round(max(0.0, min(1.0, (baseline + strength) / 2.0)), 4)
    if calibrated >= 0.75:
        tier = "high"
    elif calibrated >= 0.5:
        tier = "medium"
    elif calibrated >= 0.25:
        tier = "low"
    else:
        tier = "very_low"
    return {
        "schema_version": SCHEMA_VERSION,
        "calibrator_id": _sha1_payload({"claims": claims, "baseline": baseline, "strength": strength})[:16],
        "claim_count": len(claims),
        "baseline_confidence": round(baseline, 4),
        "evidence_strength": round(strength, 4),
        "calibrated_confidence": calibrated,
        "tier": tier,
        "is_calibrated": bool(claims),
        "should_warn": not bool(claims),
        "should_block": False,
        "reason": "causal_confidence_calibrator_" + tier,
    }


def build_causality_regression_suite(
    *,
    failing_runs: Sequence[Mapping[str, Any] | str] | None = None,
    passing_runs: Sequence[Mapping[str, Any] | str] | None = None,
) -> Dict[str, Any]:
    failing: List[Dict[str, Any]] = []
    passing: List[Dict[str, Any]] = []
    for idx, row in enumerate(failing_runs or [], start=1):
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip()
            payload = {"name": text} if text else {}
        name = str(_first_nonempty(payload.get("profile"), payload.get("name"), payload.get("reason"), f"fail_{idx}")).strip()
        failing.append({"name": name, "reason": str(_first_nonempty(payload.get("reason"), name))})
    for idx, row in enumerate(passing_runs or [], start=1):
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip()
            payload = {"name": text} if text else {}
        name = str(_first_nonempty(payload.get("profile"), payload.get("name"), payload.get("reason"), f"pass_{idx}")).strip()
        passing.append({"name": name, "reason": str(_first_nonempty(payload.get("reason"), name))})
    regressed = bool(failing) and len(failing) >= len(passing)
    return {
        "schema_version": SCHEMA_VERSION,
        "suite_id": _sha1_payload({"failing": failing, "passing": passing})[:16],
        "failing_runs": failing,
        "passing_runs": passing,
        "failing_count": len(failing),
        "passing_count": len(passing),
        "is_regressed": regressed,
        "should_warn": bool(failing),
        "should_block": regressed,
        "reason": "causality_regression_suite_regressed" if regressed else "causality_regression_suite_stable",
    }


def build_causal_explanation_guard(
    *,
    explanation_text: str = "",
    evidence_rows: Sequence[Mapping[str, Any] | str] | None = None,
    counterfactual_rows: Sequence[Mapping[str, Any] | str] | None = None,
    mechanism_text: str = "",
) -> Dict[str, Any]:
    explanation = str(explanation_text or "").strip()
    mechanism = str(mechanism_text or "").strip()
    evidence_count = len([row for row in (evidence_rows or []) if row])
    counter_count = len([row for row in (counterfactual_rows or []) if row])
    sufficient = bool(explanation and evidence_count > 0 and (mechanism or counter_count > 0))
    return {
        "schema_version": SCHEMA_VERSION,
        "guard_id": _sha1_payload(
            {
                "explanation": explanation,
                "mechanism": mechanism,
                "evidence_count": evidence_count,
                "counter_count": counter_count,
            }
        )[:16],
        "evidence_count": evidence_count,
        "counterfactual_count": counter_count,
        "mechanism_text": mechanism,
        "is_sufficient": sufficient,
        "should_warn": not sufficient,
        "should_block": not sufficient,
        "reason": "causal_explanation_guard_sufficient" if sufficient else "causal_explanation_guard_insufficient",
    }


def build_causal_brief_packet(
    *,
    hypothesis_rows: Sequence[Mapping[str, Any] | str] | None = None,
    intervention_rows: Sequence[Mapping[str, Any] | str] | None = None,
    confidence_rows: Sequence[Mapping[str, Any] | str] | None = None,
) -> Dict[str, Any]:
    hypotheses = [row for row in (hypothesis_rows or []) if row]
    interventions = [row for row in (intervention_rows or []) if row]
    confidences = [row for row in (confidence_rows or []) if row]
    ready = bool(hypotheses) and bool(interventions) and bool(confidences)
    return {
        "schema_version": SCHEMA_VERSION,
        "packet_id": _sha1_payload({"hypotheses": hypotheses, "interventions": interventions, "confidences": confidences})[:16],
        "hypothesis_count": len(hypotheses),
        "intervention_count": len(interventions),
        "confidence_count": len(confidences),
        "is_ready": ready,
        "should_warn": not ready,
        "should_block": not ready,
        "reason": "causal_brief_packet_ready" if ready else "causal_brief_packet_incomplete",
    }


def build_compliance_boundary_contract(
    *,
    site_name: str = "",
    section_name: str = "",
    allowed_actions: Sequence[str] | None = None,
    restricted_actions: Sequence[str] | None = None,
) -> Dict[str, Any]:
    site = str(site_name or "").strip()
    section = str(section_name or "").strip()
    allowed = [str(item or "").strip().lower() for item in (allowed_actions or []) if str(item or "").strip()]
    restricted = [str(item or "").strip().lower() for item in (restricted_actions or []) if str(item or "").strip()]
    defined = bool(site and section and (allowed or restricted))
    return {
        "schema_version": SCHEMA_VERSION,
        "boundary_id": _sha1_payload({"site": site, "section": section, "allowed": allowed, "restricted": restricted})[:16],
        "site_name": site,
        "section_name": section,
        "allowed_actions": allowed,
        "restricted_actions": restricted,
        "is_defined": defined,
        "should_warn": not defined,
        "should_block": not defined,
        "reason": "compliance_boundary_contract_defined" if defined else "compliance_boundary_contract_incomplete",
    }


def build_sensitive_surface_identity(
    *,
    surface_rows: Sequence[Mapping[str, Any] | str] | None = None,
    site_name: str = "",
) -> Dict[str, Any]:
    rows: List[Dict[str, Any]] = []
    counts = {"ordinary": 0, "private": 0, "regulated": 0, "forbidden": 0}
    for idx, row in enumerate(surface_rows or [], start=1):
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip()
            payload = {"name": text} if text else {}
        name = str(_first_nonempty(payload.get("name"), payload.get("field"), payload.get("kind"), f"surface_{idx}")).strip()
        lowered = name.lower()
        kind = "ordinary"
        if bool(payload.get("is_forbidden")) or any(token in lowered for token in ("forbidden", "ban", "blocked")):
            kind = "forbidden"
        elif bool(payload.get("is_regulated")) or any(token in lowered for token in ("regulated", "legal", "policy")):
            kind = "regulated"
        elif bool(payload.get("is_private")) or any(token in lowered for token in ("private", "personal", "pii", "secret")):
            kind = "private"
        counts[kind] = int(counts.get(kind, 0) + 1)
        rows.append({"name": name, "kind": kind, "reason": str(_first_nonempty(payload.get("reason"), name))})
    return {
        "schema_version": SCHEMA_VERSION,
        "identity_id": _sha1_payload({"rows": rows, "site_name": site_name})[:16],
        "site_name": str(site_name or "").strip(),
        "rows": rows,
        "counts": counts,
        "has_sensitive_surface": bool(counts["private"] or counts["regulated"] or counts["forbidden"]),
        "should_warn": bool(counts["private"] or counts["regulated"] or counts["forbidden"]),
        "should_block": counts["forbidden"] > 0,
        "reason": "sensitive_surface_identity_classified" if rows else "sensitive_surface_identity_empty",
    }


def build_compliance_hint_packet(
    *,
    compliance_boundary_contract: Mapping[str, Any] | None = None,
    sensitive_surface_identity: Mapping[str, Any] | None = None,
    allowed_actions: Sequence[str] | None = None,
) -> Dict[str, Any]:
    boundary = dict(compliance_boundary_contract or {})
    surface = dict(sensitive_surface_identity or {})
    allowed = [str(item or "").strip().lower() for item in (allowed_actions or []) if str(item or "").strip()]
    restricted = set(str(item or "").strip().lower() for item in boundary.get("restricted_actions") or [])
    should_block = bool(surface.get("should_block")) or bool(restricted and not set(allowed).isdisjoint(restricted))
    return {
        "schema_version": SCHEMA_VERSION,
        "hint_id": _sha1_payload({"boundary": boundary, "surface": surface, "allowed": allowed})[:16],
        "allowed_actions": allowed,
        "restricted_actions": sorted(restricted),
        "surface_identity_id": str(surface.get("identity_id") or ""),
        "is_actionable": bool(allowed) and not should_block,
        "should_warn": should_block or bool(surface.get("should_warn")),
        "should_block": should_block,
        "reason": "compliance_hint_packet_actionable" if not should_block else "compliance_hint_packet_restricted",
    }


def build_policy_basis_record(
    *,
    decision_rows: Sequence[Mapping[str, Any] | str] | None = None,
    basis_text: str = "",
    boundary_contract: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    decisions = [row for row in (decision_rows or []) if row]
    boundary = dict(boundary_contract or {})
    basis = str(basis_text or "").strip()
    audited = bool(basis and decisions)
    return {
        "schema_version": SCHEMA_VERSION,
        "record_id": _sha1_payload({"decisions": decisions, "basis": basis, "boundary": boundary})[:16],
        "decision_count": len(decisions),
        "basis_text": basis,
        "boundary_id": str(boundary.get("boundary_id") or ""),
        "is_audited": audited,
        "should_warn": not audited,
        "should_block": not audited,
        "reason": "policy_basis_record_audited" if audited else "policy_basis_record_incomplete",
    }


def build_compliance_action_gate(
    *,
    compliance_boundary_contract: Mapping[str, Any] | None = None,
    action_name: str = "",
    surface_kind: str = "",
) -> Dict[str, Any]:
    boundary = dict(compliance_boundary_contract or {})
    action = str(action_name or "").strip().lower()
    surface = str(surface_kind or "").strip().lower()
    restricted = set(str(item or "").strip().lower() for item in boundary.get("restricted_actions") or [])
    permitted = set(str(item or "").strip().lower() for item in boundary.get("allowed_actions") or [])
    restricted_surface = surface in {"private", "regulated", "forbidden"}
    blocked = restricted_surface and (action in restricted or action in {"submit", "replay", "write"})
    if not restricted_surface and action in permitted:
        decision = "allow"
    elif blocked:
        decision = "block"
    else:
        decision = "observe"
    return {
        "schema_version": SCHEMA_VERSION,
        "gate_id": _sha1_payload({"boundary": boundary, "action": action, "surface": surface, "decision": decision})[:16],
        "action_name": action,
        "surface_kind": surface,
        "decision": decision,
        "should_warn": decision != "allow",
        "should_block": decision == "block",
        "reason": "compliance_action_gate_" + decision,
    }


def build_sensitivity_uncertainty_escalation(
    *,
    sensitivity_classifier: Mapping[str, Any] | None = None,
    confidence: float = 0.0,
) -> Dict[str, Any]:
    classifier = dict(sensitivity_classifier or {})
    score = max(0.0, min(1.0, float(confidence or 0.0)))
    has_sensitive = bool(classifier.get("has_sensitive_field") or classifier.get("has_sensitive_surface"))
    if score >= 0.75:
        action = "continue"
    elif score >= 0.4:
        action = "escalate"
    else:
        action = "block"
    if has_sensitive and action == "continue":
        action = "escalate"
    return {
        "schema_version": SCHEMA_VERSION,
        "escalation_id": _sha1_payload({"classifier": classifier, "confidence": round(score, 4), "action": action})[:16],
        "confidence": round(score, 4),
        "has_sensitive": has_sensitive,
        "action": action,
        "should_warn": action != "continue",
        "should_block": action == "block",
        "reason": "sensitivity_uncertainty_escalation_" + action,
    }


def build_depth_of_intrusion_budget(
    *,
    requested_depth: int = 0,
    max_depth: int = 0,
    risk_level: float = 0.0,
) -> Dict[str, Any]:
    depth = max(0, int(requested_depth or 0))
    limit = max(0, int(max_depth or 0))
    risk = max(0.0, min(1.0, float(risk_level or 0.0)))
    allowed = depth <= limit if limit > 0 else depth == 0
    if not allowed or risk >= 0.8:
        status = "blocked"
    elif risk >= 0.4:
        status = "limited"
    else:
        status = "allowed"
    return {
        "schema_version": SCHEMA_VERSION,
        "budget_id": _sha1_payload({"depth": depth, "limit": limit, "risk": round(risk, 4), "status": status})[:16],
        "requested_depth": depth,
        "max_depth": limit,
        "risk_level": round(risk, 4),
        "status": status,
        "should_warn": status != "allowed",
        "should_block": status == "blocked",
        "reason": "depth_of_intrusion_budget_" + status,
    }


def build_compliance_redaction_contract(
    *,
    artifact_rows: Sequence[Mapping[str, Any] | str] | None = None,
    redaction_level: str = "",
    brief_rows: Sequence[Mapping[str, Any] | str] | None = None,
) -> Dict[str, Any]:
    artifacts = [row for row in (artifact_rows or []) if row]
    briefs = [row for row in (brief_rows or []) if row]
    level = str(redaction_level or "").strip().lower()
    ready = bool(level) and (bool(artifacts) or bool(briefs))
    if level in {"full", "strict"}:
        mode = "strict"
    elif level in {"partial", "mask"}:
        mode = "partial"
    else:
        mode = "none"
    return {
        "schema_version": SCHEMA_VERSION,
        "contract_id": _sha1_payload({"artifacts": artifacts, "briefs": briefs, "level": level, "mode": mode})[:16],
        "artifact_count": len(artifacts),
        "brief_count": len(briefs),
        "redaction_level": level,
        "mode": mode,
        "is_ready": ready,
        "should_warn": not ready or mode != "strict",
        "should_block": mode == "none",
        "reason": "compliance_redaction_contract_" + mode,
    }


def build_field_sensitivity_classifier(
    *,
    field_rows: Sequence[Mapping[str, Any] | str] | None = None,
    section_name: str = "",
) -> Dict[str, Any]:
    rows: List[Dict[str, Any]] = []
    counts = {"ordinary": 0, "private": 0, "regulated": 0, "forbidden": 0}
    for idx, row in enumerate(field_rows or [], start=1):
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip()
            payload = {"name": text} if text else {}
        name = str(_first_nonempty(payload.get("name"), payload.get("field"), payload.get("label"), f"field_{idx}")).strip()
        lowered = " ".join(
            filter(
                None,
                [
                    name.lower(),
                    str(_first_nonempty(payload.get("placeholder"), "")).lower(),
                    str(_first_nonempty(payload.get("validation"), "")).lower(),
                    str(section_name or "").lower(),
                ],
            )
        )
        kind = "ordinary"
        if bool(payload.get("is_forbidden")) or any(token in lowered for token in ("forbidden", "ban", "blocked")):
            kind = "forbidden"
        elif bool(payload.get("is_regulated")) or any(token in lowered for token in ("regulated", "legal", "policy", "consent")):
            kind = "regulated"
        elif bool(payload.get("is_private")) or any(token in lowered for token in ("private", "personal", "pii", "email", "phone", "password", "secret")):
            kind = "private"
        counts[kind] = int(counts.get(kind, 0) + 1)
        rows.append({"name": name, "kind": kind, "reason": str(_first_nonempty(payload.get("reason"), name))})
    return {
        "schema_version": SCHEMA_VERSION,
        "classifier_id": _sha1_payload({"rows": rows, "section_name": section_name})[:16],
        "section_name": str(section_name or "").strip(),
        "rows": rows,
        "counts": counts,
        "has_sensitive_field": bool(counts["private"] or counts["regulated"] or counts["forbidden"]),
        "should_warn": bool(counts["private"] or counts["regulated"] or counts["forbidden"]),
        "should_block": counts["forbidden"] > 0,
        "reason": "field_sensitivity_classifier_classified" if rows else "field_sensitivity_classifier_empty",
    }


def build_contextual_sensitivity_guard(
    *,
    field_sensitivity_classifier: Mapping[str, Any] | None = None,
    question_context: Mapping[str, Any] | None = None,
) -> Dict[str, Any]:
    classifier = dict(field_sensitivity_classifier or {})
    context = dict(question_context or {})
    field_count = len(classifier.get("rows") or [])
    private_count = int((classifier.get("counts") or {}).get("private", 0))
    regulated_count = int((classifier.get("counts") or {}).get("regulated", 0))
    context_text = " ".join(
        filter(
            None,
            [
                str(_first_nonempty(context.get("section"), context.get("name"), "")).lower(),
                str(_first_nonempty(context.get("intent"), context.get("question"), "")).lower(),
                str(_first_nonempty(context.get("expected_payload"), context.get("payload"), "")).lower(),
            ],
        )
    )
    matched = bool(field_count) and (private_count > 0 or regulated_count > 0 or any(term in context_text for term in ("consent", "privacy", "personal", "payment", "health")))
    return {
        "schema_version": SCHEMA_VERSION,
        "guard_id": _sha1_payload({"classifier": classifier, "context": context})[:16],
        "field_count": field_count,
        "private_count": private_count,
        "regulated_count": regulated_count,
        "is_sensitive": matched,
        "should_warn": matched,
        "should_block": matched and private_count > 0,
        "reason": "contextual_sensitivity_guard_sensitive" if matched else "contextual_sensitivity_guard_clear",
    }


def build_restricted_input_policy(
    *,
    field_sensitivity_classifier: Mapping[str, Any] | None = None,
    sample_values: Sequence[str] | None = None,
) -> Dict[str, Any]:
    classifier = dict(field_sensitivity_classifier or {})
    values = [str(value or "").strip() for value in (sample_values or []) if str(value or "").strip()]
    kind_counts = dict(classifier.get("counts") or {})
    sensitivity = "ordinary"
    if kind_counts.get("forbidden", 0) > 0:
        sensitivity = "forbidden"
    elif kind_counts.get("regulated", 0) > 0:
        sensitivity = "regulated"
    elif kind_counts.get("private", 0) > 0:
        sensitivity = "private"
    allowed_samples = ["synthetic_text", "placeholder", "redacted", "empty"]
    if sensitivity == "forbidden":
        allowed_samples = []
    elif sensitivity == "regulated":
        allowed_samples = ["synthetic_text", "redacted", "empty"]
    elif sensitivity == "private":
        allowed_samples = ["synthetic_text", "redacted", "placeholder", "empty"]
    return {
        "schema_version": SCHEMA_VERSION,
        "policy_id": _sha1_payload({"sensitivity": sensitivity, "values": values})[:16],
        "sensitivity": sensitivity,
        "sample_values": values,
        "allowed_samples": allowed_samples,
        "is_restricted": sensitivity != "ordinary",
        "should_warn": sensitivity != "ordinary",
        "should_block": sensitivity == "forbidden",
        "reason": "restricted_input_policy_" + sensitivity,
    }


def build_consent_and_privacy_text_reader(
    *,
    text_rows: Sequence[Mapping[str, Any] | str] | None = None,
    section_name: str = "",
) -> Dict[str, Any]:
    rows: List[Dict[str, Any]] = []
    max_restriction = "ordinary"
    restriction_order = {"ordinary": 0, "private": 1, "regulated": 2, "forbidden": 3}
    for idx, row in enumerate(text_rows or [], start=1):
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip()
            payload = {"text": text} if text else {}
        text = str(_first_nonempty(payload.get("text"), payload.get("name"), payload.get("label"), f"text_{idx}")).strip()
        lowered = " ".join(filter(None, [text.lower(), str(section_name or "").lower()]))
        kind = "ordinary"
        if any(token in lowered for token in ("forbidden", "ban", "blocked", "do not share")):
            kind = "forbidden"
        elif any(token in lowered for token in ("consent", "privacy", "gdpr", "legal", "policy")):
            kind = "regulated"
        elif any(token in lowered for token in ("private", "personal", "pii", "email", "phone")):
            kind = "private"
        if restriction_order[kind] > restriction_order[max_restriction]:
            max_restriction = kind
        rows.append({"text": text, "kind": kind, "reason": str(_first_nonempty(payload.get("reason"), text))})
    return {
        "schema_version": SCHEMA_VERSION,
        "reader_id": _sha1_payload({"rows": rows, "section_name": section_name})[:16],
        "section_name": str(section_name or "").strip(),
        "rows": rows,
        "max_restriction": max_restriction,
        "should_warn": max_restriction != "ordinary",
        "should_block": max_restriction == "forbidden",
        "reason": "consent_and_privacy_text_reader_" + max_restriction,
    }


def build_capacity_unit_contract(
    *,
    cpu_units: float = 0.0,
    gpu_units: float = 0.0,
    worker_units: float = 0.0,
    artifact_units: float = 0.0,
) -> Dict[str, Any]:
    cpu = max(0.0, float(cpu_units or 0.0))
    gpu = max(0.0, float(gpu_units or 0.0))
    workers = max(0.0, float(worker_units or 0.0))
    artifacts = max(0.0, float(artifact_units or 0.0))
    total_cost = round(cpu + (gpu * 2.0) + workers + (artifacts * 0.5), 4)
    is_defined = total_cost > 0.0
    return {
        "schema_version": SCHEMA_VERSION,
        "unit_id": _sha1_payload(
            {
                "cpu_units": cpu,
                "gpu_units": gpu,
                "worker_units": workers,
                "artifact_units": artifacts,
            }
        )[:16],
        "cpu_units": cpu,
        "gpu_units": gpu,
        "worker_units": workers,
        "artifact_units": artifacts,
        "total_cost": total_cost,
        "is_defined": is_defined,
        "should_warn": not is_defined,
        "should_block": not is_defined,
        "reason": "capacity_unit_contract_defined" if is_defined else "capacity_unit_contract_incomplete",
    }


def build_workload_class_registry(
    *,
    workload_rows: Sequence[Mapping[str, Any] | str] | None = None,
    active_class: str = "",
) -> Dict[str, Any]:
    rows: List[Dict[str, Any]] = []
    seen: Set[str] = set()
    active = str(active_class or "").strip().lower()
    for idx, row in enumerate(workload_rows or [], start=1):
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip()
            payload = {"name": text} if text else {}
        kind = str(_first_nonempty(payload.get("kind"), payload.get("name"), f"class_{idx}")).strip().lower()
        if kind in seen:
            continue
        seen.add(kind)
        rows.append(
            {
                "kind": kind,
                "weight": max(0.0, float(_first_nonempty(payload.get("weight"), 1.0))),
                "reason": str(_first_nonempty(payload.get("reason"), payload.get("description"), kind)),
            }
        )
    valid_active = active in seen if active else bool(rows)
    return {
        "schema_version": SCHEMA_VERSION,
        "registry_id": _sha1_payload({"rows": rows, "active_class": active})[:16],
        "rows": rows,
        "active_class": active,
        "class_count": len(rows),
        "is_valid": valid_active,
        "should_warn": not valid_active,
        "should_block": not valid_active,
        "reason": "workload_class_registry_valid" if valid_active else "workload_class_registry_invalid",
    }


def build_capacity_snapshot_identity(
    *,
    active_sessions: int = 0,
    worker_count: int = 0,
    runtime_backends: Sequence[str] | None = None,
    budget_remaining: float = 0.0,
) -> Dict[str, Any]:
    backends = [str(item or "").strip().lower() for item in (runtime_backends or []) if str(item or "").strip()]
    sessions = max(0, int(active_sessions or 0))
    workers = max(0, int(worker_count or 0))
    budget = max(0.0, float(budget_remaining or 0.0))
    complete = bool(backends) and (sessions > 0 or workers > 0 or budget > 0.0)
    return {
        "schema_version": SCHEMA_VERSION,
        "snapshot_id": _sha1_payload(
            {
                "active_sessions": sessions,
                "worker_count": workers,
                "runtime_backends": backends,
                "budget_remaining": round(budget, 4),
            }
        )[:16],
        "active_sessions": sessions,
        "worker_count": workers,
        "runtime_backends": backends,
        "budget_remaining": budget,
        "is_complete": complete,
        "should_warn": not complete,
        "should_block": not complete,
        "reason": "capacity_snapshot_identity_complete" if complete else "capacity_snapshot_identity_incomplete",
    }


def build_cost_hint_packet(
    *,
    estimated_runtime_s: float = 0.0,
    artifact_count: int = 0,
    resource_pressure: str = "",
) -> Dict[str, Any]:
    runtime = max(0.0, float(estimated_runtime_s or 0.0))
    artifacts = max(0, int(artifact_count or 0))
    pressure = str(resource_pressure or "").strip().lower()
    actionable = runtime > 0.0 or artifacts > 0 or bool(pressure)
    return {
        "schema_version": SCHEMA_VERSION,
        "hint_id": _sha1_payload({"runtime": runtime, "artifacts": artifacts, "pressure": pressure})[:16],
        "estimated_runtime_s": round(runtime, 4),
        "artifact_count": artifacts,
        "resource_pressure": pressure,
        "is_actionable": actionable,
        "should_warn": actionable,
        "should_block": False,
        "reason": "cost_hint_packet_actionable" if actionable else "cost_hint_packet_empty",
    }


def build_global_concurrency_governor(
    *,
    runtime_slots: int = 0,
    replay_slots: int = 0,
    worker_slots: int = 0,
    budget_remaining: float = 0.0,
) -> Dict[str, Any]:
    runtime = max(0, int(runtime_slots or 0))
    replay = max(0, int(replay_slots or 0))
    workers = max(0, int(worker_slots or 0))
    budget = max(0.0, float(budget_remaining or 0.0))
    total_slots = runtime + replay + workers
    ready = total_slots > 0 and budget > 0.0
    return {
        "schema_version": SCHEMA_VERSION,
        "governor_id": _sha1_payload({"runtime_slots": runtime, "replay_slots": replay, "worker_slots": workers, "budget_remaining": round(budget, 4)})[:16],
        "runtime_slots": runtime,
        "replay_slots": replay,
        "worker_slots": workers,
        "budget_remaining": budget,
        "total_slots": total_slots,
        "is_ready": ready,
        "should_warn": not ready,
        "should_block": not ready,
        "reason": "global_concurrency_governor_ready" if ready else "global_concurrency_governor_incomplete",
    }


def build_system_priority_router(
    *,
    task_rows: Sequence[Mapping[str, Any] | str] | None = None,
    active_mode: str = "",
) -> Dict[str, Any]:
    priorities = {"smoke": 0, "critical": 1, "experiment": 2, "background": 3}
    rows: List[Dict[str, Any]] = []
    for idx, row in enumerate(task_rows or [], start=1):
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip()
            payload = {"name": text} if text else {}
        name = str(_first_nonempty(payload.get("name"), payload.get("task"), f"task_{idx}")).strip()
        priority = str(_first_nonempty(payload.get("priority"), payload.get("kind"), "background")).strip().lower()
        rows.append({"name": name, "priority": priority})
    ordered = sorted(rows, key=lambda item: priorities.get(item["priority"], 99))
    valid = bool(ordered)
    return {
        "schema_version": SCHEMA_VERSION,
        "router_id": _sha1_payload({"rows": rows, "active_mode": active_mode})[:16],
        "rows": rows,
        "ordered_rows": ordered,
        "active_mode": str(active_mode or "").strip().lower(),
        "task_count": len(rows),
        "is_valid": valid,
        "should_warn": not valid,
        "should_block": not valid,
        "reason": "system_priority_router_valid" if valid else "system_priority_router_incomplete",
    }


def build_starvation_guard(
    *,
    queue_rows: Sequence[Mapping[str, Any] | str] | None = None,
    max_wait_s: float = 0.0,
) -> Dict[str, Any]:
    rows: List[Dict[str, Any]] = []
    wait_times: List[float] = []
    threshold = max(0.0, float(max_wait_s or 0.0))
    for idx, row in enumerate(queue_rows or [], start=1):
        if isinstance(row, Mapping):
            payload = dict(row)
        else:
            text = str(row or "").strip()
            payload = {"name": text} if text else {}
        name = str(_first_nonempty(payload.get("name"), payload.get("task"), f"queue_{idx}")).strip()
        wait = max(0.0, float(_first_nonempty(payload.get("wait_s"), payload.get("wait"), 0.0)))
        wait_times.append(wait)
        rows.append({"name": name, "wait_s": round(wait, 4)})
    starved = any(wait > threshold for wait in wait_times) if threshold > 0.0 else False
    return {
        "schema_version": SCHEMA_VERSION,
        "guard_id": _sha1_payload({"rows": rows, "max_wait_s": threshold})[:16],
        "rows": rows,
        "max_wait_s": threshold,
        "max_observed_wait_s": round(max(wait_times) if wait_times else 0.0, 4),
        "is_starved": starved,
        "should_warn": starved,
        "should_block": False,
        "reason": "starvation_guard_starved" if starved else "starvation_guard_clear",
    }


def build_overload_degradation_policy(
    *,
    system_pressure: float = 0.0,
    active_sessions: int = 0,
    active_modes: Sequence[str] | None = None,
) -> Dict[str, Any]:
    pressure = max(0.0, float(system_pressure or 0.0))
    sessions = max(0, int(active_sessions or 0))
    modes = [str(item or "").strip().lower() for item in (active_modes or []) if str(item or "").strip()]
    if pressure >= 0.8 or sessions >= 8:
        action = "degrade_replay"
    elif pressure >= 0.6:
        action = "degrade_shadow_eval"
    elif pressure >= 0.4 and "experiment" in modes:
        action = "throttle_experiment"
    else:
        action = "normal"
    return {
        "schema_version": SCHEMA_VERSION,
        "policy_id": _sha1_payload({"pressure": round(pressure, 4), "sessions": sessions, "modes": modes, "action": action})[:16],
        "system_pressure": round(pressure, 4),
        "active_sessions": sessions,
        "active_modes": modes,
        "action": action,
        "should_warn": action != "normal",
        "should_block": action == "degrade_replay",
        "reason": "overload_degradation_policy_" + action,
    }


def build_multi_agent_cost_model(
    *,
    worker_count: int = 0,
    coordination_overhead: float = 0.0,
    estimated_worker_cost: float = 0.0,
) -> Dict[str, Any]:
    workers = max(0, int(worker_count or 0))
    overhead = max(0.0, float(coordination_overhead or 0.0))
    worker_cost = max(0.0, float(estimated_worker_cost or 0.0))
    total_cost = round((workers * worker_cost) + overhead, 4)
    efficient = workers > 1 and total_cost < (workers * worker_cost * 1.25 if worker_cost > 0 else total_cost + 1.0)
    return {
        "schema_version": SCHEMA_VERSION,
        "model_id": _sha1_payload({"workers": workers, "overhead": overhead, "worker_cost": worker_cost})[:16],
        "worker_count": workers,
        "coordination_overhead": overhead,
        "estimated_worker_cost": worker_cost,
        "total_cost": total_cost,
        "is_efficient": efficient,
        "should_warn": not efficient,
        "should_block": False,
        "reason": "multi_agent_cost_model_efficient" if efficient else "multi_agent_cost_model_costly",
    }


def build_bundle_cost_estimator(
    *,
    write_scope: int = 0,
    runtime_minutes: float = 0.0,
    local_tests: int = 0,
) -> Dict[str, Any]:
    scope = max(0, int(write_scope or 0))
    runtime = max(0.0, float(runtime_minutes or 0.0))
    tests = max(0, int(local_tests or 0))
    estimated = round((scope * 0.5) + (runtime * 0.75) + (tests * 0.25), 4)
    return {
        "schema_version": SCHEMA_VERSION,
        "estimator_id": _sha1_payload({"scope": scope, "runtime": runtime, "tests": tests})[:16],
        "write_scope": scope,
        "runtime_minutes": runtime,
        "local_tests": tests,
        "estimated_cost": estimated,
        "reason": "bundle_cost_estimator_estimated",
    }


def build_background_load_budget(
    *,
    active_background_jobs: int = 0,
    max_background_jobs: int = 0,
    active_debugging: bool = False,
) -> Dict[str, Any]:
    active = max(0, int(active_background_jobs or 0))
    limit = max(0, int(max_background_jobs or 0))
    remaining = max(0, limit - active)
    capped = limit > 0 and active >= limit
    if active_debugging and active > 0:
        mode = "restricted"
    elif capped:
        mode = "exhausted"
    else:
        mode = "open"
    return {
        "schema_version": SCHEMA_VERSION,
        "budget_id": _sha1_payload({"active": active, "limit": limit, "mode": mode})[:16],
        "active_background_jobs": active,
        "max_background_jobs": limit,
        "remaining_background_jobs": remaining,
        "mode": mode,
        "should_warn": mode != "open",
        "should_block": mode == "exhausted",
        "reason": "background_load_budget_" + mode,
    }


def build_cost_vs_value_gate(
    *,
    estimated_cost: float = 0.0,
    estimated_value: float = 0.0,
    risk_multiplier: float = 1.0,
) -> Dict[str, Any]:
    cost = max(0.0, float(estimated_cost or 0.0))
    value = max(0.0, float(estimated_value or 0.0))
    risk = max(0.0, float(risk_multiplier or 0.0))
    score = round(value - (cost * risk), 4)
    if score >= 0.5:
        decision = "proceed"
    elif score >= 0.0:
        decision = "maybe"
    else:
        decision = "skip"
    return {
        "schema_version": SCHEMA_VERSION,
        "gate_id": _sha1_payload({"cost": cost, "value": value, "risk": risk, "decision": decision})[:16],
        "estimated_cost": cost,
        "estimated_value": value,
        "risk_multiplier": risk,
        "score": score,
        "decision": decision,
        "should_warn": decision != "proceed",
        "should_block": decision == "skip",
        "reason": "cost_vs_value_gate_" + decision,
    }


def build_capacity_regression_suite(
    *,
    throughput_rows: Sequence[Mapping[str, Any] | str] | None = None,
    queue_time_rows: Sequence[Mapping[str, Any] | str] | None = None,
    load_scenarios: Sequence[Mapping[str, Any] | str] | None = None,
) -> Dict[str, Any]:
    throughput = [row for row in (throughput_rows or []) if row]
    queue_times = [row for row in (queue_time_rows or []) if row]
    scenarios = [row for row in (load_scenarios or []) if row]
    regressed = bool(throughput) and bool(queue_times) and len(queue_times) >= len(throughput)
    return {
        "schema_version": SCHEMA_VERSION,
        "suite_id": _sha1_payload({"throughput": throughput, "queue_times": queue_times, "scenarios": scenarios})[:16],
        "throughput_count": len(throughput),
        "queue_time_count": len(queue_times),
        "scenario_count": len(scenarios),
        "is_regressed": regressed,
        "should_warn": bool(queue_times),
        "should_block": regressed,
        "reason": "capacity_regression_suite_regressed" if regressed else "capacity_regression_suite_stable",
    }


def build_queue_health_contract(
    *,
    waiting_time_s: float = 0.0,
    expiry_risk: float = 0.0,
    session_result: str = "",
) -> Dict[str, Any]:
    wait = max(0.0, float(waiting_time_s or 0.0))
    risk = max(0.0, min(1.0, float(expiry_risk or 0.0)))
    result = str(session_result or "").strip().lower()
    health = "good"
    if wait >= 10.0 or risk >= 0.75:
        health = "bad"
    elif wait >= 5.0 or risk >= 0.4:
        health = "warn"
    if result == "expired":
        health = "bad"
    return {
        "schema_version": SCHEMA_VERSION,
        "contract_id": _sha1_payload({"wait": wait, "risk": risk, "result": result})[:16],
        "waiting_time_s": round(wait, 4),
        "expiry_risk": round(risk, 4),
        "session_result": result,
        "health": health,
        "should_warn": health != "good",
        "should_block": health == "bad",
        "reason": "queue_health_contract_" + health,
    }


def build_capacity_brief_packet(
    *,
    current_usage: Mapping[str, Any] | None = None,
    deferrable_items: Sequence[Mapping[str, Any] | str] | None = None,
    bottlenecks: Sequence[Mapping[str, Any] | str] | None = None,
) -> Dict[str, Any]:
    usage = dict(current_usage or {})
    deferrable = [row for row in (deferrable_items or []) if row]
    bottleneck_rows = [row for row in (bottlenecks or []) if row]
    ready = bool(usage) and bool(deferrable) and bool(bottleneck_rows)
    return {
        "schema_version": SCHEMA_VERSION,
        "packet_id": _sha1_payload({"usage": usage, "deferrable": deferrable, "bottlenecks": bottleneck_rows})[:16],
        "current_usage": usage,
        "deferrable_items": deferrable,
        "bottlenecks": bottleneck_rows,
        "is_ready": ready,
        "should_warn": not ready,
        "should_block": not ready,
        "reason": "capacity_brief_packet_ready" if ready else "capacity_brief_packet_incomplete",
    }


def build_capacity_gap_promoter(
    *,
    capacity_gap_events: Sequence[Mapping[str, Any] | str] | None = None,
    capacity_regression_suite: Mapping[str, Any] | None = None,
    capacity_brief_packet: Mapping[str, Any] | None = None,
    threshold: int = 2,
) -> Dict[str, Any]:
    events = [row for row in (capacity_gap_events or []) if row]
    regression = dict(capacity_regression_suite or {})
    brief = dict(capacity_brief_packet or {})
    recurring_count = len(events)
    promote = recurring_count >= max(1, int(threshold or 0)) or bool(regression.get("is_regressed")) or bool(brief.get("is_ready"))
    tier = "promote" if promote else "monitor"
    return {
        "schema_version": SCHEMA_VERSION,
        "promotion_tier": tier,
        "recurring_count": recurring_count,
        "threshold": int(threshold or 0),
        "is_promoted": promote,
        "should_warn": not promote,
        "should_block": False,
        "reason": "capacity_gap_promoter_" + tier,
    }


def build_blank_screen_audit(records: Sequence[Mapping[str, Any]]) -> Dict[str, Any]:
    rows: List[Dict[str, Any]] = []
    counts: Dict[str, int] = {}
    for record in records:
        detection = detect_blank_screen(
            screen_state=record.get("screen_state") if isinstance(record, Mapping) else None,
            page_state=record.get("page_state") if isinstance(record, Mapping) else None,
            image_stats=record.get("image_stats") if isinstance(record, Mapping) else None,
            ocr_rows=record.get("ocr_rows") if isinstance(record, Mapping) else None,
        )
        kind = str(detection.get("kind") or "not_blank")
        counts[kind] = int(counts.get(kind, 0) + 1)
        rows.append(
            {
                "id": _first_nonempty(record.get("id") if isinstance(record, Mapping) else ""),
                "kind": kind,
                "is_blank": bool(detection.get("is_blank")),
            }
        )
    return {
        "schema_version": SCHEMA_VERSION,
        "counts": counts,
        "rows": rows,
    }


